    // The smallest pile (a[0]) will be used as the source for copying.
    // All other piles (a[1] to a[n-1]) will be targets.
    std::sort(a.begin(), a.end());

    long long min_val = a[0]; // The value of the smallest pile
    long long total_operations = 0;

    // Iterate through all piles except the smallest one (which is a[0]).
    // These are the target piles.
    for (int i = 1; i < n; ++i) {
        // For each target pile a[i], calculate how many times min_val can be
        // added to it without exceeding k.
        // The condition is: a[i] + x * min_val <= k
        // Rearranging for x: x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        // Since x must be an integer, we use integer division.
        total_operations += (k - a[i]) / min_val;
    }

    std::cout << total_operations << std::endl;
}

