    std::string ans(n, '0');

    // Initialize current_min_idx and current_max_idx with the position of '1'.
    // For m=1, the segment containing only '1' is p[pos[1]...pos[1]].
    // Its length is 1. Its maximum value is 1.
    // Thus, 1 is always a beautiful number.
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];
    ans[0] = '1';

    // Iterate for m from 2 to n.
    // For each m, we want to find the smallest contiguous subsegment
    // that contains all numbers from 1 to m.
    // This subsegment will span from min(pos[1], ..., pos[m]) to max(pos[1], ..., pos[m]).
    // Let these be current_min_idx and current_max_idx.
    // A number m is beautiful if this subsegment has length exactly m.
    // If the length is m, it means the subsegment contains exactly m distinct numbers,
    // which are 1, 2, ..., m.
    for (int m = 2; m <= n; ++m) {
