    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_char(k, '?');

    bool possible = true;

    // First pass: Determine fixed characters for each column (s[i], s[i+k], s[i+2k], ...)
    // All characters s[j] where j % k == i must be the same.
    for (int i = 0; i < k; ++i) {
        for (int j = i; j < n; j += k) {
            if (s[j] == '0') {
                if (fixed_char[i] == '1') { // Conflict: already determined to be '1'
                    possible = false;
                    break;
                }
                fixed_char[i] = '0'; // Set to '0'
            } else if (s[j] == '1') {
                if (fixed_char[i] == '0') { // Conflict: already determined to be '0'
                    possible = false;
                    break;
                }
                fixed_char[i] = '1'; // Set to '1'
            }
            // If s[j] is '?', fixed_char[i] remains as is (either '?' or already '0'/'1')
        }
        if (!possible) {
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Second pass: Check if the first k characters (based on fixed_char) can be balanced
    // A k-balanced string requires every substring of length k to have k/2 zeros and k/2 ones.
    // Due to the periodicity s[i] == s[i+k], this means the first k characters s[0...k-1]
    // must form a k-balanced substring.
    int zeros_count = 0;
    int ones_count = 0;
    int q_count = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_char[i] == '0') {
            zeros_count++;
        } else if (fixed_char[i] == '1') {
            ones_count++;
        } else { // fixed_char[i] == '?'
            q_count++;
        }
    }

    // We need to fill 'q_count' question marks.
    // The target is k/2 zeros and k/2 ones in total for the first k characters.
    int needed_zeros = k / 2 - zeros_count;
    int needed_ones = k / 2 - ones_count;

    // Conditions for possibility:
    // 1. We don't already have too many zeros or ones.
    if (needed_zeros < 0 || needed_ones < 0) {
        possible = false;
    }
    // 2. The number of '?'s is exactly enough to fill the needed zeros and ones.
    if (needed_zeros + needed_ones != q_count) {
        possible = false;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

