// Function to find distinct prime factors of a number
std::vector<long long> get_distinct_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) { // If n is still greater than 1, it must be a prime factor itself
        factors.push_back(n);
    }
    return factors;
}

