        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // Each coal requires y sticks. So, k coal requires k * y sticks.
        // Total sticks needed for crafting and buying coal: k + k * y.
        long long total_sticks_required = k + k * y;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks.
        long long sticks_to_acquire = total_sticks_required - 1;

        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of stick trades needed: ceil(sticks_to_acquire / (x - 1)).
        // Using integer division: (A + B - 1) / B for ceil(A / B)
        long long num_stick_trades = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = number of stick trades + number of coal trades.
        // Number of coal trades is k (one trade per coal).
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

