#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it already matches.
            // The flags for has_pos_one and has_neg_one should reflect elements
            // that are *before* the current index i.
            // So, if a[i] is 1 or -1, it can be used for elements to its right.
            // But for checking a[i] itself, we only care about elements a[k] with k < i.
            // The flags are updated *after* checking a[i] against b[i].
            // This means when we check a[i], has_pos_one and has_neg_one refer to a[0...i-1].
            // This is correct.
        } else if (a[i] < b[i]) {
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for the next iteration (i-1)
        // These flags will represent elements a[0...i-1]
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

