int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (a[i] == min_val) {
                // This is the pile with minimum candies.
                // We can use it as a source, but we cannot add to it using itself.
                // If there are multiple piles with min_val, we can use one as source
                // and others as targets. However, the problem states i != j.
                // The strategy is to use the *smallest* pile as source for *all other* piles.
                // So, we skip counting operations for the actual min_val pile itself
                // when it's the target.
                // We will iterate through all piles and calculate how many times min_val
                // can be added to them. The pile that *is* min_val will have 0 additions
                // to itself from min_val.
                continue; 
            }
            // For any other pile a[i], we can add min_val to it as long as it doesn't exceed k.
            // The number of times min_val can be added to a[i] is (k - a[i]) / min_val.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

