void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_occupied(n, false);
    std::vector<bool> col_occupied(m, false);
    int initial_claimed_count = 0;

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int cell_val;
            std::cin >> cell_val;
            if (cell_val == 1) {
                if (!row_occupied[i] && !col_occupied[j]) {
                    // This cell (i,j) is a valid initial claim that occupies a new row/col
                    // The problem statement implies that initial claimed cells are valid
                    // in the sense that no two initial claimed cells share a row/column.
                    // If they did, the game state would be invalid by the rules.
                    // So we just mark the rows/cols as occupied.
                    row_occupied[i] = true;
                    col_occupied[j] = true;
                    initial_claimed_count++; // This count is not strictly needed for the logic,
                                             // but helps understand the state.
                }
                // If row_occupied[i] or col_occupied[j] was already true, it means
                // another initial '1' cell already occupied this row/column.
                // This is fine, we just don't count it as a *new* independent claim.
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_occupied[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_occupied[j]) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

