#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is equal to n-1. If so, it should be n.
    // This handles the case where the maximum value in the permutation is n.
    // If p[i] = n, then min(p[i], p[j]) for any j != i will be p[j].
    // The maximum of these p[j] values will be n-1 (if n-1 is present).
    // So, if p[i] is n, max_val_for_i would be n-1.
    // We need to find if there's a missing value in the set {1, ..., n}.
    // The values in p are {1, ..., n-1} if n is present, or {1, ..., n} if n is not present.
    // Since it's a permutation of 1 to n, n must be present.
    // If n is present, say at index k, then p[k] = n.
    // For any j != k, a[k][j] = min(p[k], p[j]) = min(n, p[j]) = p[j].
    // So, max_{j != k} (a[k][j]) = max_{j != k} (p[j]).
    // The maximum value among p[j] for j != k is n-1 (assuming n-1 is in the permutation).
    // Thus, if p[k] = n, our initial calculation would set p[k] to n-1.
    // We need to find if there's a value from 1 to n that is not present in the calculated p.
    // If such a value exists, it must be n, and one of the p[i] values that was calculated as n-1 should be n.

    std::vector<bool> seen(n + 1, false);
    for (int val : p) {
        if (val >= 1 && val <= n) { // Ensure val is within expected range
            seen[val] = true;
        }
    }

    bool n_is_missing = true;
    for (int i = 1; i <= n; ++i) {
        if (!seen[i]) {
            if (i == n) {
                n_is_missing = true;
            } else {
                // This case should not happen based on problem constraints
                // (guaranteed a solution exists and p is a permutation of 1 to n)
                n_is_missing = false; // A smaller number is missing, implies n is not the special case
                break;
            }
        } else {
            if (i == n) { // n is seen, so it's not missing
                n_is_missing = false;
            }
        }
    }

    if (n_is_missing) {
        // If n is missing, it means one of the elements that was calculated as n-1
        // should actually be n. We need to find which one.
        // The problem guarantees a solution, so there must be exactly one such element.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                // Check if changing this p[i] to n makes the set of values {1..n} complete.
                // This is implicitly true because we found n was missing and n-1 was present.
                // If we change one n-1 to n, then n becomes present, and n-1 is still present
                // (unless there was only one n-1, in which case n-1 becomes missing, which is wrong).
                // The logic is: if n is missing, it means one of the p[i] values that was calculated as n-1
                // was actually n. All other p[j] values (j!=i) are correctly calculated.
                // So, we find an index k where p[k] was calculated as n-1, and change p[k] to n.
                // This is valid because if p[k] was truly n, then max_{j!=k} a[k][j] would be n-1.
                // And if there are multiple n-1s, only one of them can be n.
                // The problem guarantees a solution, so we can just pick the first one.
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long sum_of_stairs = 1; // Number of stairs for the current staircase (1, 3, 7, ...)

        while (x >= current_cost) {
            x -= current_cost;
            count++;
            sum_of_stairs = sum_of_stairs * 2 + 1; // Next nice staircase has 2*N+1 stairs
            current_cost = sum_of_stairs * (sum_of_stairs + 1) / 2; // Cost for the next nice staircase
        }
        std::cout << count << "\n";
    }
    return 0;
}

