int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate differences up to k

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k distinct differences (1 to k),
    // the remaining numbers should be printed in increasing order
    // to ensure only difference 1 is generated.
    // The numbers used so far are 1, 2, ..., k+1.
    // The next number to print is left (which is right+1 if k is odd, or left if k is even).
    // In any case, `left` holds the smallest unused number greater than 0.
    // `right` holds the largest unused number less than or equal to k+1.
    // After the loop, `left` will be `(k+1)/2 + 1` if k is odd, or `k/2 + 1` if k is even.
    // `right` will be `(k+1)/2` if k is odd, or `k/2 + 1` if k is even.
    // The numbers used are `1, ..., k+1`.
    // The next number to print is `k+2`.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    std::vector<int> available_values;

    p[0] = q[0];
    used_values.insert(q[0]);

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new max.
                // But as a safety check.
                std::cout << -1 << "\n";
                return;
            }
            used_values.insert(q[i]);
        } else {
            // q[i] == q[i-1]
            // p[i] must be some value x such that x < q[i] and x is not yet used.
            // We need to fill these p[i] values later.
            // For now, mark them as 0 or some placeholder.
            p[i] = 0; 
        }
    }

    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            available_values.push_back(i);
        }
    }
    std::reverse(available_values.begin(), available_values.end());

    int current_available_idx = 0;
    for (int i = 0; i < n; ++i) {
        if (p[i] == 0) { // This is a position where q[i] == q[i-1]
            if (current_available_idx >= available_values.size()) {
                std::cout << -1 << "\n"; // Not enough available numbers
                return;
            }
            int val_to_assign = available_values[current_available_idx];
            if (val_to_assign > q[i]) { // p_i must be <= q_i (which is q_{i-1})
                std::cout << -1 << "\n";
                return;
            }
            p[i] = val_to_assign;
            current_available_idx++;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

