}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int last_01 = -1; // Index of the last '0' in a that should be '1' in b
    int last_10 = -1; // Index of the last '1' in a that should be '0' in b

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1' (Type 01)
                if (last_10 != -1) { // Found a '1' in a that should be '0' in b (Type 10)
                    // We can swap a[last_10] and a[i].
                    // This fixes both positions.
                    // a[last_10] was '1', becomes '0' (correct for b[last_10])
                    // a[i] was '0', becomes '1' (correct for b[i])
                    cost += (i - last_10);
                    last_10 = -1; // This '10' position is now resolved
                } else {
                    // No pending '10' to swap with.
                    // This '01' position might be resolved by a future '10' or by a flip.
                    // We mark it as a pending '01' position.
                    last_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0' (Type 10)
                if (last_01 != -1) { // Found a '0' in a that should be '1' in b (Type 01)
                    // We can swap a[last_01] and a[i].
                    // This fixes both positions.
                    // a[last_01] was '0', becomes '1' (correct for b[last_01])
                    // a[i] was '1', becomes '0' (correct for b[i])
                    cost += (i - last_01);
                    last_01 = -1; // This '01' position is now resolved
                } else {
                    // No pending '01' to swap with.
                    // This '10' position might be resolved by a future '01' or by a flip.
                    // We mark it as a pending '10' position.
                    last_10 = i;
                }
            }
        }
    }

    // Any remaining last_01 or last_10 means there's an unmatched differing bit.
    // These must be fixed by flipping. Each flip costs 1.
    if (last_01 != -1) {
        cost += 1;
    }
    if (last_10 != -1) {
        cost += 1;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will track the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end of array
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition with x[i]
        // We need to choose two points from the range [x[i+1], ..., x[right_ptr-1]]
        // Let k be the number of points in this range.
        // The number of points available for j and k (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i.
        // If m >= 2, we can choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // The median element must be s.
    // Cost to change a[mid_idx] to s.
    operations += std::abs(a[mid_idx] - s);

    // Elements to the left of median must be <= s.
    // If any a[i] < s for i < mid_idx, we don't need to change it.
    // If any a[i] > s for i < mid_idx, we must decrease it to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median must be >= s.
    // If any a[i] > s for i > mid_idx, we don't need to change it.
    // If any a[i] < s for i > mid_idx, we must increase it to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementsA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementsB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A_sorted[i].value;
        A_sorted[i].original_index = i;
    }

    std::vector<ElementB> B_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B_sorted[i].value;
        B_sorted[i].original_index = i;
    }

    std::sort(A_sorted.begin(), A_sorted.end(), compareElementsA);
    std::sort(B_sorted.begin(), B_sorted.end(), compareElementsB);

    std::vector<long long> result_A_prime(m);

    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (B_sorted[i].value) should be paired with
        // the (m-1-i)-th smallest A value (A_sorted[m-1-i].value)
        // to maximize F(A', B) = A' * B / (B + 1)
        // This means A_sorted[m-1-i].value is assigned to the original position B_sorted[i].original_index
        result_A_prime[B_sorted[i].original_index] = A_sorted[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Box 1: (-inf, -1]
    // Can be special if:
    // 1. There's an odd number of negative toys (A+B is odd) AND
    // 2. There's at least one toy with magnitude >= 1 (A+D > 0) AND
    // 3. It's possible to make the final magnitude >= 1.
    //    This requires A+D > 0. If A+D=0, all initial toys have magnitude < 1.
    //    Then the final product will have magnitude < 1.
    //    If A+D > 0, we can always pick values such that the product is >= 1.
    //    For example, if A>0, pick -2. If D>0, pick 2.
    //    If A+D > 0, we can always ensure the final product's magnitude is >= 1.
    //    Example: if A=1, B=1, C=1, D=0. Toys: {-2, -0.5, 0.5}.
    //    (-2)*(-0.5) = 1 (Box 4). (1)*(0.5) = 0.5 (Box 3).
    //    (-2)*(0.5) = -1 (Box 1). (-1)*(-0.5) = 0.5 (Box 3).
    //    It seems if A+D > 0, we can always make magnitude >= 1.
    //    The only way to guarantee magnitude < 1 is if A+D=0.
    //    If A+D=0, then all toys are in B or C. All have magnitude < 1.
    //    Product of numbers with magnitude < 1 is always magnitude < 1.
    //    So if A+D=0, Box 1 and Box 4 are impossible.
    if ((a + b) % 2 == 1 && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    // Can be special if:
    // 1. There's an odd number of negative toys (A+B is odd) AND
    // 2. It's possible to make the final magnitude < 1.
    //    This is always possible if B+C > 0.
    //    If B+C > 0, we can pick values like -0.5 or 0.5.
    //    If A+D=0, then all toys are in B or C, so magnitude < 1 is guaranteed.
    //    If A+D > 0, we can still make magnitude < 1.
    //    Example: A=1, D=1. Toys: {-2, 2}. Product -4 (Box 1).
    //    But if we have B or C, say B=1. Toys: {-2, 2, -0.5}.
    //    (-2)*(-0.5) = 1 (Box 4). (1)*(2) = 2 (Box 4).
    //    (-2)*(2) = -4 (Box 1). (-4)*(-0.5) = 2 (Box 4).
    //    It seems if A+D > 0, we can always make magnitude >= 1.
    //    However, we can choose to multiply a large number by a small number at the end.
    //    E.g., if we have a toy in Box 1 or 4, and a toy in Box 2 or 3.
    //    If A+D > 0 and B+C > 0, we can always make magnitude < 1.
    //    Example: A=1, B=1, C=0, D=1. Toys: {-2, -0.5, 2}.
    //    Sequence: (-2)*(2) = -4 (Box 1). Then (-4)*(-0.5) = 2 (Box 4).
    //    Sequence: (-2)*(-0.5) = 1 (Box 4). Then (1)*(2) = 2 (Box 4).
    //    Sequence: (2)*(-0.5) = -1 (Box 1). Then (-1)*(-2) = 2 (Box 4).
    //    This is tricky. The example shows that if A=1, B=2, D=1, Box 2 can be special.
    //    This implies that if A+D > 0 and B+C > 0, we can make magnitude < 1.
    //    The only way to *guarantee* magnitude >= 1 is if B+C=0.
    //    If B+C=0, all toys are in A or D. All have magnitude >= 1.
    //    Product of numbers with magnitude >= 1 is always magnitude >= 1.
    //    So if B+C=0, Box 2 and Box 3 are impossible.
    if ((a + b) % 2 == 1 && (b + c > 0 || (a + d == 0 && b + c > 0))) { // (b+c > 0) covers all cases where magnitude < 1 is possible
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    // Can be special if:
    // 1. There's an even number of negative toys (A+B is even) AND
    // 2. It's possible to make the final magnitude < 1. (Same condition as Box 2)
    if ((a + b) % 2 == 0 && (b + c > 0 || (a + d == 0 && b + c > 0))) { // (b+c > 0) covers all cases where magnitude < 1 is possible
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    // Can be special if:
    // 1. There's an even number of negative toys (A+B is even) AND
    // 2. It's possible to make the final magnitude >= 1. (Same condition as Box 1)
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special edge cases:
    // If A+D=0, all toys are in B or C. All have magnitude < 1.
    // The final product will always have magnitude < 1. So Box 1 and Box 4 are impossible.
    if (a + d == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }
    // If B+C=0, all toys are in A or D. All have magnitude >= 1.
    // The final product will always have magnitude >= 1. So Box 2 and Box 3 are impossible.
    if (b + c == 0) {
        ans2 = "Tidak";
        ans3 = "Tidak";
    }

    // One more check for Box 2 and Box 3:
    // If A+D > 0 and B+C > 0, it is always possible to make the final magnitude < 1.
    // This is because we can always multiply a large number by a small number at the end.
    // For example, if we have a toy with value X (from A or D) and a toy with value Y (from B or C).
    // We can arrange operations such that X is multiplied by Y last.
    // If |X| >= 1 and |Y| < 1, then |X*Y| can be < 1.
    // Example: A=1, B=1, C=0, D=1. Toys: {-2, -0.5, 2}.
    // We want to end in Box 2 or 3. This means final magnitude < 1.
    // If we multiply (-2) * (2) = -4. Then (-4) * (-0.5) = 2. Final magnitude >= 1.
    // If we multiply (-2) * (-0.5) = 1. Then (1) * (2) = 2. Final magnitude >= 1.
    // If we multiply (2) * (-0.5) = -1. Then (-1) * (-2) = 2. Final magnitude >= 1.
    // This implies that if A+D > 0, it's *not* always possible to make magnitude < 1.
    // The example output for 1 2 0 1 is Ya Ya Tidak Tidak.
    // Here A=1, B=2, C=0, D=1. A+D=2 > 0. B+C=2 > 0.
    // Box 3 is "Tidak". This contradicts my previous logic that B+C > 0 implies magnitude < 1 is possible.

    // Let's re-evaluate the magnitude part.
    // The final magnitude is < 1 if and only if it's possible to have at least one toy from B or C
    // remaining until the very last step, and its magnitude "dominates" the product.
    // Or, if all toys are from B or C.
    // If A+D > 0 and B+C > 0:
    // It is possible to make the final magnitude < 1 if and only if (A+D) <= (B+C) + 1.
    // This is because each multiplication can reduce the count of "large" numbers (from A or D) by one,
    // or reduce the count of "small" numbers (from B or C) by one.
    // If we have L large numbers and S small numbers.
    // L*L -> L (magnitude >= 1)
    // S*S -> S (magnitude < 1)
    // L*S -> can be L or S.
    // To get a final magnitude < 1, we need to ensure that the last multiplication involves a "small" number,
    // or that all intermediate products eventually become "small".
    // If we have L large numbers and S small numbers.
    // If L > S+1, we can always pair up L numbers such that the product remains large.
    // Example: L=3, S=1. Toys: {2, 2, 2, 0.5}.
    // (2*2)*2*0.5 = 8*0.5 = 4 (large)
    // (2*2)*0.5*2 = 4*0.5*2 = 2*2 = 4 (large)
    // (2*0.5)*2*2 = 1*2*2 = 4 (large)
    // It seems if (A+D) > (B+C) + 1, then the final product's magnitude will always be >= 1.
    // If (A+D) <= (B+C) + 1, then it's possible to make the final product's magnitude < 1.
    // This is because we can always "cancel out" large numbers with small numbers.
    // For example, if we have L large numbers and S small numbers, and L <= S+1.
    // We can pair up L-1 large numbers with L-1 small numbers.
    // This leaves 1 large number and S-(L-1) small numbers.
    // Or, we can pair up all S small numbers with S large numbers.
    // This leaves L-S large numbers.
    // The condition (A+D) <= (B+C) + 1 seems to be the correct one for possibility of magnitude < 1.

    bool can_be_mag_lt_1 = false;
    if (b + c > 0) { // If there's at least one small number
        if (a + d == 0) { // All numbers are small
            can_be_mag_lt_1 = true;
        } else { // Mix of large and small numbers
            // If (A+D) <= (B+C) + 1, we can make magnitude < 1.
            // This is because we can always ensure that the last remaining "large" number
            // is multiplied by a "small" number, or that all large numbers are "neutralized"
            // by small numbers.
            // Example: A=1, B=2, D=1. (A+D)=2, (B+C)=2. (A+D) <= (B+C)+1 is 2 <= 2+1 (True).
            // Toys: {-3, -0.5, -0.5, 3}.
            // (-0.5)*(-0.5) = 0.25 (Box 3).
            // (-3)*(0.25) = -0.75 (Box 2).
            // (-0.75)*(3) = -2.25 (Box 1).
            // This sequence ends in Box 1.
            // Example from problem:
            // A=1, B=2, D=1. Toys: {-3, -0.33, -0.25, 3}.
            // (-3)*(-0.33) = 0.99 (Box 3).
            // (0.99)*(3) = 2.97 (Box 4).
            // (2.97)*(-0.25) = -0.7425 (Box 2).
            // This sequence ends in Box 2.
            // So if B+C > 0, it is always possible to make the final magnitude < 1.
            // The only way it's NOT possible is if B+C=0.
            can_be_mag_lt_1 = true;
        }
    }

    bool can_be_mag_ge_1 = false;
    if (a + d > 0) { // If there's at least one large number
        if (b + c == 0) { // All numbers are large
            can_be_mag_ge_1 = true;
        } else { // Mix of large and small numbers
            // If (B+C) <= (A+D) + 1, we can make magnitude >= 1.
            // This is always true if A+D > 0.
            // We can always ensure that the last remaining "small" number
            // is multiplied by a "large" number, or that all small numbers are "neutralized"
            // by large numbers.
            // Example: A=1, B=2, D=1. (A+D)=2, (B+C)=2.
            // Toys: {-3, -0.5, -0.5, 3}.
            // (-0.5)*(-0.5) = 0.25 (Box 3).
            // (-3)*(0.25) = -0.75 (Box 2).
            // (-0.75)*(3) = -2.25 (Box 1).
            // This sequence ends in Box 1.
            // So if A+D > 0, it is always possible to make the final magnitude >= 1.
            // The only way it's NOT possible is if A+D=0.
            can_be_mag_ge_1 = true;
        }
    }

    // Re-evaluate based on simplified logic:
    // Sign: (A+B) % 2 determines if final product can be negative or positive.
    // Magnitude:
    //   - If A+D == 0 (all toys are in B or C), then final magnitude is always < 1.
    //   - If B+C == 0 (all toys are in A or D), then final magnitude is always >= 1.
    //   - If A+D > 0 AND B+C > 0 (mix of large and small):
    //     It is possible to achieve final magnitude < 1. (Example 1, Box 2)
    //     It is possible to achieve final magnitude >= 1. (Example 1, Box 1)
    //     So, if A+D > 0 and B+C > 0, both magnitude outcomes are possible.

    // Box 1: (-inf, -1]
    // Condition: (A+B) is odd AND final magnitude >= 1 is possible.
    if ((a + b) % 2 == 1 && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    // Condition: (A+B) is odd AND final magnitude < 1 is possible.
    if ((a + b) % 2 == 1 && (b + c > 0)) {
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    // Condition: (A+B) is even AND final magnitude < 1 is possible.
    if ((a + b) % 2 == 0 && (b + c > 0)) {
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    // Condition: (A+B) is even AND final magnitude >= 1 is possible.
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

