#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    int distinct_count_prefix = 0;

    for (int l1 = 1; l1 <= n; ++l1) {
        int current_val = a[l1 - 1];
        if (current_val > l1 || seen_prefix[current_val]) {
            break; // Cannot be a permutation of length l1
        }
        seen_prefix[current_val] = true;
        distinct_count_prefix++;
        max_val_prefix = std::max(max_val_prefix, current_val);

        if (distinct_count_prefix == l1 && max_val_prefix == l1) {
            is_prefix_perm[l1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    int distinct_count_suffix = 0;

    for (int l2 = 1; l2 <= n; ++l2) {
        int current_val = a[n - l2];
        if (current_val > l2 || seen_suffix[current_val]) {
            break; // Cannot be a permutation of length l2
        }
        seen_suffix[current_val] = true;
        distinct_count_suffix++;
        max_val_suffix = std::max(max_val_suffix, current_val);

        if (distinct_count_suffix == l2 && max_val_suffix == l2) {
            is_suffix_perm[l2] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

