long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1;
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even
                chanek_coins += 1;
                n -= 1;
            }
        }

        if (n > 0) { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    n /= 2;
                } else { // N/2 is even
                    n -= 1;
                }
            }
        }
    }
    return chanek_coins;
}

