#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int initial_losses = 0;

        // Calculate initial score and count initial losses
        bool prev_won = false;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                current_score += (prev_won ? 2 : 1);
                prev_won = true;
            } else {
                initial_losses++;
                prev_won = false;
            }
        }

        // If all games are losses initially, and we have k changes
        // We can win k games. The score will be 1 for the first win, 0 for others.
        // If k > 0, score is 1. If k = 0, score is 0.
        if (initial_losses == n) {
            if (k > 0) {
                std::cout << 1 + 2 * std::min(k - 1, n - 1) << "\n";
            } else {
                std::cout << 0 << "\n";
            }
            continue;
        }

        // Number of 'L's we can change
        int changes_to_make = std::min(k, initial_losses);

        // The score from existing 'W's is already counted.
        // We want to convert 'L's to 'W's.
        // Converting an 'L' to 'W' can give 1 or 2 points.
        // It gives 2 points if it connects two 'W' segments or extends a 'W' segment.
        // It gives 1 point if it starts a new 'W' segment.

        // Strategy:
        // 1. Fill gaps between existing 'W's to get 2 points per 'L' converted.
        // 2. Extend existing 'W' segments (either left or right) to get 2 points per 'L' converted.
        // 3. Convert isolated 'L's to 'W's to get 1 point per 'L' converted.

        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Collect gap lengths between 'W's
        if (first_W != -1) { // If there's at least one 'W'
            int current_gap = 0;
            for (int i = first_W + 1; i <= last_W; ++i) {
                if (s[i] == 'L') {
                    current_gap++;
                } else { // s[i] == 'W'
                    if (current_gap > 0) {
                        gap_lengths.push_back(current_gap);
                    }
                    current_gap = 0;
                }
            }
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        // Fill gaps
        for (int gap_len : gap_lengths) {
            if (changes_to_make >= gap_len) {
                current_score += 2 * gap_len; // Each 'L' in gap becomes 'W', connecting two 'W's, so 2 points
                changes_to_make -= gap_len;
            } else {
                current_score += 2 * changes_to_make;
                changes_to_make = 0;
                break;
            }
        }

        // Extend 'W' segments
        if (changes_to_make > 0) {
            // Count 'L's before first 'W'
            int l_before_first_W = 0;
            if (first_W != -1) {
                l_before_first_W = first_W;
            } else { // Should not happen if initial_losses != n
                l_before_first_W = 0;
            }

            // Count 'L's after last 'W'
            int l_after_last_W = 0;
            if (last_W != -1) {
                l_after_last_W = n - 1 - last_W;
            } else { // Should not happen if initial_losses != n
                l_after_last_W = 0;
            }

            // Prioritize extending to get 2 points.
            // Each 'L' converted next to an existing 'W' gives 2 points.
            // The first 'L' converted that is not next to an existing 'W' gives 1 point.
            // But we already handled the initial score, so existing 'W's are already counted.
            // Any new 'W' that is adjacent to an existing 'W' will give 2 points.
            // Any new 'W' that is not adjacent to an existing 'W' will give 1 point.
            // The logic for filling gaps already gives 2 points.
            // The remaining changes will either extend existing W segments (2 points)
            // or create new W segments (1 point for the first, 2 for subsequent if k allows).
            // Since we already have at least one 'W' (initial_losses != n),
            // any 'L' converted adjacent to an existing 'W' will give 2 points.
            // Any 'L' converted that is not adjacent to an existing 'W' will give 1 point.
            // The problem is that we don't know which 'L's are adjacent to 'W's after filling gaps.
            // A simpler approach:
            // Each 'L' converted to 'W' adds 1 point.
            // If this 'W' is adjacent to another 'W', it adds an *additional* 1 point.
            // The initial score already counts 1 point for each 'W' (or 2 if prev was W).
            // When we convert an 'L' to 'W':
            // 1. If it's adjacent to an existing 'W' (or a newly converted 'W' that is adjacent to an existing 'W'), it adds 2 points.
            // 2. If it's not adjacent to any 'W', it adds 1 point.
            // The gap filling already handles case 1.
            // The remaining changes will either extend existing 'W' blocks (2 points per L) or create new 'W' blocks (1 point for first L, then 2 for subsequent Ls).
            // Since we have already filled gaps, all remaining 'L's are either before the first 'W' or after the last 'W'.
            // Or they are isolated 'L's if there were no 'W's to begin with (handled by initial_losses == n case).

            // The current_score already includes points for initial 'W's.
            // Each 'L' we convert adds 1 point.
            // If this 'L' becomes 'W' and is adjacent to another 'W', it adds an *additional* 1 point.
            // The number of 'L's we can convert is `changes_to_make`.
            // Each of these `changes_to_make` 'L's will add at least 1 point.
            // So, `current_score += changes_to_make`.
            // Now, we need to count how many of these `changes_to_make` 'L's will be adjacent to another 'W' (either original or newly converted).
            // This is equivalent to counting how many 'W's will be adjacent to another 'W' after all conversions.
            // The number of 'W's that are adjacent to another 'W' is `(number of W's) - (number of W blocks)`.
            // Each 'W' that is adjacent to another 'W' contributes an extra 1 point.
            // Total score = (total W's) + (total W's - total W blocks).
            // Total W's = (initial W's) + changes_to_make.
            // Total W blocks:
            //   Initially, count W blocks.
            //   Filling gaps reduces W blocks.
            //   Extending W blocks doesn't change W blocks.
            //   Creating new W blocks increases W blocks.

            // Let's simplify:
            // Each 'W' contributes 1 point.
            // Each 'W' that has a 'W' before it contributes an additional 1 point.
            // So, total score = (count of 'W's) + (count of 'W's with 'W' before them).
            // After filling gaps, we have `changes_to_make` remaining.
            // These remaining changes can only extend the 'W' blocks at the ends.
            // Each such extension adds 2 points per 'L' converted.
            // Example: WWLWW, k=1. Fill gap: WWWW. Score +2.
            // Example: LWWL, k=1. Extend: LWWWL. Score +2.
            // Example: LWWL, k=2. Extend: LWWWW. Score +4.
            // Example: LWWL, k=3. Extend: WWWWW. Score +6.

            // The `current_score` already reflects the initial 'W's and the 'W's from filling gaps.
            // Each 'L' converted to 'W' adds 1 point.
            // If this 'L' is adjacent to an existing 'W' (original or converted), it adds an *additional* 1 point.
            // The `changes_to_make` variable holds the number of 'L's we can still convert.
            // Each of these `changes_to_make` 'L's will add 1 point.
            current_score += changes_to_make;

            // Now, we need to count how many of these `changes_to_make` 'L's will be adjacent to another 'W'.
            // These are 'L's at the ends of the string or adjacent to the first/last 'W' after gap filling.
            // Since we filled all possible gaps, any remaining 'L's are either before the first 'W' or after the last 'W'.
            // All these 'L's, when converted, will be adjacent to an existing 'W' (the first or last 'W' of the main block).
            // So, each of these `changes_to_make` 'L's will contribute an *additional* 1 point.
            current_score += changes_to_make;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
