void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Friends with w_i = 1 get the largest remaining numbers
    // These are the friends with largest w_i values after sorting
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // All remaining friends have w_i > 1
            // We can break here because w is sorted
            break;
        }
    }

    // Friends with w_i > 1
    // These are the friends with smallest w_i values after sorting
    // They get one largest remaining number (for max_val)
    // and one smallest remaining number (for min_val)
    // and w_i - 2 other numbers (which don't affect max/min)
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;
            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest numbers
        }
    }

    std::cout << total_happiness << std::endl;
}

