    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
        // Let S = current_sum, X = current_xor_sum
        // We want (S + b1 + b2 + b3) = 2 * (X ^ b1 ^ b2 ^ b3)

        // Strategy: Append at most 3 elements.
        // It's always possible to append 2 elements.
        // Let's try to append two elements, b1 and b2.
        // We want (S + b1 + b2) = 2 * (X ^ b1 ^ b2)
        // A simple choice for b1 and b2 that works:
        // Let b1 = X.
        // Then the XOR sum becomes X ^ X = 0.
        // The equation becomes (S + X + b2) = 2 * (0 ^ b2) = 2 * b2.
        // So, S + X + b2 = 2 * b2
        // S + X = b2
        // Thus, b2 = S + X.

        // So, we can append X and (S + X).
        // The new sum will be S + X + (S + X) = 2S + 2X.
        // The new XOR sum will be X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
        // Check the condition: (2S + 2X) = 2 * (S + X). This is true.

        // The problem states that appended elements don't have to be different.
        // The problem states that we don't have to minimize the number of added elements.
        // So, appending X and (S + X) always works.
        // The number of elements to append is 2.
        // The elements are current_xor_sum and (current_sum + current_xor_sum).

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << "\n";
    }
    return 0;
}

