int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_one_two_count = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Check for the chain starting with 1, 2, 3, ...
        if (chain[0] == 1) {
            int current_val = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_val) {
                    consecutive_one_two_count++;
                    current_val++;
                } else {
                    break; // Chain 1,2,3... is broken
                }
            }
        }
    }

    // Total operations to achieve 1->2->...->n is n-1.
    // We need to perform (n-1) nesting operations.
    // Some of these are already present.
    // The number of already present correct nestings is (consecutive_one_two_count - 1).
    // For example, if 1->2->3 is present, consecutive_one_two_count is 3.
    // This means 1->2 and 2->3 are present. That's 2 nestings. (3-1).

    // Operations to disassemble:
    // Each chain needs to be disassembled into individual dolls, except for the
    // part that forms the beginning of the 1->2->...->n sequence.
    // If a chain is a_1 -> a_2 -> ... -> a_m, it has m-1 internal nestings.
    // To disassemble it completely, we need m-1 operations.
    // Total initial nestings across all chains: sum(m_i - 1) = (sum m_i) - k = n - k.
    // These are the operations that need to be undone if they are not part of the final sequence.

    // The 'consecutive_one_two_count' represents the length of the prefix 1->2->...->X
    // that is already correctly formed and doesn't need to be touched.
    // This prefix has (consecutive_one_two_count - 1) internal nestings.
    // These (consecutive_one_two_count - 1) nestings do NOT need to be undone.

    // So, the number of nestings that need to be undone is (n - k) - (consecutive_one_two_count - 1).
    // This is the number of 'get out' operations.
    total_operations += (n - k) - (consecutive_one_two_count - 1);

    // Operations to assemble:
    // We need to form n-1 total nestings.
    // (consecutive_one_two_count - 1) of these are already formed.
    // So, we need to perform (n-1) - (consecutive_one_two_count - 1) new 'put in' operations.
    total_operations += (n - 1) - (consecutive_one_two_count - 1);

    std::cout << total_operations << std::endl;

    return 0;
}

