// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must be a divisor of p, but x must not be a multiple of q.
        // This implies that for at least one prime factor f_j of q,
        // the power of f_j in x must be less than the power of f_j in q.

        // Get prime factors of q
        std::map<long long, int> q_factors = get_prime_factors(q);

        long long max_x = 0;

        // Iterate through each distinct prime factor f of q
        for (auto const& [f, q_power] : q_factors) {
            // Calculate the power of f in p
            long long temp_p = p;
            int p_power = 0;
            while (temp_p > 0 && temp_p % f == 0) {
                p_power++;
                temp_p /= f;
            }

            // If p_power < q_power, it means p already doesn't have enough factors of f
            // to be divisible by q (which contradicts p % q == 0).
            // So p_power must be >= q_power.
            // We need to remove enough factors of f from p such that the new number x
            // has f_power < q_power.
            // The largest such x would be p / f^(p_power - q_power + 1).
            // This ensures that the power of f in x is exactly q_power - 1.

            long long current_x = p;
            for (int i = 0; i < p_power - q_power + 1; ++i) {
                current_x /= f;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
