#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_s(n, '?');

    // Step 1: Propagate constraints from s[i] and s[i+k]
    for (int i = 0; i < n - k; ++i) {
        if (s[i] != '?' && s[i+k] != '?') {
            if (s[i] != s[i+k]) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Determine fixed characters for each residue class modulo k
    for (int r = 0; r < k; ++r) {
        char determined_char = '?';
        for (int i = r; i < n; i += k) {
            if (s[i] != '?') {
                if (determined_char == '?') {
                    determined_char = s[i];
                } else if (determined_char != s[i]) {
                    // This case should ideally be caught by Step 1 if k is small enough
                    // but it's good to have a check here too.
                    // If s[i] and s[j] are in the same residue class r,
                    // and s[i] != s[j], then it's impossible.
                    // This is implicitly handled by the propagation logic.
                    // For example, if s[r] = '0' and s[r+k] = '1', Step 1 catches it.
                    // If s[r] = '0' and s[r+2k] = '1', then s[r] must be s[r+k] and s[r+k] must be s[r+2k].
                    // So s[r] must be s[r+2k]. If they differ, it's impossible.
                    // This check is redundant if Step 1 is correct.
                }
            }
        }
        for (int i = r; i < n; i += k) {
            fixed_s[i] = determined_char;
        }
    }

    // Step 3: Check if any original '0' or '1' conflicts with fixed_s
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?' && fixed_s[i] != '?' && s[i] != fixed_s[i]) {
            std::cout << "NO\n";
            return;
        }
    }

    // Step 4: Verify k-balance for the first k characters
    // Count 0s, 1s, and ?s in the first k characters of fixed_s
    int count0 = 0;
    int count1 = 0;
    int countQ = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_s[i] == '0') {
            count0++;
        } else if (fixed_s[i] == '1') {
            count1++;
        } else { // fixed_s[i] == '?'
            countQ++;
        }
    }

    // Check if it's possible to make the first k characters k/2 zeros and k/2 ones
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we have enough '?' to fill the remaining slots
    // (k/2 - count0) for zeros and (k/2 - count1) for ones
    // The total '?' needed is (k/2 - count0) + (k/2 - count1) = k - count0 - count1
    // This must be less than or equal to countQ.
    // Since count0 + count1 + countQ = k, this condition simplifies to:
    // k - count0 - count1 <= countQ
    // (k - count0 - count1) == countQ
    // So, if count0 <= k/2 and count1 <= k/2, it's always possible to fill the '?'s.

    std::cout << "YES\n";
}

