int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed for k torches and k coal
        // k sticks for torches + k * y sticks for k coal
        // Total sticks = k * (y + 1)

        // We start with 1 stick.
        // So, we need to acquire (k * (y + 1)) - 1 additional sticks.
        long long sticks_to_acquire = k * (y + 1) - 1;

        // Each stick-generating trade (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        long long sticks_per_trade_gain = x - 1;

        // Number of stick-generating trades needed
        // This is ceil(sticks_to_acquire / sticks_per_trade_gain)
        long long num_stick_trades = (sticks_to_acquire + sticks_per_trade_gain - 1) / sticks_per_trade_gain;

        // Total trades = num_stick_trades + num_coal_trades
        // num_coal_trades is k (one trade per coal)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

