int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form 'one', we need 'o', 'n', 'e'.
    // To form 'zero', we need 'z', 'e', 'r', 'o'.

    // Prioritize '1's to maximize the binary number.
    // The number of '1's is limited by 'n', 'o', 'e'.
    // Each 'one' uses one 'n', one 'o', one 'e'.
    int num_ones = count_n; // 'n' is unique to 'one'

    // After forming 'num_ones' '1's, we use up 'num_ones' 'o's and 'num_ones' 'e's.
    count_o -= num_ones;
    count_e -= num_ones;

    // The remaining letters are used for '0's.
    // Each 'zero' uses one 'z', one 'e', one 'r', one 'o'.
    // The number of '0's is limited by 'z', 'e', 'r', 'o'.
    // 'z' and 'r' are unique to 'zero'.
    // 'o' and 'e' are shared, but we've already accounted for their use in 'one's.
    int num_zeros = count_z; // 'z' is unique to 'zero'

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

