void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Minimum price encountered from the current position to the end

    // Iterate from right to left, starting from the second to last element
    // The last element (a[n-1]) can never be a bad price as there are no days after it.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means a[i] is
            // either less than or equal to min_suffix_price.
            // In this case, a[i] becomes the new minimum for the suffix
            // starting from this position.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

