int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
                            // Cell 0 is effectively an 'R' cell as it allows jumping right.

        // Iterate through the string s (cells 1 to n)
        for (int i = 0; i < s.length(); ++i) {
            // s[i] corresponds to cell i+1
            if (s[i] == 'R') {
                // If we find an 'R' at cell i+1, calculate the distance from the last 'R' (or cell 0)
                // The distance is (current_R_cell_index) - (last_R_cell_index)
                // current_R_cell_index is i+1
                // last_R_cell_index is last_R_pos
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell
            }
        }

        // After iterating through all cells, consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's were found) to the target cell n+1.
        // The distance is (n+1) - (last_R_cell_index)
        max_gap = std::max(max_gap, (int)s.length() + 1 - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

