#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then p[i] must be equal to max_{j!=i} min(p[i], p[j])
        // because there must be some p[k] such that p[k] = p[i] and p[i] is the minimum.
        // No, this is not quite right.
        // If p[i] is not n, then there is some p[k] = n.
        // Then a[i][k] = min(p[i], p[k]) = min(p[i], n) = p[i].
        // So, max_{j!=i} a[i][j] will be at least p[i].
        // Since a[i][j] = min(p[i], p[j]) <= p[i],
        // it must be that max_{j!=i} a[i][j] = p[i].
        // The only exception is if p[i] = n. In that case, max_{j!=i} a[i][j] = max_{j!=i} p[j] = n-1.
        // So, if max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

