#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1;

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horz_moves = std::min(counts['L'], counts['R']);
    int vert_moves = std::min(counts['U'], counts['D']);

    std::string result = "";
    int total_length = 0;

    if (horz_moves == 0 && vert_moves == 0) {
        // No moves possible
        total_length = 0;
    } else if (horz_moves == 0) {
        // Only vertical moves possible, must be U and D
        // To form a valid path, we need at least one U and one D.
        // If we have only U or only D, or both but only one of each,
        // the path would be "UD" or "DU".
        // If we have more, e.g., "UUDD", it visits (0,1) twice.
        // So, if horz_moves is 0, we can only use one 'U' and one 'D' if available.
        if (vert_moves > 0) {
            result = "UD";
            total_length = 2;
        } else {
            total_length = 0;
        }
    } else if (vert_moves == 0) {
        // Only horizontal moves possible, must be L and R
        // Similar to vertical, we can only use one 'L' and one 'R' if available.
        if (horz_moves > 0) {
            result = "LR";
            total_length = 2;
        } else {
            total_length = 0;
        }
    } else {
        // Both horizontal and vertical moves are available.
        // We can use all available paired moves.
        // Example: LLLRRRUUUDDD
        // horz_moves = 3, vert_moves = 3
        // Path: LLLUUUDDDRRR
        // This path is valid because it expands outwards and then contracts.
        // The order can be:
        // horz_moves 'L's
        // vert_moves 'U's
        // vert_moves 'D's
        // horz_moves 'R's
        // Or any permutation that keeps L/R and U/D balanced and doesn't revisit.
        // A simple construction is L...LU...UD...DR...R

        for (int i = 0; i < horz_moves; ++i) result += 'L';
        for (int i = 0; i < vert_moves; ++i) result += 'U';
        for (int i = 0; i < vert_moves; ++i) result += 'D';
        for (int i = 0; i < horz_moves; ++i) result += 'R';
        total_length = 2 * horz_moves + 2 * vert_moves;
    }

    std::cout << total_length << std::endl;
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

