void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. It's always beautiful.
        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // The segment must have length m.

        // Update current_min_idx and current_max_idx to cover all numbers from 1 to m.
        // This means the segment must span from min(pos[1]...pos[m]) to max(pos[1]...pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // has length exactly 'm'.
        // If it does, it means it contains all numbers from 1 to m (by construction of min/max indices)
        // and no other numbers (because its length is exactly m).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

