int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Mismatch found at index i
            // Check if there's an adjacent mismatch of the opposite type
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Found a[i] != b[i] and a[i+1] != b[i+1]
                // And a[i] and a[i+1] are different (e.g., '0' and '1')
                // This means (a[i], b[i]) is (0,1) and (a[i+1], b[i+1]) is (1,0)
                // OR (a[i], b[i]) is (1,0) and (a[i+1], b[i+1]) is (0,1)
                // In both cases, swapping a[i] and a[i+1] resolves both mismatches.
                // Cost of swap is |(i+1) - i| = 1.
                cost += 1;
                i += 2; // Both positions i and i+1 are resolved
            } else {
                // No adjacent opposite mismatch, or no adjacent mismatch at all.
                // The best we can do is flip a[i]. Cost is 1.
                cost += 1;
                i += 1; // Position i is resolved
            }
        } else {
            // Match at index i, move to the next position
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

