void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    long long total_toys = a + b + c + d;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Determine if a positive final value is possible
    // A positive final value requires an even number of negative factors.
    // The number of negative factors is 'a' + 'b'.
    // If (a + b) is even, a positive final value is possible.
    bool can_be_positive = ((a + b) % 2 == 0);

    // Determine if a negative final value is possible
    // A negative final value requires an odd number of negative factors.
    // If (a + b) is odd, a negative final value is possible.
    bool can_be_negative = ((a + b) % 2 == 1);

    // Determine if magnitude can be < 1
    // This requires at least one toy from Box 2 or Box 3 to be the last one multiplied,
    // or a sequence of multiplications that results in a value < 1.
    // If there are any toys in B or C, it's possible to get a magnitude < 1.
    // If all toys are in A and D, then all products will have magnitude >= 1.
    // Exception: if A=0, D=0, then all toys are in B and C.
    // If B+C > 0, then magnitude < 1 is possible.
    // If A+D > 0, then magnitude >= 1 is possible.

    // Can the final value be in Box 1 (negative, magnitude >= 1)?
    // Requires: can_be_negative AND can_be_magnitude_ge_1
    // can_be_magnitude_ge_1:
    // If there's at least one toy in A or D, we can always ensure magnitude >= 1.
    // If all toys are in B and C (A=0, D=0), then all products will have magnitude < 1.
    // So, if A+D > 0, magnitude >= 1 is possible.
    // If A+D == 0, then magnitude >= 1 is NOT possible.
    if (can_be_negative && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Can the final value be in Box 2 (negative, magnitude < 1)?
    // Requires: can_be_negative AND can_be_magnitude_lt_1
    // can_be_magnitude_lt_1:
    // If there's at least one toy in B or C, we can always ensure magnitude < 1.
    // If all toys are in A and D (B=0, C=0), then all products will have magnitude >= 1.
    // So, if B+C > 0, magnitude < 1 is possible.
    // If B+C == 0, then magnitude < 1 is NOT possible.
    if (can_be_negative && (b + c > 0)) {
        ans2 = "Ya";
    }

    // Can the final value be in Box 3 (positive, magnitude < 1)?
    // Requires: can_be_positive AND can_be_magnitude_lt_1
    if (can_be_positive && (b + c > 0)) {
        ans3 = "Ya";
    }

    // Can the final value be in Box 4 (positive, magnitude >= 1)?
    // Requires: can_be_positive AND can_be_magnitude_ge_1
    if (can_be_positive && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special case: If A+D=0, then all toys are in B and C.
    // All products will have magnitude < 1.
    // So, Box 1 and Box 4 are impossible.
    if (a + d == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }

    // Special case: If B+C=0, then all toys are in A and D.
    // All products will have magnitude >= 1.
    // So, Box 2 and Box 3 are impossible.
    if (b + c == 0) {
        ans2 = "Tidak";
        ans3 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

