int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i], we want to find all x[k] such that x[k] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr.
        // right_ptr will always be >= i.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, x[right_ptr-1] is the largest x_k satisfying the condition for x[i].
        // All points from x[i+1] to x[right_ptr-1] can be x_j or x_k.
        // The number of points in the valid range [x[i+1], ..., x[right_ptr-1]] is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the number of points available to be x_j or x_k.
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = (long long)right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

