#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1: they get one number, which is both min and max.
    // To maximize happiness, these friends should get the largest available numbers.
    // These are the k largest numbers from 'a'.
    // Since w is sorted, w[0]...w[k-1] are the counts.
    // The largest numbers in 'a' are a[n-1], a[n-2], ..., a[n-k].
    // We pair the largest w_i=1 with the largest a_j.
    // The friends with w_i = 1 are at the beginning of the sorted 'w' array.
    // The largest numbers in 'a' are at the end of the sorted 'a' array.

    int a_ptr_large = n - 1; // Pointer to the largest available number in 'a'
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += a[a_ptr_large] * 2; // max + min = val + val
            a_ptr_large--;
        } else {
            // All remaining w[i] will be > 1.
            // Since w is sorted, all w[0]...w[i] will be > 1.
            // We can break here because we processed all w_i = 1.
            break;
        }
    }

    // Friends with w_i > 1: they get w_i numbers.
    // To maximize happiness, they should get one of the remaining largest numbers as their max,
    // and one of the smallest available numbers as their min.
    // The remaining largest numbers are a[a_ptr_large], a[a_ptr_large-1], ...
    // The smallest numbers are a[0], a[1], ...

    int a_ptr_small = 0; // Pointer to the smallest available number in 'a'
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // This friend gets a[a_ptr_large] as their max.
            total_happiness += a[a_ptr_large];
            a_ptr_large--;

            // This friend needs w[i]-1 additional numbers.
            // To maximize happiness, the min should be as large as possible.
            // But we must use the smallest available numbers for min values.
            // So, this friend gets a[a_ptr_small] as their min.
            total_happiness += a[a_ptr_small];
            a_ptr_small += (w[i] - 1); // Consume w[i]-1 smallest numbers
        }
    }

    std::cout << total_happiness << std::endl;
}

