#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_pairs_in_place = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the first doll in a chain is 1, it's a special case.
        // We count how many consecutive pairs (j, j+1) exist starting from 1.
        if (m > 0 && chain[0] == 1) {
            int current_val = 1;
            for (int j = 1; j < m; ++j) {
                if (chain[j] == current_val + 1) {
                    consecutive_pairs_in_place++;
                    current_val++;
                } else {
                    break; // Chain of 1->2->... broken
                }
            }
        }
    }

    // Total operations needed:
    // 1. Disassemble all existing chains into individual dolls.
    //    Each chain of length m has m-1 nesting relationships.
    //    To break these, we need m-1 'get out' operations.
    //    Sum of (m-1) for all chains = (sum of m) - k = n - k.
    //    This is the cost to get all dolls out.
    // 2. Assemble the target chain 1->2->...->n.
    //    This requires n-1 'put in' operations.
    //
    // Total operations if we disassemble everything and reassemble: (n - k) + (n - 1).
    //
    // However, some relationships (i -> i+1) might already be in place
    // and are part of the 1->2->...->N sequence.
    // Specifically, if we have 1 -> 2 -> ... -> X in one of the initial chains,
    // these X-1 relationships are already formed and don't need to be broken
    // or re-formed.
    //
    // The number of such relationships is `consecutive_pairs_in_place`.
    //
    // For each such relationship (i -> i+1) that is part of the 1->2->...->N sequence:
    // - We save 1 'get out' operation (because we don't need to break it).
    // - We save 1 'put in' operation (because it's already formed).
    // So, we save 2 operations for each such pair.
    //
    // The total operations are:
    // (n - k) + (n - 1) - (2 * consecutive_pairs_in_place)
    //
    // Let's re-evaluate:
    // Total 'get out' operations needed: (n - k) - consecutive_pairs_in_place
    // (n-k) is the total number of existing nesting relationships.
    // `consecutive_pairs_in_place` are the ones we want to keep.
    // So, we need to break (n-k) - `consecutive_pairs_in_place` relationships.
    //
    // Total 'put in' operations needed: (n - 1) - consecutive_pairs_in_place
    // (n-1) is the total number of relationships in the final chain.
    // `consecutive_pairs_in_place` are the ones already formed.
    // So, we need to form (n-1) - `consecutive_pairs_in_place` relationships.
    //
    // Total = ((n - k) - consecutive_pairs_in_place) + ((n - 1) - consecutive_pairs_in_place)
    // Total = n - k - consecutive_pairs_in_place + n - 1 - consecutive_pairs_in_place
    // Total = 2*n - k - 1 - 2*consecutive_pairs_in_place

    total_operations = (long long)(n - k - consecutive_pairs_in_place) + (long long)(n - 1 - consecutive_pairs_in_place);

    std::cout << total_operations << std::endl;

    return 0;
}

