// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must not be divisible by q.
        // To make x not divisible by q, we must remove at least one prime factor of q from p,
        // such that the resulting number is no longer divisible by q.
        // We want to remove the minimum possible "amount" of prime factors to keep x as large as possible.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by 'factor'
            // or until current_p is no longer divisible by q.
            // The goal is to find the largest divisor of p that is not divisible by q.
            // We iterate through prime factors of q. For each prime factor f of q,
            // we try to construct a candidate x by dividing p by f until x is not divisible by q.
            // Specifically, we divide p by f until the exponent of f in x is less than its exponent in q.
            // This is equivalent to dividing p by f^k where f^k is the highest power of f that divides q.
            // More precisely, we divide p by f until p/f is no longer divisible by q.
            // This is not quite right. We need to find the largest x such that x | p and x % q != 0.
            // If p % q == 0, then p is not a candidate.
            // We need to find a divisor x of p such that x % q != 0.
            // To maximize x, we want to divide p by the smallest possible factor that makes it not divisible by q.
            // This means we should divide p by some f^k where f is a prime factor of q, and f^k is the highest power of f that divides p,
            // such that p / f^k is still divisible by q, but p / f^(k+1) is not.
            // No, this is also not quite right.

            // Let's re-evaluate:
            // We have p and q. p is divisible by q.
            // We want max x such that x | p and x % q != 0.
            // Consider a prime factor `f` of `q`.
            // If we divide `p` by `f` repeatedly until `p` is no longer divisible by `q`,
            // the resulting number `p'` will be a divisor of `p` and `p' % q != 0`.
            // We want the largest such `p'`.
            // So, for each prime factor `f` of `q`:
            // 1. Start with `temp_p = p`.
            // 2. While `temp_p` is divisible by `q` AND `temp_p` is divisible by `f`:
            //    `temp_p /= f`.
            // 3. After the loop, `temp_p` is a candidate for `x`. It is a divisor of `p` and `temp_p % q != 0`.
            // 4. We take the maximum of all such `temp_p` found for each prime factor of `q`.

            long long current_candidate = p;
            while (current_candidate % q == 0) {
                current_candidate /= factor;
            }
            max_x = std::max(max_x, current_candidate);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the value 'val' to the current_sum 'count' times.
        // This is equivalent to adding val * count, but we need to be careful
        // if current_sum exceeds 2048.
        // The logic is that we have 'count' copies of 'val'.
        // We can combine pairs of 'val's to form '2*val'.
        // This means we can effectively add (count * val) to our total sum,
        // but we only care about the sum up to 2048.
        // Any excess sum beyond 2048 is effectively lost for the purpose of
        // forming 2048, as we can't break down larger numbers.

        // The most straightforward way is to simulate the merging process
        // by accumulating the sum of numbers that are <= 2048.
        // If we have X and X, they become 2X. The sum remains the same.
        // So, we just need to sum up all numbers <= 2048.
        // If the sum is >= 2048, we can always form 2048.
        // Example: {1024, 512, 512, 4} -> sum = 2048.
        // 512+512 -> 1024. Multiset becomes {1024, 1024, 4}.
        // 1024+1024 -> 2048. Multiset becomes {2048, 4}. Win.
        // This logic holds because all numbers are powers of two.
        // Any sum of powers of two can be represented as a unique sum of distinct powers of two.
        // If the total sum of numbers <= 2048 is S, and S >= 2048,
        // then we can always combine numbers until we have a set of distinct powers of two.
        // If S >= 2048, then 2048 must be formable or already present.
        // For example, if S = 2048 + 1024, we can form 2048 and 1024.
        // If S = 2048, we can form 2048.
        // If S = 1024 + 512 + 256 + ... + 1, which is 2047, we cannot form 2048.
        // So, the condition is simply whether the sum of all numbers <= 2048 is >= 2048.

        current_sum += val * count;
        if (current_sum >= 2048) {
            current_sum = 2048; // Cap the sum at 2048, as anything beyond is not useful for forming 2048
        }
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

