#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each remainder i % k

    // Step 1: Propagate constraints s[i] == s[i+k]
    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int remainder = i % k;

        if (current_char != '?') {
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = current_char;
            } else if (fixed_chars[remainder] != current_char) {
                // Conflict: s[i] is '0' but s[j] (where j % k == i % k) is '1'
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Apply fixed_chars back to s and check for conflicts
    // This step is actually redundant if we only care about the final counts,
    // but it helps to visualize the string if needed.
    // For the purpose of counting, we just need fixed_chars.

    // Step 3: Check the k-balance condition for the first k characters
    // (which represent any substring of length k due to s[i] == s[i+k] property)
    int zeros = 0;
    int ones = 0;
    int questions = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            zeros++;
        } else if (fixed_chars[i] == '1') {
            ones++;
        } else { // fixed_chars[i] == '?'
            questions++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means:
    // 1. No direct conflicts (s[i] != s[i+k] for determined chars).
    // 2. The counts of '0's and '1's in the first k positions (after propagation)
    //    do not exceed k/2.
    // The remaining '?'s can always be filled to satisfy k/2 zeros and k/2 ones.
    // We need (k/2 - zeros) more zeros and (k/2 - ones) more ones.
    // The total number of '?'s is 'questions'.
    // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones).
    // This must be equal to 'questions'.
    // Since zeros + ones + questions = k, it implies questions = k - (zeros + ones).
    // So, if zeros <= k/2 and ones <= k/2, we can always fill the '?'s.

    std::cout << "YES\n";
}

