    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {value, index}

    for (int i = 0; i < n; ++i) {
        long long current_val = h[i] + i;
        while (!dq_L.empty() && dq_L.back().first >= current_val) {
            dq_L.pop_back();
        }
        dq_L.push_back({current_val, i});

        while (dq_L.front().second < i - h[i] + 1) {
            dq_L.pop_front();
        }
        L[i] = dq_L.front().first - i;
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {value, index}

    for (int i = n - 1; i >= 0; --i) {
        long long current_val = h[i] - i;
        while (!dq_R.empty() && dq_R.back().first >= current_val) {
            dq_R.pop_back();
        }
        dq_R.push_back({current_val, i});

        while (dq_R.front().second > i + h[i] - 1) {
            dq_R.pop_front();
        }
        R[i] = dq_R.front().first + i;
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        long long ops_i = std::min(L[i], R[i]);
        max_ops = std::max(max_ops, ops_i);
    }

