            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    int final_and_const = 1023; // Represents the 'AND' constant
    int final_or_const = 0;    // Represents the 'OR' constant
    int final_xor_const = 0;   // Represents the 'XOR' constant

    for (int b = 0; b < 10; ++b) {
        int bit_0_result = (current_val_0 >> b) & 1;
        int bit_1_result = (current_val_1023 >> b) & 1;

        if (bit_0_result == 0 && bit_1_result == 0) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 0.
            // This means the bit is forced to 0.
            // Equivalent to ANDing with 0 at this bit position.
            final_and_const &= ~(1 << b);
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 1.
            // This means the bit is forced to 1.
