            final_or_const |= (1 << b);
        } else if (bit_0_result == 0 && bit_1_result == 1) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
            // This means the bit is unchanged.
            // No effect on AND, OR, XOR constants for this bit.
        } else { // bit_0_result == 1 && bit_1_result == 0
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 0.
            // This means the bit is flipped.
            // Equivalent to XORing with 1 at this bit position.
            final_xor_const |= (1 << b);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If any bit was forced to 0
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit was forced to 1
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit was flipped
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
