        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = sum_1_to_k(n);

        // Number of zeros
        long long num_zeros = n - m;

        // Number of blocks of zeros
        // If m ones, there are m+1 potential blocks of zeros.
        // To minimize zero-only substrings, we want to make zero blocks as equal as possible.
        // This means distributing num_zeros among m+1 blocks.
        // Let k be the number of blocks that get floor(num_zeros / (m+1)) + 1 zeros.
        // Let (m+1-k) be the number of blocks that get floor(num_zeros / (m+1)) zeros.

        long long num_blocks = m + 1;
        long long min_zero_substrings = 0;

        if (num_zeros > 0) {
            long long base_len = num_zeros / num_blocks;
            long long extra_blocks = num_zeros % num_blocks;

            // extra_blocks blocks will have length base_len + 1
            min_zero_substrings += extra_blocks * sum_1_to_k(base_len + 1);
            // (num_blocks - extra_blocks) blocks will have length base_len
            min_zero_substrings += (num_blocks - extra_blocks) * sum_1_to_k(base_len);
        }

        std::cout << total_substrings - min_zero_substrings << "\n";
    }
    return 0;
}

