            k = static_cast<long long>(std::floor(std::log2(X + 1)));
        }

        // If 2^k - 1 > X, we need to reduce k.
        // This can happen if X+1 is not a power of 2, and log2(X+1) is rounded up by floor due to precision.
        // Or if X+1 is a power of 2, but X is not 2^k-1.
        // Example: X=3. log2(4)=2. k=2. 2^2-1=3. Correct.
        // Example: X=5. log2(6) approx 2.58. k=2. 2^2-1=3.
        // We need to ensure 2^k - 1 <= X.
        // The largest k such that 2^k - 1 <= X is k = floor(log2(X+1)).
        // If X+1 is a power of 2, say 2^P, then k=P. 2^P-1 = X.
        // If X+1 is not a power of 2, say 2^P < X+1 < 2^(P+1), then k=P. 2^P-1 < X.
        // So the k calculated by floor(log2(X+1)) is always correct.
        // The only edge case is X=1, where floor(log2(2))=1, 2^1-1=1. This is fine.
        // The only issue is if X+1 is 1, i.e., X=0, but X > 0.
        // So k = floor(log2(X+1)) is generally correct.

        // Add k copies of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract 2^k - 1 from X
        X -= ((1LL << k) - 1);

        // Increment current_val by d + 1 for the next block
        current_val += (d + 1);
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false);

    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added to the active set

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the core of Floyd-Warshall: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // We iterate over all pairs (i, j) that are currently active.
        // The order of loops for i, j, k is important for Floyd-Warshall.
        // Here, k is the new intermediate vertex.
        // So, we update paths through k for all active i and j.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Also, update paths using existing active vertices as intermediate nodes
        // for paths involving the newly added vertex k.
        // This ensures that dist[i][k] and dist[k][j] are also minimal.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[k][i] + dist[i][j] < dist[k][j]) {
                    dist[k][j] = dist[k][i] + dist[i][j];
                }
                if (dist[j][i] + dist[i][k] < dist[j][k]) {
                    dist[j][k] = dist[j][i] + dist[i][k];
                }
            }
        }

        // After adding k and updating all paths involving k,
        // re-run Floyd-Warshall for all active vertices to ensure all-pairs shortest paths
        // are correct within the current active set.
        // This is essentially running Floyd-Warshall on the subgraph of active vertices.
        // The previous two loops already did most of the work for the new k.
        // This triple loop ensures that any path i -> ... -> j that uses k as an intermediate
        // or any path that uses k as an endpoint is correctly updated.
        // The standard Floyd-Warshall structure is:
        // for k_prime in active_vertices:
        //   for i_prime in active_vertices:
        //     for j_prime in active_vertices:
        //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime])
        // Since we are adding vertices one by one, the `k` in the outer loop of Floyd-Warshall
        // corresponds to the vertex being added.
        // The `dist` matrix already contains shortest paths considering all vertices added *before* `k`.
        // When `k` is added, we need to update paths `i -> j` using `k` as an intermediate.
        // And also paths `i -> k` and `k -> j` using other active vertices as intermediates.
        // The three loops below effectively do this for the current set of active vertices.
        for (int current_k = 0; current_k < n; ++current_k) {
            if (!active[current_k]) continue;
            for (int i = 0; i < n; ++i) {
                if (!active[i]) continue;
                for (int j = 0; j < n; ++j) {
                    if (!active[j]) continue;
                    if (dist[i][current_k] + dist[current_k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][current_k] + dist[current_k][j];
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

