#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // 'e', 'r', 'o' are common to both words or only in 'zero'
    // 'n' is unique to 'one'
    // 'z' is unique to 'zero'

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To maximize the binary number, we want as many '1's as possible, followed by '0's.
    // Each '1' comes from the word "one".
    // Each '0' comes from the word "zero".

    // The number of '1's we can form is directly limited by the count of 'n's.
    // (Because 'o' and 'e' are also used in 'zero', but 'n' is only in 'one'.
    // If we have 'n's, we must use them for 'one's to maximize '1's.
    // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // This implies that if we have 'n's, we will also have enough 'o's and 'e's to form "one"s,
    // and if we have 'z's, we will also have enough 'e's, 'r's, 'o's to form "zero"s.)

    // So, the number of '1's is simply `count_n`.
    // And the number of '0's is simply `count_z`.

    std::vector<int> result;
    for (int i = 0; i < count_n; ++i) {
        result.push_back(1);
    }
    for (int i = 0; i < count_z; ++i) {
        result.push_back(0);
    }

    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

