        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    if (a[0] == 1) {
        has_one = true;
    } else if (a[0] == -1) {
        has_minus_one = true;
