            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }

        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    std::cout << "YES\n";
