    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_values;
    long long current_sum = 0;
    int current_block_size = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_sum += a[i];
        current_block_size++;

        if (current_sum == target_duration) {
            s_values.push_back(current_block_size);
            posts_found++;
            current_sum = 0;
            current_block_size = 0;
        } else if (current_sum > target_duration) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_sum > target_duration
        // or if the loop finishes and current_sum != 0 (meaning last block didn't sum up)
        // or if posts_found < k even if current_sum is 0 at the end.
        // The logic above ensures current_sum is 0 at the end if a solution is found.
        // So if posts_found != k, it means no solution.
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last price

        // Iterate from right to left, starting from the second to last element
        // The last element a[n-1] can never be a bad price because there are no days after it.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price, it means a[i] is
                // either equal to or less than the current minimum.
                // In this case, a[i] becomes the new minimum for elements to its left.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

