    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - last_r_pos
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or 0 if no 'R's)
        // to the target cell n+1.
        // The distance is (n+1) - last_r_pos
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

