        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it should be n.
    // This handles the case where the maximum value in the permutation is n.
    // If p_i = n, then min(p_i, p_j) = p_j for all j != i.
    // So max_val_in_row for this i would be max(p_j for j != i) = n-1.
    // Since the permutation contains values from 1 to n, if n-1 is the max
    // of the other elements, then p_i must be n.
    bool found_n_minus_1 = false;
    for (int val : p) {
        if (val == n - 1) {
            found_n_minus_1 = true;
            break;
        }
    }

    if (!found_n_minus_1) {
        // This means all p[i] are less than n-1, or one of them is n.
        // If there's no n-1 in p, it implies that the largest value in the permutation (n)
        // was assigned to some p[k] such that max(p_j for j!=k) was less than n-1.
        // This is only possible if n=2.
        // For n=2, p can be {1,2} or {2,1}.
        // If p={1,2}, a[0][1]=1, a[1][0]=1. p[0]=max(a[0][j])=1. p[1]=max(a[1][j])=1.
        // If p={2,1}, a[0][1]=1, a[1][0]=1. p[0]=max(a[0][j])=1. p[1]=max(a[1][j])=1.
        // In both cases, p becomes {1,1}.
        // The logic for max_val_in_row works for all p_i < n.
        // If p_i = n, then max_val_in_row will be n-1.
        // So if we don't find n-1 in the computed p, it means that the true n
        // was not assigned to any p_i. This can only happen if n-1 is not present
        // in the permutation, which is impossible.
        // The only way max_val_in_row for p_i=n is not n-1 is if n=1 (not allowed)
        // or if the permutation doesn't contain n-1.
        // The problem guarantees a solution exists.
        // The only case where max_val_in_row for p_i=n is not n-1 is if n=2.
        // If n=2, p={1,2}. p[0]=1, p[1]=2.
        // a[0][1]=min(p[0],p[1])=min(1,2)=1.
        // a[1][0]=min(p[1],p[0])=min(2,1)=1.
        // Calculated p[0] = max(a[0][j] for j!=0) = a[0][1] = 1.
        // Calculated p[1] = max(a[1][j] for j!=1) = a[1][0] = 1.
        // So p becomes {1,1}. Neither is n-1=1.
        // In this specific case, we need to change one of the 1s to 2.
        // Since the problem guarantees a solution, and we know one element must be n,
        // we can just find any element that is not n and increment it.
        // Or, more robustly, find the maximum value in the current p, and if it's n-1,
        // increment it.
        // The logic is: if the true permutation contains n, then for the index k where p[k]=n,
        // the computed p[k] will be max(p_j for j!=k) which is n-1.
        // So, there must be at least one element in the computed p that is n-1.
        // If there isn't, it means the max value in the permutation is not n-1.
        // This implies that the max value in the permutation is n, and it was assigned to some p[k],
        // and max(p_j for j!=k) was less than n-1. This can only happen if n=2.
        // For n=2, p={1,2}. max_val_in_row for p_i=2 is 1.
        // So if n=2, and p={1,1} is computed, we need to change one to 2.
        // For n > 2, if p_i = n, then max_val_in_row for p_i is n-1.
        // So for n > 2, there will always be an n-1 in the computed p.
        // Thus, the `found_n_minus_1` check is only relevant for n=2.
        // If n=2 and p={1,1} is computed, we change one to 2.
        // For n > 2, if `found_n_minus_1` is false, it means something is wrong with my logic.
        // Let's re-evaluate.
        // If p_k = n, then for all j != k, a[k][j] = min(n, p_j) = p_j.
        // So, the computed p[k] = max_{j!=k} a[k][j] = max_{j!=k} p_j.
        // Since p is a permutation of 1..n, the maximum value among p_j for j!=k is n-1.
        // So, the computed p[k] will be n-1.
        // This means that if n > 1, there will always be at least one element in the computed `p` that is `n-1`.
        // Therefore, `found_n_minus_1` will always be true for n > 1.
        // The only exception is if n=2, and the permutation is {1,2}.
        // p[0]=1, p[1]=2.
        // a[0][1]=1, a[1][0]=1.
        // Computed p[0]=1, computed p[1]=1.
        // In this case, `found_n_minus_1` (which is `found_1`) is true.
        // So the `if (!found_n_minus_1)` block is never reached.
        // The logic should be: if the maximum value in the computed `p` is `n-1`,
        // then one of the elements that is `n-1` should actually be `n`.
        // This is because the true `n` would have been reduced to `n-1` by the `max_val_in_row` operation.
        // All other elements `p_i < n` would have `max_val_in_row` also less than `n-1`.
        // So, we find the maximum value in the computed `p`. If it's `n-1`, we change one instance of it to `n`.
        int current_max_in_p = 0;
        for (int val : p) {
            if (val > current_max_in_p) {
                current_max_in_p = val;
            }
        }

        if (current_max_in_p == n - 1) {
            for (int i = 0; i < n; ++i) {
                if (p[i] == n - 1) {
                    p[i] = n;
                    break;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

