#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For i from 1 to n-1 (corresponding to q_2 to q_n)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            if (used_values.count(q[i])) {
                // q_i is already used, impossible
                possible = false;
                break;
            }
            p[i] = q[i];
            used_values.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some value x <= q_{i-1}
            // and x must not have been used yet.
            // To maximize chances of finding a solution, we should pick the smallest available x.
            // The smallest available x must be greater than 0.
            // We need to find the smallest positive integer not in used_values.
            // This will be filled later.
            p[i] = 0; // Placeholder for values to be filled
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet
    std::vector<int> available_nums;
    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            available_nums.push_back(i);
        }
    }
    std::sort(available_nums.rbegin(), available_nums.rend()); // Sort in descending order

    // Fill in the placeholders (p_i = 0)
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) { // This is a placeholder
            if (available_nums.empty()) {
                possible = false; // Not enough numbers to fill
                break;
            }
            int val_to_fill = available_nums.back();
            available_nums.pop_back();

            // Check if the chosen value is valid: val_to_fill <= q_i
            if (val_to_fill > q[i]) {
                possible = false;
                break;
            }
            p[i] = val_to_fill;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            // If we still need open brackets and adding it won't exceed k/2
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we still need close brackets and adding it won't make balance negative
            // and we still have open brackets to match
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

