    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we use to generate k distinct differences (1 to k)

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (small)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (large)
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining elements in increasing order
    // These elements will be from `left` to `n` (inclusive)
    // The last element used in the alternating sequence was either `left-1` or `right+1`.
    // The next available number is `left`.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This is equivalent to `left++` if `left` was correctly tracked.
                      // The numbers used for the first k+1 elements are 1, 2, ..., k+1.
                      // So the remaining numbers are k+2, k+3, ..., n.
                      // We can just fill them in order.
    }

    // A more robust way to fill the remaining elements:
    // The numbers used in the first loop are 1, 2, ..., k+1.
    // The `left` pointer will be `(k+1)/2 + 1` if `k` is even, or `(k+1)/2 + 1` if `k` is odd.
    // The `right` pointer will be `k+1 - (k+1)/2` if `k` is even, or `k+1 - (k+1)/2` if `k` is odd.
    // In essence, `left` will point to the smallest unused number from the range `1` to `k+1`.
    // After the first loop, `left` will be `(k+1)/2 + 1` and `right` will be `k+1 - (k+1)/2`.
    // The numbers used are `1, ..., k+1`.
    // The next available number is `k+2`.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }


    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

