    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // Pointer for the rightmost point x_k

    for (int i = 0; i < n; ++i) {
        // For each x_i, find the rightmost x_k such that x_k - x_i <= d
        // Since x is sorted, we can advance right_ptr.
        // right_ptr should always be at least i.
        right_ptr = std::max(right_ptr, i); 
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // After the loop, right_ptr points to the first element x_k such that x_k - x_i > d,
        // or right_ptr == n if all remaining elements satisfy the condition.
        // The valid indices for x_k are from i+1 to right_ptr-1.
        // The number of such points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.

        long long num_valid_k = right_ptr - 1 - i;

        // We need to choose 2 points (x_j, x_k) from these num_valid_k points.
        // The number of ways to choose 2 points from num_valid_k points is C(num_valid_k, 2).
        // C(N, 2) = N * (N - 1) / 2.
        if (num_valid_k >= 2) {
            count += num_valid_k * (num_valid_k - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

