    //   If B is odd, the final product is negative.
    //   But all toys are in (-1,0) or (0,1). Their product will always be in (-1,0) or (0,1).
    //   So, if A+D == 0, Box 1 is impossible.
    //   Therefore, for Box 1 to be possible, (A+B) must be odd AND (A+D > 0).
    if ((a + b) % 2 != 0 && (a + d > 0)) {
        result[0] = "Ya";
    }

    // Case 2: Final toy in Box 2 (fun value in (-1, 0))
    // This requires an odd number of negative factors overall.
    // And the final magnitude must be < 1.
    // If (A+B) is odd, the final sign is negative.
    // To get magnitude < 1:
    //   This is always possible if there are enough toys from Box 2 or Box 3.
    //   For example, if we have a toy with value -0.5, it's in Box 2.
    //   If we have a toy with value -2 and another with 0.1, product is -0.2 (Box 2).
    //   If we have a toy with value 2 and another with -0.1, product is -0.2 (Box 2).
    //   The only way it's impossible to get magnitude < 1 is if all toys have magnitude >= 1,
    //   and there's only one such toy (A+D=1, B=C=0).
    //   If A+D=1 and B=C=0, then the single toy is either in Box 1 or Box 4.
    //   If it's in Box 1, it's <= -1. If it's in Box 4, it's >= 1. Neither is in Box 2.
    //   So, if total_toys == 1, and that toy is in Box 1 or Box 4, Box 2 is impossible.
    //   Otherwise, if (A+B) is odd, Box 2 is possible.
    if ((a + b) % 2 != 0) {
        if (total_toys == 1) {
            if (b == 1) { // The single toy is in Box 2
                result[1] = "Ya";
            }
        } else { // total_toys > 1
            result[1] = "Ya";
        }
    }

    // Case 3: Final toy in Box 3 (fun value in (0, 1))
    // This requires an even number of negative factors overall.
    // And the final magnitude must be < 1.
    // If (A+B) is even, the final sign is positive.
    // To get magnitude < 1:
    //   Similar to Box 2, this is always possible if there are enough toys from Box 2 or Box 3.
    //   The only way it's impossible to get magnitude < 1 is if all toys have magnitude >= 1,
    //   and there's only one such toy (A+D=1, B=C=0).
    //   If A+D=1 and B=C=0, then the single toy is either in Box 1 or Box 4.
    //   If it's in Box 1, it's <= -1. If it's in Box 4, it's >= 1. Neither is in Box 3.
    //   So, if total_toys == 1, and that toy is in Box 1 or Box 4, Box 3 is impossible.
    //   Otherwise, if (A+B) is even, Box 3 is possible.
    if ((a + b) % 2 == 0) {
        if (total_toys == 1) {
            if (c == 1) { // The single toy is in Box 3
                result[2] = "Ya";
            }
        } else { // total_toys > 1
            result[2] = "Ya";
        }
    }

    // Case 4: Final toy in Box 4 (fun value >= 1)
    // This requires an even number of negative factors overall.
    // And the final magnitude must be >= 1.
    // If (A+B) is even, the final sign is positive.
    // To get magnitude >= 1:
    //   This is possible if there's at least one toy from Box 1 or Box 4.
    //   If (A+B) is even, and (A+D) > 0, then Box 4 is possible.
    //   What if A+D == 0? Then A=0, D=0. All toys are from B and C.
    //   If A+D == 0, then A=0, D=0. All toys are from B and C.
    //   If B is even, the final product is positive.
    //   But all toys are in (-1,0) or (0,1). Their product will always be in (-1,0) or (0,1).
    //   So, if A+D == 0, Box 4 is impossible.
    //   Therefore, for Box 4 to be possible, (A+B) must be even AND (A+D > 0).
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        result[3] = "Ya";
    }

    // Special handling for total_toys == 1
    if (total_toys == 1) {
        if (a == 1) {
            result[0] = "Ya";
            result[1] = "Tidak";
            result[2] = "Tidak";
            result[3] = "Tidak";
        } else if (b == 1) {
            result[0] = "Tidak";
            result[1] = "Ya";
            result[2] = "Tidak";
            result[3] = "Tidak";
        } else if (c == 1) {
            result[0] = "Tidak";
            result[1] = "Tidak";
            result[2] = "Ya";
            result[3] = "Tidak";
        } else if (d == 1) {
            result[0] = "Tidak";
            result[1] = "Tidak";
            result[2] = "Tidak";
            result[3] = "Ya";
        }
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
}

