#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1;
            } else {
                // Check if N is a power of 2
                // A number is a power of 2 if (n & (n - 1)) == 0
                // and n > 0. Since n is even, n > 0 is guaranteed.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }
        // Opponent's turn (implicitly handled by reducing N)
        // The problem asks for Chanek's coins, assuming optimal play.
        // The logic above determines Chanek's optimal move and the resulting N.
        // The opponent will also play optimally to maximize their own coins.
        // However, since we are only calculating Chanek's coins, we just need to
        // simulate Chanek's optimal choices. The opponent's choices don't directly
        // add to Chanek's sum, but they affect the remaining N for Chanek's next turn.
        // The strategy derived (take 1 for odd, take N/2 for even non-power-of-2,
        // take 1 for power-of-2) implicitly accounts for the opponent's optimal play
        // by ensuring Chanek maximizes his gain at each step given the current N.
    }
    return chanek_coins;
}

