    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (len > arr.size()) return false; // Cannot form a permutation of length > available elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] <= 0 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        int max_val_a = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] > max_val_a) {
                max_val_a = a[i];
            }
        }

        std::vector<int> prefix_max(n);
        prefix_max[0] = a[0];
        for (int i = 1; i < n; ++i) {
            prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
        }

        std::vector<int> suffix_max(n);
        suffix_max[n - 1] = a[n - 1];
        for (int i = n - 2; i >= 0; --i) {
            suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
        }

        std::vector<bool> is_prefix_perm(n + 1, false);
        std::vector<bool> seen_prefix(n + 1, false);
        int current_max_prefix = 0;
        bool possible_prefix = true;
        for (int i = 0; i < n; ++i) {
            if (a[i] <= 0 || a[i] > n || seen_prefix[a[i]]) {
                possible_prefix = false;
                break;
            }
            seen_prefix[a[i]] = true;
            if (a[i] > current_max_prefix) {
                current_max_prefix = a[i];
            }
            if (possible_prefix && current_max_prefix == (i + 1)) {
                is_prefix_perm[i + 1] = true;
            } else {
                possible_prefix = false; // If it's not a permutation up to this point, it won't be for longer prefixes either
            }
        }

        std::vector<bool> is_suffix_perm(n + 1, false);
        std::vector<bool> seen_suffix(n + 1, false);
        int current_max_suffix = 0;
        bool possible_suffix = true;
        for (int i = n - 1; i >= 0; --i) {
            int len = n - i;
            if (a[i] <= 0 || a[i] > n || seen_suffix[a[i]]) {
                possible_suffix = false;
                break;
            }
            seen_suffix[a[i]] = true;
            if (a[i] > current_max_suffix) {
                current_max_suffix = a[i];
            }
            if (possible_suffix && current_max_suffix == len) {
                is_suffix_perm[len] = true;
            } else {
                possible_suffix = false; // If it's not a permutation up to this point, it won't be for longer suffixes either
            }
        }

        std::vector<std::pair<int, int>> results;

        // Case 1: l1 = max_val_a
        // If the first max_val_a elements form a permutation of length max_val_a
        // AND the remaining n - max_val_a elements form a permutation of length n - max_val_a
        if (max_val_a > 0 && max_val_a < n) { // l1 must be < n, l2 must be > 0
            if (is_prefix_perm[max_val_a] && is_suffix_perm[n - max_val_a]) {
                results.push_back({max_val_a, n - max_val_a});
            }
        }

        // Case 2: l2 = max_val_a
        // If the first n - max_val_a elements form a permutation of length n - max_val_a
        // AND the remaining max_val_a elements form a permutation of length max_val_a
        // This is distinct from Case 1 if max_val_a != n - max_val_a
        if (max_val_a > 0 && max_val_a < n) { // l2 must be < n, l1 must be > 0
            if (is_prefix_perm[n - max_val_a] && is_suffix_perm[max_val_a]) {
                if (max_val_a != n - max_val_a) { // Avoid duplicate if l1 = l2
                    results.push_back({n - max_val_a, max_val_a});
                }
            }
        }

        std::sort(results.begin(), results.end());

        std::cout << results.size() << "\n";
        for (const auto& p : results) {
            std::cout << p.first << " " << p.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins++;
                if (i > 0 && s[i-1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (wins == 0) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << std::min(k, n) * 2 - 1 << "\n";
            }
            continue;
        }

        // Strategy:
        // 1. Change 'L's to 'W's to connect existing 'W' blocks. This gives +2 points per 'L' changed.
        // 2. Change 'L's to 'W's at the ends or isolated 'L's. This gives +1 point per 'L' changed.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Collect gaps between Ws
        if (first_W != -1) { // If there's at least one W
            int current_gap = 0;
            for (int i = first_W + 1; i <= last_W; ++i) {
                if (s[i] == 'L') {
                    current_gap++;
                } else { // s[i] == 'W'
                    if (current_gap > 0) {
                        gaps.push_back(current_gap);
                    }
                    current_gap = 0;
                }
            }
        }
        std::sort(gaps.begin(), gaps.end());

        for (int gap_len : gaps) {
            if (k >= gap_len) {
                current_score += gap_len * 2 + 1; // Each L becomes W, connecting two Ws, adds 2 points. The last L connects, adding 1 more point for the new W-W pair.
                k -= gap_len;
            } else {
                current_score += k * 2; // Can only fill part of the gap, each L gives 2 points.
                k = 0;
                break;
            }
        }

        if (k > 0) {
            // Remaining k can be used to change Ls before first W or after last W, or isolated Ls.
            // Each such change adds 2 points (if it connects to an existing W) or 1 point (if it's isolated).
            // Since we've connected all internal gaps, any remaining Ls are either before first W, after last W, or isolated.
            // Changing an L to W next to an existing W gives 2 points.
            // Changing an L to W not next to an existing W gives 1 point.
            // We prioritize changing Ls next to existing Ws.
            // The number of Ls we can change to Ws to get 2 points is at most k.
            // The number of Ls we can change to Ws to get 1 point is at most k.
            // Each change increases wins by 1.
            // Each change increases score by 2 if it forms a W-W pair.
            // Each change increases score by 1 if it forms an L-W pair or is the first W.

            // The current_score already accounts for all Ws and internal gaps.
            // Any additional Ws will either extend a chain (2 points) or start a new chain (1 point).
            // Since we've filled all internal gaps, any new Ws will be at the ends of the string or isolated.
            // If we change an L to W, it adds 1 point. If it's adjacent to an existing W, it also makes that W contribute 2 points instead of 1 (if it was previously 1).
            // But the current_score calculation already considers existing Ws.
            // So, if we change an L to W, it adds 1 point for itself. If it's next to a W, it also makes that W contribute 2 instead of 1.
            // This means changing an L to W next to an existing W effectively adds 2 points.
            // Changing an L to W not next to an existing W effectively adds 1 point.
            // We can always get 2 points for each k if we have enough Ls to change.
            // The number of Ls we can change is k. Each change adds 2 points.
            // The number of Ls we can change is at most n - wins.

            // The number of Ls we can change to Ws is k.
            // Each such change adds 2 points to the score.
            // This is because we are adding Ws to the ends of existing W blocks, or creating new W blocks.
            // If we add a W next to an existing W, it gets 2 points.
            // If we add a W not next to an existing W, it gets 1 point.
            // However, if we add a W, and it's the first W in a new block, it gets 1 point.
            // If we add a W, and it's next to an existing W, it gets 2 points.
            // The logic for `wins == 0` case already handles this.
            // For `wins > 0`, we have existing Ws.
            // Any new W we add will either be adjacent to an existing W or not.
            // If it's adjacent, it gets 2 points.
            // If it's not adjacent, it gets 1 point.
            // But we can always choose to add Ws adjacent to existing Ws first.
            // So, each of the remaining k changes will add 2 points.
            // The number of Ls available to change is `n - wins - sum(gaps)`.
            // We can change at most `k` of these.
            // Each such change adds 2 points.
            current_score += std::min(k, n - wins) * 2;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This `i` is the start of the first decreasing sequence from the right.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now `i` is the first index from the right where a[i-1] < a[i] is NOT true,
    // meaning a[i-1] >= a[i].
    // Or `i` is 0 if the whole array is non-decreasing.
    // The suffix a[i...n-1] is non-decreasing.

    // If i is 0, the whole array is non-decreasing, so it's good.
    // If i > 0, then a[i-1] > a[i] (because we stopped when a[i-1] >= a[i] was true,
    // and we are looking for the first point where it's not true, which means a[i-1] < a[i]
    // is the condition for the non-decreasing suffix.
    // So, if a[i-1] < a[i] is false, it means a[i-1] >= a[i].
    // The loop stops at the first `i` from the right such that `a[i-1] < a[i]` is false.
    // This means `a[i-1] >= a[i]`.
    // The suffix `a[i...n-1]` is non-decreasing.
    // We need to find the point where the non-decreasing property from the right breaks.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n=7
    // i=6, a[5]=5, a[6]=2. a[5] >= a[6] (5 >= 2) is true. i becomes 5.
    // i=5, a[4]=4, a[5]=5. a[4] >= a[5] (4 >= 5) is false. Loop stops.
    // So i=5. The suffix a[5...6] is [5, 2]. This is not non-decreasing.
    // My logic for `i` is slightly off.

    // Let's re-evaluate `i`.
    // We want to find the longest suffix that is non-decreasing.
    // This means `a[k], a[k+1], ..., a[n-1]` where `a[j] <= a[j+1]` for `j` from `k` to `n-2`.
    // We can find the first index `k` from the right such that `a[k] > a[k+1]`.
    // If no such `k` exists, the whole array is non-decreasing.
    // Let `k_dec` be the rightmost index such that `a[k_dec] > a[k_dec+1]`.
    // The suffix `a[k_dec+1 ... n-1]` is non-decreasing.
    int k_dec = n - 2;
    while (k_dec >= 0 && a[k_dec] <= a[k_dec+1]) {
        k_dec--;
    }
    // Now `k_dec` is the rightmost index such that `a[k_dec] > a[k_dec+1]`.
    // If `k_dec` is -1, the whole array is non-decreasing.
    // The non-decreasing suffix starts at `k_dec + 1`.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // k_dec = 5, a[5]=5, a[6]=2. a[5] <= a[6] (5 <= 2) is false. k_dec remains 5.
    // k_dec = 4, a[4]=4, a[5]=5. a[4] <= a[5] (4 <= 5) is true. k_dec becomes 3.
    // k_dec = 3, a[3]=8, a[4]=4. a[3] <= a[4] (8 <= 4) is false. k_dec remains 3.
    // k_dec = 2, a[2]=3, a[3]=8. a[2] <= a[3] (3 <= 8) is true. k_dec becomes 1.
    // k_dec = 1, a[1]=3, a[2]=3. a[1] <= a[2] (3 <= 3) is true. k_dec becomes 0.
    // k_dec = 0, a[0]=4, a[1]=3. a[0] <= a[1] (4 <= 3) is false. k_dec remains 0.
    // Loop ends. k_dec = 0.
    // The non-decreasing suffix starts at `k_dec + 1 = 1`. This is `[3, 3, 8, 4, 5, 2]`. This is wrong.

    // Let's restart the logic for finding the "peak".
    // A good array can be visualized as a "mountain" shape (or "valley" if inverted).
    // It must be non-decreasing up to some point, then non-increasing.
    // Or, more accurately, it's a sequence of elements that can be picked from ends to form a non-decreasing sequence.
    // This implies that the elements remaining in the middle must be "smaller" than elements picked from ends.
    // The crucial property is that the array must be of the form:
    // `X_1, X_2, ..., X_k, Y_1, Y_2, ..., Y_m, Z_p, ..., Z_2, Z_1`
