void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // Let S' = current_sum + b1 + b2 + ...
    // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...

    // Strategy: Append at most 2 elements.
    // Let's try to append two elements, say x and y.
    // New sum: current_sum + x + y
    // New XOR sum: current_xor_sum ^ x ^ y
    // We want: current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)

    // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let b1 = current_xor_sum
    // Let b2 = current_sum + current_xor_sum
    // This strategy is based on the observation that for any two numbers A, B, A+B = (A^B) + 2*(A&B).
    // If we want S' = 2*X', we can try to make X' such that S' = 2*X' is satisfied.
    // A common trick is to make the XOR sum equal to some value, say X_target.
    // And then make the sum equal to 2 * X_target.

    // Let's try to append two numbers, b1 and b2.
    // The new XOR sum will be X' = current_xor_sum ^ b1 ^ b2.
    // The new sum will be S' = current_sum + b1 + b2.
    // We want S' = 2 * X'.

    // A simple strategy that always works with 2 elements:
    // Let b1 = current_xor_sum.
    // After appending b1, the new XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
    // The new sum becomes current_sum + current_xor_sum.
    // Now we have:
    // Sum_intermediate = current_sum + current_xor_sum
    // Xor_intermediate = 0
    // We need to append one more element, say b2, such that:
    // (Sum_intermediate + b2) = 2 * (Xor_intermediate ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * b2
    // current_sum + current_xor_sum = 2 * b2 - b2
    // current_sum + current_xor_sum = b2
    // So, b2 = current_sum + current_xor_sum.

    // The two elements to append are:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum

    // Let's verify this:
    // New array elements: original_elements, b1, b2
    // New sum S' = current_sum + b1 + b2
    // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S' = 2 * (current_sum + current_xor_sum)

    // New XOR sum X' = current_xor_sum ^ b1 ^ b2
    // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum

    // Check condition: S' = 2 * X'
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This holds true.

    // The problem states we can append at most 3 elements. This strategy uses 2.
    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 (approx 10^9).
    // b1 = current_xor_sum is fine.
    // b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.
    // The problem statement says $0 \le b_i \le 10^{18}$, so this is fine.

    // Output the solution
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

