void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int k = 0; k <= 9; ++k) {
        std::vector<int> colors(n);
        bool possible = true;
        int last1 = -1; // Last digit colored 1
        int last2 = -1; // Last digit colored 2

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                colors[i] = 1;
                if (d[i] < last1) {
                    possible = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > k) {
                colors[i] = 2;
                if (d[i] < last2) {
                    possible = false;
                    break;
                }
                last2 = d[i];
            } else { // d[i] == k
                if (d[i] >= last2) { // Try to color 2
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Try to color 1
                    colors[i] = 1;
                    last1 = d[i];
                } else { // Cannot color either 1 or 2
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            if (last1 != -1 && last2 != -1 && last1 > last2) {
                possible = false;
            }
        }

        if (possible) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

