#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_count = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Calculate operations for this chain
        // Each chain has m_i dolls. It has m_i - 1 existing nestings.
        // To break these m_i - 1 nestings, it takes m_i - 1 "get out" operations.
        // If the chain is not part of the 1->2->...->n sequence, these are "wasted" nestings.
        // If the chain is 1->2->...->m_i, then these m_i-1 nestings are useful.
        // We need to count how many dolls are NOT part of the 1->2->...->n sequence.
        // For each doll that is not 1, and is not nested in the doll before it in the target sequence,
        // it needs to be "freed" (if nested) and then "put" into its target parent.
        // The total number of "put" operations needed for the final chain is n-1.
        // The total number of "get out" operations needed is the sum of (m_i - 1) for all chains,
        // MINUS the number of existing nestings that are part of the 1->2->...->n sequence.

        // Let's count the number of consecutive dolls starting from 1.
        // If the chain starts with 1, and continues 2, 3, ..., then these are "good" nestings.
        // We want to find the longest prefix 1, 2, ..., X that exists in the initial configuration.
        // This prefix will not require any "get out" operations for its internal structure,
        // nor any "put" operations for its internal structure.
        // The first doll in the chain is chain[0].
        // If chain[0] is 1, then we check for 2, 3, etc.
        if (chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    consecutive_count++;
                    current_expected++;
                } else {
                    // The sequence 1, 2, ..., consecutive_count is broken.
                    // All subsequent dolls in this chain, and all dolls in other chains,
                    // will need to be handled.
                    // For this chain, the remaining m - consecutive_count dolls need to be freed.
                    // And then put into their correct places.
                    // The number of "get out" operations for this chain is (m - 1) - (consecutive_count - 1)
                    // = m - consecutive_count.
                    // The number of "put" operations for this chain is m - consecutive_count.
                    // So, 2 * (m - consecutive_count) operations for the remaining part of this chain.
                    total_operations += (m - consecutive_count) * 2;
                    consecutive_count = n + 1; // Mark as "found all consecutive 1..X"
                    break;
                }
            }
        } else {
            // This chain does not start with 1.
            // All m dolls in this chain need to be freed from their current nestings,
            // and then put into their correct places.
            // m-1 "get out" operations to disassemble the chain.
            // m "put" operations to place them correctly (if they are not 1, they need a parent).
            // But we are counting operations relative to the final state.
            // Each doll needs to be "put" into its parent, unless it's doll 'n'.
            // Each existing nesting that is NOT part of the 1->2->...->n sequence needs to be undone.
            // Each doll that is not 1, and is not nested in the doll before it in the target sequence,
            // needs 1 "put" operation.
            // Each existing nesting that is not part of the target sequence needs 1 "get out" operation.

            // For any chain not starting with 1, all its m-1 internal nestings are "wrong".
            // So, m-1 "get out" operations.
            // All m dolls in this chain need to be put into their correct places.
            // This means m "put" operations.
            // Total for this chain: (m-1) + m = 2m - 1.
            total_operations += (m - 1) * 2 + 1; // (m-1) get out, (m-1) put, +1 for the last doll's put
        }
    }

    // After processing all chains, consecutive_count holds the length of the initial 1->2->...->X sequence.
    // The dolls 1, 2, ..., consecutive_count are already correctly nested.
    // The remaining dolls are from consecutive_count + 1 to n.
    // Number of dolls to be processed: n - consecutive_count.
    // Each of these dolls needs to be "put" into its parent.
    // So, n - consecutive_count "put" operations.
    // We already accounted for "get out" operations for dolls not in the 1->...->X sequence.
    // And "put" operations for dolls not in the 1->...->X sequence.
    // The total number of "put" operations needed for the final chain is n-1.
    // We have `consecutive_count - 1` "put" operations already satisfied by the initial 1->...->X sequence.
    // So, we need `(n-1) - (consecutive_count - 1)` more "put" operations.
    // This simplifies to `n - consecutive_count` "put" operations.

    // The total number of "get out" operations is:
    // (sum of (m_i - 1) for all chains) - (consecutive_count - 1)
    // This is because (consecutive_count - 1) nestings (1->2, 2->3, ..., (consecutive_count-1)->consecutive_count)
    // are already correct and don't need to be undone.
    // Let's re-evaluate the total operations.

    // Total operations = (total "get out" operations) + (total "put" operations)
    // Total "put" operations needed for the final chain 1->2->...->n is (n-1).
    // Of these, (consecutive_count - 1) are already satisfied.
    // So, remaining "put" operations needed = (n - 1) - (consecutive_count - 1) = n - consecutive_count.

    // Total "get out" operations:
    // Sum of (m_i - 1) for all chains is the total number of existing nestings.
    // Of these, (consecutive_count - 1) are correct and don't need to be undone.
    // So, total "get out" operations = (sum of (m_i - 1)) - (consecutive_count - 1).
    // The sum of (m_i - 1) over all chains is (sum of m_i) - k = n - k.
    // So, total "get out" operations = (n - k) - (consecutive_count - 1).

    // Total operations = (n - k - consecutive_count + 1) + (n - consecutive_count)
    // Total operations = 2*n - k - 2*consecutive_count + 1.

    // Let's re-check the logic with the example:
    // N=3, K=2
    // Chain 1: 2 1 2 (1->2)
    // Chain 2: 1 3 (3)
    // consecutive_count = 2 (1, 2)
    // Total ops = 2*3 - 2 - 2*2 + 1 = 6 - 2 - 4 + 1 = 1. Correct. (Put 1->2 into 3)

    // N=7, K=3
    // Chain 1: 3 1 3 7 (1->3->7)
    // Chain 2: 2 2 5 (2->5)
    // Chain 3: 2 4 6 (4->6)
    // consecutive_count = 1 (only 1 is correct, 3 is not 2)
    // Total ops = 2*7 - 3 - 2*1 + 1 = 14 - 3 - 2 + 1 = 10. Correct.

    // The formula seems to be:
    // (n - k) - (consecutive_count - 1)  // get out operations
    // + (n - consecutive_count)           // put operations
    // = n - k - consecutive_count + 1 + n - consecutive_count
    // = 2*n - k - 2*consecutive_count + 1

    // The `consecutive_count` variable correctly stores the length of the prefix 1, 2, ..., X.
    // If no chain starts with 1, then `consecutive_count` remains 0.
    // If `consecutive_count` is 0, the formula becomes 2*n - k + 1.
    // If `consecutive_count` is 1, it means only doll 1 is present, but not 1->2.
    // The formula is 2*n - k - 2 + 1 = 2*n - k - 1.
    // This is correct. If 1 is present, but not 1->2, then 1 is not nested in 2.
    // We need to put 1 into 2. This is 1 "put" operation.
    // The formula correctly handles the `consecutive_count` being 0 or 1.
    // If `consecutive_count` is 0, it means doll 1 is not the first doll in any chain, or not present.
    // In this case, we need to put 1 into 2.
    // The formula `2*n - k - 2*consecutive_count + 1` works for `consecutive_count >= 0`.

    std::cout << 2LL * n - k - 2LL * consecutive_count + 1 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each remainder i % k

    // Step 1: Propagate constraints within each congruence class
    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int remainder = i % k;

        if (current_char != '?') {
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = current_char;
            } else if (fixed_chars[remainder] != current_char) {
                // Conflict: s[i] and s[j] are in the same congruence class (i % k == j % k)
                // but s[i] != s[j]. This is impossible.
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count 0s, 1s, and ?s in the first k characters based on fixed_chars
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else { // fixed_chars[i] == '?'
            count_q++;
        }
    }

    // Step 3: Check if it's possible to fill '?'s to satisfy k/2 balance
    int target_half = k / 2;

    if (count0 > target_half || count1 > target_half) {
        // Already too many 0s or 1s
        std::cout << "NO\n";
        return;
    }

    // We need to fill (target_half - count0) zeros and (target_half - count1) ones
    // using the available '?'s.
    int needed_zeros = target_half - count0;
    int needed_ones = target_half - count1;

    if (needed_zeros + needed_ones == count_q) {
        // It's possible to fill the '?'s to achieve k/2 balance in the first k characters.
        // Since fixed_chars[i] == fixed_chars[i+k] for all i, this balance will hold for all k-length substrings.
        std::cout << "YES\n";
    } else {
        // Not enough '?'s or too many '?'s to satisfy the balance.
        std::cout << "NO\n";
    }
}

