        }

        // f3 = 0: cannot move right (x_c + 1).
        // This means the target X must be <= current x.
        // So, X <= x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // f4 = 0: cannot move down (y_c - 1).
        // This means the target Y must be >= current y.
        // So, Y >= y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // The problem guarantees that if a solution exists,
        // there's one with coordinates not exceeding 10^5 by absolute value.
        // We can pick any valid point, e.g., (min_x, min_y).
        // We need to clamp min_x and min_y to the guaranteed range if they exceed it,
        // but since the problem guarantees a solution within [-10^5, 10^5]
        // if one exists, and our bounds are derived from robot positions
        // which are within [-10^5, 10^5], min_x and min_y will naturally
        // fall within a reasonable range if a solution exists.
        // The problem statement implies that if min_x, max_x, min_y, max_y
        // define a valid range, then min_x and min_y will be within [-10^5, 10^5]
        // if a solution exists.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
