int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val = (b - 1);
    sum_r_val %= MOD;
    sum_r_val = (sum_r_val * b) % MOD;

    // We need to divide by 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_kb_plus_1_val
    // sum_{k=1 to a} (k * b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a + 1) / 2) + a

    long long sum_k_val = a;
    sum_k_val %= MOD;
    sum_k_val = (sum_k_val * (a + 1)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long sum_kb_plus_1_val = (b % MOD * sum_k_val) % MOD;
    sum_kb_plus_1_val = (sum_kb_plus_1_val + a) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {height, index}

    for (int i = 0; i < n; ++i) {
        long long current_h = h[i];
        long long current_val = 0;

        while (!dq_L.empty() && dq_L.back().first >= current_h) {
            dq_L.pop_back();
        }

        if (dq_L.empty()) {
            current_val = current_h;
        } else {
            current_val = std::min(current_h, dq_L.back().first + (i - dq_L.back().second));
        }

        L[i] = current_val;
        dq_L.push_back({current_val, i});
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        long long current_h = h[i];
        long long current_val = 0;

        while (!dq_R.empty() && dq_R.back().first >= current_h) {
            dq_R.pop_back();
        }

        if (dq_R.empty()) {
            current_val = current_h;
        } else {
            current_val = std::min(current_h, dq_R.back().first + (dq_R.back().second - i));
        }

        R[i] = current_val;
        dq_R.push_back({current_val, i});
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

