int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i] in this segment, we want to add b_i such that (a[i] + b_i) % n == 0.
    // b_i must be a multiple of (n-1).
    // We can choose b_i = (n - (a[i] % n + n) % n) % n * (n-1).
    // This makes a[i] + b_i a multiple of n.
    // But we need a[i] + b_i to be a multiple of (n-1) as well.
    // This is not the strategy.

    // Strategy:
    // 1. For elements a[0] to a[n-2]:
    //    Select segment [1, n-1]. Length is n-1.
    //    For each a[i] (0 <= i <= n-2), we want to add b_i such that a[i] + b_i becomes a multiple of n.
    //    And b_i must be a multiple of (n-1).
    //    Let current_a_i = a[i].
    //    We need (current_a_i + b_i) % n == 0.
    //    We also need b_i % (n-1) == 0.
    //    Let b_i = k * (n-1).
    //    Then (current_a_i + k * (n-1)) % n == 0.
    //    (current_a_i + k * (-1)) % n == 0 (since (n-1) % n == -1 % n)
    //    (current_a_i - k) % n == 0
    //    So k % n == current_a_i % n.
    //    We can choose k = (current_a_i % n + n) % n.
    //    Then b_i = ((current_a_i % n + n) % n) * (n-1).
    //    After this operation, a[i] becomes a[i] + b_i, which is a multiple of n.
    //    And a[i] + b_i is also a multiple of (n-1) because b_i is a multiple of (n-1) and a[i] + b_i = a[i] + k*(n-1).
    //    No, this is not correct. a[i] + b_i is a multiple of n.
    //    The goal is to make a[i] a multiple of n.
    //    Let's make a[i] a multiple of n for i from 0 to n-2.
    //    Segment [1, n-1] (0-indexed: [0, n-2]). Length is n-1.
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n;
        long long add_val = remainder * (n - 1); // This makes a[i] + add_val a multiple of n.
                                                  // And add_val is a multiple of (n-1).
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // 2. For the last element a[n-1]:
    //    Select segment [n, n]. Length is 1.
    //    We want to make a[n-1] a multiple of n.
    //    Add b_{n-1} such that (a[n-1] + b_{n-1}) % n == 0.
    //    b_{n-1} must be a multiple of 1. This is always true.
    //    Let current_a_n_minus_1 = a[n-1].
    //    We need (current_a_n_minus_1 + b_{n-1}) % n == 0.
    //    We can choose b_{n-1} = (n - (current_a_n_minus_1 % n + n) % n) % n.
    //    This makes a[n-1] + b_{n-1} a multiple of n.
    std::cout << n << " " << n << "\n";
    long long remainder_last = (a[n - 1] % n + n) % n;
    long long add_val_last = remainder_last; // This makes a[n-1] + add_val_last a multiple of n.
    std::cout << add_val_last << "\n";
    a[n - 1] += add_val_last;

    // After these two operations, all a[i] are multiples of n.
    // Now, for the third operation, select segment [1, n]. Length is n.
    // For each a[i], we want to add b_i such that a[i] + b_i = 0.
    // b_i must be a multiple of n.
    // Since a[i] is already a multiple of n, we can choose b_i = -a[i].
    // -a[i] will also be a multiple of n.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

