}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_sum_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_left[i + 1] = prefix_sum_left[i] + (a[i] == 1 ? 1 : -1);
    }

    std::vector<int> prefix_sum_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_right[i + 1] = prefix_sum_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    std::map<int, int> right_balance_to_k_map;
    for (int k = 0; k <= n; ++k) {
        int balance = prefix_sum_right[k];
        if (right_balance_to_k_map.find(balance) == right_balance_to_k_map.end()) {
            right_balance_to_k_map[balance] = k;
        }
    }

    int min_removed = 2 * n;

    for (int i = 0; i <= n; ++i) {
        int current_left_balance = prefix_sum_left[i];
        int target_right_balance = -current_left_balance;

        if (right_balance_to_k_map.count(target_right_balance)) {
            int k_right = right_balance_to_k_map[target_right_balance];
            min_removed = std::min(min_removed, i + k_right);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

