long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
    // This means we want to break up the '0's into as many small blocks as possible.
    // The 'm' ones divide the 'n-m' zeros into 'm+1' potential blocks.
    // To minimize the sum of k*(k+1)/2 for these blocks, we should make the block lengths as equal as possible.

    long long num_zeros = n - m;

    // If m+1 > num_zeros, it means we have more 'slots' for zeros than zeros themselves.
    // In this case, we can place each zero in its own block (separated by ones),
    // or effectively, we can make some blocks of zeros of length 1 and others of length 0.
    // The minimum number of zero-only substrings is achieved when all zero blocks have length 0 or 1.
    // Each block of length 1 contributes 1 zero-only substring.
    // So, if num_zeros <= m+1, the minimum number of zero-only substrings is num_zeros.
    // This happens when we distribute the 'num_zeros' into 'num_zeros' blocks of length 1,
    // and 'm+1 - num_zeros' blocks of length 0.
    // Example: n=5, m=2. num_zeros = 3. m+1 = 3.
    // We need 3 blocks of zeros. 3/3 = 1. All blocks are length 1.
    // String "01010". Blocks: 0, 0, 0.
    // Number of zero-only substrings = 1+1+1 = 3.
    // This is equivalent to num_zeros * (1 * (1+1) / 2) = num_zeros * 1 = num_zeros.

    // If m+1 <= num_zeros, we have more zeros than slots.
    // We distribute num_zeros among m+1 blocks.
    // Let k be the average number of zeros per block: k = num_zeros / (m+1).
    // There will be (m+1) - (num_zeros % (m+1)) blocks of length k.
    // There will be (num_zeros % (m+1)) blocks of length k+1.

    long long k = num_zeros / (m + 1);
    long long remainder = num_zeros % (m + 1);

    long long num_blocks_k_plus_1 = remainder;
    long long num_blocks_k = (m + 1) - remainder;

    long long zero_substrings_k = k * (k + 1) / 2;
    long long zero_substrings_k_plus_1 = (k + 1) * (k + 2) / 2;

    long long min_zero_substrings = num_blocks_k * zero_substrings_k +
                                    num_blocks_k_plus_1 * zero_substrings_k_plus_1;

    return total_substrings - min_zero_substrings;
}

