        // for i in {1,2}:
        //   for j in {1,2}:
        //     dist[i][j] = min(dist[i][j], dist[i][1] + dist[1][j])
        // This updates:
        // dist[2][1] = min(dist[2][1], dist[2][1] + dist[1][1]) -> no change
        // dist[1][2] = min(dist[1][2], dist[1][1] + dist[1][2]) -> no change
        // dist[2][2] = min(dist[2][2], dist[2][1] + dist[1][2])
