        // Now we want to include `k` as an intermediate.
        //
        // The correct update is:
        // for (int i = 0; i < n; ++i) { // i is an active vertex
        //     if (!active[i]) continue;
        //     for (int j = 0; j < n; ++j) { // j is an active vertex
