#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_line.push_back({i + 1, v_val, d_val, p_val});
    }

    std::vector<int> cured_children_ids;

    while (!children_line.empty()) {
        Child current_child = children_line.front();
        children_line.pop_front();
        cured_children_ids.push_back(current_child.id);

        long long doctor_cry_volume = current_child.v;
        long long chain_reaction_cry_volume = 0;

        auto it = children_line.begin();
        while (it != children_line.end()) {
            if (doctor_cry_volume > 0) {
                it->p -= doctor_cry_volume;
                doctor_cry_volume--;
            }

            it->p -= chain_reaction_cry_volume;

            if (it->p < 0) {
                chain_reaction_cry_volume += it->d;
                it = children_line.erase(it);
            } else {
                ++it;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // Process operations in reverse to find upper bounds for b[i]
    // b[i] represents a_0[i] + sum_of_d_affecting_i_after_this_op
    // So, b[i] is the maximum possible value for a_0[i] + current_sum_of_d_affecting_i
    // at the time of a type 2 query.
    // We want to find a_0[i] such that a_0[i] + current_sum_of_d_affecting_i <= m
    // which means a_0[i] <= m - current_sum_of_d_affecting_i.
    // Let current_sum_of_d_affecting_i be `delta[i]`.
    // Then a_0[i] <= m - delta[i].
    // We are looking for the maximum possible a_0[i] that satisfies all constraints.
    // So, a_0[i] = min(m - delta[i]) over all type 2 queries affecting i.
    // Initialize b[i] to a very large value.
    // When we process a type 2 query (2, l, r, m_val), it means for all j in [l, r],
    // a_0[j] + delta[j] <= m_val.
    // So, a_0[j] <= m_val - delta[j].
    // We update b[j] = min(b[j], m_val - delta[j]).
    // When we process a type 1 query (1, l, r, d_val), it means delta[j] changes.
    // Since we are processing in reverse, this means delta[j] *before* this operation
    // was delta[j] - d_val.
    // So, we need to update delta[j] by subtracting d_val for j in [l, r].

    std::vector<long long> delta(n, 0); // delta[i] stores sum of d for a_0[i]
                                        // for operations *after* the current one being processed (in reverse)

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta[j] -= ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - delta[j]);
            }
        }
    }

    // Initialize a_0 with values from b.
    // If b[i] is still std::numeric_limits<long long>::max(), it means a_0[i] was never constrained by a type 2 query.
    // In this case, we can set a_0[i] to 0 (or any value within [-10^9, 10^9]).
    // The problem statement says |a_i| <= 10^9.
    // The initial values a_0[i] must be within [-10^9, 10^9].
    // If b[i] is still max, it means a_0[i] can be anything. Let's pick 0.
    // If b[i] is constrained, it means a_0[i] <= b[i].
    // To maximize the chance of satisfying max constraints, we should pick a_0[i] = b[i].
    // However, we also need |a_0[i]| <= 10^9.
    // So, a_0[i] = std::min(b[i], 1000000000LL).
    // And a_0[i] = std::max(a_0[i], -1000000000LL).
    // Let's just set a_0[i] = b[i] if b[i] is not max, otherwise 0.
    // Then check if it's within bounds.
    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == std::numeric_limits<long long>::max()) {
            a0[i] = 0;
        } else {
            a0[i] = b[i];
        }
        // Ensure a0[i] is within [-10^9, 10^9]
        // If b[i] is already outside this range, it's a problem.
        // But the problem states m_i is within [-5e7, 5e7] and d_i is within [-1e4, 1e4].
        // The number of operations is up to 5000.
        // So delta[j] can be up to 5000 * 1e4 = 5e7.
        // m_val - delta[j] can be 5e7 - (-5e7) = 1e8 or -5e7 - 5e7 = -1e8.
        // So b[j] will be within [-1e8, 1e8], which is within [-1e9, 1e9].
        // So no explicit clamping for a0[i] is needed here.
    }

    // Verify the constructed a0
    std::vector<long long> current_a = a0;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

