    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long min_goodness = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> best_partition(n, 1);

    // Case 2: At least one element in each subsequence.
    // The minimum possible sum is a[0] + a[1].
    // The maximum possible sum is a[n-2] + a[n-1] + h (if a[n-2] and a[n-1] are in different groups)
    // or a[n-2] + a[n-1] (if they are in the same group).
    //
    // Consider the partition where a[0] is in group 1, and all other elements are in group 2.
    // min_f:
    //   - a[0] + a[1] + h (a[0] in group 1, a[1] in group 2)
    //   - a[1] + a[2] (a[1], a[2] in group 2)
    //   So, min_f = min(a[0] + a[1] + h, a[1] + a[2])
    // max_f:
    //   - a[0] + a[n-1] + h (a[0] in group 1, a[n-1] in group 2)
    //   - a[n-2] + a[n-1] (a[n-2], a[n-1] in group 2)
    //   So, max_f = max(a[0] + a[n-1] + h, a[n-2] + a[n-1])
    //
    // Goodness for this partition: max_f - min_f
    //
    // Let's analyze the values:
    // min_same = a[1].value + a[2].value
    // max_same = a[n-2].value + a[n-1].value
    // min_diff = a[0].value + a[1].value + h
    // max_diff = a[0].value + a[n-1].value + h
    //
    // Overall min_f = std::min(min_same, min_diff)
    // Overall max_f = std::max(max_same, max_diff)
    //
    // This specific partition (a[0] in group 1, rest in group 2) is interesting because it minimizes
    // the `min_f` value by potentially having `a[1]+a[2]` as the minimum, and `a[0]+a[1]+h` as another candidate.
    // It also minimizes `max_f` by having `a[n-2]+a[n-1]` as a candidate, and `a[0]+a[n-1]+h` as another.
    //
    // The key observation is that `a[0] + a[n-1] + h` is always greater than or equal to `a[n-2] + a[n-1]`
    // if `h` is large enough, or if `a[0]` is not much smaller than `a[n-2]`.
    //
    // The minimum possible sum is `a[0] + a[1]`.
    // The maximum possible sum is `a[n-1] + a[n-2]`.
    //
    // If we put `a[0]` in group 1 and `a[1]` in group 2, then `a[0]+a[1]+h` is a value.
    // If we put `a[0]` in group 1 and `a[n-1]` in group 2, then `a[0]+a[n-1]+h` is a value.
    // If we put `a[n-2]` in group 2 and `a[n-1]` in group 2, then `a[n-2]+a[n-1]` is a value.
    //
    // Consider the partition where `a[0]` is in group 1, and all other `n-1` elements are in group 2.
    // The values of f are:
    //   - `a[0] + a[j] + h` for `j = 1, ..., n-1` (one from group 1, one from group 2)
    //   - `a[i] + a[j]` for `i, j = 1, ..., n-1, i != j` (both from group 2)
    //
    // Min f: `min(a[0] + a[1] + h, a[1] + a[2])`
    // Max f: `max(a[0] + a[n-1] + h, a[n-2] + a[n-1])`
    //
    // Goodness = `max(a[0] + a[n-1] + h, a[n-2] + a[n-1]) - min(a[0] + a[1] + h, a[1] + a[2])`
    //
    // Let's calculate this goodness.
    long long current_min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    long long current_max_f = std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // Consider the partition where `a[n-1]` is in group 1, and all other `n-1` elements are in group 2.
    // This is symmetric to the previous case, but the values are different.
    // Min f: `min(a[0] + a[1], a[0] + a[n-1] + h)`
    // Max f: `max(a[n-2] + a[n-1] + h, a[n-2] + a[n-1])`
    //
    // Goodness = `max(a[n-2] + a[n-1] + h, a[n-2] + a[n-1]) - min(a[0] + a[1], a[0] + a[n-1] + h)`
    //
    // This simplifies to:
    // Max f = a[n-2] + a[n-1] + h (since h >= 0)
    // Min f = min(a[0] + a[1], a[0] + a[n-1] + h)
    //
    // Goodness = (a[n-2].value + a[n-1].value + h) - std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);
    //
    // This is the same as the previous case if we swap the roles of a[0] and a[n-1] and consider the other elements.
    // The previous case was: a[0] in group 1, rest in group 2.
    // The current case is: a[n-1] in group 1, rest in group 2.
    //
    // Let's re-evaluate the second case more generally.
    // We have two groups.
    // Let `min_A = a[0].value`, `max_A = a[n-1].value`.
    // Let `min_B = a[1].value`, `max_B = a[n-2].value`.
    //
    // The minimum possible sum of two elements is `a[0] + a[1]`.
    // The maximum possible sum of two elements is `a[n-2] + a[n-1]`.
    //
    // If we have at least one element in each group:
    // The minimum `f` value will be `min(a[0]+a[1], a[0]+a[1]+h)`. This is `a[0]+a[1]`.
    // The maximum `f` value will be `max(a[n-2]+a[n-1], a[n-2]+a[n-1]+h)`. This is `a[n-2]+a[n-1]+h`.
    //
    // So, if both groups are non-empty, the goodness is at least `(a[n-2]+a[n-1]+h) - (a[0]+a[1])`.
    // This is achieved if `a[0]` and `a[1]` are in the same group, and `a[n-2]` and `a[n-1]` are in different groups.
    // Or if `a[0]` and `a[1]` are in different groups, and `a[n-2]` and `a[n-1]` are in the same group.
    //
    // Let's consider the partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    // min_f = min(a[0]+a[1]+h, a[1]+a[2])
    // max_f = max(a[0]+a[n-1]+h, a[n-2]+a[n-1])
    //
    // Let's consider the partition where `a[n-1]` is in group 1, and `a[0], ..., a[n-2]` are in group 2.
    // min_f = min(a[0]+a[1], a[0]+a[n-1]+h)
    // max_f = max(a[n-2]+a[n-1]+h, a[n-2]+a[n-1])
    //
    // The second case is:
    // `a[0]` in group 1, `a[1], ..., a[n-1]` in group 2.
    // `min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value)`
    // `max_f = max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)`
    // `goodness = max_f - min_f`
    //
    // This is the `current_goodness` calculated above.
    //
    // The other "extreme" partition is `a[n-1]` in group 1, and `a[0], ..., a[n-2]` in group 2.
    // `min_f = min(a[0].value + a[1].value, a[0].value + a[n-1].value + h)`
    // `max_f = max(a[n-2].value + a[n-1].value + h, a[n-2].value + a[n-1].value)`
    // `max_f` simplifies to `a[n-2].value + a[n-1].value + h` because `h >= 0`.
    // `goodness = (a[n-2].value + a[n-1].value + h) - min(a[0].value + a[1].value, a[0].value + a[n-1].value + h)`
    //
    // Let's compare this with `min_goodness`.
    long long goodness_alt = (a[n-2].value + a[n-1].value + h) - std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);

    if (goodness_alt < min_goodness) {
        min_goodness = goodness_alt;
        best_partition[a[n-1].original_index] = 1;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

