        if (dp_y[i] != -2) continue;

        std::vector<int> path;
        int current_x = i;

        while (current_x >= 1 && current_x <= n && dp_y[current_x] == -2) {
            path.push_back(current_x);
            current_x += a[current_x]; // This is the x value after step 2
            if (current_x >= 1 && current_x <= n) {
                current_x -= a[current_x]; // This is the x value after step 3
            }
        }

