long long N_val, M_val;
std::vector<long long> H_val;
std::vector<long long> P_val;

bool check(long long T) {
    std::vector<long long> head_reach_left(N_val);
    std::vector<long long> head_reach_right(N_val);

    for (int i = 0; i < N_val; ++i) {
        head_reach_left[i] = H_val[i] - T;
        head_reach_right[i] = H_val[i] + T;
    }

    int p_idx = 0;
    int h_idx = 0;

    while (p_idx < M_val) {
        long long current_p = P_val[p_idx];

        // Find the first head that can potentially reach current_p
        // or is to its right and can reach back to current_p
        while (h_idx < N_val && head_reach_right[h_idx] < current_p) {
            h_idx++;
        }

        if (h_idx == N_val) {
            return false; // No head can reach current_p or any subsequent p
        }

        // If the current head h_idx cannot reach current_p from its left,
        // it means current_p is too far left for this head.
        // This should not happen if h_idx is correctly advanced.
        // The condition `head_reach_right[h_idx] < current_p` handles this.
        // If we are here, it means head_reach_right[h_idx] >= current_p.
        // We also need head_reach_left[h_idx] <= current_p.
        // If head_reach_left[h_idx] > current_p, then current_p is to the left of the head's range.
        // This means the current head cannot cover current_p.
        // Since heads are sorted, and p_i are sorted, if current_p is too far left for h_idx,
        // it will be too far left for all subsequent heads h_idx+1, ...
        // So, if head_reach_left[h_idx] > current_p, it's impossible.
        if (head_reach_left[h_idx] > current_p) {
            return false;
        }

        // This head h_idx can cover current_p.
        // Now, find how many subsequent p_j tracks this head can cover.
        long long max_covered_by_current_head = head_reach_right[h_idx];
        while (p_idx < M_val && P_val[p_idx] <= max_covered_by_current_head) {
            p_idx++;
        }
        // Move to the next head for the next iteration, as this head's full range has been utilized.
        h_idx++;
    }

    return true;
}

