    for (int i = 0; i < N_val; ++i) {
        std::cin >> H_val[i];
    }

    P_val.resize(M_val);
    for (int i = 0; i < M_val; ++i) {
        std::cin >> P_val[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max track) - 1 (min track)
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

