int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_z = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To form '1' (one): requires 'o', 'n', 'e'
    // To form '0' (zero): requires 'z', 'e', 'r', 'o'

    // We want to maximize the number, so prioritize '1's.
    // The number of '1's is limited by 'n', 'o', 'e'.
    int num_ones = std::min({count_n, count_o, count_e});

    // After forming 'num_ones' '1's, update available characters.
    count_n -= num_ones; // Not strictly necessary as 'n' is only used for 'one'
    count_o -= num_ones;
    count_e -= num_ones;

    // The remaining characters are used to form '0's.
    // The number of '0's is limited by 'z', 'e', 'r', 'o'.
    int num_zeros = std::min({count_z, count_e, count_r, count_o});

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

