    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and torches = k * y + k.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks
        // using the first trade offer.
        long long sticks_to_generate = total_sticks_required - 1;

        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of type 1 trades needed = ceil(sticks_to_generate / (x - 1)).
        // Using integer division: (A + B - 1) / B for ceil(A / B)
        long long type1_trades = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Number of type 2 trades (y sticks -> 1 coal) is exactly k.
        long long type2_trades = k;

        // Total trades = type1_trades + type2_trades
        long long total_trades = type1_trades + type2_trades;

        std::cout << total_trades << std::endl;
    }
    return 0;
}

