#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // Check the last element first
    if (a[n - 1] != b[n - 1]) {
        std::cout << "NO\n";
        return;
    }

    // Iterate from n-2 down to 0
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == b[i]) {
            // If a[i] == b[i], no operation is needed for this position.
            // We just need to ensure that if a[i] is 1 or -1, we update
            // has_one/has_minus_one for elements to its left.
            // However, has_one/has_minus_one are only relevant for elements
            // *before* the current index i. So, we don't need to update them
            // here. They are already correctly set based on elements 0 to i.
            continue;
        }

        if (a[i] < b[i]) {
            // We need to increase a[i]. This requires adding a positive value.
            // The only way to add a positive value is to add a '1' from some a_k (k < i).
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // a[i] > b[i]
            // We need to decrease a[i]. This requires adding a negative value.
            // The only way to add a negative value is to add a '-1' from some a_k (k < i).
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    std::cout << "YES\n";
}

