        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be covered by the logic above,
        // but as a safeguard, if we didn't form exactly k posts.
        // This can happen if the last post's duration doesn't match target_duration_per_post
        // or if current_post_duration is not 0 at the end.
        // However, if total_duration % k == 0 and no current_post_duration > target_duration_per_post
        // occurred, then the last post must sum up correctly.
        std::cout << "No\n";
    }

    return 0;
}

