    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is 0
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it means n is missing.
    // This happens if the original p[k] was n, then max_val_in_row_k would be n-1.
    // All other p[i] would be max(p[j] for j!=i, p[j] < p[i]) or p[i] itself.
    // If p[i] is not n, then max_val_in_row_i is either p[i] or some p[j] < p[i].
    // If p[i] is n, then max_val_in_row_i is n-1.
    // So, if n is not present in the reconstructed p, it means one of the original p[k] was n.
    // In that case, the corresponding p[k] in our reconstructed array would be n-1.
    // We need to find such an element and change it to n.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means one of the original p[k] was n,
        // and its corresponding max_val_in_row_k became n-1.
        // We need to find an element that is n-1 and change it to n.
        // Since it's guaranteed a solution exists, there must be at least one such n-1.
        // If there are multiple n-1s, any one can be changed to n.
        // The problem statement guarantees a solution, so this logic is sound.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

