#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // p_1 must be within [1, n]
        possible = false;
    } else {
        used_numbers.insert(p[0]);
    }

    for (int i = 1; i < n; ++i) {
        if (!possible) break;

        if (q[i] > q[i-1]) {
            // If q[i] is strictly greater than q[i-1], then p[i] must be q[i].
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_numbers.count(p[i])) {
                possible = false;
            } else {
                used_numbers.insert(p[i]);
            }
        } else { // q[i] == q[i-1]
            // If q[i] == q[i-1], p[i] must be some unused number x such that x < q[i].
            // To maximize chances of finding a solution, we should pick the smallest available unused number.
            // This is because larger numbers are more likely to be needed for future q_j > q_{j-1} cases.
            // However, the problem asks for *any* valid permutation.
            // A greedy strategy: pick the largest available number that is less than q[i].
            // This leaves smaller numbers for later, which might be needed if q[i] is small.
            // But wait, the numbers we need to pick are from 1 to n.
            // The numbers that are *not* in `used_numbers` are candidates.
            // We need to pick an `x` such that `x < q[i]` and `x` is not in `used_numbers`.
            // To ensure we can always find such an `x` if one exists, we should iterate downwards from `q[i]-1`.
            // Or, more simply, find the smallest available number that is not yet used.
            // Let's find the smallest number `k` such that `k` is not in `used_numbers`.
            // If `k >= q[i]`, then it's impossible to satisfy `p[i] < q[i]`.
            // Otherwise, we can assign `p[i] = k`.
            // This greedy choice (smallest available) is generally good.
            // Let's try to find the largest available number that is less than q[i].
            // This is because if we use a small number, a larger number might be needed later.
            // If we use a large number now, it might be needed later.
            // The numbers that are *not* used are candidates.
            // We need to pick `p[i]` such that `p[i] < q[i]` and `p[i]` is not used.
            // The largest possible value for `p[i]` is `q[i]-1`.
            // Let's try to find the largest unused number `x` such that `x < q[i]`.
            // This is equivalent to finding the largest `x` in `[1, q[i]-1]` that is not in `used_numbers`.
            // A `std::set` of available numbers can help.
            // Let's maintain a set of numbers from 1 to n that have not been used.
            // When `q[i] == q[i-1]`, we need to pick `p[i]` from `available_numbers` such that `p[i] < q[i]`.
            // To maximize our chances, we should pick the largest such available number.
            // This is because if we pick a small number, a larger number might be needed later for a `q_j > q_{j-1}` case.
            // If we pick a large number now, it might be needed later.
            // The largest available number less than `q[i]` is `*(--available_numbers.lower_bound(q[i]))`.
            // If `available_numbers.lower_bound(q[i])` is `available_numbers.begin()`, then no such number exists.

            // Let's use a boolean array for `used_numbers` for efficiency, as `n` can be up to 10^5.
            // Or, just iterate downwards from `q[i]-1` to find the largest unused number.
            int current_val = q[i] - 1;
            while (current_val >= 1 && used_numbers.count(current_val)) {
                current_val--;
            }
            if (current_val < 1) { // No unused number less than q[i]
                possible = false;
            } else {
                p[i] = current_val;
                used_numbers.insert(p[i]);
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

