    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horizontal_pairs = std::min(counts['L'], counts['R']);
        int vertical_pairs = std::min(counts['U'], counts['D']);

        std::string result = "";
        int length = 0;

        if (horizontal_pairs == 0 && vertical_pairs == 0) {
            // No moves possible
        } else if (horizontal_pairs == 0) { // Only vertical moves possible
            // To form a valid path, we need to go U and then D.
            // If we have vertical_pairs > 0, we can make "UD".
            // If vertical_pairs == 0, then horizontal_pairs must be 0 too, handled above.
            result = "UD";
            length = 2;
        } else if (vertical_pairs == 0) { // Only horizontal moves possible
            // To form a valid path, we need to go L and then R.
            // If we have horizontal_pairs > 0, we can make "LR".
            // If horizontal_pairs == 0, then vertical_pairs must be 0 too, handled above.
            result = "LR";
            length = 2;
        } else {
            // We have both horizontal and vertical pairs.
            // The optimal strategy is to go all U's, then all R's, then all D's, then all L's.
            // Or any permutation that forms a simple path.
            // Example: U...UR...RD...DL...L
            // The length will be 2 * horizontal_pairs + 2 * vertical_pairs.

            for (int i = 0; i < vertical_pairs; ++i) {
                result += 'U';
            }
            for (int i = 0; i < horizontal_pairs; ++i) {
                result += 'R';
            }
            for (int i = 0; i < vertical_pairs; ++i) {
                result += 'D';
            }
            for (int i = 0; i < horizontal_pairs; ++i) {
                result += 'L';
            }
            length = 2 * horizontal_pairs + 2 * vertical_pairs;
        }

        std::cout << length << "\n";
        std::cout << result << "\n";
    }
    return 0;
}

