void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we expand the segment to include m.
        // The segment must contain all numbers from 1 to m.
        // The current segment covers numbers 1 to m-1, from current_min_idx to current_max_idx.
        // To include m, we need to extend the segment to include pos[m].
        // The new segment will span from min(current_min_idx, pos[m]) to max(current_max_idx, pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the segment [current_min_idx, current_max_idx]
        // contains all numbers from 1 to m, and its length is exactly m.
        // The length of the segment is (current_max_idx - current_min_idx + 1).
        // If this length is equal to m, then it means all numbers from 1 to m are
        // present in this segment, and no other numbers (because it's a permutation
        // and the length matches the count of distinct numbers).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

