int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    bool prev_diff_01 = false; // true if a[i-1]='0', b[i-1]='1'
    bool prev_diff_10 = false; // true if a[i-1]='1', b[i-1]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0' && b[i] == '1') { // Current mismatch is 0 -> 1
                if (prev_diff_10) { // Previous mismatch was 1 -> 0
                    // We can swap a[i-1] and a[i].
                    // a[i-1] was '1', b[i-1] was '0'.
                    // a[i] was '0', b[i] was '1'.
                    // Swap makes a[i-1] become '0', a[i] become '1'.
                    // Both become correct. Cost is |(i-1) - i| = 1.
                    cost += 1;
                    prev_diff_01 = false; // Both resolved
                    prev_diff_10 = false;
                } else {
                    // Cannot resolve with previous. This 0->1 mismatch is pending.
                    prev_diff_01 = true;
                    prev_diff_10 = false; // Ensure only one type of pending mismatch is tracked
                }
            } else { // Current mismatch is 1 -> 0
                if (prev_diff_01) { // Previous mismatch was 0 -> 1
                    // We can swap a[i-1] and a[i].
                    // a[i-1] was '0', b[i-1] was '1'.
                    // a[i] was '1', b[i] was '0'.
                    // Swap makes a[i-1] become '1', a[i] become '0'.
                    // Both become correct. Cost is |(i-1) - i| = 1.
                    cost += 1;
                    prev_diff_01 = false; // Both resolved
                    prev_diff_10 = false;
                } else {
                    // Cannot resolve with previous. This 1->0 mismatch is pending.
                    prev_diff_10 = true;
                    prev_diff_01 = false; // Ensure only one type of pending mismatch is tracked
                }
            }
        } else { // a[i] == b[i]
            // If there was a pending mismatch, it must be resolved by a flip.
            if (prev_diff_01 || prev_diff_10) {
                cost += 1; // Flip the previous pending bit
            }
            prev_diff_01 = false; // No pending mismatch after this position
            prev_diff_10 = false;
        }
    }

    // After the loop, if there's any pending mismatch, it must be resolved by a flip.
    if (prev_diff_01 || prev_diff_10) {
        cost += 1;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
