#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Box 1: (-inf, -1] (Negative, Large magnitude)
    // Final product must be negative and have magnitude >= 1.
    // For negative: odd number of initial negative toys.
    // For magnitude >= 1:
    //   - If there's at least one initial toy with magnitude >= 1 (A or D),
    //     we can try to make the product magnitude >= 1.
    //   - If all initial toys have magnitude < 1 (B and C only),
    //     the product magnitude will always be < 1.
    //   - If there are A or D toys, we can make the product magnitude >= 1
    //     by carefully choosing values. For example, if we have one D toy (e.g., 2)
    //     and many B/C toys (e.g., 0.1), we can multiply the D toy with B/C toys
    //     to reduce its magnitude, or multiply B/C toys together to get a small
    //     magnitude, then multiply with D.
    //     The only way to guarantee magnitude < 1 is if all initial toys are B or C.
    //     If A+D > 0, it's possible to get magnitude >= 1.
    //     If A+D == 0, then all toys are B or C, so the final product will have magnitude < 1.

    // Can be Box 1? (Negative, Large magnitude)
    // Condition for negative: (A+B) is odd.
    // Condition for large magnitude: (A+D > 0)
    if (((A + B) % 2 != 0) && (A + D > 0)) {
        ans1 = "Ya";
    }

    // Can be Box 2? (-1, 0) (Negative, Small magnitude)
    // Condition for negative: (A+B) is odd.
    // Condition for small magnitude:
    //   - If A+D == 0 (all toys are B or C), then magnitude is always < 1.
    //   - If A+D > 0, we need to be able to make the magnitude < 1.
    //     This is possible if we have at least one toy with magnitude < 1 (B or C)
    //     to "dilute" the large magnitude toys.
    //     If A+D > 0 and B+C > 0, we can always make magnitude < 1.
    //     Example: D=1 (value 2), B=1 (value -0.1). Product -0.2.
    //     What if B+C == 0? Then all toys are A or D.
    //     If A+D > 0 and B+C == 0:
    //       - If A+D == 1, it's the initial toy. If it's A, it's Box 1. If it's D, it's Box 4.
    //       - If A+D > 1, all toys have magnitude >= 1. Their product will also have magnitude >= 1.
    //         So, if B+C == 0 and A+D > 1, it's impossible to get magnitude < 1.
    //     So, for magnitude < 1: (A+D == 0) OR (B+C > 0 AND A+D > 0).
    //     This simplifies to: (A+D == 0) OR (B+C > 0).
    //     This is equivalent to NOT (A+D > 0 AND B+C == 0).
    //     This is equivalent to NOT (all toys are A or D, and there's more than one toy).
    //     So, if (A+D > 0 and B+C == 0 and total_toys > 1), then magnitude is always >= 1.
    //     Otherwise, magnitude < 1 is possible.
    bool can_be_small_magnitude = true;
    if (A + D > 0 && B + C == 0 && total_toys > 1) { // All toys are A or D, and there's more than one.
        can_be_small_magnitude = false;
    }

    if (((A + B) % 2 != 0) && can_be_small_magnitude) {
        ans2 = "Ya";
    }

    // Can be Box 3? (0, 1) (Positive, Small magnitude)
    // Condition for positive: (A+B) is even.
    // Condition for small magnitude: same as for Box 2.
    if (((A + B) % 2 == 0) && can_be_small_magnitude) {
        ans3 = "Ya";
    }

    // Can be Box 4? [1, inf) (Positive, Large magnitude)
    // Condition for positive: (A+B) is even.
    // Condition for large magnitude: (A+D > 0)
    if (((A + B) % 2 == 0) && (A + D > 0)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

