int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        long long current_score = 0;
        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (initial_wins == 0) { // All L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 2 * k - 1 << "\n"; // k wins, first is 1, rest k-1 are 2s
            }
            continue;
        }

        // Case: k=0, no changes allowed
        if (k == 0) {
            std::cout << current_score << "\n";
            continue;
        }

        // Find segments of L's between W's
        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // L's before the first W
        long long L_prefix_count = first_W;
        // L's after the last W
        long long L_suffix_count = n - 1 - last_W;

        // L's between W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        // Greedily fill gaps between W's
        for (int gap_len : gap_lengths) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W, connecting two W's.
                                                  // The first L in the gap connects to previous W (1 point),
                                                  // subsequent L's connect to previous W (2 points).
                                                  // Total: 1 + 2*(gap_len-1) = 2*gap_len - 1.
                                                  // But wait, this is simpler: each L becomes W, and it connects to a W.
                                                  // If we fill a gap of length `g`, we add `g` new W's.
                                                  // The first new W connects to the previous W, giving 2 points.
                                                  // All subsequent `g-1` new W's connect to previous W, giving 2 points each.
                                                  // So, `g` new W's, all giving 2 points. Total `2*g` points.
                                                  // Additionally, the W *after* the gap now connects to a W instead of L,
                                                  // increasing its score from 1 to 2. This is +1 point.
                                                  // So, total increase is `2*g + 1`.
            } else {
                current_score += 2 * k; // Use remaining k to fill part of this gap. Each gives 2 points.
                k = 0;
                break;
            }
        }

        // Use remaining k for prefix/suffix L's
        if (k > 0) {
            // Fill suffix L's first (they connect to last_W)
            long long fill_suffix = std::min(k, L_suffix_count);
            current_score += 2 * fill_suffix;
            k -= fill_suffix;

            // Fill prefix L's (they connect to first_W)
            long long fill_prefix = std::min(k, L_prefix_count);
            current_score += 2 * fill_prefix;
            k -= fill_prefix;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take N/2
                // Option 2: Take 1

                // If N is a power of 2, taking N/2 might be bad if it leaves a small N for opponent.
                // Example: N=4.
                // Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1=2. Opponent: 1+1=2.
                // Chanek takes N/2=2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Chanek prefers 3. So take N/2.

                // Example: N=6.
                // Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Chanek takes N/2=3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Both give 4.

                // The strategy is: if N is even, and N is not 2, take N/2.
                // If N is 2, taking 1 is better for Chanek (1 coin, leaves 1 for opponent, Chanek gets 1).
                // If N is 2, taking N/2=1 is also 1 coin.
                // So if N=2, it doesn't matter.
                // The only case where taking 1 is better than N/2 is when N/2 leaves the opponent with a very good move.
                // This happens when N/2 is 1 (i.e., N=2).
                // For N > 2 and even:
                // If Chanek takes N/2, N becomes N/2.
                // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1, N becomes N-2 (even).
                // The opponent will try to maximize their coins.
                // If N is a power of 2 (e.g., 4, 8, 16, ...), taking N/2 is always optimal for the current player.
                // If N is even but not a power of 2 (e.g., 6, 10, 12, ...), taking N/2 is also optimal.
                // The only exception is N=2.

                // Let's check if N is a power of 2.
                // A number is a power of 2 if (n & (n - 1)) == 0.
                if ((n & (n - 1)) == 0 && n != 2) { // N is a power of 2 and N > 2
                    // In this case, taking N/2 is optimal.
                    // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    // This seems to prolong the game and give opponent more chances.
                    // Taking N/2 is generally better for the current player if N is a power of 2.
                    chanek_coins += n / 2;
                    n /= 2;
                } else if (n == 2) {
                    chanek_coins += 1;
                    n -= 1;
                }
                else { // N is even, not a power of 2, and N > 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0 && n != 2) { // N is a power of 2 and N > 2
                    n /= 2;
                } else if (n == 2) {
                    n -= 1;
                }
                else { // N is even, not a power of 2, and N > 2
                    n /= 2;
                }
            }
        }
        turn = 1 - turn; // Switch turn
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

