#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends with w_i = 1: they get one number, which is both max and min.
    // To maximize happiness, these friends should get the largest available numbers.
    // Since w is sorted, friends with w_i = 1 are at the beginning of the sorted w array.
    // We assign them the largest numbers from 'a'.
    int a_ptr_end = n - 1;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_end];
            a_ptr_end--;
        } else {
            // All remaining w_i will be > 1 because w is sorted.
            // Break and handle them in the next loop.
            break;
        }
    }

    // Friends with w_i > 1: they get w_i numbers.
    // To maximize happiness, they should get the largest available number as their max,
    // and the smallest available number as their min.
    // We assign the largest remaining numbers from 'a' as max_val to these friends.
    // We assign the smallest remaining numbers from 'a' as min_val to these friends.
    // To maximize sum of (max_val + min_val), we pair the largest remaining max_val
    // with the smallest remaining min_val.
    // The friends with larger w_i values need more numbers, so they "consume" more
    // of the smaller numbers. To maximize the sum, we want to use the smallest
    // possible numbers for min_val, but we also want to use the largest possible
    // numbers for max_val.
    // The largest w_i values (at the end of sorted w) should get the smallest numbers
    // as their min_val, because they consume more numbers in between.
    // The smallest w_i values (that are > 1, at the beginning of the remaining w array)
    // should get the largest numbers as their max_val.
    // This means we iterate w in descending order for w_i > 1.

    int a_ptr_start = 0;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_end]; // This friend gets the current largest available number as max_val
            a_ptr_end--;

            // This friend also needs w[i]-1 more numbers.
            // These numbers will be taken from the smallest available numbers.
            // The smallest of these w[i] numbers will be the min_val for this friend.
            // This min_val will be a[a_ptr_start].
            total_happiness += a[a_ptr_start];
            a_ptr_start += (w[i] - 1); // Consume w[i]-1 numbers from the start
        }
    }

    std::cout << total_happiness << std::endl;
}

