    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually pass this 'b'.
            // Each 'a' to its left will contribute 'count_a' steps
            // to pass this 'b' and the 'count_a' 'b's generated by previous 'a's.
            // When an 'a' passes a 'b', it becomes 'bba'.
            // The 'a' effectively moves past two 'b's.
            // So, the number of 'a's that need to pass future 'b's doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's to its right.
            // The current 'count_a' represents the number of 'a's that
            // have already been processed (from right to left) and are
            // effectively "waiting" to pass 'b's.
            // This 'a' adds 1 to the count of 'a's that need to pass future 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

