        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_segments = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (m > 0 && chain[0] == 1) {
            int current_val = 1;
            int segment_len = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_val) {
                    segment_len++;
                    current_val++;
                } else {
                    break; 
                }
            }
            correct_segments += segment_len;
        }
    }

    // Operations to break existing chains:
    // Each chain of length m has m-1 existing nestings.
    // We need to break all of them except for the longest correct segment starting with 1.
    // The number of nestings to break is (n - k) - (correct_segments - 1).
    // (n - k) is the total number of nestings in the initial k chains.
    // correct_segments - 1 is the number of nestings in the longest correct segment starting with 1.
    // If correct_segments is 0, it means no segment starts with 1, so we don't subtract 1.
    // However, the problem statement guarantees that if a chain starts with 1, it's 1, 2, ..., segment_len.
    // So, if correct_segments > 0, it means we have 1 -> 2 -> ... -> correct_segments.
    // This segment has (correct_segments - 1) nestings.
    // These (correct_segments - 1) nestings do not need to be broken.
    // All other (n - k) - (correct_segments - 1) nestings must be broken.
    // Each break operation costs 1 second.

    // Total nestings in initial configuration: n - k
    // Number of nestings that are part of the 1 -> 2 -> ... -> correct_segments sequence: correct_segments - 1 (if correct_segments > 0)
    // Number of nestings to break: (n - k) - (correct_segments > 0 ? correct_segments - 1 : 0)
    // This simplifies to n - k - correct_segments + 1 (if correct_segments > 0)
    // Or n - k (if correct_segments == 0)
    // This can be written as (n - k) - std::max(0, correct_segments - 1)

    total_operations += (n - k) - std::max(0, correct_segments - 1);

    // Operations to form the final chain:
    // The final chain 1 -> 2 -> ... -> n requires n-1 nestings.
    // We already have (correct_segments - 1) nestings in place.
    // So we need to form (n - 1) - (correct_segments - 1) new nestings.
    // This simplifies to n - correct_segments.
    // Each form operation costs 1 second.

    total_operations += (n - 1) - std::max(0, correct_segments - 1);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
