#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?'); // Stores the determined pattern for s[i % k]

    // Step 1: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_pattern[i % k] == '?') {
                fixed_pattern[i % k] = s[i];
            } else if (fixed_pattern[i % k] != s[i]) {
                // Conflict: s[i] contradicts a previously determined character for this position in the k-cycle
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Fill in '?' in s based on fixed_pattern
    // This step is not strictly necessary for correctness but helps visualize the string
    // and ensures that the counts are based on the most constrained version of s.
    // For the actual check, we only need the fixed_pattern.
    // We can directly count 0s and 1s from fixed_pattern.

    // Step 3: Check if the first k characters (or the pattern derived for them) can be k-balanced
    int zeros = 0;
    int ones = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            zeros++;
        } else if (fixed_pattern[i] == '1') {
            ones++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        // Too many 0s or 1s already in the fixed part of the first k-block
        std::cout << "NO\n";
        return;
    }

    // If we have enough '?' to fill the remaining slots to make k/2 zeros and k/2 ones
    // (i.e., k/2 - zeros '0's and k/2 - ones '1's), then it's possible.
    // The number of '?'s available is k - zeros - ones.
    // We need (k/2 - zeros) '0's and (k/2 - ones) '1's.
    // The sum of these needed counts is k/2 - zeros + k/2 - ones = k - zeros - ones.
    // This sum must be less than or equal to the number of '?'s.
    // Since k - zeros - ones is exactly the count of '?'s, this condition is always met
    // if zeros <= k/2 and ones <= k/2.
    // So, if we reach here, it means the first k-block (and by extension, all k-blocks) can be made k-balanced.

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

