int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_part
    long long sum_r_part;
    if (b == 1) { // If b=1, then r must be 0, but r!=0 is required. So no nice integers.
        sum_r_part = 0;
    } else {
        sum_r_part = (b - 1);
        sum_r_part = (sum_r_part * b) / 2;
        sum_r_part %= MOD; // sum_r_part can be large, but it's not multiplied by MOD yet.
                           // The division by 2 is exact.
    }

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_k_part
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_part;
    long long sum_k_val = (a * (a + 1)) / 2; // sum_{k=1 to a} k
    sum_k_val %= MOD;

    sum_k_part = (b % MOD * sum_k_val) % MOD; // b * sum_{k=1 to a} k
    sum_k_part = (sum_k_part + a) % MOD;      // + a

    // Total sum = (sum_r_part * sum_k_part) % MOD
    long long total_sum = (sum_r_part * sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
