// Function to check if a subarray is a permutation
// `arr` is the original array, `start` is the starting index (inclusive),
// `end` is the ending index (exclusive), `length` is the expected length of the permutation.
bool is_permutation(const std::vector<int>& arr, int start, int end, int length) {
    if (length == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (end - start != length) return false; // Length mismatch

    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = start; i < end; ++i) {
        if (arr[i] < 1 || arr[i] > length) {
            return false; // Value out of range [1, length]
        }
        if (seen[arr[i]]) {
            return false; // Duplicate value
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    // Check if all numbers from 1 to length are present
    // This is implicitly covered by checking max_val == length and no duplicates
    // and all values being within [1, length].
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_overall) {
            max_val_overall = a[i];
        }
    }

    // Precompute prefix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    // Precompute suffix maximums
    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix counts for distinct elements
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    // Precompute suffix counts for distinct elements
    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> solutions;

    // Iterate through all possible split points l1
    // l1 can range from 1 to n-1.
    // If l1 = 0 or l1 = n, one of the permutations would be empty or length n.
    // The problem states non-zero lengths, so l1, l2 >= 1.
    // Also, a_i <= n-1, so a permutation of length n is impossible.
    // Thus, 1 <= l1 <= n-1, which implies 1 <= l2 <= n-1.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if p1 (a[0...l1-1]) is a permutation of length l1
        // Conditions for p1 to be a permutation of length l1:
        // 1. Max element in a[0...l1-1] must be l1.
        // 2. Number of distinct elements in a[0...l1-1] must be l1.
        bool p1_is_perm = (prefix_max[l1 - 1] == l1) && (prefix_distinct_count[l1 - 1] == l1);

        // Check if p2 (a[l1...n-1]) is a permutation of length l2
        // Conditions for p2 to be a permutation of length l2:
        // 1. Max element in a[l1...n-1] must be l2.
        // 2. Number of distinct elements in a[l1...n-1] must be l2.
        bool p2_is_perm = (suffix_max[l1] == l2) && (suffix_distinct_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& p : solutions) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

