int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To form '1' (word "one"): requires 'o', 'n', 'e'
    // To form '0' (word "zero"): requires 'z', 'e', 'r', 'o'

    // To maximize the number, we want to have as many '1's as possible,
    // and place them before '0's.

    // Calculate how many '1's can be formed
    int num_ones = count_n; // 'n' is unique to "one" among 'o', 'n', 'e' for "one" and 'z', 'e', 'r', 'o' for "zero"
                            // More precisely, 'n' only appears in "one".
                            // So, the number of '1's is directly limited by count_n.
                            // The other letters 'o' and 'e' are shared, but 'n' is not.
                            // If we have N 'n's, we can form at most N "one"s.
                            // Each "one" consumes one 'o', one 'n', one 'e'.
                            // So, after forming num_ones, we have:
                            // count_o -= num_ones;
                            // count_e -= num_ones;
                            // count_n -= num_ones; (becomes 0)

    // Calculate how many '0's can be formed from remaining letters
    // Each "zero" consumes one 'z', one 'e', one 'r', one 'o'.
    // 'z' and 'r' are unique to "zero".
    // So, the number of '0's is limited by count_z (and count_r, but count_z is sufficient as 'r' is also unique to 'zero').
    int num_zeros = count_z; // 'z' is unique to "zero".
                             // If we have Z 'z's, we can form at most Z "zero"s.

    // Output '1's first
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "1";
        first_digit = false;
    }

    // Then output '0's
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "0";
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

