void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = n - 1; i >= 1; --i) {
        if (a[i] == b[i]) {
            continue;
        }

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    std::cout << "YES\n";
}

