int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_duration = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_duration += a[i];
    }

    if (total_duration % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration_per_post = total_duration / k;
    std::vector<int> s_values;
    long long current_post_duration = 0;
    int current_post_videos_count = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_post_duration += a[i];
        current_post_videos_count++;

        if (current_post_duration == target_duration_per_post) {
            s_values.push_back(current_post_videos_count);
            current_post_duration = 0;
            current_post_videos_count = 0;
            posts_found++;
        } else if (current_post_duration > target_duration_per_post) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be covered by current_post_duration > target_duration_per_post
        // or by the loop finishing without posts_found == k.
        // For example, if n=5, k=2, a={1,1,1,1,1}, total=5, target=2.5 (not divisible).
        // If n=6, k=2, a={1,1,1,1,1,1}, total=6, target=3.
        // i=0, a[0]=1, cur_dur=1, cur_vid=1
        // i=1, a[1]=1, cur_dur=2, cur_vid=2
        // i=2, a[2]=1, cur_dur=3, cur_vid=3. Match! s_values={3}, posts_found=1. Reset.
        // i=3, a[3]=1, cur_dur=1, cur_vid=1
        // i=4, a[4]=1, cur_dur=2, cur_vid=2
        // i=5, a[5]=1, cur_dur=3, cur_vid=3. Match! s_values={3,3}, posts_found=2. Reset.
        // Loop ends. posts_found == k. Output Yes.
        //
        // What if posts_found < k?
        // This means the last post didn't sum up to target_duration_per_post.
        // This would imply current_post_duration != 0 after the loop,
        // which means it was either < target_duration_per_post or > target_duration_per_post.
        // The > case is handled. The < case means the total sum was not divisible by k,
        // or the last segment was too short. But total_duration % k == 0 is checked.
        // So if total_duration % k == 0, and we didn't exceed target_duration_per_post,
        // then the last segment must also sum up to target_duration_per_post.
        // Thus, posts_found must be equal to k.
        // This 'else' branch should theoretically not be reached if the logic is sound.
        std::cout << "No\n"; 
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 0) { // Edge case for n=0, though constraints say n >= 1
        std::cout << 0 << std::endl;
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means a[i] is
            // either equal to or less than the current minimum in the suffix.
            // So, a[i] becomes the new minimum for the suffix starting at i.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << std::endl;
}

