#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the last position from which we could jump right.
                            // Initially, this is cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we are at cell `i+1` (1-indexed for string char),
                // and it's an 'R', we can jump from `last_R_pos` to `i+1`.
                // The distance needed for this jump is `(i+1) - last_R_pos`.
                // We need `d >= (i+1) - last_R_pos`.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update `last_R_pos` to current cell `i+1`
                                    // because we can now jump from here.
            }
        }

        // After iterating through the string, we need to make one final jump
        // from `last_R_pos` to `n+1`.
        // The distance needed for this jump is `(n+1) - last_R_pos`.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

