#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] must be max_val_in_row.
        // This logic is derived from the observation that if p[i] is the largest element (n),
        // then min(p[i], p[j]) = p[j] for all j != i. The maximum of these p[j]s is n-1.
        // If p[i] is not the largest element, then there is some p[k] > p[i].
        // But also, there must be some p[j] < p[i].
        // The maximum value in row i, max_{j!=i} a[i][j], will be p[i] itself.
        // This is because if p[i] is not n, there must be at least one p[k] such that p[k] > p[i].
        // For such k, a[i][k] = min(p[i], p[k]) = p[i].
        // For any j such that p[j] < p[i], a[i][j] = min(p[i], p[j]) = p[j].
        // So, max_{j!=i} a[i][j] will be p[i].
        // The only exception is when p[i] = n, in which case max_{j!=i} a[i][j] = n-1.
        // So, if max_val_in_row == n-1, then p[i] = n.
        // Otherwise, p[i] = max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 1; // Cost for a 1-stair nice staircase
        long long k = 1; // Represents the 'k' in 2^k - 1 stairs

        while (current_cost <= x) {
            count++;
            x -= current_cost;

            // Calculate cost for the next nice staircase
            // If current staircase has (2^k - 1) stairs, the next one has (2^(k+1) - 1) stairs.
            // The cost difference is (2^(k+1) - 1) * (2^(k+1)) / 2 - (2^k - 1) * (2^k) / 2
            // This simplifies to (2^(k+1) - 1) * 2^k
            // Or, more simply, the cost of a nice staircase with N stairs is N * (N+1) / 2.
            // The number of stairs for the next nice staircase is 2 * (2^k - 1) + 1 = 2^(k+1) - 1.
            // Let N_prev = 2^k - 1.
            // Let N_curr = 2^(k+1) - 1.
            // The cost of the staircase with N_curr stairs is N_curr * (N_curr + 1) / 2.
            // The cost of the staircase with N_prev stairs is N_prev * (N_prev + 1) / 2.
            // The problem asks for the cost of the *next* nice staircase, which is the cost of the
            // staircase with (2^(k+1) - 1) stairs.
            // The sequence of costs for nice staircases is:
            // N=1: 1*(1+1)/2 = 1
            // N=3: 3*(3+1)/2 = 6
            // N=7: 7*(7+1)/2 = 28
            // N=15: 15*(15+1)/2 = 120
            // The cost of the (k+1)-th nice staircase (which has 2^(k+1)-1 stairs) is (2^(k+1)-1) * 2^k.
            // This is equivalent to (2*N_prev + 1) * (N_prev + 1).
            // Or, the cost of the next nice staircase is (2 * current_N + 1) * (current_N + 1)
            // where current_N is the number of stairs in the current nice staircase.
            // The number of stairs for the current nice staircase is 2^k - 1.
            // The number of stairs for the next nice staircase is 2^(k+1) - 1.
            // The cost of a nice staircase with N stairs is N * (N+1) / 2.
            // So, the cost of the next nice staircase is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // This can be written as (2^(k+1) - 1) * 2^k.
            // Let's use the previous cost to calculate the next cost.
            // Cost_k = (2^k - 1) * 2^(k-1)
            // Cost_{k+1} = (2^(k+1) - 1) * 2^k
            // Cost_{k+1} = (2 * (2^k - 1) + 1) * 2^k
            // Cost_{k+1} = (2 * (2^k - 1) + 1) * (2 * 2^(k-1))
            // This is not simply related.
            // Let's use the formula: cost of nice staircase with N stairs is N * (N+1) / 2.
            // The number of stairs for the k-th nice staircase is 2^k - 1.
            // So, the cost is (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).
            // For k=1, N=1, cost = (2^1 - 1) * 2^0 = 1 * 1 = 1.
            // For k=2, N=3, cost = (2^2 - 1) * 2^1 = 3 * 2 = 6.
            // For k=3, N=7, cost = (2^3 - 1) * 2^2 = 7 * 4 = 28.
            // So, if current_cost is for k, the next cost is for k+1.
            // current_cost = (2^k - 1) * 2^(k-1).
            // Next cost = (2^(k+1) - 1) * 2^k.
            // We can update k:
            k++;
            current_cost = ( (1LL << k) - 1 ) * (1LL << (k - 1));
        }
        std::cout << count << "\n";
    }
    return 0;
}

