void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This `i` is the end of the non-increasing suffix.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n-1 = 6, a[6]=2
    // n-2 = 5, a[5]=5. a[5] > a[6] (5 > 2). i=5.
    // n-3 = 4, a[4]=4. a[4] < a[5] (4 < 5). This is the first break.
    // So the suffix [4, 5, 2] starts at index 4.
    // The non-increasing suffix is [5, 2] starting at index 5.
    // The first element of the non-increasing suffix is a[i+1].
    // The index of the first element of the non-increasing suffix is `i_suffix_start`.
    // `i_suffix_start` is `i+1` from the loop below.
    int i_suffix_start = n - 1;
    while (i_suffix_start > 0 && a[i_suffix_start - 1] >= a[i_suffix_start]) {
        i_suffix_start--;
    }
    // After this loop, a[i_suffix_start ... n-1] is non-increasing.
    // If i_suffix_start is 0, the whole array is non-increasing.

    // Now, find the rightmost index `j` such that a[j] > a[j+1]
    // This `j` is the end of the non-decreasing suffix.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // i_suffix_start = 5. Suffix is [5, 2].
    // Now we look for the non-decreasing part before this.
    // j = i_suffix_start - 1 = 4. a[4]=4.
    // j-1 = 3. a[3]=8. a[3] > a[4] (8 > 4). This is the first break.
    // So the non-decreasing suffix starts at index 4.
    // The index of the first element of the non-decreasing suffix is `j_suffix_start`.
    // `j_suffix_start` is `j+1` from the loop below.
    int j_suffix_start = i_suffix_start;
    while (j_suffix_start > 0 && a[j_suffix_start - 1] <= a[j_suffix_start]) {
        j_suffix_start--;
    }
    // After this loop, a[j_suffix_start ... n-1] is non-decreasing.
    // If j_suffix_start is 0, the whole array is non-decreasing.

    std::cout << j_suffix_start << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already set to pos[1].
        // The length is 1. Max value is 1. Min value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include m.
        // The segment must contain 1, 2, ..., m.
        // The current segment [current_min_idx, current_max_idx] already contains 1, ..., m-1.
        // To include m, we must extend the segment to include pos[m].
        // Update current_min_idx and current_max_idx to cover the range [1, ..., m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This means its length must be exactly m.
        // The length of the segment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

