int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies the condition for the current left_ptr

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The condition is x[right_ptr] <= x[left_ptr] + d
        while (right_ptr < n && x[right_ptr] <= x[left_ptr] + d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr] to x[right_ptr - 1] satisfy the condition
        // x[k] - x[left_ptr] <= d.
        // We need to choose two more points from the range (left_ptr, right_ptr - 1].
        // The number of available points in this range is (right_ptr - 1) - (left_ptr + 1) + 1
        // which simplifies to right_ptr - 1 - left_ptr.
        // Let k = right_ptr - 1 - left_ptr. These are the points x_{left_ptr+1}, ..., x_{right_ptr-1}.
        // We need to choose 2 points from these k points.
        // The number of ways to choose 2 points from k points is k * (k - 1) / 2.

        long long num_available_points = (long long)right_ptr - 1 - left_ptr;

        if (num_available_points >= 2) {
            count += num_available_points * (num_available_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

