    for (int i = start; i <= end; ++i) {
        int val = arr[i];
        if (val <= 0 || val > expected_len) { // Value out of range [1, expected_len]
            return false;
        }
        if (seen[val]) { // Duplicate value
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // All values must be present from 1 to expected_len
    // This is implicitly checked by `seen` array and `max_val` if all values are distinct and within range.
    // Specifically, if all values are distinct and within [1, expected_len], and there are `expected_len` such values,
    // then they must be exactly 1 to expected_len.
    return max_val == expected_len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_overall) {
            max_val_overall = a[i];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix properties
    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false); // For checking distinctness and range
    int current_max_prefix = 0;
    bool prefix_valid = true;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (!prefix_valid || val > l1 || seen_prefix[val]) {
            prefix_valid = false;
        } else {
            seen_prefix[val] = true;
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            if (current_max_prefix == l1) { // If max element seen so far is l1, and all 1..l1 are present
                is_prefix_perm[l1] = true;
            }
        }
    }

    // Precompute suffix properties
    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false); // For checking distinctness and range
    int current_max_suffix = 0;
    bool suffix_valid = true;
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (!suffix_valid || val > l2 || seen_suffix[val]) {
            suffix_valid = false;
        } else {
            seen_suffix[val] = true;
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            if (current_max_suffix == l2) { // If max element seen so far is l2, and all 1..l2 are present
                is_suffix_perm[l2] = true;
            }
        }
    }

    // Iterate through all possible split points l1
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

