int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Found a mismatch at index i
            // Check if there's an adjacent mismatch that can be swapped
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // If a[i] != b[i] and a[i+1] != b[i+1]
                // AND a[i] != a[i+1] (meaning a[i] is '0' and a[i+1] is '1', or vice versa)
                // This implies that after swapping a[i] and a[i+1],
                // a[i] will become a[i+1] and a[i+1] will become a[i].
                // Since a[i] != a[i+1], the new values will be different.
                //
                // Let's analyze the conditions for a successful swap:
                // Original: a[i], a[i+1]
                // Target:   b[i], b[i+1]
                // We know: a[i] != b[i] and a[i+1] != b[i+1]
                //
                // If a[i] = '0', b[i] = '1'
                // If a[i+1] = '1', b[i+1] = '0'
                // Then a[i] != a[i+1] is true.
                // Swapping a[i] and a[i+1] makes a[i] become '1' and a[i+1] become '0'.
                // Both positions are fixed. Cost = |i - (i+1)| = 1.
                //
                // If a[i] = '1', b[i] = '0'
                // If a[i+1] = '0', b[i+1] = '1'
                // Then a[i] != a[i+1] is true.
                // Swapping a[i] and a[i+1] makes a[i] become '0' and a[i+1] become '1'.
                // Both positions are fixed. Cost = |i - (i+1)| = 1.
                //
                // In both cases, if a[i] != a[i+1], an adjacent swap fixes both.
                cost += 1;
                i += 2; // Both i and i+1 are fixed
            } else {
                // Cannot perform an adjacent swap that fixes two positions.
                // This mismatch must be fixed by a flip.
                cost += 1;
                i += 1; // Only i is fixed
            }
        } else {
            // a[i] == b[i], no action needed for this bit.
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k == 0) { // No wins possible even after using all k changes
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate initial score
        long long current_score = 0;
        if (s[0] == 'W') {
            current_score = 1;
        }
        for (int i = 1; i < n; ++i) {
            if (s[i] == 'W') {
                if (s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        // Find segments of 'L's between 'W's
        std::vector<int> l_segments;
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        if (first_w == -1) { // All 'L's initially
            // Change k 'L's to 'W's.
            // If k > 0, the first 'W' gives 1 point.
            // The remaining k-1 'W's give 2 points each (by making them consecutive).
            // Total: 1 + 2*(k-1) = 2k - 1.
            // If k=0, score is 0.
            // This can be simplified to max(0, 2*k - 1).
            std::cout << std::max(0, 2 * k - 1) << "\n";
            continue;
        }

        // Iterate between first_w and last_w to find L-segments
        int current_l_count = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_l_count++;
            } else { // s[i] == 'W'
                if (current_l_count > 0) {
                    l_segments.push_back(current_l_count);
                }
                current_l_count = 0;
            }
        }
        std::sort(l_segments.begin(), l_segments.end());

        // Fill internal L-segments
        for (int segment_len : l_segments) {
            if (k >= segment_len) {
                k -= segment_len;
                current_score += 2 * segment_len + 1; // Each L becomes W, connects two Ws, adds 2*len points. Plus 1 for connecting.
            } else {
                current_score += 2 * k; // Use remaining k to turn Ls into Ws, each adds 2 points (as they are between Ws)
                k = 0;
                break;
            }
        }

        // Use remaining k for L's at ends or remaining L's in internal segments
        // Each remaining k change adds 2 points (W after W)
        current_score += 2LL * k;

        std::cout << current_score << "\n";
    }
    return 0;
}

