        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1 && n != 4) { // N/2 is odd, and N is not 4
                    // If Chanek takes N/2, opponent gets an odd number.
                    // If Chanek takes 1, opponent gets an even number.
                    // Taking N/2 is better for Chanek if N/2 is odd (and N > 2)
                    // because it leaves an odd number for the opponent, forcing them to take 1.
                    // Exception: N=4. If Chanek takes 2, opponent takes 1, Chanek takes 1. Chanek gets 3.
                    // If Chanek takes 1, opponent takes 2, Chanek takes 1. Chanek gets 2.
                    // So for N=4, Chanek takes N/2.
                    // The condition (n/2)%2 == 1 covers N=6, 10, 14, ...
                    // For N=6, N/2=3 (odd). Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // Both strategies yield 4 for Chanek.
                    // The logic for N/2 being odd is to force opponent to take 1.
                    // If N/2 is odd, taking N/2 is generally good.
                    // The only case where N/2 is odd but taking 1 is better is if N=2.
                    // For N=2, N/2=1 (odd). If Chanek takes N/2=1, N=1. Opponent takes 1. Chanek:1, Opponent:1.
                    // If Chanek takes 1, N=1. Opponent takes 1. Chanek:1, Opponent:1.
                    // So for N=2, it doesn't matter. The N=2 special case handles it.
                    // For N > 2 and N/2 is odd, taking N/2 is optimal.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even (or N=4)
                    // If N/2 is even, taking N/2 leaves an even number for the opponent,
                    // allowing them to take half again. This might be bad.
                    // Taking 1 leaves an odd number for the opponent, forcing them to take 1.
                    // This seems like a better strategy for Chanek.
                    // Example N=4: N/2=2 (even).
                    // If Chanek takes N/2=2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    // Chanek: 2+1=3. Opponent: 1.
                    // If Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+1=2. Opponent: 1+1=2.
                    // So for N=4, taking N/2 is better.
                    // The condition (n/2)%2 == 1 && n != 4 covers N=6, 10, 14, ...
                    // The else branch covers N=4, 8, 12, 16, ...
                    // For N=4, we want to take N/2.
                    // For N=8, N/2=4 (even).
                    // If Chanek takes N/2=4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 4+1=5. Opponent: 2+1=3.
                    // If Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    // Both strategies yield 5 for Chanek.
                    // It seems that if N/2 is even, taking 1 is generally better to force opponent to take 1.
                    // But if N/2 is even, and N is a power of 2 (N=2^k), then taking N/2 repeatedly is good.
                    // Let's re-evaluate.
                    // If N is even:
                    //   Option 1: Take N/2. Remaining N/2.
                    //   Option 2: Take 1. Remaining N-1.
                    // If N/2 is odd (and N > 2), Chanek takes N/2. Opponent faces odd N/2. Opponent takes 1.
                    // Chanek gets N/2. Opponent gets 1.
                    // If N/2 is even (and N > 2):
                    //   If Chanek takes N/2. Opponent faces even N/2. Opponent can take (N/2)/2 = N/4.
                    //   This is a chain of N/2, N/4, N/8...
                    //   If Chanek takes 1. Opponent faces odd N-1. Opponent takes 1.
                    //   Chanek gets 1. Opponent gets 1.
                    // The strategy is: if N is even, and N/2 is odd, take N/2.
                    // Otherwise (N is odd, or N is even and N/2 is even), take 1.
                    // This is the "take 1 unless N is even and N/2 is odd" strategy.
                    // Let's test this strategy.
                    // N=5: odd. Chanek takes 1. N=4. Opponent's turn.
                    // N=4: even, N/2=2 (even). Opponent takes 1. N=3. Chanek's turn.
                    // N=3: odd. Chanek takes 1. N=2. Opponent's turn.
                    // N=2: even, N/2=1 (odd). Opponent takes N/2=1. N=1. Chanek's turn.
                    // N=1: odd. Chanek takes 1. N=0.
                    // Chanek: 1+1+1=3. Opponent: 1+1=2. Total 5.
                    // Example output for N=5 is Chanek: 2. My strategy gives 3.
                    // The example output for N=5: Chanek takes 1. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    // Chanek: 1+1=2. Opponent: 2+1=3.
                    // This means for N=4, opponent chose to take N/2=2, not 1.
                    // So the opponent's optimal play for N=4 is to take N/2.
                    // This implies that if N is even, and N/2 is even, taking N/2 is sometimes better.
                    // The rule "take 1 unless N is even and N/2 is odd" is not quite right.

                    // Let's re-evaluate the optimal strategy for an even N.
                    // If N is even, player can take 1 or N/2.
                    // If player takes 1, remaining N-1 (odd). Next player takes 1.
                    // If player takes N/2, remaining N/2. Next player faces N/2.
                    // The goal is to maximize own coins.
                    // If N is even:
                    //   Option A: Take 1. Chanek gets 1. Opponent faces N-1. Opponent takes 1. Chanek faces N-2.
                    //   Option B: Take N/2. Chanek gets N/2. Opponent faces N/2.
                    // This is a recursive problem.
                    // Let f(N) be the maximum coins Chanek can get if it's his turn and N coins are left.
                    // This is not quite right, as it's a two-player game.
                    // Let C(N) be coins Chanek gets, O(N) be coins Opponent gets.
                    // We want to maximize C(N).
                    // The game ends when N=0.
                    // The total coins are N. So C + O = N. Maximizing C is equivalent to minimizing O.

                    // The strategy is:
                    // If N is odd: take 1. N becomes N-1 (even).
                    // If N is even:
                    //   If N is a power of 2 (N = 2^k):
                    //     Take N/2. This leaves N/2 (also a power of 2).
                    //     This continues until N=2.
                    //     Example N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    //     Chanek: 4+1=5. Opponent: 2+1=3.
                    //   If N is even but not a power of 2:
                    //     N = 2^k * M, where M is odd and M > 1.
                    //     Example N=6: N=2*3.
                    //     Option 1: Take 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    //     Chanek: 1+2+1=4. Opponent: 1+1=2.
                    //     Option 2: Take N/2=3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                    //     Chanek: 3+1=4. Opponent: 1+1=2.
                    //     In this case, both give 4.
                    //     Example N=12: N=2^2*3.
                    //     Option 1: Take 1. N=11. Opponent takes 1. N=10. Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    //     Chanek: 1+5+2+1=9. Opponent: 1+1+1=3.
                    //     Option 2: Take N/2=6. N=6. Opponent takes 3. N=3. Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                    //     Chanek: 6+1+1=8. Opponent: 3+1=4.
                    //     Here, taking 1 is better (9 vs 8).

                    // The optimal strategy for the current player (Chanek) when N is even:
                    // If N is a power of 2 (N=2^k): take N/2.
                    // If N is even but not a power of 2: take 1.
                    // This is because if N is a power of 2, taking N/2 leaves N/2, which is also a power of 2.
                    // This allows the current player to keep taking half, effectively "hogging" the power-of-2 chain.
                    // If N is even but not a power of 2, N = 2^k * M (M > 1, odd).
                    // Taking N/2 leaves 2^(k-1) * M. This is still not a power of 2.
                    // Taking 1 leaves N-1 (odd). The opponent is forced to take 1.
                    // This seems to be the correct greedy strategy.

                    // Let's implement this strategy.
                    // Check if N is a power of 2: (N & (N-1)) == 0.
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        chanek_coins += n / 2;
                        n /= 2;
                    } else { // N is even but not a power of 2
                        chanek_coins += 1;
                        n -= 1;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

