int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // Friends who get w_i = 1: they get two copies of the largest available numbers.
        // These are the k largest numbers in 'a'.
        // Since w is sorted, these are the friends with largest w_i values.
        // But we want to give the largest numbers to friends with w_i = 1.
        // So we iterate w from largest to smallest.
        // No, the problem states w_i = 1 means they get one integer.
        // Happiness is max + min. If w_i = 1, max = min = that integer. Happiness = 2 * integer.
        // To maximize 2 * integer, we should give the largest available integers.
        // So, friends with w_i = 1 should get the largest available numbers.
        // These are the k largest numbers in 'a'.
        // The w array is sorted, so w_i = 1 will be at the beginning of w.
        // We need to process friends with w_i = 1 first, giving them the largest numbers.
        // Then process friends with w_i > 1.

        // First, handle friends with w_i = 1.
        // These friends should get the largest available numbers.
        // Since w is sorted, w_i = 1 will appear at the beginning.
        // We iterate w from right to left to find friends with w_i = 1.
        // No, this is wrong. w is sorted, so w_i=1 are at the beginning.
        // We need to give the largest numbers to friends with w_i=1.
        // So we iterate w from right to left.
        // The friends with w_i = 1 are those for whom w[j] == 1.
        // These should get the largest numbers from 'a'.
        // The largest numbers are at a_ptr_right.

        // Iterate through w from largest to smallest.
        // Friends with w_i = 1 should get the largest numbers.
        // Friends with w_i > 1 should get the largest available number as their max,
        // and the smallest available number as their min.

        // Let's re-evaluate.
        // Each friend needs a max and a min. There are k maxes and k mins.
        // The k largest numbers in 'a' (a[n-k]...a[n-1]) should be the maxes for the k friends.
        // This contributes sum(a[n-k]...a[n-1]) to total_happiness.
        // So, total_happiness += a[n-1] + a[n-2] + ... + a[n-k].
        // This means a_ptr_right will be used k times, decrementing each time.
        // After this, a_ptr_right points to a[n-k-1].

        // For friends with w_i = 1:
        // They get one number. Max = Min = that number. Happiness = 2 * number.
        // To maximize this, they should get the largest available numbers.
        // These are the k largest numbers.
        // So, for each friend with w_i = 1, they get one of the k largest numbers.
        // This means their happiness is 2 * a[n-1], 2 * a[n-2], etc.
        // This is equivalent to adding a[n-1] to the sum of maxes, and a[n-1] to the sum of mins.
        // So, for each w_i = 1, we add a[a_ptr_right] to total_happiness, and decrement a_ptr_right.
        // This is done for the 'max' part.
        // And then we add a[a_ptr_right] again for the 'min' part.
        // So, for w_i = 1, total_happiness += 2 * a[a_ptr_right].
        // This uses up one number from 'a'.

        // For friends with w_i > 1:
        // They get w_i numbers. Max is one of the k largest numbers. Min is one of the k smallest numbers.
        // The remaining w_i - 2 numbers can be anything in between.
        // To maximize happiness, we want the largest possible max and largest possible min.
        // The k largest numbers are already assigned as maxes.
        // So, for each friend with w_i > 1, they get one of the k largest numbers as their max.
        // This contributes a[a_ptr_right] to total_happiness.
        // Then they need w_i - 1 more numbers.
        // One of these will be their min. To maximize min, we should pick the largest available from the smallest numbers.
        // The smallest numbers are at a_ptr_left.
        // So, for each friend with w_i > 1, they get a[a_ptr_left] as their min.
        // This contributes a[a_ptr_left] to total_happiness.
        // The remaining w_i - 2 numbers are consumed from a_ptr_left.
        // So, a_ptr_left moves by w_i - 1 positions.

        // Let's process friends with w_i = 1 first.
        // These friends should get the largest numbers.
        // Iterate w from right to left.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += a[a_ptr_right] * 2;
                a_ptr_right--;
            } else {
                // Break when w[i] > 1, because all remaining w[j] for j < i will also be > 1.
                // This is because w is sorted.
                break;
            }
        }

        // Now, process friends with w_i > 1.
        // These friends need one max (from a_ptr_right) and one min (from a_ptr_left).
        // The remaining w_i - 2 numbers are consumed from a_ptr_left.
        // Iterate w from left to right (smallest w_i first).
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max for this friend
                a_ptr_right--;
                total_happiness += a[a_ptr_left]; // Min for this friend
                a_ptr_left += (w[i] - 1); // Consume w_i - 1 numbers from the left
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

#include <iostream>
