#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually pass this 'b'.
            // Each 'a' to its left will contribute 'count_a' steps
            // to pass this 'b' and the 'count_a' 'b's generated by previous 'a's.
            // When an 'a' passes a 'b', it becomes 'bba'.
            // The 'a' effectively moves past two 'b's.
            // So, the number of 'a's that need to pass future 'b's doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's to its right.
            // The current 'count_a' represents the number of 'a's that
            // have already been processed (from right to left) and are
            // effectively "waiting" to pass 'b's.
            // This 'a' adds 1 to the count of 'a's that need to pass future 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Count operations for this chain
        // Each chain starts with m dolls.
        // To make them all individual, we need m-1 unnesting operations.
        // Then, to re-nest them into a single chain, we need m-1 nesting operations.
        // So, if we break and rebuild, it's 2*(m-1) operations.
        // However, we want to find existing correct sequences.

        // The first doll in the chain must be 1 for it to be part of the target sequence 1->2->...->n
        if (chain[0] == 1) {
            // This chain potentially contains a prefix of the target sequence.
            // We count how many consecutive correct pairs (j, j+1) exist starting from 1.
            int current_correct_length = 1; // Doll 1 is correct
            for (int j = 0; j < m - 1; ++j) {
                if (chain[j+1] == chain[j] + 1) {
                    current_correct_length++;
                } else {
                    break; // Sequence broken
                }
            }
            correct_pairs = current_correct_length - 1; // Number of (j, j+1) pairs
        }
    }

    // Total operations needed:
    // 1. Disassemble all existing chains: Each chain of length m has m-1 nested pairs.
    //    These m-1 pairs need to be unnested. Total unnesting operations = (n - k).
    //    (This is because there are n dolls, k chains, so n-k dolls are nested).
    // 2. Assemble the final chain: The final chain 1->2->...->n has n-1 nested pairs.
    //    These n-1 pairs need to be nested. Total nesting operations = (n - 1).
    //
    // Total operations if we break everything and rebuild: (n - k) + (n - 1).
    //
    // However, we found `correct_pairs` pairs that are already in the desired configuration
    // (i.e., 1->2, 2->3, ..., `correct_pairs` -> `correct_pairs`+1).
    // These `correct_pairs` pairs do not need to be unnested and then re-nested.
    //
    // So, we save `correct_pairs` unnesting operations and `correct_pairs` nesting operations.
    //
    // The number of unnesting operations is (n - k) - correct_pairs.
    // The number of nesting operations is (n - 1) - correct_pairs.
    //
    // Total = (n - k - correct_pairs) + (n - 1 - correct_pairs)
    // Total = n - k - correct_pairs + n - 1 - correct_pairs
    // Total = 2*n - k - 1 - 2*correct_pairs

    total_operations = (long long)(n - k) + (n - 1) - 2LL * correct_pairs;

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least f_i^a_i for all i.
        // To make x not divisible by q, we must remove at least one prime factor f_i
        // from p enough times such that the power of f_i in x is less than a_i.
        // We want to maximize x, so we should remove as few factors as possible.
        // For each prime factor f_i of q, we can form a candidate x by dividing p by f_i
        // until the power of f_i in x is less than a_i.
        // Specifically, if p = f_i^b_i * R and q = f_i^a_i * S, where R and S are not divisible by f_i.
        // If b_i >= a_i, then p is divisible by f_i^a_i.
        // We want to find x = p / f_i^k such that (p / f_i^k) % q != 0.
        // The smallest k that makes (p / f_i^k) not divisible by f_i^a_i is k = b_i - a_i + 1.
        // So, for each prime factor f_i of q, we can consider x = p / f_i^(b_i - a_i + 1).
        // We take the maximum of these candidates.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            int a = factor_pair.second; // exponent of f in q

            // Calculate the exponent of f in p
            long long temp_p = p;
            int b = 0; // exponent of f in p
            while (temp_p > 0 && temp_p % f == 0) {
                temp_p /= f;
                b++;
            }

            // If f is a prime factor of q, and p is divisible by f^b, q is divisible by f^a.
            // If b < a, then p is not divisible by q (contradicts initial check p%q==0).
            // So we must have b >= a.
            // To make x not divisible by q, we need to reduce the power of f in x to be less than a.
            // The largest such x would be p / f^(b - a + 1).
            // This ensures that the power of f in x is b - (b - a + 1) = a - 1, which is < a.
            // This candidate x is p / (f^(b-a+1)).
            long long current_x = p;
            for (int i = 0; i < (b - a + 1); ++i) {
                current_x /= f;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string coloring(n, ' ');
        char last1 = '0' - 1; // Sentinel for the last digit colored 1
        char last2 = '0' - 1; // Sentinel for the last digit colored 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (p + '0')) {
                // Must be color 1
                if (current_digit < last1) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '1';
                last1 = current_digit;
            } else if (current_digit > (p + '0')) {
                // Must be color 2
                if (current_digit < last2) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '2';
                last2 = current_digit;
            } else { // current_digit == (p + '0')
                // Can be color 1 or 2
                // Try to put it in color 2 if possible, to keep color 1 digits small
                if (current_digit >= last2) {
                    coloring[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    coloring[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

