#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<int> fixed_char(k, -1); // -1 for unknown, 0 for '0', 1 for '1'
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        int char_val;
        if (s[i] == '0') {
            char_val = 0;
        } else if (s[i] == '1') {
            char_val = 1;
        } else { // s[i] == '?'
            char_val = -1;
        }

        int remainder = i % k;
        if (fixed_char[remainder] == -1) {
            fixed_char[remainder] = char_val;
        } else if (char_val != -1 && fixed_char[remainder] != char_val) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_char[i] == 0) {
            count0++;
        } else if (fixed_char[i] == 1) {
            count1++;
        }
    }

    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

