#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_part
    long long sum_r_part;
    if (b == 1) { // If b=1, then r must be 0, but r!=0 is required. So no nice integers.
        sum_r_part = 0;
    } else {
        sum_r_part = (b - 1);
        sum_r_part = (sum_r_part * b) / 2;
        sum_r_part %= MOD; // sum_r_part can be large, but it's not multiplied by MOD yet.
                           // The division by 2 is exact.
    }

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_k_part
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_part;
    long long sum_k_val = (a * (a + 1)) / 2; // sum_{k=1 to a} k
    sum_k_val %= MOD;

    sum_k_part = (b % MOD * sum_k_val) % MOD; // b * sum_{k=1 to a} k
    sum_k_part = (sum_k_part + a) % MOD;      // + a

    // Total sum = (sum_r_part * sum_k_part) % MOD
    long long total_sum = (sum_r_part * sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n); // d[i] stores the minimum operations to destroy tower i from left/right
    std::deque<int> q; // Stores indices of towers in increasing order of h[i] - i

    // Calculate d[i] considering only left boundary
    // For each tower i, we want to find the minimum k such that h[k] >= h[i] - (i-k)
    // This is equivalent to h[k] + k >= h[i] + i
    // Or, h[k] - k >= h[i] - i
    // The value we are interested in is h[i] - (i-k) = h[i] - i + k
    // The number of operations for tower i from left is min(h[i], h[k] + (i-k))
    // This is not quite right. The number of operations for tower i from left is min(h[i], d[k] + (i-k))
    // No, it's simpler. The number of operations for tower i from left is min(h[i], d[i-1]+1)
    // This is the "water level" approach.
    // The number of operations for a block at (i, y) is max(y, distance_to_left_boundary, distance_to_right_boundary)
    // The number of operations for tower i is max_y(min(y, distance_to_left_boundary, distance_to_right_boundary))
    // This is equivalent to finding the maximum k such that a block at height k in tower i is destroyed at step k.
    // This k is min(h[i], min_left_dist[i], min_right_dist[i])
    // where min_left_dist[i] is the minimum number of steps for a block at (i, y) to be destroyed from the left side.
    // min_left_dist[i] = min(h[i], min_left_dist[i-1] + 1)
    // min_right_dist[i] = min(h[i], min_right_dist[i+1] + 1)

    // Calculate min_left_dist
    std::vector<long long> min_left_dist(n);
    min_left_dist[0] = 1; // A block at (0,1) is destroyed in 1 step from left.
    for (int i = 1; i < n; ++i) {
        min_left_dist[i] = std::min(h[i], min_left_dist[i-1] + 1);
    }

    // Calculate min_right_dist and combine with min_left_dist to get d[i]
    std::vector<long long> min_right_dist(n);
    min_right_dist[n-1] = 1; // A block at (n-1,1) is destroyed in 1 step from right.
    d[n-1] = std::min(h[n-1], min_left_dist[n-1]);
    d[n-1] = std::min(d[n-1], min_right_dist[n-1]);

    for (int i = n - 2; i >= 0; --i) {
        min_right_dist[i] = std::min(h[i], min_right_dist[i+1] + 1);
        d[i] = std::min(h[i], min_left_dist[i]);
        d[i] = std::min(d[i], min_right_dist[i]);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, d[i]);
    }

    std::cout << max_ops << std::endl;

    return 0;
}

