#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i] in this segment, we want to add a multiple of (n-1)
    // such that a[i] becomes a multiple of n.
    // Or, more simply, we want to add a multiple of (n-1) such that a[i] becomes 0.
    // This is not quite right. The strategy is to make a[i] % n == 0 for i < n-1.
    // Let's use the standard trick for n > 1.

    if (n == 1) {
        // Case n=1:
        // Operation 1: segment [1, 1], len=1. Add -a[0].
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0; // a becomes [0]

        // Operations 2 and 3: do nothing.
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Case n > 1:

        // Operation 1: Target a[0]...a[n-2]
        // Segment [1, n-1] (0-indexed: [0, n-2])
        // Length is n-1.
        // For each a[i] in this segment, we want to add a multiple of (n-1)
        // such that a[i] becomes 0.
        // This is not possible directly if a[i] is not a multiple of (n-1).
        // The trick is to make a[i] become a multiple of n.
        // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0 and x_i % (n-1) == 0.
        // This is equivalent to a[i] + x_i = k*n for some integer k.
        // x_i = k*n - a[i]. We need (k*n - a[i]) % (n-1) == 0.
        // (k*n - a[i]) % (n-1) = (k*(n-1+1) - a[i]) % (n-1) = (k - a[i]) % (n-1).
        // So we need (k - a[i]) % (n-1) == 0, which means k % (n-1) == a[i] % (n-1).
        // Let rem = a[i] % (n-1). If rem < 0, rem += (n-1).
        // We can choose k = rem. Then x_i = rem * n - a[i].
        // This x_i is a multiple of (n-1) and makes a[i] + x_i a multiple of n.

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long rem = a[i] % (n - 1);
            if (rem < 0) rem += (n - 1); // Ensure rem is non-negative
            long long b_i = rem * n - a[i];
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i] to be a multiple of n
        }
        std::cout << "\n";

        // Operation 2: Target a[n-1]
        // Segment [n, n] (0-indexed: [n-1, n-1])
        // Length is 1.
        // We want to add a multiple of 1 to a[n-1] such that a[n-1] becomes 0.
        // This is always possible by adding -a[n-1].
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0; // Update a[n-1] to be 0

        // Operation 3: Target a[0]...a[n-1]
        // Segment [1, n] (0-indexed: [0, n-1])
        // Length is n.
        // At this point, a[0]...a[n-2] are multiples of n, and a[n-1] is 0.
        // For each a[i], we want to add a multiple of n such that a[i] becomes 0.
        // Since a[i] is already a multiple of n (or 0), we can just add -a[i].
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
