int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for simpler logic, as the problem is symmetric for x and y
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: Target (n, m) is unreachable in k moves due to parity mismatch
        // The parity of (n+m) must be the same as the parity of k.
        // Each move changes the sum of coordinates (x+y) by -2, 0, or 2 (diagonal)
        // or by -1 or 1 (axial).
        // This means (x+y) changes parity with each move.
        // So, (n+m) must have the same parity as k.
        if ((n + m) % 2 != k % 2) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Target (n, m) is unreachable because k is too small
        // The minimum number of moves to reach (n, m) is max(n, m).
        // This is because each move can change x by at most 1 and y by at most 1.
        // So, to cover a distance of max(n, m) in one coordinate, at least max(n, m) moves are needed.
        if (k < m) { // m is max(n, m) after swap
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible to reach (n, m) in k moves.
        // We want to maximize diagonal moves.
        // The maximum number of diagonal moves is limited by the coordinates themselves.
        // We can make min(n, m) diagonal moves towards (n, m) to reach (n-min(n,m), m-min(n,m))
        // or (0, m-n) if n <= m.
        // This takes n moves.
        // After n diagonal moves, we are at (0, m-n).
        // We have k - n moves remaining.
        // We need to reach (0, m-n) from (0,0) in k-n moves.
        // The remaining m-n distance must be covered by axial moves.
        // This takes m-n axial moves.
        // Total moves so far: n (diagonal) + (m-n) (axial) = m moves.
        // We have k - m moves remaining.
        // These k - m moves must be "wasted" moves, meaning they don't contribute to net displacement.
        // Each wasted move must be paired with another wasted move to cancel out displacement.
        // For example, (0,0) -> (1,0) -> (0,0) uses 2 axial moves.
        // (0,0) -> (1,1) -> (0,0) uses 2 diagonal moves.
        // (0,0) -> (1,0) -> (1,1) -> (0,1) -> (0,0) uses 2 axial, 2 diagonal.
        // The key is that each pair of wasted moves (e.g., move right, then move left)
        // changes the total number of moves by 2, but doesn't change the final position.
        // If k - m is even, we can use (k - m) / 2 pairs of moves like (x,y) -> (x+1,y) -> (x,y).
        // These are axial moves.
        // So, the total number of diagonal moves would be n.
        // The total number of axial moves would be (m-n) + (k-m).
        // This strategy uses n diagonal moves and (m-n) + (k-m) axial moves.
        // Total moves: n + (m-n) + (k-m) = k.
        // This strategy maximizes diagonal moves by making as many as possible towards the target,
        // and then using axial moves for the remaining straight line distance and for wasting moves.

        // However, we can also waste moves using diagonal moves.
        // For example, (x,y) -> (x+1,y+1) -> (x,y) uses 2 diagonal moves.
        // This means if we have k-m moves to waste, and k-m is even, we can use (k-m)/2 pairs of moves.
        // Each such pair can be either two axial moves or two diagonal moves.
        // To maximize diagonal moves, we should use diagonal pairs for wasting moves.
        // So, the initial n diagonal moves are definitely used.
        // The remaining k-m moves are wasted. Since k-m is even, we can make (k-m)/2 pairs of moves.
        // Each pair can be two diagonal moves.
        // So, we can add (k-m) diagonal moves to the initial n diagonal moves.
        // Total diagonal moves = n + (k-m).
        // This is the maximum possible.

        // Let's verify this.
        // We make n diagonal moves to reach (0, m-n).
        // We have k-n moves left.
        // We need to reach (0, m-n) from (0,0).
        // The remaining k-n moves must cover the distance m-n and waste the rest.
        // The number of moves to waste is (k-n) - (m-n) = k-m.
        // Since (n+m) and k have the same parity, (k-m) and n must have the same parity.
        // (k-m) % 2 == n % 2.
        // This is not quite right. (n+m)%2 == k%2 implies (k-m)%2 == n%2.
        // Example: n=2, m=2, k=3. (n+m)%2 = 0, k%2 = 1. Parity mismatch. Output -1. Correct.
        // Example: n=4, m=3, k=7. (n+m)%2 = 1, k%2 = 1. Parity match.
        // n=3, m=4, k=7.
        // k >= m is 7 >= 4. OK.
        // Initial diagonal moves = n = 3. We are at (0, 4-3) = (0,1).
        // Moves remaining = k-n = 7-3 = 4.
        // We need to reach (0,1) from (0,0) in 4 moves.
        // Minimum moves to reach (0,1) is 1.
        // Moves to waste = 4-1 = 3.
        // This is odd. We cannot waste 3 moves using pairs of moves.
        // This means the simple strategy of n diagonal moves + (k-m) diagonal wasted moves is not always correct.

        // Let's re-evaluate.
        // The maximum number of diagonal moves is k. This happens if n=0, m=0, k is even.
        // Or if n=1, m=1, k is odd.
        // The minimum number of diagonal moves is 0.
        // Each move changes the parity of (x+y).
        // So, (n+m) must have the same parity as k. This is already checked.
        // Each move changes the parity of (x-y).
        // So, (n-m) must have the same parity as k.
        // Since (n+m) and (n-m) have the same parity (because (n+m)-(n-m) = 2m is even),
        // this condition is equivalent to (n+m)%2 == k%2.

        // Consider the total number of moves k.
        // We want to maximize diagonal moves.
        // Let D be the number of diagonal moves.
        // Let A be the number of axial moves.
        // D + A = k.
        // Each diagonal move changes both x and y by +/- 1.
        // Each axial move changes one of x or y by +/- 1.
        // The total change in x is sum(dx_i) = n.
        // The total change in y is sum(dy_i) = m.
        // The maximum number of diagonal moves is k.
        // The minimum number of diagonal moves is 0.
        // The number of diagonal moves must have the same parity as k - (m-n).
        // This is because we need at least m-n axial moves to cover the difference between m and n.
        // And we need at least n moves to cover the common part.
        // So, we need at least m moves.
        // The number of moves that are not "net" moves is k - m.
        // These k-m moves must be "wasted" moves.
        // Each wasted move must be part of a pair that cancels out displacement.
        // E.g., (1,0) then (-1,0). Or (1,1) then (-1,-1).
        // Each such pair uses 2 moves.
        // So, k-m must be even.
        // If k-m is odd, then we must have one "unpaired" wasted move.
        // An unpaired wasted move means we end up at (n +/- 1, m) or (n, m +/- 1) or (n +/- 1, m +/- 1)
        // if we only consider the "net" moves.
        // This means the final position (n,m) would be off by one unit from the target.
        // This implies that if k-m is odd, we cannot reach (n,m) in k moves.
        // But this contradicts the parity check (n+m)%2 == k%2.
        // If (n+m)%2 == k%2, then (k-m)%2 == n%2.
        // If n is even, k-m must be even.
        // If n is odd, k-m must be odd.

        // Let's consider the number of moves that change x, and the number of moves that change y.
        // Let dx_pos, dx_neg be number of moves increasing/decreasing x.
        // Let dy_pos, dy_neg be number of moves increasing/decreasing y.
        // n = dx_pos - dx_neg
        // m = dy_pos - dy_neg
        // Total moves k = dx_pos + dx_neg + dy_pos + dy_neg (this is not right, it double counts diagonal moves)

        // Let's use the property that each move changes the parity of (x+y).
        // So, (n+m) must have the same parity as k. This is the first check.
        // If this holds, then it is always possible to reach (n,m) in k moves, provided k >= max(n,m).
        // The minimum number of moves is max(n,m) if (n+m)%2 == max(n,m)%2.
        // If (n+m)%2 != max(n,m)%2, then the minimum moves is max(n,m)+1.
        // This is because if max(n,m) moves are used, the parity of (n+m) will be max(n,m)%2.
        // If (n+m)%2 != max(n,m)%2, we need at least one extra move, making it max(n,m)+1.
        // But our initial parity check (n+m)%2 == k%2 already covers this.
        // If k >= m (which is max(n,m)), and (n+m)%2 == k%2, then it is always possible.

        // Now, to maximize diagonal moves.
        // We can make n diagonal moves to reach (0, m-n).
        // This uses n moves. We have k-n moves left.
        // We are at (0, m-n). We need to reach (0, m-n) in k-n moves.
        // The remaining distance is m-n.
        // We need at least m-n axial moves to cover this distance.
        // So, we use m-n axial moves.
        // Total moves used so far: n (diagonal) + (m-n) (axial) = m moves.
        // We have k-m moves remaining.
        // These k-m moves must be "wasted" moves.
        // Since (n+m)%2 == k%2, and (n+m)%2 == (n + (m-n))%2,
        // we have (n + (m-n))%2 == k%2.
        // This means (m)%2 == k%2.
        // So, k-m must be an even number.
        // If k-m is even, we can waste (k-m)/2 pairs of moves.
        // Each pair can be two diagonal moves (e.g., (1,1) then (-1,-1)).
        // Or each pair can be two axial moves (e.g., (1,0) then (-1,0)).
        // To maximize diagonal moves, we should use diagonal pairs for wasting moves.
        // So, we have n initial diagonal moves.
        // And we have (k-m) diagonal moves from wasting.
        // Total diagonal moves = n + (k-m).

        // Let's test this formula with the examples:
        // 1. n=2, m=2, k=3
        //    (n+m)%2 = 4%2 = 0. k%2 = 3%2 = 1. Parity mismatch. Output -1. Correct.

        // 2. n=4, m=3, k=7
        //    Swap to n=3, m=4, k=7.
        //    (n+m)%2 = 7%2 = 1. k%2 = 7%2 = 1. Parity match.
        //    k >= m is 7 >= 4. OK.
        //    Formula: n + (k-m) = 3 + (7-4) = 3 + 3 = 6. Output 6. Correct.

        // 3. n=10, m=1, k=9
        //    Swap to n=1, m=10, k=9.
        //    (n+m)%2 = 11%2 = 1. k%2 = 9%2 = 1. Parity match.
        //    k >= m is 9 >= 10. False. k < m. Output -1. Correct.

        // The logic seems sound.
        // The maximum number of diagonal moves is n + (k-m).
        // This is because:
        // 1. We make n diagonal moves to reach (0, m-n). This uses n moves.
        // 2. We then need to reach (0, m-n) from (0,0) in k-n moves.
        //    The minimum moves to cover the remaining (m-n) distance is m-n axial moves.
        //    This brings total moves to n + (m-n) = m.
        //    We have k-m moves left to "waste".
        // 3. Since (n+m)%2 == k%2, and n <= m, we have (m+n)%2 == k%2.
        //    This implies (m-n)%2 == (k-n)%2.
        //    Also, (k-m)%2 == n%2.
        //    If n is even, k-m is even. If n is odd, k-m is odd.
        //    This means the number of "wasted" moves (k-m) has the same parity as n.
        //    If k-m is even, we can use (k-m)/2 pairs of diagonal moves to waste them.
        //    This adds k-m diagonal moves. Total: n + (k-m).
        //    If k-m is odd, this means n is odd.
        //    We cannot waste an odd number of moves using pairs.
        //    This implies that we must use one axial move to "fix" the parity.
        //    Consider the state after n diagonal moves: (0, m-n).
        //    Remaining moves: k-n. Target: (0, m-n).
        //    We need to cover m-n distance.
        //    If (k-n) - (m-n) = k-m is odd, we cannot just use pairs of moves.
        //    This means we must use one axial move to change the parity of the remaining moves.
        //    For example, if we are at (0, m-n) and need to reach (0, m-n) in X moves,
        //    and X is odd, we can't do it.
        //    This is where the parity of (n+m) and k comes in.
        //    If (n+m)%2 == k%2, then it is always possible.
        //    The number of diagonal moves is k - (number of axial moves).
        //    We want to minimize axial moves.
        //    The minimum number of axial moves is (m-n) + (k-m)%2.
        //    If k-m is even, min axial moves = m-n.
        //    If k-m is odd, min axial moves = m-n + 1.
        //    This is because if k-m is odd, we must make one extra axial move to adjust parity.
        //    For example, if we are at (0, m-n) and need to reach (0, m-n) in X moves,
        //    and X is odd, we can't do it.
        //    This means the number of axial moves must be at least m-n.
        //    And the total number of moves k must have the same parity as m.
        //    If k and m have the same parity, then k-m is even.
        //    In this case, the number of axial moves is m-n.
        //    Total diagonal moves = k - (m-n).
        //    This is k - m + n. This matches the formula.

        //    What if k and m have different parities?
        //    This means k-m is odd.
        //    But we already established (n+m)%2 == k%2.
        //    And (n+m)%2 == (n + (m-n))%2.
        //    So, (n + (m-n))%2 == k%2.
        //    This means (m)%2 == k%2.
        //    So, k-m must always be even if (n+m)%2 == k%2.
        //    Therefore, the number of wasted moves (k-m) is always even.
        //    So, we can always waste them using diagonal pairs.
        //    The formula n + (k-m) is correct.

        long long result = n + (k - m);
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> diff_L(n + 1, 0);
    int s1_L = 0;
    int s2_L = 0;
    for (int k = 0; k < n; ++k) {
        if (a[k] == 1) {
            s1_L++;
        } else {
            s2_L++;
        }
        diff_L[k + 1] = s1_L - s2_L;
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-1...2n-k]) - (count of 2s in a[2n-1...2n-k])
    // for k from 0 to n
    std::vector<int> diff_R(n + 1, 0);
    int s1_R = 0;
    int s2_R = 0;
    for (int k = 0; k < n; ++k) {
        if (a[2 * n - 1 - k] == 1) {
            s1_R++;
        } else {
            s2_R++;
        }
        diff_R[k + 1] = s1_R - s2_R;
    }

    // Store the minimum number of jars eaten from the right to achieve a certain diff_R value
    // map: diff_val -> min_jars_eaten_from_right
    std::map<int, int> min_jars_right;
    for (int k = 0; k <= n; ++k) {
        int current_diff_R = diff_R[k];
        if (min_jars_right.find(current_diff_R) == min_jars_right.end()) {
            min_jars_right[current_diff_R] = k;
        } else {
            min_jars_right[current_diff_R] = std::min(min_jars_right[current_diff_R], k);
        }
    }

    int min_total_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible jars eaten from the left (0 to n)
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff_L = diff_L[k_L];
        // We need diff_L[k_L] + diff_R[k_R] = 0, so diff_R[k_R] = -diff_L[k_L]
        int target_diff_R = -current_diff_L;

        if (min_jars_right.count(target_diff_R)) {
            int k_R = min_jars_right[target_diff_R];
            min_total_eaten = std::min(min_total_eaten, k_L + k_R);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros is n - m
        long long num_zeros = n - m;

        // To minimize substrings of all zeros, we want to break up
        // the zeros into as many small, equal-sized blocks as possible.
        // This means distributing the m '1's to separate the zeros.
        // The '1's create m+1 potential blocks of zeros (some might be empty).
        // We have num_zeros '0's to distribute among m+1 blocks.
        // Let k be the number of '1's that are used to separate blocks of '0's.
        // These '1's divide the string into k+1 segments.
        // The optimal strategy is to place '1's such that the blocks of '0's are as equal in length as possible.
        // This means we have m '1's. These '1's divide the string into m+1 potential segments of '0's.
        // However, the '1's themselves are part of the string.
        // The '1's effectively break the string into segments of '0's.
        // If we have m '1's, we can have at most m+1 blocks of '0's.
        // For example, 10101 has 3 ones, and 4 blocks of zeros (empty, 0, 0, empty).
        // The number of '0's is num_zeros.
        // We want to distribute these num_zeros '0's into m+1 blocks.
        // Let q = num_zeros / (m + 1) be the minimum length of a block of zeros.
        // Let r = num_zeros % (m + 1) be the number of blocks that get an extra zero.
        // So, r blocks will have length q+1, and (m+1-r) blocks will have length q.

        long long num_blocks = m + 1;
        long long q = num_zeros / num_blocks;
        long long r = num_zeros % num_blocks;

        long long zeros_substrings = 0;
        // r blocks of length q+1
        zeros_substrings += r * (q + 1) * (q + 2) / 2;
        // (num_blocks - r) blocks of length q
        zeros_substrings += (num_blocks - r) * q * (q + 1) / 2;

        std::cout << total_substrings - zeros_substrings << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available (c + m + x) / 3
        // 2. The number of coders available (c)
        // 3. The number of mathematicians available (m)
        // So, a naive upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'k'.
        // We need to check if 'k' teams can actually be formed.
        // For 'k' teams, we need 'k' coders and 'k' mathematicians.
        // The remaining 'k' spots (3 members per team - 1 coder - 1 mathematician)
        // must be filled by any remaining students.
        // The remaining students are (c - k) coders, (m - k) mathematicians, and x non-specialized.
        // The total number of these remaining students is (c - k) + (m - k) + x.
        // This sum must be at least 'k'.
        // So, (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3
        // This condition is already covered by the initial min calculation.
        //
        // The problem is that the minimum of c, m, and (c+m+x)/3 might not be achievable
        // if, for example, c is very small, m is very small, but x is very large.
        // Example: c=1, m=1, x=100.
        // min(1, 1, (1+1+100)/3) = min(1, 1, 102/3) = min(1, 1, 34) = 1.
        // One team can be formed (1 coder, 1 mathematician, 1 non-specialized).
        //
        // Example: c=10, m=10, x=0.
        // min(10, 10, (10+10+0)/3) = min(10, 10, 20/3) = min(10, 10, 6) = 6.
        // Can we form 6 teams?
        // We need 6 coders, 6 mathematicians.
        // Remaining students: (10-6)=4 coders, (10-6)=4 mathematicians, 0 non-specialized.
        // Total remaining: 4+4+0 = 8.
        // We need to fill 6 spots. We have 8 students. Yes, 6 teams can be formed.
        //
        // The maximum number of teams 'k' is limited by:
        // 1. The total number of students: k <= (c + m + x) / 3
        // 2. The number of coders: k <= c
        // 3. The number of mathematicians: k <= m
        //
        // All these conditions must hold. So, k <= min(c, m, (c + m + x) / 3).
        // This is the correct logic. The maximum number of teams is simply the minimum of these three values.

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

const long long INF = 1e18; // A sufficiently large value for infinity

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Adjust to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks vertices currently in the graph

    // The problem asks for sums before removal, but the removals are given in order.
    // This means we process the removals in reverse order to build up the graph.
    // x[n-1] is the last vertex to be removed, so it's the first one we consider adding.
    // x[0] is the first vertex to be removed, so it's the last one we consider adding.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added back" to the graph

        active[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step:
        // Consider paths going through vertex k.
        // For all pairs (i, j) of currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices

                // Update paths involving k as an intermediate vertex
                if (dist[i][k] != INF && dist[k][j] != INF) {
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        // After adding k and updating all paths through k,
        // we also need to update paths where k is an endpoint.
        // This is implicitly handled by the above loops if i or j is k.
        // However, the standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This structure correctly updates all paths.
        // The key here is that when we add vertex k, it can be an intermediate vertex
        // for any pair (i, j) that are *already active*.
        // It can also be an endpoint for paths from/to other active vertices.
        // The loops above correctly handle this:
        // - If i=k, it updates dist[k][j] using dist[k][k] + dist[k][j] (which is dist[k][j])
        //   and dist[k][j] using dist[k][i_old] + dist[i_old][j].
        // - If j=k, it updates dist[i][k] using dist[i][k] + dist[k][k] (which is dist[i][k])
        //   and dist[i][k] using dist[i][j_old] + dist[j_old][k].
        // The crucial part is that when `k` is added, it can be an intermediate vertex
        // for any pair `(i, j)` that are *currently active*.
        // The loops `for i`, `for j` iterate over all `n` vertices, but the `if (!active[i]) continue;`
        // and `if (!active[j]) continue;` ensure we only consider paths between currently active vertices.
        // The `k` in `dist[i][k]` and `dist[k][j]` is the vertex just activated.
        // So, the loops are effectively:
        // for (int i_active : active_vertices)
        //   for (int j_active : active_vertices)
        //     dist[i_active][j_active] = min(dist[i_active][j_active], dist[i_active][k] + dist[k][j_active])
        // This is the correct way to integrate a new vertex `k` into the APSP solution.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Shortest path from v to v is 0, but problem asks for v != u
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last step)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    // Iterate through powers of 2 from largest to smallest
    // 2^60 is roughly 10^18, so 59 is a good upper bound for k
    // 2^1 - 1 = 1, 2^2 - 1 = 3, ..., 2^59 - 1
    for (int k = 59; k >= 1; --k) {
        long long count_for_k = (1LL << k) - 1;
        while (X >= count_for_k) {
            result_array.push_back(current_val);
            X -= count_for_k;
            if (result_array.size() > 10000) {
                // This case should ideally not be reached if X is within limits
                // and the strategy is correct, but as a safeguard.
                std::cout << -1 << std::endl;
                return 0;
            }
        }
        // Prepare for the next block of numbers.
        // The next block's minimum element must be at least `d` greater than
        // the current block's maximum element to ensure no cross-block subsequences
        // satisfy the condition.
        // current_val + d is the minimum value for the next block.
        // We add 1 to ensure it's strictly greater than current_val + d - 1.
        // This ensures max(s) - min(s) >= d for any s spanning blocks.
        // The maximum value in the current block is current_val + (1LL << k) - 1.
        // To be safe, we can just make the next current_val very large.
        // A simple current_val += d + 1 is sufficient.
        // However, to avoid overflow and keep numbers distinct, we can use a large multiplier.
        // current_val * 2 + d + 1 is a common strategy.
        // Or, current_val + d + 1.
        // Let's use current_val + d + 1.
        // If current_val is 1, d is 10^9, then current_val becomes 10^9+2.
        // If we add 59 numbers, current_val could be 59 * (10^9+1) which is ~6*10^10.
        // This is well within 10^18.
        current_val += d + 1;
        if (current_val >= 1000000000000000000LL) { // Check for overflow
            // If current_val exceeds 10^18, it's impossible to construct.
            // This might happen if d is very large and X requires many distinct blocks.
            std::cout << -1 << std::endl;
            return 0;
        }
    }

    if (X != 0) {
        // This means X could not be fully decomposed into (2^k - 1) terms.
        // This should not happen with the current strategy if X is positive.
        // The loop for k=1 (2^1-1 = 1) should handle any remaining X.
        // If X is 0 initially, result_array would be empty.
        // If X becomes 0, it's fine.
        // If X is not 0 after the loop, it means something went wrong or X was too large.
        std::cout << -1 << std::endl;
        return 0;
    }

    if (result_array.empty()) {
        // If X was 0 initially, or no numbers could be added.
        // The problem states 1 <= X, so this case should not be reached for valid X.
        // If X=0 was allowed, we might output 0 and empty line, but problem says 1 <= X.
        std::cout << -1 << std::endl;
        return 0;
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values:
    // val0: what 0 becomes after all operations
    // val1: what 1023 becomes after all operations
    // We only care about bits 0-9.
    // For each bit position, we track what 0 becomes and what 1 becomes.
    // Let's use `current_val_if_input_is_0` and `current_val_if_input_is_1`
    // for a single bit.
    // Initially, for bit `b`:
    // if input `x_b` is 0, output is 0.
    // if input `x_b` is 1, output is 1.
    // So, `current_val_if_input_is_0` starts at 0, `current_val_if_input_is_1` starts at 1.
    // We can represent this for all 10 bits simultaneously.
    // `val0` will store the result if the initial input is 0.
    // `val1` will store the result if the initial input is 1023 (all 1s for bits 0-9).
    int val0 = 0;    // Represents the state of bits if input was 0
    int val1 = 1023; // Represents the state of bits if input was 1023 (all 1s for bits 0-9)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now we have `val0` and `val1`.
    // `val0` is the output if input was 0.
    // `val1` is the output if input was 1023.
    // We need to find a minimal sequence of operations that transforms
    // 0 -> val0 and 1023 -> val1.

    // Let's analyze each bit position `b` (from 0 to 9).
    // Let `x_b` be the `b`-th bit of the input.
    // Let `y_b` be the `b`-th bit of the output.
    // We know:
    // If `x_b = 0`, then `y_b = (val0 >> b) & 1`.
    // If `x_b = 1`, then `y_b = (val1 >> b) & 1`.

    // We want to find `A, O, X` such that:
    // `(0 & A | O ^ X)` results in `val0`
    // `(1023 & A | O ^ X)` results in `val1`
    // This is equivalent to finding `A_b, O_b, X_b` for each bit `b` such that:
    // `(0 & A_b | O_b ^ X_b)` results in `(val0 >> b) & 1`
    // `(1 & A_b | O_b ^ X_b)` results in `(val1 >> b) & 1`

    // Let's define the target behavior for each bit:
    // `f(0) = (val0 >> b) & 1`
    // `f(1) = (val1 >> b) & 1`

    // We can represent the final transformation for each bit `b` as a function `f_b(x_b)`.
    // There are 4 possible functions for a single bit:
    // 1. `f_b(x_b) = 0` (always 0)
    // 2. `f_b(x_b) = 1` (always 1)
    // 3. `f_b(x_b) = x_b` (identity)
    // 4. `f_b(x_b) = 1 - x_b` (negation / XOR 1)

    // Let's determine which of these 4 functions each bit `b` follows:
    // `f_b(0)` is `(val0 >> b) & 1`
    // `f_b(1)` is `(val1 >> b) & 1`

    // Initialize the constants for the new operations.
    // We will try to use at most 3 operations: AND, OR, XOR.
    // The constants will be built bit by bit.
    int final_and_const = 1023; // Start with all 1s for AND
    int final_or_const = 0;     // Start with all 0s for OR
    int final_xor_const = 0;    // Start with all 0s for XOR

    for (int b = 0; b < 10; ++b) {
        int f0 = (val0 >> b) & 1;
        int f1 = (val1 >> b) & 1;

        // Case 1: f_b(x_b) = 0 (always 0)
        // This means f0=0, f1=0.
        // To achieve this:
        //   `x_b & 0` makes it 0. So `final_and_const` should have 0 at bit `b`.
        //   `x_b | 0` keeps it `x_b`.
        //   `x_b ^ 0` keeps it `x_b`.
        //   `x_b ^ 1` flips it.
        // The simplest way to force a bit to 0 is `& 0`.
        if (f0 == 0 && f1 == 0) {
            final_and_const &= ~(1 << b); // Set b-th bit of AND constant to 0
        }
        // Case 2: f_b(x_b) = 1 (always 1)
        // This means f0=1, f1=1.
        // The simplest way to force a bit to 1 is `| 1`.
        else if (f0 == 1 && f1 == 1) {
            final_or_const |= (1 << b); // Set b-th bit of OR constant to 1
        }
        // Case 3: f_b(x_b) = x_b (identity)
        // This means f0=0, f1=1.
        // To achieve this, we need to ensure the bit is not changed by AND/OR/XOR.
        //   `& 1` keeps it `x_b`. So `final_and_const` should have 1 at bit `b`. (default)
        //   `| 0` keeps it `x_b`. So `final_or_const` should have 0 at bit `b`. (default)
        //   `^ 0` keeps it `x_b`. So `final_xor_const` should have 0 at bit `b`. (default)
        // No change needed for `final_and_const`, `final_or_const`, `final_xor_const` for this bit.
        else if (f0 == 0 && f1 == 1) {
            // Do nothing, defaults work: &1 |0 ^0
        }
        // Case 4: f_b(x_b) = 1 - x_b (negation / XOR 1)
        // This means f0=1, f1=0.
        // To achieve this, we need to flip the bit.
        //   `^ 1` flips it. So `final_xor_const` should have 1 at bit `b`.
        else if (f0 == 1 && f1 == 0) {
            final_xor_const |= (1 << b); // Set b-th bit of XOR constant to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters.
    // A common canonical form is AND then OR then XOR.
    // Let's verify if this order works with our derived constants.
    // Initial value `x`.
    // `x_after_and = x & final_and_const`
    // `x_after_or = x_after_and | final_or_const`
    // `x_after_xor = x_after_or ^ final_xor_const`

    // If `final_and_const` is not all 1s (1023), we need an AND operation.
    if (final_and_const != 1023) {
        result_ops.push_back({'&', final_and_const});
    }
    // If `final_or_const` is not all 0s (0), we need an OR operation.
    if (final_or_const != 0) {
        result_ops.push_back({'|', final_or_const});
    }
    // If `final_xor_const` is not all 0s (0), we need an XOR operation.
    if (final_xor_const != 0) {
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Edge case, though problem states n >= 3.
                  // For n=1,2, b_1=a_1, b_n=a_n, no middle elements.
                  // Sequence is always stable.
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, -1); // Stores index of nearest 1 to the left (inclusive)
    std::vector<int> right_ones(n, n); // Stores index of nearest 1 to the right (inclusive)
    std::vector<int> left_zeros(n, -1); // Stores index of nearest 0 to the left (inclusive)
    std::vector<int> right_zeros(n, n); // Stores index of nearest 0 to the right (inclusive)

    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = i;
        } else if (i > 0) {
            left_ones[i] = left_ones[i - 1];
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = i;
        } else if (i < n - 1) {
            right_ones[i] = right_ones[i + 1];
        }
    }

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = i;
        } else if (i > 0) {
            left_zeros[i] = left_zeros[i - 1];
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = i;
        } else if (i < n - 1) {
            right_zeros[i] = right_zeros[i + 1];
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0, might turn to 1
            int r_one = right_ones[i];
            int l_one = left_ones[i];

            if (r_one != n && l_one != -1) { // 0 is surrounded by 1s
                int dist_l = i - l_one;
                int dist_r = r_one - i;

                if (dist_l == dist_r) { // 0 is exactly in the middle of two 1s
                    std::cout << -1 << std::endl;
                    return 0;
                }

                int k_val = std::min(dist_l, dist_r);
                max_k = std::max(max_k, k_val);

                if (dist_l < dist_r) { // Closer to left 1, will become 1
                    final_a[i] = 1;
                } else { // Closer to right 1, will become 1
                    final_a[i] = 1;
                }
            }
        } else { // Current element is 1, might turn to 0
            int r_zero = right_zeros[i];
            int l_zero = left_zeros[i];

            if (r_zero != n && l_zero != -1) { // 1 is surrounded by 0s
                int dist_l = i - l_zero;
                int dist_r = r_zero - i;

                if (dist_l == dist_r) { // 1 is exactly in the middle of two 0s
                    std::cout << -1 << std::endl;
                    return 0;
                }

                int k_val = std::min(dist_l, dist_r);
                max_k = std::max(max_k, k_val);

                if (dist_l < dist_r) { // Closer to left 0, will become 0
                    final_a[i] = 0;
                } else { // Closer to right 0, will become 0
                    final_a[i] = 0;
                }
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    std::vector<int> s;
    s.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i-1] < p[i] > p[i+1]  (local maximum)
        // p[i-1] > p[i] < p[i+1]  (local minimum)
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            s.push_back(p[i]);
        }
    }
    s.push_back(p[n-1]);

    std::cout << s.size() << "\n";
    for (size_t i = 0; i < s.size(); ++i) {
        std::cout << s[i] << (i == s.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to dentist

        long long current_v_effect = children[i].v;
        long long total_d_effect_from_chain = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from child i's crying
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply cumulative effect from children who cried and left
            children[j].p -= total_d_effect_from_chain;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect_from_chain += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1).
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    if (n >= 2) {
        long long current_goodness = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[elements[i].original_index] = 1;
            }
        }
    } else { // n=1, but problem constraints say n >= 2. This branch is unreachable.
        min_goodness = 0; // No pairs, so goodness is 0.
        best_partition[elements[0].original_index] = 1;
    }

    // Case 2: Partition where elements[0] is in one subsequence and elements[1] is in another.
    // This implies elements[0] and elements[1] are in different subsequences.
    // The minimum possible f value is elements[0].value + elements[1].value + h.
    // The maximum possible f value could be:
    //   - elements[n-2].value + elements[n-1].value (if they are in the same subsequence)
    //   - elements[n-2].value + elements[n-1].value + h (if they are in different subsequences)
    //
    // Consider a partition where elements[0] is in subseq 1, and all other elements are in subseq 2.
    // min_f = elements[0].value + elements[1].value + h (between elements[0] and elements[1])
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    //
    // Let's analyze the values:
    // min_f_val = elements[0].value + elements[1].value + h
    // max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //
    // This specific partition strategy (elements[0] alone, rest together) is optimal for this case.
    // The minimum value of f is always elements[0].value + elements[1].value + h (since elements[0] and elements[1] are separated).
    // The maximum value of f is either:
    //   1. elements[0].value + elements[n-1].value + h (if elements[n-1] is in subseq 2)
    //   2. elements[n-2].value + elements[n-1].value (if elements[n-2] and elements[n-1] are in subseq 2)
    // So, max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //
    // The goodness for this partition is max_f_val - min_f_val.
    //
    // This strategy is valid only if n >= 2.
    if (n >= 2) {
        long long current_min_f = elements[0].value + elements[1].value + h;
        long long current_max_f = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[elements[0].original_index] = 1; // elements[0] in subseq 1
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2; // rest in subseq 2
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Stores upper bounds for initial_a[j]
    std::vector<long long> current_diff(n, 0); // Stores sum of d's applied to a[j] so far

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_diff[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_diff[j]);
            }
        }
    }

    // If initial_a[j] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == LLONG_MAX) {
            initial_a[j] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> temp_a = initial_a; // This will be modified by type 1 ops

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                temp_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, temp_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> next_bad_idx(n + 1, n + 1); // next_bad_idx[i] stores the smallest j >= i such that s[j-1], s[j], s[j+1] form a pattern.
                                                // Using 1-based indexing for string positions for clarity with problem statement,
                                                // but 0-based for string access.
                                                // next_bad_idx[i] means the smallest index `x` (1-based) such that `x >= i` and `s_x = s_{x+k} = s_{x+2k}`
                                                // for some `k`, and `x+2k` is the end of the pattern.
                                                // We are interested in `x+2k`.
                                                // Let's redefine: `next_bad_idx[i]` is the smallest `r` (1-based) such that `r >= i` and there exists
                                                // `x, k` with `x <= r`, `x+2k = r`, and `s_x = s_{x+k} = s_{x+2k}`.
                                                // This is not quite right. The problem asks for `l <= x < x+2k <= r`.
                                                // Let `min_r_for_pattern[x]` be the smallest `r` such that `s_x = s_{x+k} = s_{x+2k}` for some `k`,
                                                // and `x+2k` is the end of the pattern.
                                                // This means `min_r_for_pattern[x] = x+2k`.
                                                // We need to find the smallest `r_prime` such that `r_prime >= x+2k` and `s_x = s_{x+k} = s_{x+2k}`.
                                                // This is `x+2k`.
                                                // Let `min_r_for_pattern[i]` be the minimum `x+2k` (1-based index) such that `x >= i` and `s_x = s_{x+k} = s_{x+2k}`.
                                                // This is also not quite right.

    // Let's use `last_valid_r[i]` to store the maximum `r` such that the substring s[i...r] (0-indexed)
    // does NOT contain any pattern.
    // This is equivalent to finding `min_bad_r[i]`, the minimum `r` such that `s[i...r]` *does* contain a pattern.
    // Then `last_valid_r[i] = min_bad_r[i] - 1`.
    // The number of valid `r` for a given `l` (0-indexed) is `last_valid_r[l] - l + 1`.
    // The total count is sum over `l` of `max(0, last_valid_r[l] - l + 1)`.

    // Let `min_r_with_pattern[i]` be the smallest `r` (0-indexed) such that `s[i...r]` contains a pattern.
    // If no such `r` exists, `min_r_with_pattern[i] = n`.
    std::vector<int> min_r_with_pattern(n, n);

    for (int i = 0; i < n; ++i) { // i is the 0-indexed starting position of the pattern s[i] = s[i+k] = s[i+2k]
        // Check k=1
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            min_r_with_pattern[i] = std::min(min_r_with_pattern[i], i + 2);
        }
        // Check k=2
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            min_r_with_pattern[i] = std::min(min_r_with_pattern[i], i + 4);
        }
        // Check k=3
        if (i + 6 < n && s[i] == s[i+3] && s[i+3] == s[i+6]) {
            min_r_with_pattern[i] = std::min(min_r_with_pattern[i], i + 6);
        }
    }

    // Now, `min_r_with_pattern[i]` stores the smallest `x+2k` (0-indexed) for a pattern starting at `x=i`.
    // We need `min_r_with_pattern_overall[l]` which is the smallest `r` (0-indexed) such that `s[l...r]` contains *any* pattern.
    // This means `min_r_with_pattern_overall[l] = min_{x >= l} (min_r_with_pattern[x])`.
    // This can be computed by iterating backwards.
    std::vector<int> min_r_overall(n + 1, n); // min_r_overall[l] is the smallest r (0-indexed) such that s[l...r] contains a pattern.
                                             // If no such r exists, it's n.
    for (int l = n - 1; l >= 0; --l) {
        min_r_overall[l] = std::min(min_r_with_pattern[l], min_r_overall[l+1]);
    }

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    for (int l = 0; l < n; ++l) { // l is 0-indexed
        // For a fixed l, we are looking for r such that l <= r < min_r_overall[l].
        // The number of such r's is (min_r_overall[l] - 1) - l + 1 = min_r_overall[l] - l.
        // These are the pairs (l, r) that do NOT contain a pattern.
        bad_pairs += (min_r_overall[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1: One cut, two pieces.
    // Try all possible cut positions.
    // s = s1 + s2. New string s' = s2 + s1.
    // We need s' to be a palindrome and s' != s.
    for (int i = 1; i < n; ++i) { // Cut after index i-1, so s1 = s.substr(0, i), s2 = s.substr(i)
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2: Two cuts, three pieces.
    // s = s1 + s2 + s3.
    // We need to find if there's any permutation of (s1, s2, s3) that forms a palindrome s' != s.
    // The problem statement implies that if k=1 doesn't work, we try k=2.
    // If k=1 didn't work, it means no single cut and swap of two pieces resulted in a new palindrome.
    // This implies that for any cut point `i`, `s.substr(i) + s.substr(0, i)` is either `s` or not a palindrome.

    // Consider the structure of s. Since s is a palindrome, s[j] == s[n-1-j].
    // If all characters in s are the same (e.g., "qqqq"), then any permutation of substrings will result in s itself.
    // For example, if s = "aaaaa", s1="a", s2="aa", s3="aa". Any permutation like "a" + "aa" + "aa" is "aaaaa".
    // In this case, it's impossible to form a new string.
    // We can check this by counting unique characters. If there's only one unique character, it's impossible.
    // Or, more simply, if s.substr(0, n/2) consists of all identical characters, then s must consist of all identical characters.
    // Example: "aaaaa", n/2 = 2. s.substr(0,2) = "aa". All 'a'.
    // Example: "ababa", n/2 = 2. s.substr(0,2) = "ab". Not all identical.
    // Example: "otto", n/2 = 2. s.substr(0,2) = "ot". Not all identical.
    // Example: "nolon", n/2 = 2. s.substr(0,2) = "no". Not all identical.

    // If s consists of all identical characters, e.g., "aaaaa", then any rearrangement of its substrings will still be "aaaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }
    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If we reach here, it means k=1 didn't work, and s is not composed of all identical characters.
    // This implies that s must have at least two distinct characters.
    // For any palindrome s that is not composed of all identical characters, and for which k=1 doesn't work,
    // it is always possible to achieve a new palindrome with k=2.
    // Consider the first half of the string s.substr(0, n/2).
    // Since s is not all identical characters, s.substr(0, n/2) must contain at least two distinct characters.
    // (If s.substr(0, n/2) were all identical, say 'a', then s would be 'a...a' or 'a...a' + middle_char + 'a...a'.
    // Since s is a palindrome, this would mean s is all 'a's, which we've already handled.)
    // So, s.substr(0, n/2) contains at least two distinct characters.
    // Let's take s = "nolon". n=5. n/2=2. s.substr(0,2) = "no".
    // We can cut it as s[0] | s[1...n-2] | s[n-1].
    // For "nolon": 'n' | "olo" | 'n'.
    // Pieces: s1='n', s2="olo", s3='n'.
    // Permutations: s1+s2+s3 = "nolon"
    // s3+s2+s1 = "nolon"
    // s1+s3+s2 = "nnoo" (not palindrome)
    // s2+s1+s3 = "olon" (not palindrome)
    // s2+s3+s1 = "olon" (not palindrome)
    // s3+s1+s2 = "nnoo" (not palindrome)

    // The problem states "cut the paper minimum number of times k".
    // If k=1 doesn't work, we try k=2.
    // The crucial observation for k=2 is that if s is a palindrome and not all characters are the same,
    // then we can always find a way to make a new palindrome with 2 cuts.
    // Example: s = "abacaba". n=7.
    // s.substr(0, n/2) = "aba".
    // We can cut s into s[0], s[1...n-2], s[n-1].
    // s1 = s[0]
    // s2 = s.substr(1, n-2)
    // s3 = s[n-1]
    // Since s is a palindrome, s[0] == s[n-1]. So s1 == s3.
    // The pieces are (s1, s2, s1).
    // We can rearrange them as s1 + s2 + s1 (original s)
    // Or s1 + s1 + s2 (e.g., "a" + "a" + "bacab" = "aabacab", not palindrome)
    // Or s2 + s1 + s1 (e.g., "bacab" + "a" + "a" = "bacabaa", not palindrome)
    // This specific cut (s[0] | s[1...n-2] | s[n-1]) doesn't guarantee a new palindrome.

    // The problem is asking for the minimum k. If k=1 fails, we output 2.
    // The only case where it's impossible is if all characters are the same.
    // We've already handled the `all_same_chars` case.
    // If `s` is a palindrome, and not all characters are the same, then `s.substr(0, n/2)` is not a palindrome.
    // (If `s.substr(0, n/2)` were a palindrome, and `s` is a palindrome, and `s` is not all same chars,
    // then `s` would look like `P + M + P_rev` where `P` is `s.substr(0, n/2)`.
    // If `P` is a palindrome, then `P = P_rev`. So `s = P + M + P`.
    // Example: "abccba". `P="abc"`. `P_rev="cba"`. `s = P + P_rev`.
    // Example: "abacaba". `P="aba"`. `M="c"`. `P_rev="aba"`. `s = P + M + P`.
    // In these cases, `s.substr(0, n/2)` is not necessarily a palindrome.
    // For "abacaba", `s.substr(0,3)` is "aba", which is a palindrome.
    // For "nolon", `s.substr(0,2)` is "no", not a palindrome.

    // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
    // then s.substr(0, n/2) is not a palindrome.
    // If s.substr(0, n/2) is not a palindrome, then we can cut s into three pieces:
    // s1 = s.substr(0, i)
    // s2 = s.substr(i, n-2*i)
    // s3 = s.substr(n-i, i)
    // where i is the smallest index such that s[i] != s[0].
    // This is not quite right.

    // The problem is simpler: if k=1 doesn't work, and the string is not all identical characters,
    // then the answer is 2.
    // Why? Because if `s` is a palindrome and not all characters are the same, then `s.substr(0, n/2)` is not a palindrome.
    // (Proof by contradiction: If `s.substr(0, n/2)` were a palindrome, then `s` would be of the form `P + (middle_char) + P`.
    // If `P` is a palindrome, then `s` would be `P + (middle_char) + P`.
    // Example: "abacaba". `P="aba"`. `s.substr(0,3)` is "aba", which is a palindrome.
    // In this case, `s` is a palindrome, `s.substr(0, n/2)` is a palindrome.
    // If `s` is "abacaba", `k=1` check:
    // "bacaba" + "a" = "bacabaa" (not palindrome)
    // "acaba" + "ab" = "acabaab" (not palindrome)
    // "caba" + "aba" = "cabaab" (not palindrome)
    // "aba" + "abac" = "abaabac" (not palindrome)
    // "ba" + "abacab" = "baabacab" (not palindrome)
    // "a" + "abacaba" = "aabacaba" (not palindrome)
    // So for "abacaba", k=1 doesn't work.
    // But "abacaba" is not all identical characters. So the answer should be 2.

    // The logic is:
    // 1. Check k=1. If a solution is found, print 1 and exit.
    // 2. If no solution for k=1, check if all characters in `s` are the same.
    //    If they are, print "Impossible" and exit.
    // 3. Otherwise (k=1 failed, but `s` has distinct characters), print 2.
    // This covers all cases. The problem guarantees that if k=1 fails and not all chars are same, k=2 is always possible.
    // This is a known property for palindromes. If a palindrome `S` is not monochromatic (all same characters),
    // and `S` cannot be rearranged into a different palindrome with one cut, then it can always be done with two cuts.
    // The specific construction for k=2 is not required, just the existence.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        long long current_p = p[p_idx];
        long long current_h = h[head_idx];

        // If current head is too far to the right to cover current_p,
        // or if current head is too far to the left to cover current_p
        // (meaning current_p is outside the range [current_h - T, current_h + T]),
        // then this head cannot cover current_p. Move to the next head.
        if (current_h + T < current_p) {
            head_idx++;
            continue;
        }

        // If current head can cover current_p, it can cover a range [current_p, current_h + T].
        // We want to cover as many subsequent tracks as possible with this head.
        long long max_reach = current_h + T;
        if (current_h - T > current_p) { // If current_h is far to the right of current_p
            // The head must move left to cover current_p.
            // The time taken to reach current_p is current_h - current_p.
            // Remaining time is T - (current_h - current_p).
            // So, it can reach up to current_p + (T - (current_h - current_p)) = 2*current_p - current_h + T.
            // This is equivalent to saying the head covers [current_p, current_p + (T - (current_h - current_p))]
            // which simplifies to [current_p, current_p + T - current_h + current_p]
            // No, this is wrong. If it moves left to current_p, its rightmost reach is current_p + (T - (current_h - current_p)).
            // This is equivalent to current_p + T - current_h + current_p.
            // A simpler way: the head can cover any track x such that |x - current_h| <= T.
            // If current_p is covered, then current_h - T <= current_p <= current_h + T.
            // The head can cover the range [max(current_p, current_h - T), current_h + T].
            // We want to cover tracks starting from current_p.
            // So, the effective range covered by this head, starting from current_p, is [current_p, current_h + T].
            // This is only if current_h - T <= current_p.
            // If current_h - T > current_p, then current_p is to the left of the head's leftmost reach.
            // This case is handled by the `if (current_h + T < current_p)` above.
            // So, if we reach here, it means current_h + T >= current_p.
            // We need to ensure current_h - T <= current_p.
            // If current_h - T > current_p, then current_p is to the left of the head's leftmost reach.
            // This means current_p cannot be covered by this head.
            // This is the case where current_h is too far to the right.
            // Example: h=10, T=2, p=5. h-T=8. p=5 is not covered.
            // Example: h=10, T=5, p=5. h-T=5. p=5 is covered.
            // The range covered by head h_i in T time is [h_i - T, h_i + T].
            // If current_p is not in this range, this head cannot cover it.
            // If current_p < current_h - T, then this head cannot cover current_p.
            // We must move to the next head.
            if (current_p < current_h - T) {
                head_idx++;
                continue;
            }
            // If we are here, it means current_h - T <= current_p <= current_h + T.
            // So current_p is covered by current_h.
            // The head can cover tracks up to current_h + T.
            // It can also cover tracks to the left of current_h, down to current_h - T.
            // Since we are processing p_idx from left to right, we want to cover current_p and subsequent tracks.
            // The rightmost track this head can cover is current_h + T.
            // So, we advance p_idx as long as p[p_idx] <= current_h + T.
            // This is the greedy choice: use the current head to cover current_p and as many subsequent tracks as possible.
        }

        // The current head at h[head_idx] can cover tracks in the range [h[head_idx] - T, h[head_idx] + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is not in this range, this head cannot cover it.
        // Specifically, if p[p_idx] < h[head_idx] - T, then this head is too far right.
        // If p[p_idx] > h[head_idx] + T, then this head is too far left.
        // The first case (p[p_idx] < h[head_idx] - T) means the head is to the right of the required track's leftmost reach.
        // This head cannot cover p[p_idx]. We must use the next head.
        if (p[p_idx] < current_h - T) {
            head_idx++;
            continue;
        }

        // If we reach here, it means current_h - T <= current_p <= current_h + T.
        // So, current_p is covered by current_h.
        // Now, greedily cover as many tracks as possible to the right with this head.
        long long rightmost_covered = current_h + T;
        while (p_idx < m && p[p_idx] <= rightmost_covered) {
            p_idx++;
        }
        head_idx++; // Move to the next head for the remaining tracks
    }

    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible difference between p_i and h_i is ~10^10.
                           // A head might need to move from 1 to 10^10, or vice versa.
                           // So T can be up to 10^10. 2e10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

