        // For example, 4. Multiples of 4 are also multiples of 2.
        // The count of 2 as a divisor will always be greater than or equal to the count of any other number k > 2.
        //
        // Consider the range [l, r].
        // The number of multiples of `k` in this range is `floor(r/k) - floor((l-1)/k)`.
        // For `k=2`, this is `floor(r/2) - floor((l-1)/2)`.
        // For `k=3`, this is `floor(r/3) - floor((l-1)/3)`.
        //
        // Since `l >= 2`, the smallest possible range is `[2, 2]`. Output `2`.
        // If `l=2, r=3`:
        // Divisors for 2: {2}
        // Divisors for 3: {3}
        // Count for 2: 1. Count for 3: 1. Output `2` is fine.
        //
        // If `l=3, r=6`:
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        // Counts: 2 (2 times), 3 (2 times), 4 (1 time), 5 (1 time), 6 (1 time).
        // Output `2` or `3` is fine. The example output is `3`.
        //
        // The problem asks for *any* of them if there are multiple answers.
        // The number 2 is a divisor of every even number.
        // The number 3 is a divisor of every third number.
        //
        // If r >= l + 1, there are at least two numbers in the range.
        // If l is even, l and l+2 are even.
        // If l is odd, l+1 and l+3 are even (if r is large enough).
        // There are always more or equal multiples of 2 than any other number k > 2 in a sufficiently large range.
        //
        // The only edge case where 2 might not be the answer is if the range is very small and contains only one even number,
        // and that even number is not 2, and there's another number whose divisor count is equal or higher.
        // Example: l=3, r=3. Output 3. (Handled by l==r)
        // Example: l=3, r=4.
        // 3: {3}
        // 4: {2, 4}
        // Counts: 2 (1), 3 (1), 4 (1). Any is fine. Output 2.
        // Example: l=3, r=5.
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // Counts: 2 (1), 3 (1), 4 (1), 5 (1). Any is fine. Output 2.
        // Example: l=3, r=6.
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        // Counts: 2 (2), 3 (2), 4 (1), 5 (1), 6 (1). Output 2 or 3. Example output is 3.
        //
        // The simplest answer that is always valid for r >= l + 1 is 2.
        // The number 2 is a divisor of approximately half the numbers in the range.
        // Any other number k > 2 is a divisor of approximately 1/k of the numbers.
        // Since 1/k < 1/2 for k > 2, 2 will always have the highest or tied highest count.
        // The problem states "If there are multiple answers, print any of them."
        // So, 2 is a safe bet for r > l.

        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is 0, it means all other elements in the row are 0.
        // This can only happen if n=1 (not possible by constraints) or if p[i]=1
        // and all other p[j] are also 1 (not possible for a permutation).
        // Or if p[i] is 1 and all other p[j] are > 1, then min(p[i], p[j]) = 1.
        // So max_val_in_row will be at least 1 if n > 1.
        // The only case where max_val_in_row could be 0 is if n=1, but n >= 2.
        // So max_val_in_row will be at least 1.
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are less than n-1.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if p[i] was the largest element (n) in the original permutation.
    // In that case, min(p[i], p[j]) = p[j] for all j != i.
    // So max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1 (since p[i]=n).
    // If there is no 'n' in the reconstructed p, it means one of the 'n-1's should be 'n'.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not present in the reconstructed p, it means one of the elements
        // that was originally 'n' got mapped to 'n-1' by the max_val_in_row logic.
        // We need to find an element that is 'n-1' and change it to 'n'.
        // Since the problem guarantees a solution, there must be exactly one such case.
        // We can just pick the first occurrence of n-1 and change it to n.
        // Or, more robustly, find the maximum value in p. If it's n-1, change it to n.
        // This is because if p[k] was originally n, then max_{j!=k} min(p[k], p[j]) = n-1.
        // All other p[i] (where original p[i] < n) would result in max_{j!=i} min(p[i], p[j]) <= p[i].
        // So, the element that was originally n will be reconstructed as n-1, and it will be
        // the largest value among those reconstructed values that are not n.
        int max_reconstructed_val = 0;
        for (int val : p) {
            if (val > max_reconstructed_val) {
                max_reconstructed_val = val;
            }
        }
        if (max_reconstructed_val == n - 1) {
            for (int i = 0; i < n; ++i) {
                if (p[i] == n - 1) {
                    p[i] = n;
                    break; // Only one such element needs to be changed
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

