#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    std::vector<int> available_numbers;

    // p_1 must be q_1
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // q_1 must be within [1, n]
        std::cout << -1 << "\n";
        return;
    }
    used_numbers.insert(p[0]);

    // Fill p_i for i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is strictly greater than q_{i-1}, then p_i must be q_i.
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_numbers.count(p[i])) {
                // q_i must be within [1, n] and not already used.
                std::cout << -1 << "\n";
                return;
            }
            used_numbers.insert(p[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be <= q_{i-1}.
            // We need to pick the smallest available number that is not greater than q_{i-1}.
            // We'll fill these later with available numbers.
            p[i] = 0; // Mark as placeholder
        }
    }

    // Collect all numbers from 1 to n that haven't been used yet
    for (int i = 1; i <= n; ++i) {
        if (!used_numbers.count(i)) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort in descending order for greedy assignment

    // Fill the placeholders (p_i where q_i == q_{i-1})
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) { // This is a placeholder
            if (available_numbers.empty()) {
                // Not enough numbers to fill placeholders
                std::cout << -1 << "\n";
                return;
            }
            int num_to_assign = available_numbers.back();
            available_numbers.pop_back();

            if (num_to_assign > q[i]) {
                // The smallest available number is greater than q_i,
                // which means max(q_{i-1}, p_i) would be num_to_assign, not q_i.
                std::cout << -1 << "\n";
                return;
            }
            p[i] = num_to_assign;
        }
    }

    // Final check: ensure all p_i are distinct and within [1, n]
    // This is implicitly handled by `used_numbers` and `available_numbers` logic.
    // Also, check if the reconstructed p generates the given q.
    // This is also implicitly handled by the construction logic.
    // The only remaining check is if we used all available numbers and didn't run out.
    if (!available_numbers.empty()) {
        // This should not happen if the input q is valid and n is correct.
        // It implies there were too many available numbers for the placeholders.
        // Or, more likely, an earlier check for -1 was missed.
        // Given the problem constraints and guarantees, this path should not be hit
        // if the previous checks are correct.
        // However, if it does, it means an invalid state.
        std::cout << -1 << "\n";
        return;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
