int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_R_pos = -1; // Represents the last 'R' cell visited, or -1 for cell 0.
                             // The actual cell index is last_R_pos + 1.
                             // So, if last_R_pos = -1, it means we are at cell 0.
                             // If last_R_pos = 2, it means we are at cell 3 (s[2] is 'R').

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at cell i+1.
                // The previous 'R' (or start 0) was at last_R_pos + 1.
                // The gap is (current cell index) - (previous cell index).
                // This is (i+1) - (last_R_pos + 1) = i - last_R_pos.
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R'
        // to the target cell n+1.
        // The last 'R' was at cell last_R_pos + 1.
        // The target is cell n+1.
        // The gap is (n+1) - (last_R_pos + 1) = n - last_R_pos.
        max_gap = std::max(max_gap, n - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

