    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                balance++;
            }
        } else { // c == ')'
            if (close_needed > 0 && balance > 0) {
                result += ')';
                close_needed--;
                balance--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the partition where Class 1 takes the first n elements
        // and Class 2 takes the last n elements.
        // This is not a valid partition because n can be even,
        // and classes must have an odd number of students.
        //
        // However, the key insight is that to minimize the difference between medians,
        // we should pick medians that are "close" in the sorted array.
        //
        // Let the two classes be C1 and C2.
        // Let |C1| = 2k1 + 1 and |C2| = 2k2 + 1.
        // We know (2k1 + 1) + (2k2 + 1) = 2n, which simplifies to 2k1 + 2k2 + 2 = 2n,
        // or k1 + k2 + 1 = n.
        //
        // The median of C1 will be its (k1+1)-th smallest element.
        // The median of C2 will be its (k2+1)-th smallest element.
        //
        // To minimize the difference, we want to pick elements for C1 and C2
        // such that their medians are as close as possible.
        //
        // Consider the elements a[n-1] and a[n].
        // If we can make a[n-1] the median of one class and a[n] the median of the other,
        // this would give a difference of a[n] - a[n-1].
        //
        // Can we always achieve this?
        //
        // Let's try to make a[n-1] the median of Class 1 and a[n] the median of Class 2.
        //
        // For a[n-1] to be the median of Class 1:
        // Class 1 must have 2k1+1 elements.
        // a[n-1] must be the (k1+1)-th element.
        // This means there must be k1 elements smaller than or equal to a[n-1] in C1,
        // and k1 elements greater than or equal to a[n-1] in C1.
        //
        // For a[n] to be the median of Class 2:
        // Class 2 must have 2k2+1 elements.
        // a[n] must be the (k2+1)-th element.
        // This means there must be k2 elements smaller than or equal to a[n] in C2,
        // and k2 elements greater than or equal to a[n] in C2.
        //
        // The simplest way to achieve this is to make k1 = 0 and k2 = n-1.
        // In this case, |C1| = 2*0 + 1 = 1. The median is its only element.
        // |C2| = 2*(n-1) + 1 = 2n - 1. The median is its (n-1+1)-th = n-th element.
        //
        // If we choose C1 = {a[n-1]} (size 1, median a[n-1]),
        // and C2 = {all other 2n-1 elements}.
        // The elements in C2 would be a[0], ..., a[n-2], a[n], ..., a[2n-1].
        // If we sort C2, its n-th element would be a[n].
        // This is a valid partition.
        //
        // The difference would be |a[n] - a[n-1]|.
        // Since the array is sorted, a[n] >= a[n-1], so the difference is a[n] - a[n-1].
        //
        // Is it possible to get a smaller difference?
        //
        // Consider any two medians, M1 and M2, from a valid partition.
        // Let M1 be the median of C1 and M2 be the median of C2.
        //
        // C1 has 2k1+1 elements. M1 is the (k1+1)-th element.
        // C2 has 2k2+1 elements. M2 is the (k2+1)-th element.
        //
        // There are at least k1 elements in C1 that are <= M1.
        // There are at least k1 elements in C1 that are >= M1.
        //
        // There are at least k2 elements in C2 that are <= M2.
        // There are at least k2 elements in C2 that are >= M2.
        //
        // Total elements <= M1 (or M2) + total elements >= M1 (or M2) must be 2n.
        //
        // Without loss of generality, assume M1 <= M2.
        //
        // The elements in the original sorted array are a_0, ..., a_{2n-1}.
        //
        // M1 must be one of the a_i's. M2 must be one of the a_j's.
        //
        // There are at least k1+1 elements in C1 that are <= M1.
        // There are at least k2+1 elements in C2 that are >= M2.
        //
        // So, there are at least (k1+1) elements in the entire set that are <= M1.
        // And there are at least (k2+1) elements in the entire set that are >= M2.
        //
        // This means M1 must be at least a[k1].
        // And M2 must be at most a[2n - 1 - k2].
        //
        // Also, there are at least k1 elements in C1 that are >= M1.
        // And there are at least k2 elements in C2 that are <= M2.
        //
        // The total number of elements is 2n.
        // The sum of elements less than or equal to M1 and elements greater than or equal to M2
        // must be at least (k1+1) + (k2+1).
        //
        // We know k1 + k2 + 1 = n.
        // So (k1+1) + (k2+1) = k1 + k2 + 2 = n + 1.
        //
        // This means there are at least n+1 distinct elements in the original array
        // that are either <= M1 or >= M2.
        //
        // If M1 = a[i] and M2 = a[j], with i <= j.
        //
        // The elements a[0], ..., a[i] are <= a[i].
        // The elements a[j], ..., a[2n-1] are >= a[j].
        //
        // The number of elements <= a[i] is i+1.
        // The number of elements >= a[j] is 2n-j.
        //
        // We need to ensure that there are enough elements for the medians.
        //
        // The median of C1, M1, must be at least a[k1].
        // The median of C2, M2, must be at least a[k2] if C2 is formed from the lower part of the array.
        // Or M2 must be at least a[n + k2] if C2 is formed from the upper part of the array.
        //
        // The crucial observation is that the median of a set of 2k+1 numbers is the (k+1)-th smallest.
        //
        // Consider the elements a[n-1] and a[n].
        //
        // If we pick a[n-1] as the median of C1, then C1 must have at least n-1 elements smaller than or equal to a[n-1]
        // and at least n-1 elements greater than or equal to a[n-1].
        // This is not correct. If a[n-1] is the median of C1, and |C1| = 2k1+1, then
        // there are k1 elements <= a[n-1] in C1, and k1 elements >= a[n-1] in C1.
        //
        // The total number of elements is 2n.
        // The elements a[0], ..., a[n-1] are the first n elements.
        // The elements a[n], ..., a[2n-1] are the last n elements.
        //
        // If we choose a[n-1] as the median of one class (say C1) and a[n] as the median of the other class (C2).
        //
        // For C1, we need to pick 2k1+1 elements such that a[n-1] is the (k1+1)-th element.
        // For C2, we need to pick 2k2+1 elements such that a[n] is the (k2+1)-th element.
        //
        // The simplest partition that achieves this is:
        // C1 = {a[n-1]} (k1=0, size 1, median a[n-1])
        // C2 = {a[0], ..., a[n-2], a[n], ..., a[2n-1]} (k2=n-1, size 2n-1, median a[n])
        //
        // This partition is always valid.
        // The difference is a[n] - a[n-1].
        //
        // Can we do better?
        // Suppose we have a partition with medians M1 and M2, and M1 <= M2.
        //
        // M1 is the (k1+1)-th element of C1.
        // M2 is the (k2+1)-th element of C2.
        //
        // There are at least k1+1 elements in C1 that are <= M1.
        // There are at least k2+1 elements in C2 that are >= M2.
        //
        // These two sets of elements are disjoint.
        // So, in the original array, there are at least (k1+1) elements <= M1
        // AND at least (k2+1) elements >= M2.
        //
        // This implies that M1 must be at least a[k1].
        // And M2 must be at most a[2n - 1 - k2].
        //
        // We know k1 + k2 + 1 = n.
        // So k1 = n - 1 - k2.
        //
        // Thus, M1 >= a[n - 1 - k2].
        // And M2 <= a[2n - 1 - k2].
        //
        // The difference M2 - M1 >= a[2n - 1 - k2] - a[n - 1 - k2].
        //
        // Let x = n - 1 - k2.
        // Then M2 - M1 >= a[x + n] - a[x].
        //
        // Since k2 can range from 0 to n-1 (because 2k2+1 <= 2n-1, so k2 <= n-1),
        // x can range from n-1 down to 0.
        //
        // So we are looking for min(a[x+n] - a[x]) for x from 0 to n-1.
        //
        // The minimum value of a[j] - a[i] for j-i = n is achieved when i=n-1 and j=n.
        // No, this is not correct.
        //
        // The difference is M2 - M1.
        // We have M1 >= a[k1] and M2 <= a[2n - 1 - k2].
        //
        // The indices are 0-based.
        // The (k1+1)-th element in a sorted array is at index k1.
        // The (k2+1)-th element in a sorted array is at index k2.
        //
        // Let's re-evaluate the indices.
        // If M1 is the median of C1, and |C1|=2k1+1, then M1 is the (k1+1)-th element of C1.
        // If M2 is the median of C2, and |C2|=2k2+1, then M2 is the (k2+1)-th element of C2.
        //
        // The elements of C1 are a subset of the original 2n elements.
        // The elements of C2 are a subset of the original 2n elements.
        //
        // Consider the elements a[0], ..., a[n-1] and a[n], ..., a[2n-1].
        //
        // The median of the first n elements (if n is odd) would be a[(n-1)/2].
        // The median of the last n elements (if n is odd) would be a[n + (n-1)/2].
