// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: (-inf, -1]
    // Final product must be negative and magnitude >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // Initial negative factors come from A and B.
    // A toy from Box 1 (x <= -1)
    // A toy from Box 2 (-1 < x < 0)
    // A toy from Box 3 (0 < x < 1)
    // A toy from Box 4 (x >= 1)

    // If A+B is odd, the final sign can be negative.
    // If A+B is even, the final sign can be positive.

    // To get a negative result, (A+B) must be odd.
    // If A+B is even, we can't get a negative result unless we can manipulate the signs.
    // A negative * negative = positive.
    // A negative * positive = negative.
    // If we have an even number of initial negatives, we can always pair them up to get positives.
    // If we have an odd number of initial negatives, we will always end up with one negative.

    // So, for a negative result, (A+B) must be odd.
    if ((A + B) % 2 == 0) {
        return false; // Cannot be negative
    }

    // Now, we need the magnitude to be >= 1.
    // We have an odd number of negative toys.
    // We need to ensure we can make the magnitude >= 1.

    // If A > 0, we have at least one toy with magnitude >= 1.
    // If D > 0, we have at least one toy with magnitude >= 1.
    // If A + D > 0, we have at least one toy with magnitude >= 1.
    // If A + D == 0, all initial toys have magnitude < 1 (from B and C).
    // If A + D == 0, and B + C > 0, then all products will have magnitude < 1.
    // So, if A + D == 0, we cannot get magnitude >= 1.
    if (A + D == 0) {
        return false;
    }

    // If A+B is odd and A+D > 0, it is possible.
    // We can always pick values such that the magnitude grows or stays large.
    // Example: Pick a large negative from A, and a large positive from D.
    // Or pick a large negative from A, and a small negative from B to make a small positive, then multiply with a large positive from D.
    // The key is that if there's at least one toy with magnitude >= 1 (from A or D),
    // and we have an odd number of negatives, we can arrange multiplications to keep the magnitude >= 1.
    // For example, if we have a toy with value -2 (from A) and a toy with value 0.5 (from C).
    // We can choose -2 * 0.5 = -1. This is in Box 1.
    // If we have -2 (A), -0.5 (B), 0.5 (C), 2 (D).
    // (A+B) is even.
    // If (A+B) is odd:
    // Example: -2 (A), -0.5 (B), -0.5 (B), 0.5 (C), 2 (D)
    // A=1, B=2, C=1, D=1. A+B=3 (odd). A+D=2 (>0).
    // We can pick -2, -0.5, -0.5, 0.5, 2.
    // (-0.5) * (-0.5) = 0.25 (Box 3)
    // (-2) * 0.25 = -0.5 (Box 2)
    // (-0.5) * 2 = -1 (Box 1)
    // -1 * 0.5 = -0.5 (Box 2)
    // This shows it's not just about A+D > 0.

    // Let's re-evaluate the magnitude condition.
    // To get magnitude >= 1, we need at least one initial toy from Box 1 or Box 4.
    // If A+D == 0, all initial toys are from Box 2 or Box 3. All products will have magnitude < 1.
    // So, if A+D == 0, Box 1 is impossible. This is correct.

    // If A+B is odd and A+D > 0, can we always make it Box 1?
    // Yes. We can always pick values such that the magnitude condition is met.
    // For example, if A > 0, pick a toy with value -100.
    // If D > 0, pick a toy with value 100.
    // If we have A+D > 0, we can always ensure that at least one toy has magnitude >= 1.
    // We can always make the final product have magnitude >= 1 by picking appropriate values.
    // For example, if A > 0, we can set one toy to -100. All other toys can be set to values like 0.1, 0.2, etc.
    // The product of all other toys will be some value X.
    // The final product will be -100 * X.
    // If X is positive, we need X to be small enough to keep the sign negative.
    // If X is negative, we need X to be small enough to keep the sign negative.
    // This is about existence of values, not about specific values.

    // The condition for Box 1 is:
    // 1. (A+B) must be odd (for negative sign).
    // 2. A+D must be > 0 (to allow magnitude >= 1).
    return (A + B) % 2 == 1 && (A + D > 0);
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: (-1, 0)
    // Final product must be negative and magnitude < 1.

    // Condition 1: Negative sign. (A+B) must be odd.
    if ((A + B) % 2 == 0) {
        return false;
    }

    // Condition 2: Magnitude < 1.
    // This is always possible if there's at least one toy.
    // We can set all toy values to be very small (e.g., -0.1, 0.1).
    // If A+D > 0, we can still make the magnitude < 1.
    // Example: A=1, B=0, C=0, D=0. Toy is -0.5. Box 2.
    // Example: A=1, B=0, C=0, D=1. Toys are -0.5, 0.5. Product -0.25. Box 2.
    // Example: A=1, B=0, C=0, D=1. Toys are -2, 0.1. Product -0.2. Box 2.
    // The only case where it's impossible to get magnitude < 1 is if A+B+C+D == 0, but the problem states A+B+C+D > 0.
    // So, if (A+B) is odd, Box 2 is always possible.
    return true;
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Final product must be positive and magnitude < 1.

    // Condition 1: Positive sign. (A+B) must be even.
    if ((A + B) % 2 == 1) {
        return false;
    }

    // Condition 2: Magnitude < 1.
    // This is always possible if there's at least one toy.
    // We can set all toy values to be very small (e.g., -0.1, 0.1).
    // If A+D > 0, we can still make the magnitude < 1.
    // Example: A=0, B=0, C=1, D=0. Toy is 0.5. Box 3.
    // Example: A=0, B=0, C=1, D=1. Toys are 0.5, 0.5. Product 0.25. Box 3.
    // Example: A=0, B=0, C=1, D=1. Toys are 0.1, 2. Product 0.2. Box 3.
    // So, if (A+B) is even, Box 3 is always possible.
    return true;
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Final product must be positive and magnitude >= 1.

    // Condition 1: Positive sign. (A+B) must be even.
    if ((A + B) % 2 == 1) {
        return false;
    }

    // Condition 2: Magnitude >= 1.
    // This requires at least one initial toy from Box 1 or Box 4.
    // If A+D == 0, all initial toys are from Box 2 or Box 3. All products will have magnitude < 1.
    // So, if A+D == 0, Box 4 is impossible.
    if (A + D == 0) {
        return false;
    }

    // If A+B is even and A+D > 0, it is possible.
    // We can always pick values such that the magnitude grows or stays large.
    // For example, if A > 0, pick a toy with value -100.
    // If D > 0, pick a toy with value 100.
    // If A+D > 0, we can always ensure that at least one toy has magnitude >= 1.
    // We can always make the final product have magnitude >= 1 by picking appropriate values.
    // For example, if A > 0, we can set one toy to -100. If B is also present, set one toy to -0.01.
    // Product is 1. This is in Box 4.
    // If A=1, B=1, C=0, D=0. A+B=2 (even). A+D=1 (>0).
    // Toys: -100, -0.01. Product 1. Box 4.
    // This is possible.
    return (A + B) % 2 == 0 && (A + D > 0);
}

