#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i] as the leftmost point of a potential triplet,
        // find the rightmost point x[right_ptr] such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, all points x[j] where i < j < right_ptr will also satisfy x[j] - x[i] <= d.
        // The right_ptr only moves forward, making this O(N) overall.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }

        // Now, all points from x[i+1] to x[right_ptr-1] can be the middle or rightmost point
        // of a valid triplet starting with x[i].
        // The number of points available to choose from (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1
        // which simplifies to right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points to form a triplet with x[i].
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = static_cast<long long>(right_ptr - 1 - i);

        if (m >= 2) { // We need at least 2 points to choose from
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Cost for elements to the left of the median
    // These must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Cost for elements to the right of the median
    // These must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& max_val_prefix, const std::vector<int>& distinct_count_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    return max_val_prefix[len - 1] == len && distinct_count_prefix[len - 1] == len;
}

// Function to check if a suffix is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_val_suffix, const std::vector<int>& distinct_count_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    return max_val_suffix[n - len] == len && distinct_count_suffix[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_val_prefix(n);
    std::vector<int> distinct_count_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_distinct_prefix = 0;
    int current_max_prefix = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // Value out of range or duplicate
            // Mark as invalid for permutation check
            max_val_prefix[i] = n + 1; // Sentinel value indicating invalidity
            distinct_count_prefix[i] = 0; // Sentinel value
        } else {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
            current_max_prefix = std::max(current_max_prefix, a[i]);
            max_val_prefix[i] = current_max_prefix;
            distinct_count_prefix[i] = current_distinct_prefix;
        }
    }

    // Precompute for suffixes
    std::vector<int> max_val_suffix(n);
    std::vector<int> distinct_count_suffix(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reset seen array
    int current_distinct_suffix = 0;
    int current_max_suffix = 0;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // Value out of range or duplicate
            // Mark as invalid for permutation check
            max_val_suffix[i] = n + 1; // Sentinel value indicating invalidity
            distinct_count_suffix[i] = 0; // Sentinel value
        } else {
            seen_prefix[a[i]] = true;
            current_distinct_suffix++;
            current_max_suffix = std::max(current_max_suffix, a[i]);
            max_val_suffix[i] = current_max_suffix;
            distinct_count_suffix[i] = current_distinct_suffix;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 from 1 to n-1
        int l2 = n - l1;
        if (is_permutation_prefix(l1, a, max_val_prefix, distinct_count_prefix) &&
            is_permutation_suffix(l2, n, a, max_val_suffix, distinct_count_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // Create the result array A'
    // The i-th smallest B value should be paired with the i-th largest A value.
    // This means b_elements[i] (which is the i-th smallest B)
    // should be paired with a_elements[m - 1 - i] (which is the i-th largest A).
    // The original index of b_elements[i] tells us where in the output array A'
    // the value a_elements[m - 1 - i].value should go.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        long long current_score = 0;
        int win_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                win_count++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (win_count == 0) { // All L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (std::min((long long)n, k) - 1) << "\n";
            }
            continue;
        }

        // If k is 0, no changes can be made, output current score
        if (k == 0) {
            std::cout << current_score << "\n";
            continue;
        }

        // Find the first and last 'W'
        int first_w = -1;
        int last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        // Collect lengths of 'L' segments between 'W's
        std::vector<int> l_segments;
        int current_l_length = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_l_length++;
            } else { // s[i] == 'W'
                if (current_l_length > 0) {
                    l_segments.push_back(current_l_length);
                }
                current_l_length = 0;
            }
        }
        std::sort(l_segments.begin(), l_segments.end());

        // Fill 'L' segments between 'W's
        for (int len : l_segments) {
            if (k >= len) {
                k -= len;
                current_score += 2 * len + 1; // Each L becomes W, connecting two W blocks.
                                              // The first W in the new block gets 1 point,
                                              // but it connects to a previous W, so it becomes 2.
                                              // The last W in the new block connects to a next W, so it becomes 2.
                                              // All intermediate Ws get 2.
                                              // Effectively, each L converted to W adds 2 points,
                                              // and the connection itself adds 1 point (from 1 to 2 for the W after the L block).
                                              // Example: W L L W -> W W W W.
                                              // Score change: (1+2) -> (1+2+2+2). Diff = 4.
                                              // Ls = 2. 2*2 + 1 = 5. This is wrong.
                                              //
                                              // Let's re-evaluate:
                                              // W L W -> W W W.
                                              // Score before: 1 (for first W) + 1 (for second W) = 2.
                                              // Score after: 1 (for first W) + 2 (for second W) + 2 (for third W) = 5.
                                              // Change = 3.
                                              // len = 1. k -= 1.
                                              // The 'L' becomes 'W'. It connects two 'W's.
                                              // The 'W' before the 'L' was giving 1 or 2. The 'W' after the 'L' was giving 1 or 2.
                                              // When 'L' becomes 'W', it gets 2 points (as it's surrounded by Ws).
                                              // The 'W' before it now has a 'W' after it, so if it was 1, it becomes 2. (+1)
                                              // The 'W' after it now has a 'W' before it, so if it was 1, it becomes 2. (+1)
                                              // Total gain: 2 (for new W) + 1 (for left W) + 1 (for right W) = 4.
                                              // This is for a single L.
                                              //
                                              // For a block of `len` L's: W L...L W (len L's)
                                              // All `len` L's become W's. This adds `2 * len` points.
                                              // The W immediately to the right of the block (s[i+len]) now has a W before it.
                                              // If it was getting 1 point (because s[i-1] was L), it now gets 2 points. This is a +1 gain.
                                              // The W immediately to the left of the block (s[i-1]) already had a W after it (the first L converted).
                                              // So, the total gain is `2 * len + 1`.
                                              // This is correct.
            } else {
                current_score += 2 * k;
                k = 0;
                break;
            }
        }

        // Fill 'L' segments at the ends
        // Left end: L...LW...
        int left_l_count = first_w;
        if (k > 0 && left_l_count > 0) {
            long long to_change = std::min((long long)left_l_count, k);
            current_score += 2 * to_change; // Each L becomes W, connecting to the first W.
                                            // The first W (s[first_w]) already gives 1 point.
                                            // If we convert Ls before it, they will connect to it.
                                            // The first L converted will get 1 point (as it's the new first W).
                                            // Subsequent Ls converted will get 2 points.
                                            // This is equivalent to 1 + 2*(to_change-1) if first_w was 0.
                                            // But here, first_w is already a W.
                                            // So, if we convert L L W -> W W W.
                                            // Score before: 1 (for W)
                                            // Score after: 1 (for first W) + 2 (for second W) + 2 (for third W) = 5.
                                            // Gain = 4.
                                            // to_change = 2. 2 * to_change = 4. This is correct.
            k -= to_change;
        }

        // Right end: ...WL...L
        int right_l_count = n - 1 - last_w;
        if (k > 0 && right_l_count > 0) {
            long long to_change = std::min((long long)right_l_count, k);
            current_score += 2 * to_change; // Each L becomes W, connecting to the last W.
                                            // The last W (s[last_w]) already gives 2 points if s[last_w-1] was W, or 1 if L.
                                            // If we convert W L L -> W W W.
                                            // Score before: 1 (for W)
                                            // Score after: 1 (for first W) + 2 (for second W) + 2 (for third W) = 5.
                                            // Gain = 4.
                                            // to_change = 2. 2 * to_change = 4. This is correct.
            k -= to_change;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
