int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute 'count_a' steps
            // to move past this 'b' (and generate a new 'b').
            // The 'count_a' itself doubles because each 'a' effectively
            // becomes 'ab' (conceptually, after the 'b' is processed).
            // So, 'count_a' is the number of 'a's that are currently
            // "active" and need to be processed.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the count of 'a's
            // that are waiting to be processed by 'b's to their right.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends who get w_i = 1 items:
    // These friends contribute 2 * (largest available number) to happiness.
    // To maximize, they should get the largest numbers.
    // These are the friends with the smallest w_i values (after sorting w).
    int a_ptr_max = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += a[a_ptr_max] * 2;
            a_ptr_max--;
        } else {
            // All remaining w[i] will be > 1.
            // We can break because w is sorted, so if w[i] > 1, then w[i-1]...w[0] are also > 1.
            // This is incorrect. w is sorted, so w[0]...w[i] are <= w[i].
            // If w[i] > 1, then w[i-1] could be 1.
            // The loop should continue to process all w[i] == 1.
            // The current logic correctly processes w[i] == 1 from largest w_idx to smallest.
            // So, if w[i] > 1, it means all w[i+1]...w[k-1] were already processed (and were 1).
            // The remaining friends (w[0]...w[i]) all have w_j > 1.
            break; 
        }
    }

    // Friends who get w_i > 1 items:
    // These friends contribute (max_val + min_val) to happiness.
    // To maximize, they should get the largest available numbers as max_val,
    // and the smallest available numbers as min_val.
    // The largest w_i values (after sorting w) should get the largest numbers as max_val.
    // The smallest w_i values (after sorting w) should get the smallest numbers as min_val.

    // The friends with w_i > 1 are those remaining after the first loop.
    // They are w[0]...w[idx_first_w_greater_than_1 - 1].
    // Let's re-evaluate the loop for w_i = 1.
    // It's better to separate friends into two groups: w_i = 1 and w_i > 1.

    std::vector<int> w_one;
    std::vector<int> w_multi;
    for (int val : w) {
        if (val == 1) {
            w_one.push_back(val);
        } else {
            w_multi.push_back(val);
        }
    }

    // Process friends with w_i = 1 first. They take the largest available numbers.
    // These are the largest 'a' values.
    a_ptr_max = n - 1;
    for (int i = 0; i < w_one.size(); ++i) {
        total_happiness += a[a_ptr_max] * 2;
        a_ptr_max--;
    }

    // Process friends with w_i > 1.
    // These friends need one largest available number (for max_val)
    // and one smallest available number (for min_val).
    // The remaining w_i - 2 numbers can be any other numbers.
    // To maximize sum of happiness, we give the largest remaining 'a' values as max_val.
    // And the smallest remaining 'a' values as min_val.

    // Sort w_multi in descending order to assign largest max_val to friends who need more numbers.
    // This is not strictly necessary for max_val, as each friend gets one max_val.
    // But it is necessary for min_val.
    // The friends with larger w_i values will "consume" more numbers from the middle,
    // leaving the smallest numbers for friends with smaller w_i values.
    std::sort(w_multi.rbegin(), w_multi.rend()); // Sort in descending order

    int a_ptr_min = 0;
    for (int i = 0; i < w_multi.size(); ++i) {
        // Each friend with w_i > 1 gets one largest available number as their max_val.
        total_happiness += a[a_ptr_max];
        a_ptr_max--;

        // Each friend with w_i > 1 gets one smallest available number as their min_val.
        // The friend with the largest w_i (from w_multi, which is w_multi[0])
        // will consume w_multi[0] - 1 numbers from the smallest available numbers.
        // The smallest w_i (from w_multi, which is w_multi[w_multi.size()-1])
        // will consume w_multi[w_multi.size()-1] - 1 numbers from the smallest available numbers.
        // To maximize sum of happiness, we want to give the smallest possible numbers as min_val.
        // The friend who needs w_i numbers will take one max_val, one min_val, and w_i-2 other numbers.
        // The w_i-2 other numbers should be the smallest available numbers after the min_val.
        // So, the friend with w_multi[i] will take a[a_ptr_min] as their min_val,
        // and then consume w_multi[i] - 1 additional numbers from a_ptr_min onwards.
        // This means a_ptr_min advances by w_multi[i] - 1.
        total_happiness += a[a_ptr_min];
        a_ptr_min += (w_multi[i] - 1); // Consume w_i - 1 numbers from the smallest end
    }

    std::cout << total_happiness << std::endl;
}

