int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = 2000000000LL; // k can be up to 10^4, a_i up to k. Max sum of k is 10^4.
                                         // min_val will be at most k.
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself, and we use min_idx as source.
                          // The problem states i != j.
                          // We are effectively copying from a[min_idx] to a[i].
                          // If i == min_idx, we can't copy a[min_idx] to a[min_idx].
                          // The source pile a[min_idx] remains unchanged.
                          // We are interested in how many times we can add a[min_idx] to OTHER piles.
            }
            // For each other pile a[i], how many times can we add min_val to it?
            // a[i] + x * min_val <= k
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            // Since x must be an integer, x = floor((k - a[i]) / min_val)
            if (min_val > 0) { // min_val is guaranteed to be >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

