#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<int> fixed_char(k, -1); // -1 for unknown, 0 for '0', 1 for '1'

    for (int i = 0; i < n; ++i) {
        int current_char_val;
        if (s[i] == '0') {
            current_char_val = 0;
        } else if (s[i] == '1') {
            current_char_val = 1;
        } else { // s[i] == '?'
            current_char_val = -1;
        }

        int remainder = i % k;
        if (fixed_char[remainder] == -1) {
            fixed_char[remainder] = current_char_val;
        } else if (current_char_val != -1 && fixed_char[remainder] != current_char_val) {
            // Conflict: s[i] is '0' or '1', but fixed_char[remainder] is already set to the opposite
            std::cout << "NO\n";
            return;
        }
        // If current_char_val is -1, fixed_char[remainder] remains as is.
        // If current_char_val is 0 or 1 and fixed_char[remainder] is already set to the same, no change needed.
    }

    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_char[i] == 0) {
            count0++;
        } else if (fixed_char[i] == 1) {
            count1++;
        }
    }

    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means the first k characters can be made consistent with the k-periodicity.
    // The remaining '?'s can be filled to satisfy the k/2 condition.
    // Since count0 <= k/2 and count1 <= k/2, and count0 + count1 <= k,
    // we can always fill the remaining (k - count0 - count1) '?'s with (k/2 - count0) '0's and (k/2 - count1) '1's.
    // This ensures the first block of k characters has k/2 zeros and k/2 ones.
    // Due to the k-periodicity, all subsequent blocks of k characters will also have k/2 zeros and k/2 ones.
    std::cout << "YES\n";
}

