#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, so use long long.
    // We need to perform division by 2. Since MOD is prime and > 2,
    // we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r must be > 0. So no nice integers.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long inv2 = 500000004; // Modular inverse of 2 mod 10^9 + 7
        sum_r_val = (b_minus_1 % MOD * (b % MOD)) % MOD;
        sum_r_val = (sum_r_val * inv2) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k is a * (a+1) / 2
    long long sum_k_term_val;
    long long a_plus_1 = a + 1;
    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9 + 7

    long long sum_k_val = (a % MOD * (a_plus_1 % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = a % MOD;
    sum_k_term_val = (term1 + term2) % MOD;

    // Total sum = (sum_r_val * sum_k_term_val) % MOD
    long long total_sum = (sum_r_val * sum_k_term_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

