                    //
                    // Option 1: Chanek takes 1.
                    // N becomes N-1 (odd). Opponent's turn.
                    // Opponent will take 1, N becomes N-2 (even).
                    // Then it's Chanek's turn with N-2 coins.
                    //
                    // Option 2: Chanek takes N/2.
                    // N becomes N/2 (could be even or odd). Opponent's turn.
                    //
                    // Consider the parity of N/2.
                    if ((n / 2) % 2 != 0) { // N/2 is odd
                        // If Chanek takes N/2, remaining N/2 is odd.
                        // Opponent will take 1.
                        // This seems like a good move for Chanek, as it leaves an odd number for the opponent.
                        chanek_coins += n / 2;
                        n /= 2;
                    } else { // N/2 is even
                        // If Chanek takes N/2, remaining N/2 is even.
                        // Opponent might take N/4.
                        // In this scenario, taking 1 might be better for Chanek.
                        // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                        // If Chanek takes N/2, N becomes N/2 (even). Opponent takes N/4. N becomes N/4 (even).
                        //
                        // The optimal strategy for Chanek when N is even and N/2 is even:
                        // Chanek takes 1. N becomes N-1.
                        // Opponent takes 1. N becomes N-2.
                        // This ensures Chanek gets 1 coin and the opponent gets 1 coin, and the game continues with N-2.
                        // This is generally better than taking N/2 if N/2 is even, because taking N/2
                        // would give the opponent a chance to take N/4, which might be a large chunk.
                        // By taking 1, Chanek forces the opponent to also take 1 (since N-1 is odd),
                        // effectively splitting the "small" coins.
                        chanek_coins += 1;
                        n -= 1;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if (n == 2) { // Special case: if N=2, opponent takes 1
                    n -= 1;
                } else {
                    // Opponent wants to maximize their own coins, which means minimizing Chanek's coins.
                    // If N/2 is odd, opponent takes N/2. This leaves an odd number for Chanek.
                    // If N/2 is even, opponent takes N/2. This leaves an even number for Chanek.
                    // Opponent will always prefer to take N/2 if N is even, because it's a larger amount.
                    // The only exception is if taking 1 leads to a better outcome for the opponent,
                    // but in this greedy game, taking the largest possible amount is usually optimal.
                    // Taking N/2 is always better for the opponent than taking 1 if N > 2.
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

