#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are placed, they divide the zeros into m+1 potential blocks.
        // To minimize substrings of all zeros, we want to make these blocks as equal as possible.
        // The number of blocks of zeros that are non-empty is at most m+1.
        // We distribute num_zeros among m+1 blocks.
        // Let k be the number of zeros in each of the larger blocks.
        // Let k-1 be the number of zeros in each of the smaller blocks.
        // Let r be the number of larger blocks (each of size k).
        // Then (m+1 - r) is the number of smaller blocks (each of size k-1).
        // num_zeros = r * k + (m+1 - r) * (k-1)
        // num_zeros = r * k + (m+1) * (k-1) - r * (k-1)
        // num_zeros = r * k + (m+1) * (k-1) - r * k + r
        // num_zeros = (m+1) * (k-1) + r
        // So, k-1 = num_zeros / (m+1) (integer division)
        // And r = num_zeros % (m+1)

        long long k_minus_1 = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);

        long long k = k_minus_1 + 1; // Size of larger blocks
        long long num_larger_blocks = r;
        long long num_smaller_blocks = (m + 1) - r; // Size of smaller blocks is k-1

        // Calculate substrings of all zeros from these blocks
        long long substrings_of_zeros = 0;
        if (k_minus_1 >= 0) { // Ensure k-1 is non-negative
            substrings_of_zeros += num_smaller_blocks * (k_minus_1 * (k_minus_1 + 1) / 2);
        }
        if (k >= 0) { // Ensure k is non-negative
            substrings_of_zeros += num_larger_blocks * (k * (k + 1) / 2);
        }

        // The maximum f(s) is total_substrings - minimum_substrings_of_zeros
        std::cout << total_substrings - substrings_of_zeros << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance for the whole array
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Precompute balances for prefixes of the left side (jars 1 to n)
    // and suffixes of the right side (jars n+1 to 2n)
    std::map<int, int> left_balance_to_k; // balance -> k (number of jars removed from left)
    left_balance_to_k[0] = 0; // If 0 jars are removed from left, balance is 0

    int current_balance_left = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar n-k+1 is the k-th jar from the right end of the left half
        // or (n-k)-th jar from the left end of the left half (0-indexed)
        // We are considering removing k jars from the left, so we are interested in jars a[n-1], a[n-2], ..., a[n-k]
        // The balance is calculated from right to left for the left half
        // a[n-1] is the first jar to the left of the stairs
        // a[n-2] is the second jar to the left of the stairs
        // ...
        // a[n-k] is the k-th jar to the left of the stairs

        // When we remove k jars from the left, we are considering the prefix a[0...n-k-1]
        // The balance of the *removed* jars is what we need.
        // Let's rephrase: we are interested in the balance of the jars *kept* on the left side.
        // If we remove k jars from the left (a[0]...a[k-1]), the remaining left jars are a[k]...a[n-1].
        // This is not what the problem implies.
        // The problem says "empty either the first non-empty jar to his left or the first non-empty jar to his right".
        // This means he removes jars from the ends of the *remaining* sequence.
        // So, if he removes `k_L` jars from the left, he removes `a[n-1], a[n-2], ..., a[n-k_L]`.
        // If he removes `k_R` jars from the right, he removes `a[n], a[n+1], ..., a[n+k_R-1]`.

        // Let's calculate the balance of the jars *removed* from the left side.
        // Jars removed from left: a[n-1], a[n-2], ..., a[n-k]
        // The balance of these k jars is what we need.
        // current_balance_left will store the balance of jars a[n-1], a[n-2], ..., a[n-k]
        if (a[n - k] == 1) { // a[n-k] is the k-th jar from the right end of the left half
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        // Store the number of jars removed (k) for this balance
        // If multiple k values result in the same balance, we want the smallest k (which is the first one encountered)
        if (left_balance_to_k.find(current_balance_left) == left_balance_to_k.end()) {
            left_balance_to_k[current_balance_left] = k;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Case 1: Remove only from the left side (k_R = 0)
    // The remaining jars are a[0]...a[n-k_L-1] and a[n]...a[2n-1].
    // The balance of the *remaining* jars must be 0.
    // Initial balance of all 2n jars is `initial_balance`.
    // If we remove `k_L` jars from the left (a[n-1]...a[n-k_L]), their balance is `current_balance_left`.
    // The balance of the remaining jars is `initial_balance - current_balance_left`.
    // We want `initial_balance - current_balance_left = 0`, so `current_balance_left = initial_balance`.
    if (left_balance_to_k.count(initial_balance)) {
        min_removed_jars = std::min(min_removed_jars, left_balance_to_k[initial_balance]);
    }

    // Case 2: Remove only from the right side (k_L = 0)
    // The remaining jars are a[0]...a[n-1] and a[n+k_R]...a[2n-1].
    // We need to iterate through possible k_R values.
    int current_balance_right = 0;
    for (int k = 1; k <= n; ++k) {
        // Jars removed from right: a[n], a[n+1], ..., a[n+k-1]
        // current_balance_right will store the balance of jars a[n], a[n+1], ..., a[n+k-1]
        if (a[n + k - 1] == 1) { // a[n+k-1] is the k-th jar from the left end of the right half
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        // The balance of the remaining jars is `initial_balance - current_balance_right`.
        // We want `initial_balance - current_balance_right = 0`, so `current_balance_right = initial_balance`.
        if (current_balance_right == initial_balance) {
            min_removed_jars = std::min(min_removed_jars, k);
        }
    }

    // Case 3: Remove from both sides (k_L > 0 and k_R > 0)
    // The balance of the remaining jars is `initial_balance - (balance of removed left jars) - (balance of removed right jars)`.
    // We want this to be 0.
    // So, `(balance of removed left jars) + (balance of removed right jars) = initial_balance`.
    // Let `bal_L` be the balance of `k_L` jars removed from left.
    // Let `bal_R` be the balance of `k_R` jars removed from right.
    // We need `bal_L + bal_R = initial_balance`.
    // This means `bal_R = initial_balance - bal_L`.

    current_balance_right = 0; // Reset for right side iteration
    for (int k_R = 1; k_R <= n; ++k_R) {
        if (a[n + k_R - 1] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        // We need to find if there's a `bal_L` such that `bal_L = initial_balance - current_balance_right`.
        int target_bal_L = initial_balance - current_balance_right;
        if (left_balance_to_k.count(target_bal_L)) {
            min_removed_jars = std::min(min_removed_jars, left_balance_to_k[target_bal_L] + k_R);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive integer

    // Iterate from largest possible power of 2 down to 1
    // A block of 'k' identical numbers contributes 2^k - 1 subsequences.
    // We want to decompose X into sum of (2^k - 1) terms.
    // The largest k such that 2^k - 1 <= X is log2(X+1).
    // Since X can be up to 10^9, log2(10^9+1) is around 30.
    // So k will be at most around 30.
    // We can use a greedy approach: take the largest possible 2^k - 1 that fits into remaining X.
    // This is equivalent to iterating k from 60 down to 1 (or 30 down to 1, practically).
    // The maximum value of k for 2^k-1 <= 10^9 is k=29 (2^29-1 approx 5*10^8).
    // For k=30, 2^30-1 approx 10^9.
    // For k=31, 2^31-1 approx 2*10^9.
    // So k can go up to 30.
    // We can iterate k from 60 down to 1 to be safe, as 2^60 is much larger than 10^9.
    // The maximum number of elements in the array is 10^4.
    // If X = 10^9, and we use k=1 (2^1-1 = 1) repeatedly, we would need 10^9 elements, which is too many.
    // However, we are using larger k values first.
    // The sum of (k_i) for all blocks must be <= 10^4.
    // The maximum number of blocks is about 60 (for X=10^9, we might use 2^29-1, then 2^28-1, etc., up to 2^1-1).
    // The total number of elements will be sum of k_i.
    // For X=10^9, the binary representation of X+1 has about 30 bits.
    // So, we will have at most 30 blocks of identical numbers.
    // The maximum k is 30. So, total elements will be at most 30 * 30 = 900, which is well within 10^4.

    for (int k = 60; k >= 1; --k) {
        long long num_subsequences_from_k_elements;
        if (k >= 63) { // Prevent overflow for 2^k-1 if k is too large
            num_subsequences_from_k_elements = -1; // Effectively infinity, won't be used
        } else {
            num_subsequences_from_k_elements = (1LL << k) - 1;
        }

        while (X >= num_subsequences_from_k_elements && num_subsequences_from_k_elements > 0) {
            for (int i = 0; i < k; ++i) {
                result_array.push_back(current_val);
            }
            X -= num_subsequences_from_k_elements;
            // Ensure current_val + d is less than 10^18.
            // If current_val is 1, d can be 10^9. current_val + d is fine.
            // If current_val is already large, say 10^18 - 10^9, then current_val + d might overflow.
            // The maximum number of distinct values is about 60 (for k=1 to 60).
            // If d=1, current_val can grow up to 60.
            // If d=10^9, current_val can grow up to 60 * 10^9. This is fine.
            // The maximum value of current_val will be roughly 1 + 60 * d.
            // If d = 10^9, max current_val is 1 + 60 * 10^9, which is less than 10^18.
            // So, current_val + d will not overflow long long and will stay below 10^18.
            current_val += (d + 1); 
        }
    }

    if (X != 0) { // Should not happen with the greedy strategy if X is positive
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using a global array for a_values to avoid passing it around
// and to allow direct indexing from 1 to n.
// Max n is 2e5, so max index is 2e5.
// a_values[0] will be unused.
long long a_values[200005];

// Memoization tables for results and visited states
// dp_y[i] stores the final y value if starting with x=i and y=0
// dp_state[i] stores the state of calculation for x=i:
//   0: not visited
//   1: currently visiting (part of current path, indicates cycle)
//   2: visited and calculated (dp_y[i] holds the result)
long long dp_y[200005];
int dp_state[200005];

// Function to solve for a given starting x (current_x) and initial y (current_y)
// This function calculates the total y accumulated from this point onwards.
// It uses memoization to avoid recomputing and detect cycles.
long long solve(long long current_x, long long current_y, int n) {
    // Termination conditions
    if (current_x <= 0 || current_x > n) {
        return current_y;
    }

    // Check memoization table
    if (dp_state[current_x] == 2) { // Already computed
        return current_y + dp_y[current_x];
    }
    if (dp_state[current_x] == 1) { // Cycle detected
        return -1;
    }

    // Mark as currently visiting
    dp_state[current_x] = 1;

    long long val_ax = a_values[current_x];

    // Step 2: x = x + a[x], y = y + a[x]
    long long next_x_step2 = current_x + val_ax;
    long long next_y_step2 = current_y + val_ax;

    // Step 3: x = x - a[x], y = y + a[x]
    long long next_x_step3 = next_x_step2 - val_ax; // This is current_x
    long long next_y_step3 = next_y_step2 + val_ax;

    // Recursive call for the next state (after step 3)
    long long result = solve(next_x_step3, next_y_step3, n);

    // Store result and mark as computed
    dp_state[current_x] = 2;
    if (result == -1) {
        dp_y[current_x] = -1; // Propagate cycle
    } else {
        dp_y[current_x] = result - current_y; // Store only the y accumulated from current_x
    }

    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Read a_2, ..., a_n
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_values[i];
    }

    // For each i from 1 to n-1, set a_1 = i and run the program
    for (int i = 1; i < n; ++i) {
        a_values[1] = i; // Set a_1 for the current run

        // Reset memoization tables for each run
        // Only need to reset for indices that might be visited.
        // For a_1 = i, the path starts at x=1.
        // The values a_2...a_n are fixed.
        // The only changing value is a_1.
        // This means that for any x > 1, the path from x onwards is always the same.
        // So, we only need to clear dp_state[1] and dp_y[1] for each run.
        // The values for dp_state[x] and dp_y[x] for x > 1 can be reused.
        // However, the problem states "run the program on the sequence i, a_2, a_3, ..., a_n".
        // This implies a fresh run for each i.
        // If we reuse dp_state/dp_y for x > 1, it means we are assuming a_x is fixed for x > 1.
        // This is true. So, we only need to clear dp_state[1] and dp_y[1].
        // But the problem implies a full reset. Let's re-evaluate.
        // The problem is "Suppose for each i (1 <= i <= n-1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a_1 is different for each run.
        // The values a_2, ..., a_n are fixed.
        // If the program reaches x > 1, the subsequent path depends only on a_2, ..., a_n.
        // So, the results for x > 1 can be memoized across different 'i' runs.
        // Only the path starting from x=1 needs to be re-evaluated.
        // The `solve` function is designed to compute the *additional* y from `current_x`.
        // So, if `solve(x, 0, n)` is called, it computes the total y from `x`.
        // If `solve(x, Y, n)` is called, it computes `Y + (total y from x)`.
        // The `dp_y[x]` stores `(total y from x)`.
        // So, `dp_y[x]` and `dp_state[x]` for `x > 1` are indeed reusable.
        // We only need to reset `dp_state[1]` and `dp_y[1]` for each iteration `i`.
        // However, the `solve` function itself will handle the memoization for `x > 1` correctly
        // because `a_values[x]` for `x > 1` never changes.
        // So, we only need to clear `dp_state[1]` and `dp_y[1]` for each `i`.
        // But to be safe and avoid subtle bugs, let's clear the whole array for each `i`.
        // This is `O(N^2)` if done naively.
        // A better approach:
        // The `solve` function is called with `current_x = 1` and `current_y = 0`.
        // It will compute `dp_y[1]` and `dp_state[1]`.
        // If it calls `solve(next_x, next_y, n)` where `next_x > 1`,
        // and `dp_state[next_x]` is 0, it will compute and store `dp_y[next_x]`.
        // This `dp_y[next_x]` is valid for all subsequent `i` runs.
        // So, we only need to reset `dp_state[1]` to 0 before each call.
        // `dp_y[1]` will be overwritten.
        // The `dp_state` array should be initialized to 0 once.
        // Then, for each `i`, set `dp_state[1] = 0` before calling `solve`.
        // This is `O(N)` total.

        // Reset only the state for x=1 for the current run.
        // Other states (x > 1) are valid across runs because a_x for x > 1 is constant.
        dp_state[1] = 0; 
        dp_y[1] = 0; // Not strictly necessary as it will be overwritten

        long long result = solve(1, 0, n);
        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added to the graph

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step for the newly added vertex k
        // For all pairs (i, j) of currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Update paths involving k as an intermediate vertex
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating all paths through k,
        // we also need to consider paths that might use k as an endpoint
        // but pass through other active vertices.
        // This is essentially the standard Floyd-Warshall triple loop,
        // but restricted to active vertices.
        // The previous loop (i,j,k) handles k as an intermediate.
        // The following loops handle k as an endpoint (i,k,j) and (k,j,i)
        // and also ensure all-pairs shortest paths among currently active vertices.
        // The standard Floyd-Warshall structure is:
        // for k_prime in active_vertices:
        //   for i_prime in active_vertices:
        //     for j_prime in active_vertices:
        //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime])
        //
        // Since we are adding vertices one by one, and `k` is the *newest* active vertex,
        // the `dist` matrix already holds all-pairs shortest paths for vertices
        // that were active *before* `k` was added.
        // So, we only need to update paths that involve `k` as an intermediate.
        // The previous loop `for i,j,k` does this.
        //
        // However, the standard Floyd-Warshall algorithm iterates `k` as the intermediate vertex.
        // When we add vertex `k`, we need to consider `k` as an intermediate vertex
        // for all pairs `(i, j)` that are currently active.
        // The `dist` matrix already contains shortest paths for all pairs `(i, j)`
        // using only intermediate vertices from `active_vertices` *excluding* `k`.
        // So, when `k` becomes active, we need to update `dist[i][j]` using `k` as an intermediate.
        // This is done by:
        // for i in active_vertices:
        //   for j in active_vertices:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //
        // This is exactly what the first triple loop does.
        //
