}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child is now cured, no longer in line

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0; // Accumulates d_j from children who run away

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Apply accumulated_d_cry effect
            children[j].p -= accumulated_d_cry;

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
