// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: Try all possible single cuts
    // A single cut divides s into s1 and s2.
    // We can form s2s1. We need s2s1 to be a palindrome and s2s1 != s.
    for (int i = 1; i < n; ++i) { // i is the length of s1, so s1 = s.substr(0, i)
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2:
    // If no solution with k=1, we check if a solution with k=2 is possible.
    // A solution with k=2 means we cut s into 3 pieces: s1, s2, s3.
    // We can reorder them.
    // The problem statement implies that if a solution exists, it's always possible with k=1 or k=2.
    // The only case where k=2 is needed is when all characters are the same,
    // or when the string is of the form 'ababa' and 'a' and 'b' are different.
    // For example, "nolon" -> "onlno" (k=2)
    // For "otto" -> "toot" (k=1)
    // For "qqqq" -> Impossible

    // If all characters in s are the same, e.g., "aaaaa",
    // then any cyclic shift will result in "aaaaa".
    // Any reordering of pieces will also result in "aaaaa".
    // In this case, it's impossible to form a new string.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        // This is because if s is not all same characters, and it's a palindrome,
        // then its first half (excluding middle char for odd length) must contain at least two distinct characters.
        // For example, "abacaba". The first half "aba" has 'a' and 'b'.
        // If we cut it into s[0] | s.substr(1, n-2) | s[n-1],
        // and reorder to s[n-1] | s.substr(1, n-2) | s[0],
        // this forms a new palindrome if s[0] != s[n-1] (which is impossible for palindrome)
        // or if s.substr(1, n-2) is not all same characters.
        // The logic is that if s is a palindrome and not all characters are the same,
        // then s.substr(0, n/2) (the first half) must contain at least two distinct characters.
        // If s.substr(0, n/2) contains only one distinct character, say 'a',
        // then s must be 'aaaa...a'.
        // So, if not all characters are the same, then s.substr(0, n/2) must contain at least two distinct characters.
        // This allows for a k=2 solution.
        // Example: "nolon" (n=5). s[0]='n', s[1]='o', s[2]='l'.
        // s.substr(0, n/2) = "no". It has 'n' and 'o'.
        // We can cut "no|l|on" and reorder to "on|l|no". This is a palindrome and different.
        // This strategy always works for non-all-same-char palindromes.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = static_cast<long long>(n) * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r-1]
    // does NOT contain any valid triplet.
    // If s[i...r-1] contains a triplet (x, x+k, x+2k), then x must be >= i.
    // So, we are looking for the smallest x+2k that is >= i.
    // If there is no triplet starting at or after i, then max_r_for_l[i] = n.
    // Otherwise, max_r_for_l[i] = min(x+2k for all triplets (x, x+k, x+2k) with x >= i) - 1.
    // Initialize with n, meaning no restriction from triplets.
    std::vector<int> max_r_for_l(n + 1, n);

    // Iterate through all possible starting positions x (1-indexed)
    // and all possible steps k.
    // The maximum possible value for x+2k is n.
    // So, x + 2k <= n => 2k <= n - x => k <= (n - x) / 2.
    // Also, k >= 1.
    for (int x = 1; x <= n; ++x) {
        for (int k = 1; ; ++k) {
            int x_idx = x - 1; // 0-indexed
            int x_plus_k_idx = x + k - 1;
            int x_plus_2k_idx = x + 2 * k - 1;

            if (x_plus_2k_idx >= n) {
                break; // x+2k is out of bounds
            }

            if (s[x_idx] == s[x_plus_k_idx] && s[x_plus_k_idx] == s[x_plus_2k_idx]) {
                // Found a valid triplet (x, x+k, x+2k)
                // This triplet covers the range [x, x+2k].
                // Any substring s[l-1...r-1] where l <= x and r >= x+2k
                // will contain this triplet.
                // We want to find pairs (l, r) that *don't* contain any triplet.
                // For any l' <= x, the maximum r' that doesn't contain this triplet
                // must be less than x+2k.
                // So, for all l_val from 1 to x, we update max_r_for_l[l_val].
                // The actual value to update is max_r_for_l[l_val] = min(max_r_for_l[l_val], x+2k-1).
                // However, we can optimize this.
                // The current triplet (x, x+k, x+2k) implies that any valid (l, r)
                // must have r < x+2k if l <= x.
                // So, for all l from 1 to x, the maximum valid r is at most x+2k-1.
                // We need to update max_r_for_l[l] for l from 1 to x.
                // This is equivalent to updating max_r_for_l[l] for l from 1 to x
                // with the value x+2k-1.
                // Since we iterate x from 1 to n, and k from 1 upwards,
                // x+2k will be increasing.
                // The smallest x+2k for a given x will be when k=1.
                // The smallest x+2k overall will be for small x and small k.
                // The max_r_for_l[l] should be the minimum of (x'+2k'-1) for all
                // triplets (x', x'+k', x'+2k') such that x' >= l.
                // So, for each l, we are interested in the smallest x'+2k' where x' >= l.
                // This means we should update max_r_for_l[x] with x+2k-1.
                // And then propagate this minimum backwards.
                // max_r_for_l[l] = min(max_r_for_l[l], max_r_for_l[l+1])
                // This is done in the final loop.
                max_r_for_l[x] = std::min(max_r_for_l[x], x + 2 * k - 1);
            }
        }
    }

    // Propagate the minimums backwards:
    // max_r_for_l[l] should be the minimum of all (x+2k-1) for x >= l.
    // So, max_r_for_l[l] = min(max_r_for_l[l], max_r_for_l[l+1]).
    for (int l = n - 1; l >= 1; --l) {
        max_r_for_l[l] = std::min(max_r_for_l[l], max_r_for_l[l + 1]);
    }

    // Now, for each l from 1 to n, max_r_for_l[l] gives the maximum r
    // such that the substring s[l-1...r-1] does NOT contain any valid triplet.
    // The number of such r's for a given l is max_r_for_l[l] - l + 1.
    // If max_r_for_l[l] < l, it means no such r exists, so count is 0.
    for (int l = 1; l <= n; ++l) {
        if (max_r_for_l[l] >= l) {
            bad_pairs += (max_r_for_l[l] - l + 1);
        }
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

