#include <iostream> // Required for input/output operations (cin, cout)

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin from cout and prevents flushing cout before each cin.
    std::ios_base::sync_with_stdio(false);
    // This prevents cout from flushing automatically after each output operation,
    // allowing it to buffer output for potentially faster execution.
    std::cin.tie(NULL);

    int n; // Declare an integer variable 'n' to store the number of commands.
    std::cin >> n; // Read the value of 'n' from standard input.

    // Initialize variables to track total packets sent and successful packets for server 'a'.
    long long total_packets_a = 0;
    long long successful_packets_a = 0;

    // Initialize variables to track total packets sent and successful packets for server 'b'.
    long long total_packets_b = 0;
    long long successful_packets_b = 0;

    // Loop 'n' times to process each command.
    for (int i = 0; i < n; ++i) {
        int type; // Declare an integer variable 'type' for the server type (1 for 'a', 2 for 'b').
        int x, y; // Declare integer variables 'x' and 'y' for successful and lost packets.
        std::cin >> type >> x >> y; // Read the type, x, and y values for the current command.

        // Check if the command is for server 'a'.
        if (type == 1) {
            total_packets_a += 10; // Each ping sends 10 packets.
            successful_packets_a += x; // Add the number of successful packets.
        }
        // Otherwise, the command is for server 'b'.
        else { // type == 2
            total_packets_b += 10; // Each ping sends 10 packets.
            successful_packets_b += x; // Add the number of successful packets.
        }
    }

    // Determine if server 'a' is "alive".
    // A server is "alive" if successful packets are at least half of total packets.
    // We use 2 * successful_packets >= total_packets to avoid floating-point arithmetic.
    if (successful_packets_a * 2 >= total_packets_a) {
        std::cout << "LIVE\n"; // Print "LIVE" if server 'a' is alive.
    } else {
        std::cout << "DEAD\n"; // Print "DEAD" if server 'a' is not alive.
    }

    // Determine if server 'b' is "alive".
    if (successful_packets_b * 2 >= total_packets_b) {
        std::cout << "LIVE\n"; // Print "LIVE" if server 'b' is alive.
    } else {
        std::cout << "DEAD\n"; // Print "DEAD" if server 'b' is not alive.
    }

    return 0; // Indicate successful program execution.
}

