int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick numbers from 2n+1 to 4n, but only even ones.
        // This ensures that no number divides another (since 2x > 4n for x > 2n)
        // and gcd(a,b) is not 1 (since all are even).
        // We need n numbers.
        // The numbers are 2n+1, 2n+2, ..., 4n.
        // The even numbers in this range are 2n+2, 2n+4, ..., 4n.
        // Let's verify the count:
        // (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n.
        // So there are exactly n even numbers in the range [2n+2, 4n].
        // These numbers are all even, so gcd(a,b) >= 2.
        // For any two numbers a, b in this set, assume a < b.
        // The smallest number is 2n+2. The largest is 4n.
        // If a divides b, then b = k*a for some integer k.
        // Since a, b are even, k can be any integer.
        // If k=1, then a=b, which is not allowed.
        // If k >= 2, then b >= 2a.
        // But the smallest number in our set is 2n+2.
        // If a = 2n+2, then 2a = 4n+4.
        // The largest number in our set is 4n.
        // Since 4n+4 > 4n, it's impossible for b >= 2a to hold for any a, b in the set.
        // Thus, no number in the set divides another.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 + 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

