            // We should always pick the smallest available cost first to maximize the count.
            // The costs are 1, 6, 28, 120, ...
            // Let `current_n_stairs = 2^p - 1`.
            // The cost for this staircase is `current_n_stairs * (current_n_stairs + 1) / 2`.
            // Let `p` be the power.
            // `p` starts from 1.
            // `n_stairs = (1LL << p) - 1;`
            // `cost = n_stairs * (n_stairs + 1) / 2;`

            long long n_stairs = (1LL << k) - 1; // Number of stairs for the current nice staircase type
            long long cost = n_stairs * (n_stairs + 1) / 2; // Total cells for this staircase type

            if (current_cost + cost <= x) {
                current_cost += cost;
                count++;
                k++; // Move to the next nice staircase type (with more stairs)
            } else {
                break; // Cannot afford the current staircase type
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

