        // Each coal costs y sticks and 1 trade.
        // We need k coal, so k trades of type 2.
        long long coal_acquisition_trades = k;

        // Total trades = trades to get enough sticks + trades to get enough coal
        long long total_trades = stick_acquisition_trades + coal_acquisition_trades;

        std::cout << total_trades << std::endl;
