    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        if (n <= 2) { // For n=2, the only subsequence of length >= 2 is p itself.
            std::cout << n << "\n";
            for (int i = 0; i < n; ++i) {
                std::cout << p[i] << (i == n - 1 ? "" : " ");
            }
            std::cout << "\n";
            continue;
        }

        std::vector<int> result_subsequence;
        result_subsequence.push_back(p[0]);

        for (int i = 1; i < n - 1; ++i) {
            // Check if p[i] is a local extremum (peak or valley)
            // A peak: p[i-1] < p[i] and p[i] > p[i+1]
            // A valley: p[i-1] > p[i] and p[i] < p[i+1]
            if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
                result_subsequence.push_back(p[i]);
            }
        }
        result_subsequence.push_back(p[n-1]);

        std::cout << result_subsequence.size() << "\n";
        for (size_t i = 0; i < result_subsequence.size(); ++i) {
            std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int count_01 = 0; // Number of positions where a[i] = '0' and b[i] = '1'
    int count_10 = 0; // Number of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            // This position needs to be fixed.
            // We have two options: flip it, or swap it with another differing bit.
            // The key insight is that a swap operation (cost |i-j|) can fix two differing bits
            // if one is '0'->'1' and the other is '1'->'0'.
            // For example, if a[i]='0', b[i]='1' and a[j]='1', b[j]='0'.
            // Swapping a[i] and a[j] makes a[i]='1' and a[j]='0'.
            // Both positions are now correct. The cost is |i-j|.
            // This is equivalent to flipping a[i] (cost 1) and flipping a[j] (cost 1)
            // if |i-j| <= 2.
            // If |i-j| = 1, swap cost is 1. Two flips cost 2. Swap is better.
            // If |i-j| = 2, swap cost is 2. Two flips cost 2. Both are equal.
            // If |i-j| > 2, swap cost is > 2. Two flips cost 2. Flips are better.

            // We can greedily pair up adjacent differing bits that can be fixed by a swap.
            // If a[i] = '0' and b[i] = '1', and a[i+1] = '1' and b[i+1] = '0',
            // we can swap a[i] and a[i+1] for cost 1. This fixes both.
            // This is better than two flips (cost 2).
            // So, we check if the current position `i` and the next position `i+1`
            // form such a pair.

            if (i + 1 < n && a[i] != a[i+1] && a[i+1] != b[i+1] && a[i] == b[i+1] && a[i+1] == b[i]) {
                // This condition means:
                // a[i] != b[i] (current position needs fixing)
                // a[i+1] != b[i+1] (next position needs fixing)
                // a[i] and a[i+1] are different (e.g., '0' and '1')
                // a[i] is the target for b[i+1] (e.g., if a[i]='0', then b[i+1] must be '0')
                // a[i+1] is the target for b[i] (e.g., if a[i+1]='1', then b[i] must be '1')
                // This simplifies to: a[i] != b[i] AND a[i+1] != b[i+1] AND a[i] == b[i+1] AND a[i+1] == b[i]
                // Example: a="01", b="10". Here a[0]='0', b[0]='1' and a[1]='1', b[1]='0'.
                // a[0] != a[1] ('0' != '1')
                // a[0] == b[1] ('0' == '0')
                // a[1] == b[0] ('1' == '1')
                // This is exactly the case where swapping a[i] and a[i+1] fixes both.
                total_cost += 1; // Cost of swap is |i - (i+1)| = 1
                i++; // Skip next position as it's now fixed
            } else {
                // If we can't find an adjacent swap that fixes two positions for cost 1,
                // then the best we can do for this single differing position is to flip it.
                total_cost += 1; // Cost of flip is 1
            }
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the first peak from the right
    // This is the first index `i` from the right such that `a[i] > a[i+1]`
    // All elements from `a[i+1]` to `a[n-1]` are non-decreasing.
    int right_peak_idx = n - 1;
    while (right_peak_idx > 0 && a[right_peak_idx - 1] >= a[right_peak_idx]) {
        right_peak_idx--;
    }

    // If right_peak_idx is 0, it means the entire array is non-decreasing.
    // In this case, the array is good, and we need to erase 0 elements.
    if (right_peak_idx == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, `a[right_peak_idx ... n-1]` is a non-decreasing suffix.
    // We need to find the first valley from the right, starting from `right_peak_idx`.
    // This is the first index `i` from the right such that `a[i] < a[i+1]`
    // All elements from `a[i+1]` to `a[right_peak_idx-1]` are non-increasing.
    int right_valley_idx = right_peak_idx;
    while (right_valley_idx > 0 && a[right_valley_idx - 1] <= a[right_valley_idx]) {
        right_valley_idx--;
    }

    std::cout << right_valley_idx << std::endl;
}

