int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // They must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // They must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The i-th element of the sorted A (a_elements[i].value)
    // should be paired with the (m-1-i)-th element of the sorted B (b_elements[m-1-i].value)
    // This pairing maximizes F(A'_i, B_i) because F(n, k) is increasing in n and decreasing in k.
    // So, largest A values should be paired with smallest B values.
    // The original index of b_elements[m-1-i] tells us where this pair should go in the output.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The value a_elements[i].value (which is the i-th smallest A value)
        // should be placed at the position corresponding to b_elements[m-1-i].original_index
        // because b_elements[m-1-i] is the (m-1-i)-th smallest B value,
        // which means it's the i-th largest B value.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // Pointer for the rightmost point within distance d

    for (int i = 0; i < n; ++i) {
        // For each x[i] as the leftmost point of a triplet,
        // find the rightmost point x[right_ptr] such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr monotonically.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] are within distance d from x[i].
        // Let k be the number of such points: k = (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // These k points are candidates for the middle and rightmost points of a triplet.
        // We need to choose 2 points from these k points.
        // The number of ways to choose 2 points from k is k * (k - 1) / 2.

        long long k = right_ptr - 1 - i;
        if (k >= 2) {
            count += k * (k - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a subarray is a permutation of length 'len'
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // For this problem, l1, l2 >= 1.
    }
    if (start_idx + len > arr.size()) {
        return false;
    }

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false); // prefix_is_perm[k] means a[0...k-1] is perm of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    int distinct_count = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] < 1 || seen_prefix[a[i]]) { // a[i] > n is technically not possible given constraints a_i <= n-1
            // This prefix cannot be a permutation of any length
            // We can stop checking for this prefix path, but we need to continue for suffix checks
            // For simplicity, just mark it false and continue.
            // The max_val check will handle it.
        } else {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        prefix_max[i] = current_max;
        if (distinct_count == i + 1 && current_max == i + 1) {
            prefix_is_perm[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[k] means a[n-k...n-1] is perm of length k
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    distinct_count = 0;
    for (int i = n - 1; i >= 0; --i) {
        int len_from_end = n - i;
        if (a[i] > n || a[i] < 1 || seen_suffix[a[i]]) {
            // This suffix cannot be a permutation of any length
        } else {
            seen_suffix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        suffix_max[i] = current_max;
        if (distinct_count == len_from_end && current_max == len_from_end) {
            suffix_is_perm[len_from_end] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

