        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs exactly three members).
        // So, k <= c, k <= m, and 3*k <= c + m + x.
        // This means k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        // This 'max_possible_teams' is the answer because if we can form 'k' teams,
        // we use 'k' coders, 'k' mathematicians, and 'k' other students.
        // The 'k' other students can be drawn from the remaining coders (c-k),
        // remaining mathematicians (m-k), and students with no specialization (x).
        // The total number of students available for these 'k' "flexible" slots is (c-k) + (m-k) + x.
        // We need to ensure that (c-k) + (m-k) + x >= k.
        // This simplifies to c + m + x >= 3k, which is already covered by the third condition.
        // Since we pick k <= c and k <= m, we always have enough coders and mathematicians
        // to satisfy the "at least one" requirement for k teams.
        // The remaining c-k coders and m-k mathematicians, along with x non-specialized students,
        // are sufficient to fill the remaining k slots because their sum is (c+m+x) - 2k,
        // and we know (c+m+x) >= 3k, so (c+m+x) - 2k >= k.

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: if N=2, taking 1 is better than taking N/2 for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else {
                    // If N is even, Chanek has two choices: take 1 or take N/2.
                    // Opponent will play optimally to minimize Chanek's gain.
                    // Chanek wants to maximize his gain.
                    //
                    // Option 1: Chanek takes 1.
                    // N becomes N-1 (odd). Opponent's turn.
                    // Opponent will take 1, N becomes N-2 (even).
                    // Then it's Chanek's turn with N-2 coins.
                    //
                    // Option 2: Chanek takes N/2.
                    // N becomes N/2 (could be even or odd). Opponent's turn.
                    //
                    // Consider the parity of N/2.
                    if ((n / 2) % 2 != 0) { // N/2 is odd
                        // If Chanek takes N/2, remaining N/2 is odd.
                        // Opponent will take 1.
                        // This seems like a good move for Chanek, as it leaves an odd number for the opponent.
                        chanek_coins += n / 2;
                        n /= 2;
                    } else { // N/2 is even
                        // If Chanek takes N/2, remaining N/2 is even.
                        // Opponent might take N/4.
                        // In this scenario, taking 1 might be better for Chanek.
                        // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                        // If Chanek takes N/2, N becomes N/2 (even). Opponent takes N/4. N becomes N/4 (even).
                        //
                        // The optimal strategy for Chanek when N is even and N/2 is even:
                        // Chanek takes 1. N becomes N-1.
                        // Opponent takes 1. N becomes N-2.
                        // This ensures Chanek gets 1 coin and the opponent gets 1 coin, and the game continues with N-2.
                        // This is generally better than taking N/2 if N/2 is even, because taking N/2
                        // would give the opponent a chance to take N/4, which might be a large chunk.
                        // By taking 1, Chanek forces the opponent to also take 1 (since N-1 is odd),
                        // effectively splitting the "small" coins.
                        chanek_coins += 1;
                        n -= 1;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if (n == 2) { // Special case: if N=2, opponent takes 1
                    n -= 1;
                } else {
                    // Opponent wants to maximize their own coins, which means minimizing Chanek's coins.
                    // If N/2 is odd, opponent takes N/2. This leaves an odd number for Chanek.
                    // If N/2 is even, opponent takes N/2. This leaves an even number for Chanek.
                    // Opponent will always prefer to take N/2 if N is even, because it's a larger amount.
                    // The only exception is if taking 1 leads to a better outcome for the opponent,
                    // but in this greedy game, taking the largest possible amount is usually optimal.
                    // Taking N/2 is always better for the opponent than taking 1 if N > 2.
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

