int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    int consecutive_sequences_starting_with_one = 0;
    int total_elements_in_consecutive_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (1 <= m_i)

        int first_doll;
        std::cin >> first_doll;

        if (first_doll == 1) {
            consecutive_sequences_starting_with_one++;
            total_elements_in_consecutive_sequences++;
            int prev_doll = first_doll;
            for (int j = 1; j < m; ++j) {
                int current_doll;
                std::cin >> current_doll;
                if (current_doll == prev_doll + 1) {
                    total_elements_in_consecutive_sequences++;
                    prev_doll = current_doll;
                } else {
                    // The sequence of consecutive numbers is broken
                    // We still need to read the rest of the chain elements
                    for (int l = j + 1; l < m; ++l) {
                        std::cin >> current_doll;
                    }
                    break; // Exit inner loop, this chain's contribution to consecutive sequence is done
                }
            }
        } else {
            // Read the rest of the chain elements if the first doll is not 1
            for (int j = 1; j < m; ++j) {
                int dummy;
                std::cin >> dummy;
            }
        }
    }

    // Operations to disassemble:
    // Each chain needs to be disassembled.
    // If a chain has m elements, it has m-1 nestings.
    // To get all elements out, we need m-1 operations.
    // Total initial nestings = n - k (since sum of m_i = n, and each chain has m_i-1 nestings)
    // So, total disassemble operations = (n - k)

    // Operations to assemble:
    // We need to form n-1 nestings in total (1->2, 2->3, ..., n-1->n).
    // We already have `total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one`
    // of these nestings formed within the initial chain starting with 1.
    // For example, if we have 1->2->3, this means 2 nestings (1,2) and (2,3).
    // `total_elements_in_consecutive_sequences` is 3. `consecutive_sequences_starting_with_one` is 1.
    // So, 3 - 1 = 2 nestings are already formed.
    // The number of new nestings we need to create is (n - 1) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one).
    // Each new nesting costs 1 operation.

    // Total operations = (disassemble operations) + (assemble operations)
    // Disassemble operations: (n - k)
    // Assemble operations: (n - 1) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)

    // Let's simplify.
    // The number of elements that are *not* part of the desired 1->2->...->N sequence
    // and are not 1 itself, need to be taken out.
    // The number of elements that are part of the desired 1->2->...->N sequence
    // and are not 1 itself, but are not correctly nested, need to be taken out.
    // This is equivalent to saying:
    // We have `n` dolls. We want `n-1` specific connections.
    // We have `k` chains.
    // The number of existing connections is `n-k`.
    // The number of *correct* existing connections is `total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one`.
    // The number of *incorrect* existing connections is `(n-k) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)`.
    // Each incorrect connection must be broken: `(n-k) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)` operations.
    // Each missing correct connection must be made: `(n-1) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)` operations.

    // Total operations = (incorrect connections to break) + (correct connections to make)
    // Total operations = (n - k - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one))
    //                  + (n - 1 - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one))

    // This simplifies to:
    // (n - k) + (n - 1) - 2 * (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)

    // Let's re-evaluate the logic based on the example.
    // Example 1: n=3, k=2. Chains: 2 1 2; 1 3.
    // Chain 1: 1->2. first_doll=1. total_elements_in_consecutive_sequences=2. consecutive_sequences_starting_with_one=1.
    // Chain 2: 3. first_doll=3.
    // Result: total_elements_in_consecutive_sequences = 2. consecutive_sequences_starting_with_one = 1.
    // Formula: (3 - 2) + (3 - 1) - 2 * (2 - 1)
    //        = 1 + 2 - 2 * 1
    //        = 3 - 2 = 1. Correct.

    // Example 2: n=7, k=3. Chains: 3 1 3 7; 2 2 5; 2 4 6.
    // Chain 1: 1->3->7. first_doll=1.
    //   1 is read. total_elements_in_consecutive_sequences=1. consecutive_sequences_starting_with_one=1.
    //   3 is read. Not 1+1. Loop breaks.
    // Chain 2: 2->5. first_doll=2.
    // Chain 3: 4->6. first_doll=4.
    // Result: total_elements_in_consecutive_sequences = 1. consecutive_sequences_starting_with_one = 1.
    // Formula: (7 - 3) + (7 - 1) - 2 * (1 - 1)
    //        = 4 + 6 - 2 * 0
    //        = 10. Correct.

    // The formula seems correct.
    // (n - k) is the number of "take out" operations needed to break all existing chains into individual dolls.
    // (n - 1) is the number of "put in" operations needed to form the final 1->2->...->n chain from individual dolls.
    // However, some dolls are already correctly nested.
    // The number of correctly nested pairs is `total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one`.
    // Each such pair (i, i+1) means:
    // 1. We don't need to "take out" doll `i` from `i+1`. (Saves 1 operation from `n-k`)
    // 2. We don't need to "put in" doll `i` into `i+1`. (Saves 1 operation from `n-1`)
    // So, for each correctly nested pair, we save 2 operations.

    // Total operations = (n - k) + (n - 1) - 2 * (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)

    long long result = (long long)(n - k) + (long long)(n - 1) - 2LL * (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one);
    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // Iterate up to sqrt(q)
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0 && current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long i = temp_q; // This is a prime factor
        long long current_p = p;
        while (current_p % i == 0 && current_p % q == 0) {
            current_p /= i;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

