int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences: 1, k, 2, k-1, 3, k-2, ...
    // This pattern generates differences: |1 - (k+1)| = k, |(k+1) - 2| = k-1, |2 - k| = k-2, ...
    // The sequence of numbers will be: 1, k+1, 2, k, 3, k-1, ...
    // This generates differences k, k-1, k-2, ..., 1.

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index: take from left (ascending)
            p[i] = left;
            left++;
        } else { // Odd index: take from right (descending)
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are left, left+1, ..., right.
    // Since left and right have crossed or met, the remaining numbers are
    // from `left` up to `n`.
    // We just append them in increasing order to maintain a difference of 1.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be left, left+1, ...
                      // Or more precisely, p[k+1] = left, p[k+2] = left+1, etc.
                      // Since left is the next available number after the first k+1 elements are placed.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

