int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long sum_r_term1 = (b - 1);
    long long sum_r_term2 = b;

    long long sum_r = (sum_r_term1 % MOD * (sum_r_term2 % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9 + 7
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k_expr = sum_{k=1 to a} (k * b + 1)
    // sum_k_expr = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_expr = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a+1) / 2
    long long sum_k_sum_k_term1 = a;
    long long sum_k_sum_k_term2 = (a + 1);

    long long sum_k_sum_k = (sum_k_sum_k_term1 % MOD * (sum_k_sum_k_term2 % MOD)) % MOD;
    sum_k_sum_k = (sum_k_sum_k * inv2) % MOD;

    long long sum_k_expr = (b % MOD * sum_k_sum_k) % MOD;
    sum_k_expr = (sum_k_expr + (a % MOD)) % MOD;

    // Total sum = sum_r * sum_k_expr
    long long total_sum = (sum_r * sum_k_expr) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

