int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
    // x_i must be a multiple of (n-1).
    // This operation is only useful if n > 1.
    if (n == 1) {
        // Case n=1:
        // Operation 1: Segment [1, 1], length 1. Add -a[0].
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: Segment [1, 1], length 1. Add 0.
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: Segment [1, 1], length 1. Add 0.
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Target a[0]...a[n-2]
        // Segment [1, n-1] (1-indexed)
        // Length = (n-1) - 1 + 1 = n-1
        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
            long long to_add = remainder * (n - 1); // This is a multiple of (n-1)
            a[i] += to_add;
            std::cout << to_add << (i == n - 2 ? "" : " ");
        }
        std::cout << "\n";

        // Operation 2: Target a[n-1]
        // Segment [n, n] (1-indexed)
        // Length = 1
        std::cout << n << " " << n << "\n";
        long long remainder = (a[n - 1] % n + n) % n; // Ensure positive remainder
        long long to_add = remainder * n; // This is a multiple of n (and 1)
        a[n - 1] += to_add;
        std::cout << to_add << "\n";

        // Now all a[i] are multiples of n.
        // Operation 3: Target all a[0]...a[n-1]
        // Segment [1, n] (1-indexed)
        // Length = n
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            long long to_add = -a[i]; // Since a[i] is a multiple of n, -a[i] is also a multiple of n
            a[i] += to_add;
            std::cout << to_add << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance (strawberry - blueberry)
    // 1 -> +1, 2 -> -1
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // If initial balance is 0, no jars need to be emptied.
    if (initial_balance == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Store prefix sums for the left side (jars 1 to n)
    // `left_diff[k]` is the balance of jars `n-k+1` to `n`
    // `left_diff[0]` is 0 (no jars removed from left)
    // `left_diff[1]` is balance of jar `n`
    // `left_diff[k]` is balance of jars `n-k+1` ... `n`
    std::map<int, int> left_diff_to_k; // maps balance_diff -> k (number of jars removed from left)
    left_diff_to_k[0] = 0; // 0 jars removed from left, balance change is 0

    int current_left_balance_change = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n - k; // 0-indexed: jar n is at index n-1, jar n-1 is at index n-2, etc.
        if (a[jar_idx] == 1) {
            current_left_balance_change++;
        } else {
            current_left_balance_change--;
        }
        if (left_diff_to_k.find(current_left_balance_change) == left_diff_to_k.end()) {
            left_diff_to_k[current_left_balance_change] = k;
        }
    }

    // Iterate through possible number of jars removed from right (k_right)
    // `right_diff[k]` is the balance of jars `n+1` to `n+k`
    // `right_diff[0]` is 0 (no jars removed from right)
    // `right_diff[1]` is balance of jar `n+1`
    // `right_diff[k]` is balance of jars `n+1` ... `n+k`
    int min_removed_jars = 2 * n; // Max possible jars to remove

    // Case 1: Only remove jars from the left
    // We need initial_balance - current_left_balance_change = 0
    // So, current_left_balance_change = initial_balance
    if (left_diff_to_k.count(initial_balance)) {
        min_removed_jars = std::min(min_removed_jars, left_diff_to_k[initial_balance]);
    }

    // Case 2: Remove jars from both left and right, or only from right
    int current_right_balance_change = 0;
    for (int k_right = 0; k_right <= n; ++k_right) {
        if (k_right > 0) {
            int jar_idx = n + k_right - 1; // 0-indexed: jar n+1 is at index n, jar n+2 is at index n+1, etc.
            if (a[jar_idx] == 1) {
                current_right_balance_change++;
            } else {
                current_right_balance_change--;
            }
        }

        // We need initial_balance - current_left_balance_change - current_right_balance_change = 0
        // So, current_left_balance_change = initial_balance - current_right_balance_change
        int target_left_balance_change = initial_balance - current_right_balance_change;

        if (left_diff_to_k.count(target_left_balance_change)) {
            int k_left = left_diff_to_k[target_left_balance_change];
            min_removed_jars = std::min(min_removed_jars, k_left + k_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two "test" values: 0 and 1023 (all bits set)
    // We track how these values change after all operations.
    // This allows us to determine the final state of each bit.
    int val0 = 0;    // Represents the state of a bit if it starts as 0
    int val1023 = 1023; // Represents the state of a bit if it starts as 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // If the j-th bit of val0 is 0 and j-th bit of val1023 is 0:
    //   The bit always becomes 0, regardless of input. (x_j -> 0)
    // If the j-th bit of val0 is 1 and j-th bit of val1023 is 1:
    //   The bit always becomes 1, regardless of input. (x_j -> 1)
    // If the j-th bit of val0 is 0 and j-th bit of val1023 is 1:
    //   The bit remains unchanged. (x_j -> x_j)
    // If the j-th bit of val0 is 1 and j-th bit of val1023 is 0:
    //   The bit is flipped. (x_j -> !x_j)

    // We want to find three constants A, B, C such that
    // ( (x & A) | B ) ^ C
    // can represent the final transformation for all bits.

    // Let's determine the target values for A, B, C bit by bit.
    // For each bit j:
    // Let x_j be the j-th bit of the input.
    // Let a_j, b_j, c_j be the j-th bits of A, B, C respectively.
    // The output bit is ((x_j & a_j) | b_j) ^ c_j.

    // Case 1: x_j -> 0
    //   This means:
    //   If x_j=0, output is 0: ((0 & a_j) | b_j) ^ c_j = (0 | b_j) ^ c_j = b_j ^ c_j = 0
    //   If x_j=1, output is 0: ((1 & a_j) | b_j) ^ c_j = (a_j | b_j) ^ c_j = 0
    //   From b_j ^ c_j = 0, we get b_j = c_j.
    //   Then (a_j | b_j) ^ b_j = 0. This implies a_j | b_j = b_j.
    //   This is true if a_j = 0.
    //   So, for x_j -> 0, we need a_j=0, b_j=0, c_j=0 OR a_j=0, b_j=1, c_j=1.
    //   The simplest choice is a_j=0, b_j=0, c_j=0.

    // Case 2: x_j -> 1
    //   This means:
    //   If x_j=0, output is 1: ((0 & a_j) | b_j) ^ c_j = b_j ^ c_j = 1
    //   If x_j=1, output is 1: ((1 & a_j) | b_j) ^ c_j = (a_j | b_j) ^ c_j = 1
    //   From b_j ^ c_j = 1, we get b_j != c_j.
    //   Then (a_j | b_j) ^ c_j = 1.
    //   If b_j=0, c_j=1: (a_j | 0) ^ 1 = a_j ^ 1 = 1 => a_j = 0.
    //   If b_j=1, c_j=0: (a_j | 1) ^ 0 = 1 ^ 0 = 1. This is always true.
    //   So, for x_j -> 1, we need a_j=0, b_j=0, c_j=1 OR a_j=any, b_j=1, c_j=0.
    //   The simplest choice is a_j=0, b_j=0, c_j=1.

    // Case 3: x_j -> x_j (identity)
    //   This means:
    //   If x_j=0, output is 0: b_j ^ c_j = 0 => b_j = c_j
    //   If x_j=1, output is 1: (a_j | b_j) ^ c_j = 1
    //   Since b_j = c_j, we have (a_j | b_j) ^ b_j = 1.
    //   This implies a_j | b_j != b_j. This is true if a_j = 1 and b_j = 0.
    //   So, for x_j -> x_j, we need a_j=1, b_j=0, c_j=0.

    // Case 4: x_j -> !x_j (flip)
    //   This means:
    //   If x_j=0, output is 1: b_j ^ c_j = 1 => b_j != c_j
    //   If x_j=1, output is 0: (a_j | b_j) ^ c_j = 0
    //   If b_j=0, c_j=1: (a_j | 0) ^ 1 = a_j ^ 1 = 0 => a_j = 1.
    //   If b_j=1, c_j=0: (a_j | 1) ^ 0 = 1 ^ 0 = 0. This is false.
    //   So, for x_j -> !x_j, we need a_j=1, b_j=0, c_j=1.

    // Let's define the target A, B, C values based on these observations.
    // We want to find A_final, B_final, C_final such that
    // ( (x & A_final) | B_final ) ^ C_final
    // is the desired function.

    // Initialize A_final to all ones (1023), B_final to all zeros (0), C_final to all zeros (0).
    // This corresponds to the identity transformation (x_j -> x_j) for all bits.
    int A_final = 1023; // Initial state for A: all bits are 1
    int B_final = 0;    // Initial state for B: all bits are 0
    int C_final = 0;    // Initial state for C: all bits are 0

    for (int j = 0; j < 10; ++j) { // Iterate through each bit position
        int bit_val0 = (val0 >> j) & 1;
        int bit_val1023 = (val1023 >> j) & 1;

        if (bit_val0 == 0 && bit_val1023 == 0) { // x_j -> 0
            // To achieve x_j -> 0 with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=0, b_j=0, c_j=0.
            // Current A_final has 1 at bit j. Set it to 0.
            A_final &= ~(1 << j); // Set j-th bit of A_final to 0
            // B_final and C_final already have 0 at bit j.
        } else if (bit_val0 == 1 && bit_val1023 == 1) { // x_j -> 1
            // To achieve x_j -> 1 with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=0, b_j=0, c_j=1.
            // Current A_final has 1 at bit j. Set it to 0.
            A_final &= ~(1 << j); // Set j-th bit of A_final to 0
            // Current B_final has 0 at bit j. Keep it 0.
            // Current C_final has 0 at bit j. Set it to 1.
            C_final |= (1 << j);  // Set j-th bit of C_final to 1
        } else if (bit_val0 == 0 && bit_val1023 == 1) { // x_j -> x_j (identity)
            // To achieve x_j -> x_j with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=1, b_j=0, c_j=0.
            // Current A_final has 1 at bit j. Keep it 1.
            // Current B_final has 0 at bit j. Keep it 0.
            // Current C_final has 0 at bit j. Keep it 0.
            // No change needed for A_final, B_final, C_final for this bit.
        } else if (bit_val0 == 1 && bit_val1023 == 0) { // x_j -> !x_j (flip)
            // To achieve x_j -> !x_j with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=1, b_j=0, c_j=1.
            // Current A_final has 1 at bit j. Keep it 1.
            // Current B_final has 0 at bit j. Keep it 0.
            // Current C_final has 0 at bit j. Set it to 1.
            C_final |= (1 << j);  // Set j-th bit of C_final to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_final != 1023) { // If A_final is not all ones, we need an AND operation
        result_ops.push_back({'&', A_final});
    }
    if (B_final != 0) { // If B_final is not all zeros, we need an OR operation
        result_ops.push_back({'|', B_final});
    }
    if (C_final != 0) { // If C_final is not all zeros, we need an XOR operation
        result_ops.push_back({'^', C_final});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the string produced by our w
    for (int i = 0; i < n; ++i) {
        // s_prime[i] is '1' if w[i-x] is '1' OR w[i+x] is '1'
        bool possible_from_left = (i - x >= 0 && w[i - x] == '1');
        bool possible_from_right = (i + x < n && w[i + x] == '1');

        if (possible_from_left || possible_from_right) {
            s_prime[i] = '1';
        }
    }

    // Step 3: Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

