#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are placed, they divide the zeros into m+1 potential blocks.
        // To minimize substrings of all zeros, we want to make these blocks as equal as possible.
        // The number of blocks of zeros that are non-empty is at most m+1.
        // We distribute num_zeros among m+1 blocks.
        // Let k be the number of zeros in each of the larger blocks.
        // Let k-1 be the number of zeros in each of the smaller blocks.
        // Let r be the number of larger blocks (each of size k).
        // Then (m+1 - r) is the number of smaller blocks (each of size k-1).
        // num_zeros = r * k + (m+1 - r) * (k-1)
        // num_zeros = r * k + (m+1) * (k-1) - r * (k-1)
        // num_zeros = r * k + (m+1) * (k-1) - r * k + r
        // num_zeros = (m+1) * (k-1) + r
        // So, k-1 = num_zeros / (m+1) (integer division)
        // And r = num_zeros % (m+1)

        long long k_minus_1 = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);

        long long k = k_minus_1 + 1; // Size of larger blocks
        long long num_larger_blocks = r;
        long long num_smaller_blocks = (m + 1) - r; // Size of smaller blocks is k-1

        // Calculate substrings of all zeros from these blocks
        long long substrings_of_zeros = 0;
        if (k_minus_1 >= 0) { // Ensure k-1 is non-negative
            substrings_of_zeros += num_smaller_blocks * (k_minus_1 * (k_minus_1 + 1) / 2);
        }
        if (k >= 0) { // Ensure k is non-negative
            substrings_of_zeros += num_larger_blocks * (k * (k + 1) / 2);
        }

        // The maximum f(s) is total_substrings - minimum_substrings_of_zeros
        std::cout << total_substrings - substrings_of_zeros << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n and m are non-negative and n >= m for simpler logic
        n = std::abs(n);
        m = std::abs(m);
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: Not enough moves to reach the target
        // The minimum number of moves to reach (n, m) is n (by making n diagonal moves if m=n, or n moves along x-axis then m moves along y-axis if m=0, etc.)
        // More generally, it's max(n, m) if we can make diagonal moves.
        // Since we ensured n >= m, the minimum moves is n.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Parity check
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // A move from (x,y) to (x',y') changes (x'+y') - (x+y).
        // (x'+y') - (x+y) = (x'-x) + (y'-y).
        // (x'-x) can be -1, 0, 1. (y'-y) can be -1, 0, 1.
        // The sum (x'-x) + (y'-y) can be any integer from -2 to 2.
        // This means the parity of (x+y) changes by the parity of (x'-x) + (y'-y).
        // (x'-x) + (y'-y) is even if both (x'-x) and (y'-y) are even (0,0 - not a move) or both are odd (diagonal move).
        // (x'-x) + (y'-y) is odd if one is even and one is odd (non-diagonal move).
        // So, a diagonal move changes (x+y) by an even amount (e.g., (1,1) -> +2, (1,-1) -> 0, (-1,-1) -> -2).
        // A non-diagonal move changes (x+y) by an odd amount (e.g., (1,0) -> +1, (0,-1) -> -1).
        //
        // The parity of (n+m) must be the same as the parity of k.
        // If (n+m) and k have different parities, it's impossible.
        // (n+m) % 2 != k % 2
        // This is equivalent to (k - (n+m)) % 2 != 0.
        //
        // Let's consider the number of moves beyond the minimum 'n' moves.
        // These are 'k - n' extra moves.
        // Each extra move must effectively cancel out a previous move or move back and forth.
        // For example, move (1,0) then (-1,0) uses 2 moves and ends at the same spot.
        // Each such pair of moves changes the coordinate sum by an even amount.
        // So, if k - n is odd, we need to make an odd number of "cancelling" moves.
        // A single "cancelling" move (e.g., (1,0) then (0,0) -> (1,0) then (0,0) -> (1,0) then (0,0))
        // A move from (x,y) to (x',y') changes the parity of (x+y) if it's a non-diagonal move.
        // A move from (x,y) to (x',y') does not change the parity of (x+y) if it's a diagonal move.
        //
        // The target (n,m) has parity (n+m)%2.
        // The start (0,0) has parity 0.
        // After k moves, the final (x,y) must have parity (x+y)%2.
