}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n + 1, std::vector<long long>(n + 1));
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    std::vector<long long> results;
    std::vector<bool> active(n + 1, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of removal
    // This means we are adding vertices one by one to an initially empty graph
    // and calculating APSP sum for the current set of active vertices.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added to the graph

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // Floyd-Warshall logic: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // We only consider paths between currently active vertices.
        for (int i = 1; i <= n; ++i) {
            if (!active[i]) continue; // Only consider active 'i'
            for (int j = 1; j <= n; ++j) {
                if (!active[j]) continue; // Only consider active 'j'

                // Update paths that go through k
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if -1 was used for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After adding k and updating paths through k, we also need to consider
        // paths between existing active vertices that might now be shorter
        // because they can use k as an endpoint or starting point.
        // This is implicitly handled by the above triple loop if we iterate over all active i, j, k.
        // The standard Floyd-Warshall structure is k-loop outermost.
        // Here, k is the *newly added* vertex. So we need to update paths
        // between any two *already active* vertices (i, j) using k,
        // and paths from k to any active j, and from any active i to k.
        // The above triple loop (i, j, k) where k is the newly added vertex
        // correctly updates all these cases.
        // For example, if i and j are already active, and k is newly active:
        // dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // dist[i][k] = min(dist[i][k], dist[i][j_old] + dist[j_old][k]) (this is not needed, dist[i][k] is initial)
        // dist[k][j] = min(dist[k][j], dist[k][i_old] + dist[i_old][j]) (this is not needed, dist[k][j] is initial)
        // The key is that when k is added, it can be an intermediate vertex.
        // The standard Floyd-Warshall structure is:
        // for k from 1 to N:
        //   for i from 1 to N:
        //     for j from 1 to N:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // Here, we are effectively doing this in reverse.
        // When we add vertex `k`, we make it available as an intermediate vertex.
        // So, for all pairs `(i, j)` that are currently active (including `k` itself),
        // we update `dist[i][j]` using `k` as an intermediate.
        // The loops above correctly implement this:
        // for all active i:
        //   for all active j:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This is the core of the reverse Floyd-Warshall.

        long long current_sum = 0;
        for (int i = 1; i <= n; ++i) {
            if (!active[i]) continue;
            for (int j = 1; j <= n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first removal to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for 'x', 'y', 'z' counts
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-based indexing
        --l; 
        // r is already exclusive for prefix sum, so it's fine

        int len = r - l;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = counts[0][r] - counts[0][l];
        int count_y = counts[1][r] - counts[1][l];
        int count_z = counts[2][r] - counts[2][l];

        // The condition for infinite loop is that the counts of 'x', 'y', 'z'
        // are "too far apart". Specifically, if the difference between the max count
        // and min count is greater than 1, it's impossible to form a string
        // where all 3-char substrings are permutations of "xyz".
        // For example, if counts are (3, 1, 1), then max-min = 2.
        // If counts are (2, 2, 1), then max-min = 1. This is fine.
        // If counts are (1, 1, 1), then max-min = 0. This is fine.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

