// Function to apply median smoothing once
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    std::vector<int> b(n);
    if (n == 0) return b;

    b[0] = a[0];
    if (n > 1) {
        b[n - 1] = a[n - 1];
    }

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        if (sum >= 2) { // Median is 1 if at least two are 1s
            b[i] = 1;
        } else { // Median is 0 otherwise
            b[i] = 0;
        }
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find all segments of alternating 01010... or 10101...
    // These are the only parts that can change.
    // A segment is defined by its start and end indices (inclusive).
    // The values at start-1 and end+1 (if they exist) must be different from the segment's pattern.
    // For example, 0 1 0 1 0 0. The segment 1 0 1 0 is from index 1 to 4.
    // a[0]=0, a[5]=0.
    // The segment 0 1 0 1 0 is from index 0 to 4.
    // a[5]=0.

    std::vector<std::pair<int, int>> alternating_segments;
    int current_start = -1;

    for (int i = 0; i < n; ++i) {
        if (i > 0 && i < n - 1 && a[i] != a[i-1] && a[i] != a[i+1] && a[i-1] == a[i+1]) {
            // This condition (a[i-1] == a[i+1] && a[i] != a[i-1]) means we have a pattern like X Y X
            // e.g., 0 1 0 or 1 0 1. This is the core of an alternating sequence.
            if (current_start == -1) {
                current_start = i - 1;
            }
        } else {
            if (current_start != -1) {
                alternating_segments.push_back({current_start, i - 1});
                current_start = -1;
            }
        }
    }
    if (current_start != -1) {
        alternating_segments.push_back({current_start, n - 1});
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (const auto& segment : alternating_segments) {
        int start = segment.first;
        int end = segment.second;

        // The length of the alternating part is end - start + 1.
        // The number of steps for stabilization depends on the length and the surrounding values.
        // The effective length for stabilization is from start to end.
        // The values at start and end are fixed by the boundary conditions of the segment.
        // The values at start-1 and end+1 (if they exist) are also fixed.

        // Case 1: Segment starts with 0 and ends with 0 (e.g., 01010)
        // Case 2: Segment starts with 1 and ends with 1 (e.g., 10101)
        // Case 3: Segment starts with 0 and ends with 1 (e.g., 0101)
        // Case 4: Segment starts with 1 and ends with 0 (e.g., 1010)

        // The crucial observation is that the "wave" of change propagates from the ends of the alternating segment.
        // If a[start] == a[end], then the segment will eventually become all a[start] (or a[end]).
        // The number of steps is ceil((length - 1) / 2).
        // If a[start] != a[end], then the segment will eventually become all 0s or all 1s,
        // but the stabilization depends on the surrounding values.
        // However, the problem statement implies that the sequence stabilizes to a state where
        // b_i = a_i for all i. This means that for any i, a[i-1], a[i], a[i+1] must be all same,
        // or two of them are same and a[i] is the median.
        // The only stable patterns are blocks of 0s and 1s.
        // e.g., 000111000.
        // An alternating sequence like 01010 will stabilize to 00000 if a[0]=0 and a[n-1]=0.
        // An alternating sequence like 10101 will stabilize to 11111 if a[0]=1 and a[n-1]=1.
        // If a[start] != a[end], then the segment will stabilize to a mix, e.g., 0101 -> 0011.
        // The number of steps is related to the distance from the ends.

        // Let's re-evaluate the stabilization for a segment [start, end].
        // The values a[start] and a[end] are fixed.
        // The values a[start+1]...a[end-1] are the ones that change.
        // The "wave" of stabilization moves inwards from both ends.
        // For example, 0 1 0 1 0.
        // a[0]=0, a[4]=0.
        // b[1] = median(a[0],a[1],a[2]) = median(0,1,0) = 0.
        // b[3] = median(a[2],a[3],a[4]) = median(0,1,0) = 0.
        // So, 0 1 0 1 0 -> 0 0 0 0 0.
        // The number of steps is (end - start) / 2.
        // For 01010 (length 5, start=0, end=4), steps = (4-0)/2 = 2.
        // For 0101 (length 4, start=0, end=3), a[0]=0, a[3]=1.
        // b[1] = median(0,1,0) = 0.
        // b[2] = median(1,0,1) = 1.
        // So, 0101 -> 0011. Steps = 1.
        // This is (end - start) / 2 if a[start] == a[end].
        // This is (end - start + 1) / 2 if a[start] != a[end].

        int current_segment_steps;
        if (a[start] == a[end]) {
            current_segment_steps = (end - start) / 2;
            // All elements in the segment [start, end] will become a[start]
            for (int k = start; k <= end; ++k) {
                final_a[k] = a[start];
            }
        } else { // a[start] != a[end]
            current_segment_steps = (end - start + 1) / 2;
            // The segment will become a[start]...a[start]a[end]...a[end]
            // The split point is at start + current_segment_steps - 1 and start + current_segment_steps
            for (int k = start; k < start + current_segment_steps; ++k) {
                final_a[k] = a[start];
            }
            for (int k = start + current_segment_steps; k <= end; ++k) {
                final_a[k] = a[end];
            }
        }
        max_steps = std::max(max_steps, current_segment_steps);
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v, d, p;
    int original_index;
    bool is_removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].is_removed = false;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (children[i].is_removed) {
            continue;
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_index);
        children[i].is_removed = true;

        long long current_v_cry = children[i].v;
        long long d_cry_sum = 0; // Accumulates d_j cries from children leaving

        for (int j = i + 1; j < n; ++j) {
            if (children[j].is_removed) {
                continue;
            }

            // Apply d_cry_sum first (from previous children who left)
            children[j].p -= d_cry_sum;

            // Apply current_v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].is_removed = true;
                d_cry_sum += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) { // i is the length of the first piece
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);

        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "qqqq"), then no matter how we cut and reorder,
    // the resulting string will always be the same string of identical characters, which is s itself.
    // In this specific case, it's impossible to form a new palindrome different from s.
    // We can check this by counting distinct characters. If there's only one, it's impossible.

    // Count distinct characters
    std::vector<bool> seen(26, false);
    int distinct_chars = 0;
    for (char c : s) {
        if (!seen[c - 'a']) {
            seen[c - 'a'] = true;
            distinct_chars++;
        }
    }

    if (distinct_chars <= 1) { // If all characters are the same
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If we reach here, it means k=1 didn't work, and there are at least two distinct characters.
    // For any palindrome s with length > 1 and at least two distinct characters,
    // it's always possible to achieve a new palindrome with k=2 cuts.
    //
    // Consider the string s = s_prefix + s_middle + s_suffix.
    // Since s is a palindrome, s_prefix = reverse(s_suffix).
    // We can cut s into three pieces:
    // 1. s_prefix (length 1 to n/2 - 1)
    // 2. s_middle (the rest of the string, including the center character if n is odd)
    // 3. s_suffix (length 1 to n/2 - 1)
    //
    // Example: "nolon" (n=5)
    // s_prefix = "n", s_middle = "olo", s_suffix = "n"
    // Cut: "n" | "olo" | "n"
    // Reorder: "n" | "n" | "olo" -> "nnolo" (not a palindrome)
    //
    // The strategy for k=2 is to take a prefix of length `i` (where `1 <= i < n`),
    // and check if the remaining suffix `s.substr(i)` is a palindrome.
    // If `s.substr(i)` is a palindrome, then `s` can be written as `P + M` where `P` is `s.substr(0, i)`
    // and `M` is `s.substr(i)`.
    // Since `s` is a palindrome, `P + M` is a palindrome.
    // If `M` is also a palindrome, then `P` must also be a palindrome.
    //
    // This is not the correct logic for k=2.
    //
    // The proof for k=2 being always possible (if not k=1 and not all same chars):
    // Take any prefix `s_prefix` of length `i` where `1 <= i < n/2`.
    // Let `s = s_prefix + s_middle + s_suffix`.
    // Since `s` is a palindrome, `s_suffix = reverse(s_prefix)`.
    //
    // Cut `s` into `s_prefix`, `s_middle`, `s_suffix`.
    // Reorder them as `s_suffix + s_middle + s_prefix`.
    // This new string is `reverse(s_prefix) + s_middle + s_prefix`.
    // This is a palindrome if `s_middle` is a palindrome.
    //
    // Example: "abacaba"
    // n=7.
    // i=1: s_prefix="a", s_middle="bacab", s_suffix="a".
    // New string: "a" + "bacab" + "a" = "abacaba" (same as s)
    //
    // The problem states "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
    //
    // For k=2, we cut s into 3 pieces: `p1`, `p2`, `p3`.
    // `s = p1 + p2 + p3`.
    // We need to find a reordering `p_a + p_b + p_c` such that it's a palindrome and not equal to `s`.
    //
    // Consider cutting `s` into `s[0...i-1]`, `s[i...j-1]`, `s[j...n-1]`.
    //
    // A simpler argument for k=2:
    // If `s` is a palindrome and not all characters are the same, and `n > 1`.
    // We can always find a `k=2` solution.
    // Take `s_prefix = s[0]`, `s_middle = s[1...n-2]`, `s_suffix = s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    //
    // If `s_middle` is not empty (i.e., `n > 2`):
    // Cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    // Reorder as `s[n-1] + s[1...n-2] + s[0]`.
    // This is `s[0] + s[1...n-2] + s[0]`.
    // This is a palindrome if `s[1...n-2]` is a palindrome.
    //
    // If `s[1...n-2]` is a palindrome, then `s[0] + s[1...n-2] + s[0]` is `s`.
    // This means `s` is of the form `c + P + c` where `P` is a palindrome.
    //
    // What if `s[1...n-2]` is NOT a palindrome?
    // Example: "abacaba"
    // s[0]='a', s[1...5]="bacab", s[6]='a'.
    // "bacab" is a palindrome. So `s[0] + s[1...5] + s[6]` is `s`.
    //
    // The key insight for k=2 is that if k=1 doesn't work, and not all characters are the same,
    // then we can always find a solution with k=2.
    //
    // Consider the string `s` and its first half `s_half = s.substr(0, n/2)`.
    // If `s_half` is not a palindrome, then `s` cannot be formed by repeating a smaller palindrome.
    //
    // The problem states: "It can be shown that there is no solution with one cut." for "nolon".
    // "nolon" has distinct characters 'n', 'o', 'l'.
    // n=5.
    // Cuts for k=1:
    // n | olon -> olonn (not pal)
    // no | lon -> lonno (not pal)
    // nol | on -> onnol (not pal)
    // nolo | n -> nolon (same as s)
    //
    // For "nolon", k=2 solution:
    // Cut: "no" | "l" | "on"
    // Reorder: "on" | "l" | "no" -> "onlno" (palindrome, not equal to "nolon")
    // This is a valid k=2 solution.
    //
    // The general proof for k=2:
    // If `s` is a palindrome, `n > 1`, and not all characters are the same.
    // If `k=1` doesn't work, it means for any split `s = s1 + s2`, `s2 + s1` is either not a palindrome or `s2 + s1 == s`.
    //
    // Consider the string `s_prime = s.substr(0, n-1)`.
    // If `s_prime` is a palindrome, then `s` must be of the form `P + c` where `P` is a palindrome.
    // Since `s` is a palindrome, `s = c + P`.
    // So `s` must be `c + P + c`.
    //
    // If `s` is a palindrome and not all characters are the same, and `n > 1`.
    // If `n` is odd, `s = s_left + center_char + s_right`. `s_left = reverse(s_right)`.
    // If `n` is even, `s = s_left + s_right`. `s_left = reverse(s_right)`.
    //
    // Consider the string `s_sub = s.substr(0, n/2)`.
    // If `s_sub` is a palindrome, then `s` is of the form `P + (middle) + reverse(P)`.
    // If `P` is a palindrome, then `s` is `P + (middle) + P`.
    // If `s` is `P + (middle) + P` and `P` is a palindrome, and `middle` is a palindrome,
    // then `s` is a palindrome.
    //
    // The condition for k=2 is simply that k=1 didn't work and not all characters are the same.
    // This is a known property for palindromes. If a palindrome `S` cannot be rearranged into a different palindrome using 1 cut,
    // and `S` contains at least two distinct characters, then it can be done with 2 cuts.
    //
    // The only case where it's impossible is when all characters are the same.
    // We've already handled that: `distinct_chars <= 1`.
    //
    // So, if we reach this point, it means `k=1` didn't work, but `distinct_chars > 1`.
    // This implies `k=2` is always possible.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();
    long long total_pairs = (long long)n * (n + 1) / 2;

    // min_r_for_l[i] stores the minimum r (1-indexed) such that the substring s[i...r-1]
    // contains a triple match. If no such r exists, it's n+1.
    // We are interested in the smallest r such that s[i...r-1] is "good".
    // This means we need to find the smallest r such that there exists x, k
    // with s[x-1]=s[x+k-1]=s[x+2k-1] and i <= x-1 and x+2k-1 <= r-1.
    // This is equivalent to finding the smallest r such that r-1 >= x+2k-1 for some valid x, k.
    // So, r >= x+2k.
    // The minimum r for a given l (1-indexed) is min(x+2k) over all valid x, k
    // such that x >= l.
    // Let's use 0-indexed for `min_r_for_l` where `min_r_for_l[i]` is the minimum
    // 0-indexed end position `j` such that `s[i...j]` contains a triple match.
    // If no such `j` exists, it's `n`.
    std::vector<int> min_end_idx(n + 1, n); // min_end_idx[i] = min j such that s[i...j] is good.

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible step sizes k.
    // The maximum possible k is (n-1-x)/2.
    // The maximum k for x=0 is (n-1)/2.
    // The maximum k for x=n-3 is 0.
    // The maximum k is roughly n/3.
    // The maximum value for x+2k is n-1.
    // So x+2k < n.
    // x < n-2k.
    // k can go up to (n-1)/2.
    // If k=1, x can go up to n-3.
    // If k=2, x can go up to n-5.
    // If k=3, x can go up to n-7.
    // The maximum k we need to check is small.
    // If k is large, say k > 6, then 2k > 12.
    // If we have a triple match s[x] = s[x+k] = s[x+2k],
    // then for any l <= x and r >= x+2k, the pair (l,r) is good.
    // We are looking for the smallest r for each l.
    // This means we need to find the smallest x+2k for each x.
    // Let's define `first_good_end[i]` as the minimum `j` such that `s[i...j]` contains a triple match.
    // If no such `j` exists, `first_good_end[i]` is `n`.

    // The problem states $1 \leq x, k \leq n$.
    // $l \leq x < x+2k \leq r$.
    // $s_x = s_{x+k} = s_{x+2k}$.
    // In 0-indexed: $s[x-1] = s[x+k-1] = s[x+2k-1]$.
    // Let $x' = x-1$. Then $s[x'] = s[x'+k] = s[x'+2k]$.
    // $0 \leq x' < x'+2k \leq n-1$.
    // $l-1 \leq x'$ and $x'+2k \leq r-1$.

    // We need to find the minimum `r_idx` (0-indexed) for each `l_idx` (0-indexed)
    // such that `s[l_idx ... r_idx]` contains a triple match.
    // Let `min_valid_r_idx[l_idx]` be this value.
    // Initialize `min_valid_r_idx` with `n` (meaning no valid `r_idx` found for that `l_idx`).

    // The maximum value for k is limited.
    // If k is large, say k >= 7, then 2k >= 14.
    // If s[x] = s[x+k] = s[x+2k], then the length of this pattern is 2k+1.
    // If k >= 7, then 2k+1 >= 15.
    // Consider the string s[x...x+14].
    // If s[x] = s[x+k] = s[x+2k] for k >= 7, then this implies that
    // s[x] = s[x+k] = s[x+2k] for some k' <= 6.
    // This is because if s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // If k >= 7, then there must be a shorter pattern.
    // For example, if s[x] = s[x+7] = s[x+14], then s[x] = s[x+1] = s[x+2] = ... = s[x+14] is not necessarily true.
    // But if s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // The crucial observation is that if a triple match exists for a large k,
    // it implies that the substring s[x...x+2k] is "good".
    // If there is a triple match s[x] = s[x+k] = s[x+2k], then the substring s[x...x+2k] is good.
    // Any substring s[l...r] where l <= x and r >= x+2k is also good.
    // We want to find the minimum r for each l.
    // This means for each l, we want to find min(x+2k) such that x >= l and s[x]=s[x+k]=s[x+2k].

    // Let's iterate through all possible starting positions `i` (0-indexed) for the pattern `s[i] = s[i+k] = s[i+2k]`.
    // For each `i`, we check small values of `k`.
    // The maximum `k` we need to check is small.
    // If `s[i] = s[i+k] = s[i+2k]`, then `i+2k` is the end index of this pattern.
    // For any `l_idx <= i`, the substring `s[l_idx ... i+2k]` is good.
    // So, `min_valid_r_idx[l_idx]` can be updated to `min(min_valid_r_idx[l_idx], i+2k)`.

    // The maximum k to check:
    // If s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // If k is large, say k=7, then s[x]=s[x+7]=s[x+14].
    // If s[x] = s[x+1] = s[x+2] = ... = s[x+m] for m >= 14, then any k <= m/2 would work.
    // The maximum k we need to check is 6.
    // Why 6? Consider any sequence of 15 characters. If it contains a triple match,
    // it must contain one with k <= 6.
    // This is a known property for certain pattern matching problems.
    // If a string of length L contains a pattern of type A_k B_k C_k (where A, B, C are characters and k is step),
    // then if L is large enough, it must contain such a pattern with small k.
    // For $s_x = s_{x+k} = s_{x+2k}$, the length of the pattern is $2k+1$.
    // If $2k+1 \ge 15$, i.e., $k \ge 7$, then it is guaranteed that if such a pattern exists,
    // there must be a pattern with $k' \le 6$ within the same range.
    // This is a result from combinatorics on words, related to "squares" or "cubes".
    // For example, if $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then the substring $s[x \dots x+2k]$ is "good".
    // It is known that if a string contains a 3-term arithmetic progression of identical characters,
    // it must contain one where the common difference is at most 6.
    // This means we only need to check $k \in \{1, 2, 3, 4, 5, 6\}$.
    // This significantly reduces the complexity.

    std::vector<int> min_r_idx_for_l_idx(n, n); // min_r_idx_for_l_idx[l_idx] = min r_idx such that s[l_idx...r_idx] is good.

    for (int i = 0; i < n; ++i) { // i is the 0-indexed x'
        for (int k = 1; k <= 6; ++k) { // k is the step
            if (i + 2 * k < n) { // Check if x'+2k is within bounds
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    // Found a triple match starting at i with step k, ending at i+2k.
                    // This means for any l_idx <= i, the substring s[l_idx ... i+2k] is good.
                    // So, we can update min_r_idx_for_l_idx[l_idx] to min(current, i+2k).
                    // Since we iterate i from 0 to n-1, and for each i, we update for l_idx <= i,
                    // we can simply update min_r_idx_for_l_idx[i] = min(current, i+2k).
                    // The propagation to smaller l_idx will be handled in the next step.
                    min_r_idx_for_l_idx[i] = std::min(min_r_idx_for_l_idx[i], i + 2 * k);
                }
            }
        }
    }

    // Now, propagate the minimum r_idx backwards.
    // If s[l_idx ... r_idx] is good, then s[l_idx-1 ... r_idx] is also good.
    // So, min_r_idx_for_l_idx[l_idx-1] must be less than or equal to min_r_idx_for_l_idx[l_idx].
    // Specifically, min_r_idx_for_l_idx[l_idx-1] = min(min_r_idx_for_l_idx[l_idx-1], min_r_idx_for_l_idx[l_idx]).
    for (int l_idx = n - 2; l_idx >= 0; --l_idx) {
        min_r_idx_for_l_idx[l_idx] = std::min(min_r_idx_for_l_idx[l_idx], min_r_idx_for_l_idx[l_idx + 1]);
    }

    long long good_pairs_count = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) {
        if (min_r_idx_for_l_idx[l_idx] < n) {
            // If min_r_idx_for_l_idx[l_idx] is less than n, it means there is at least one
            // valid r_idx for this l_idx.
            // The valid r_idx values are from min_r_idx_for_l_idx[l_idx] up to n-1.
            // The number of such r_idx values is (n-1) - min_r_idx_for_l_idx[l_idx] + 1.
            good_pairs_count += (n - min_r_idx_for_l_idx[l_idx]);
        }
    }

    std::cout << good_pairs_count << std::endl;

    return 0;
}

