#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long operations = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we want to add min_val to it
            // as many times as possible without exceeding k.
            // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
            // This is integer division, which correctly gives the floor.
            operations += (k - a[i]) / min_val;
        }
        std::cout << operations << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min (though not strictly needed with direct counts)

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // The number of '1's is limited by the count of 'n'
    // because 'n' is only used in "one".
    int num_ones = count_n;

    // The number of '0's is limited by the count of 'z'
    // because 'z' is only used in "zero".
    int num_zeros = count_z;

    // Print '1's first to form the maximum possible binary number
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "1";
        first_digit = false;
    }

    // Then print '0's
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "0";
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

