#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n even numbers starting from 4n and going downwards by 2,
        // but skipping 2*n if n is odd.
        // More simply, pick n numbers from the sequence 4n, 4n-2, 4n-4, ...
        // such that none divides another.
        // The sequence 4n, 4n-2, 4n-4, ..., 2n+2, 2n, 2n-2, ...
        // We need n numbers.
        // If we pick numbers from 2n+2 up to 4n, these are n numbers:
        // 2n+2, 2n+4, ..., 4n.
        // There are (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n numbers.
        // For any two numbers a, b in this set, say a < b:
        // a >= 2n+2.
        // b <= 4n.
        // If a divides b, then b = k*a for some integer k.
        // Since a and b are even, k must be an integer.
        // If k=1, then a=b, but we need distinct numbers.
        // If k >= 2, then b >= 2a.
        // But 2a >= 2*(2n+2) = 4n+4.
        // This contradicts b <= 4n.
        // So, no number in this set divides another.
        // Also, all numbers are even, so gcd(a,b) >= 2.
        // Thus, this set satisfies all conditions.

        for (int i = 0; i < n; ++i) {
            std::cout << 4 * n - 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

