#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required for k torches:
        // k sticks for crafting + k * y sticks for buying k coal
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to generate (total_sticks_required - 1) additional sticks.
        long long sticks_to_generate = total_sticks_required - 1;

        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of stick-generating trades needed:
        // (sticks_to_generate + (x - 1) - 1) / (x - 1) is equivalent to ceil(sticks_to_generate / (x - 1))
        long long stick_generating_trades = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Total trades = stick_generating_trades + trades for coal
        // Trades for coal = k (since 1 trade for 1 coal)
        long long total_trades = stick_generating_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

