void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // a_1 must be equal to b_1
    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Iterate from right to left (n-1 down to 1)
    // For each a_i, we need to check if it can be transformed into b_i
    // The elements a_0 to a_{i-1} are available to modify a_i.
    // We need to know if there's a 1 or a -1 among a_0 to a_{i-1}.
    // We can maintain this information as we iterate.

    // has_pos_one_prefix[k] is true if there is a 1 in a[0...k]
    // has_neg_one_prefix[k] is true if there is a -1 in a[0...k]
    // We need this for a[0...i-1] when considering a[i].
    // So, we can iterate from i=1 to n-1.
    // For a[i], we need to know if there's a 1 or -1 in a[0...i-1].
    // Let's track this dynamically.

    bool current_has_pos_one = (a[0] == 1);
    bool current_has_neg_one = (a[0] == -1);

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!current_has_pos_one) { // Can only increase if there's a 1 before it
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!current_has_neg_one) { // Can only decrease if there's a -1 before it
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed, or it can be done if possible.
        // The crucial part is that if a[i] needs to change, the necessary prefix element must exist.

        // Update prefix information for the next iteration (i+1)
        if (a[i] == 1) {
            current_has_pos_one = true;
        } else if (a[i] == -1) {
            current_has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

