#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_elements;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_elements.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_elements.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new value.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_elements.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused value less than q_i
            // We need to find the smallest available number that is not yet used.
            // The numbers available are 1 to n.
            // We can iterate from 1 upwards to find the smallest unused number.
            // However, a more efficient way is to keep track of available numbers.
            // The problem states p_i must be distinct and between 1 and n.
            // The values q_i are also between 1 and n.
            // The values already used are in `used_elements`.
            // We need to find an `x` such that `1 <= x < q_i` and `x` is not in `used_elements`.
            // To maximize chances of finding a solution, we should pick the smallest available `x`.

            // Find the smallest number `x` such that `x` is not in `used_elements`
            // and `x < q_i`.
            int current_val = 1;
            while (used_elements.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) {
                // No available number less than q_i
                possible = false;
                break;
            }
            p[i] = current_val;
            used_elements.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

