        long long current_cost = 0;
        long long k = 1; // Represents the 'n' for the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a nice staircase with k stairs is k * (k + 1) / 2
            // For k = 1, cost = 1 * 2 / 2 = 1
            // For k = 3, cost = 3 * 4 / 2 = 6
            // For k = 7, cost = 7 * 8 / 2 = 28
            // For k = 15, cost = 15 * 16 / 2 = 120
            long long cost_of_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_staircase <= x) {
                current_cost += cost_of_staircase;
                count++;
                // Next k is 2*k + 1
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

