    // If B + C > 0, magnitude < 1 is possible (same logic as for Box 2).
    // Now we only need to ensure the sign is positive.
    // This means the total number of negative factors (A+B) must be even.
    if ((A + B) % 2 == 0) {
        return true;
    } else {
        // If (A+B) is odd, the product of all toys is negative.
        // To get a positive final product, we need to effectively change the parity of negative signs.
        // This is impossible. The final product's sign is determined by the parity of negative factors.
        return false;
    }
}

// Function to check if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // To end up in Box 4, the final toy must be positive and have magnitude >= 1.
    // This means the total number of negative factors must be even.
    // And the product of magnitudes must be >= 1.

    // Case 1: Final product is positive.
    // This requires an even number of initial negative toys.
    // (A + B) % 2 == 0

    // Case 2: Final product has magnitude >= 1.
    // This requires at least one toy with magnitude >= 1 (from Box 1 or Box 4)
    // OR multiple toys from Box 2/3 that can combine to magnitude >= 1.
    // If A + D == 0, then all initial toys have magnitude < 1.
    // In this case, the final product will always have magnitude < 1.
    // So if A+D == 0, Box 1 and Box 4 are impossible.

    if (A + D == 0) { // All initial toys have magnitude < 1
        return false;
    }

    // If A + D > 0, magnitude >= 1 is possible (same logic as for Box 1).
    // Now we only need to ensure the sign is positive.
    // This means the total number of negative factors (A+B) must be even.
    if ((A + B) % 2 == 0) {
        return true;
    } else {
        // If (A+B) is odd, the product of all toys is negative.
        // To get a positive final product, we need to effectively change the parity of negative signs.
        // This is impossible. The final product's sign is determined by the parity of negative factors.
        return false;
    }
}

