#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k that satisfies x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each fixed x_i, we want to find all x_k such that x_k - x_i <= d.
        // Since x is sorted, we can advance right_ptr.
        // right_ptr will always be >= i.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i] to x[right_ptr - 1] satisfy the condition with x[i].
        // We need to choose two other points x_j and x_k from the range (x[i], x[right_ptr - 1]].
        // The number of available points in this range (excluding x[i] itself) is (right_ptr - 1) - i.
        // Let m = (right_ptr - 1) - i. These are the points x_{i+1}, ..., x_{right_ptr-1}.
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        // The number of points available to be x_j or x_k (where j, k > i) is (right_ptr - 1) - i.
        // Let's call this number 'num_valid_points_after_i'.
        // These points are x[i+1], x[i+2], ..., x[right_ptr-1].
        long long num_valid_points_after_i = (long long)(right_ptr - 1) - i;

        if (num_valid_points_after_i >= 2) {
            count += num_valid_points_after_i * (num_valid_points_after_i - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // 0-indexed median position

    // Operations for elements smaller than s that must be <= s
    // These are elements a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s.
    // However, the problem states that elements to the left of median must be <= s.
    // If a[i] > s for i < median_idx, we must decrease it to s.
    // If a[i] < s for i < median_idx, it's already fine.
    // The median itself must be s.
    // Elements to the right of median must be >= s.

    // First, handle the median element itself.
    // It must become s.
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually set it to s for subsequent checks

    // Handle elements to the left of the median (indices 0 to median_idx - 1)
    // These elements must be <= s.
    // If any a[i] (i < median_idx) is greater than s, we must decrease it to s.
    // If a[i] is already <= s, no operations are needed for it to satisfy the condition.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Handle elements to the right of the median (indices median_idx + 1 to n - 1)
    // These elements must be >= s.
    // If any a[i] (i > median_idx) is smaller than s, we must increase it to s.
    // If a[i] is already >= s, no operations are needed for it to satisfy the condition.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

