int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Create pairs (B_i, original_index_i) and sort them by B_i in ascending order
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }
    std::sort(b_indexed.begin(), b_indexed.end());

    // The optimal strategy is to pair the largest A_i with the largest F(A_i, B_j) value.
    // F(n, k) = (n+1) / (k+1).
    // We want to maximize sum((A_i + 1) / (B_j + 1)).
    // This is equivalent to maximizing sum((A_i + 1) * (1 / (B_j + 1))).
    // To maximize sum(x_i * y_i) where x_i and y_i are elements from two sets,
    // we should sort one set in ascending order and the other in descending order,
    // then pair them up.
    // Here, A_i + 1 is sorted ascending.
    // So, 1 / (B_j + 1) should be sorted descending.
    // This means B_j + 1 should be sorted ascending.
    // So, B_j should be sorted ascending.

    // We have sorted A in ascending order.
    // We have sorted B_indexed by B_i in ascending order.
    // To maximize the sum, we should pair the largest A_i with the largest (1/(B_j+1)),
    // which means pairing the largest A_i with the smallest B_j.
    // And the smallest A_i with the smallest (1/(B_j+1)),
    // which means pairing the smallest A_i with the largest B_j.
    // This is a reverse pairing.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B_j (b_indexed[i].first) should be paired with
        // the (m-1-i)-th smallest A_k (a[m-1-i]), which is the (i+1)-th largest A_k.
        // The original index for this B_j is b_indexed[i].second.
        result_a_prime[b_indexed[i].second] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

