// Function to check if a sub-array is a permutation of 1 to len
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // For this problem, l1, l2 >= 1.
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_distinct(n + 1, false);
    int current_max = 0;
    bool current_distinct = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || prefix_distinct[a[i]]) {
            current_distinct = false;
        }
        prefix_distinct[a[i]] = true;
        if (a[i] > current_max) {
            current_max = a[i];
        }
        prefix_max[i] = current_max;
        // Store 1 if prefix a[0...i] is a permutation of 1 to i+1
        // Store 0 otherwise
        // This is a bitmask or flag, not a count.
        // We need to check if current_distinct is true AND current_max == i+1
        prefix_max[i] = (current_distinct && current_max == (i + 1)) ? 1 : 0;
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_distinct(n + 1, false);
    current_max = 0;
    current_distinct = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || suffix_distinct[a[i]]) {
            current_distinct = false;
        }
        suffix_distinct[a[i]] = true;
        if (a[i] > current_max) {
            current_max = a[i];
        }
        // Store 1 if suffix a[i...n-1] is a permutation of 1 to n-i
        // Store 0 otherwise
        suffix_max[i] = (current_distinct && current_max == (n - i)) ? 1 : 0;
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (prefix_max[l1 - 1] == 1 && suffix_max[l1] == 1) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

