    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // We need to append two elements.
        // Let the two elements be X and S + X.
        // New XOR sum: current_xor_sum ^ X ^ (S + X)
        // New sum: current_sum + X + (S + X)
        // We want: current_sum + X + (S + X) = 2 * (current_xor_sum ^ X ^ (S + X))
        // Let b1 = current_xor_sum.
        // Let b2 = current_sum + current_xor_sum.
        // New XOR sum: current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        //            = 0 ^ (current_sum + current_xor_sum)
        //            = current_sum + current_xor_sum
        // New sum: current_sum + current_xor_sum + (current_sum + current_xor_sum)
        //        = 2 * (current_sum + current_xor_sum)
        // This satisfies the condition: New sum = 2 * New XOR sum.

        std::cout << 2 << std::endl;
