int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long power_of_2 = 1; // Represents 2^count_a
    const long long MOD = 1e9 + 7;

    // Iterate through the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // that moves past it will contribute to the total steps.
            // The number of 'a's currently to its left (count_a)
            // determines how many times this 'b' will be involved
            // in an 'ab' -> 'bba' operation.
            // Each 'a' to its left will effectively "double" the number
            // of 'b's that this 'b' represents for future 'a's.
            // So, when we see a 'b', we add the current power_of_2
            // (which is 2^count_a) to the total steps.
            total_steps = (total_steps + power_of_2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means it will eventually
            // move past all 'b's to its right.
            // Each 'a' effectively doubles the number of 'b's that
            // will be generated for subsequent 'a's to its left.
            // So, we double power_of_2.
            power_of_2 = (power_of_2 * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
