int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_count = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Check for the longest prefix of 1, 2, 3, ...
        // If the chain starts with 1, then 1->2->3...
        if (chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    consecutive_count++;
                    current_expected++;
                } else {
                    break; // Sequence 1,2,3... is broken
                }
            }
        }
    }

    // Total operations to disassemble everything:
    // Each matryoshka that is nested needs to be taken out.
    // In a chain of length m, there are m-1 nested matryoshkas.
    // Sum of (m_i - 1) for all chains = (sum m_i) - k = n - k.
    // This is the number of 'get out' operations.
    total_operations += (n - k);

    // Total operations to assemble the target chain 1->2->...->n:
    // We need n-1 'put in' operations.
    total_operations += (n - 1);

    // Now, subtract the operations saved by the existing 1->2->...->consecutive_count sequence.
    // This sequence is already formed.
    // It means 'consecutive_count - 1' 'put in' operations are already done.
    // It also means 'consecutive_count - 1' 'get out' operations are not needed for this part
    // if it were to be disassembled and reassembled.
    // The problem states that we need to form 1->2->...->n.
    // If we have 1->2->...->X already, we don't need to disassemble it.
    // We also don't need to re-assemble it.
    //
    // The `consecutive_count` represents the length of the prefix `1, 2, ..., consecutive_count`
    // that is already correctly formed and connected.
    //
    // For example, if `consecutive_count` is 3 (meaning 1->2->3 is present):
    // We save 2 'put in' operations (put 1 in 2, put 2 in 3).
    // We save 2 'get out' operations (get 1 out of 2, get 2 out of 3).
    // So, we save 2 * (consecutive_count - 1) operations.
    //
    // The number of 'put in' operations saved is `consecutive_count - 1`.
    // The number of 'get out' operations saved is `consecutive_count - 1`.
    //
    // So, total operations saved = 2 * (consecutive_count - 1).
    //
    // Example: n=3, k=2, chains: 2 1 2; 1 3
    // consecutive_count = 2 (from 1->2)
    // total_operations = (3-2) + (3-1) = 1 + 2 = 3
    // saved = 2 * (2-1) = 2
    // result = 3 - 2 = 1. Correct.
    //
    // Example: n=7, k=3, chains: 3 1 3 7; 2 2 5; 2 4 6
    // consecutive_count = 1 (from 1)
    // total_operations = (7-3) + (7-1) = 4 + 6 = 10
    // saved = 2 * (1-1) = 0
    // result = 10 - 0 = 10. Correct.

    total_operations -= 2LL * (consecutive_count - 1);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <map>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find the largest divisor of p that is not divisible by q.
    // This means we need to remove factors from p such that it's no longer divisible by q.
    // To maximize x, we should remove as few factors as possible, and specifically,
    // remove factors that are "critical" for q's divisibility.

    // Find prime factors of q
    std::map<long long, int> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            while (temp_q % i == 0) {
                q_prime_factors[i]++;
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors[temp_q]++;
    }

    long long max_x = 1;

    // For each prime factor f of q, we try to divide p by f until p is no longer divisible by q.
    // The resulting p' will be a candidate for x. We take the maximum among these candidates.
    for (auto const& [factor, count] : q_prime_factors) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::vector<char> current_coloring(n);
        int last1 = -1;
        int last2 = -1;
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < pivot_digit) {
                // Must be color 1
                if (digit < last1) {
                    possible_with_pivot = false;
                    break;
                }
                current_coloring[i] = '1';
                last1 = digit;
            } else if (digit > pivot_digit) {
                // Must be color 2
                if (digit < last2) {
                    possible_with_pivot = false;
                    break;
                }
                current_coloring[i] = '2';
                last2 = digit;
            } else { // digit == pivot_digit
                // Can be color 1 or color 2
                // Try to put it in color 2 if possible, to keep color 1 digits small
                if (digit >= last2) {
                    current_coloring[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) {
                    current_coloring[i] = '1';
                    last1 = digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            // Verify the final condition: last1 <= first2
            // This is implicitly handled by the logic.
            // If last1 is the largest digit in S1 and first2 is the smallest in S2,
            // then last1 <= pivot_digit <= first2.
            // Our construction ensures S1 and S2 are individually sorted.
            // The only remaining check is if last1 > first2.
            // If a digit `d` is assigned to color 1, it must be `d <= pivot_digit`.
            // If a digit `d` is assigned to color 2, it must be `d >= pivot_digit`.
            // So, `last1` (max of S1) will be `<= pivot_digit`.
            // And `first2` (min of S2) will be `>= pivot_digit`.
            // Thus, `last1 <= pivot_digit <= first2` is always true if both S1 and S2 are non-empty.
            // If S1 is empty, last1 is -1, condition holds.
            // If S2 is empty, first2 is effectively infinity, condition holds.
            // So, if `possible_with_pivot` is true, the coloring is valid.

            for (int i = 0; i < n; ++i) {
                result[i] = current_coloring[i];
            }
            found_solution = true;
            break; 
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined characters for each position modulo k

    // Step 1: Propagate constraints based on s[i] and s[i+k]
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int pos_mod_k = i % k;
            if (fixed_chars[pos_mod_k] == '?') {
                fixed_chars[pos_mod_k] = s[i];
            } else if (fixed_chars[pos_mod_k] != s[i]) {
                // Conflict: s[i] contradicts a previously determined character for this position modulo k
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Apply fixed_chars back to s and check for conflicts
    // This step is actually redundant if we only care about the final counts,
    // but it helps to visualize the string if needed.
    // The crucial part is that fixed_chars[j] must be consistent for all j.
    // We already ensured this in Step 1.

    // Step 3: Check if the first k characters (after applying fixed_chars) can form a k-balanced string
    int count0 = 0;
    int count1 = 0;
    int count_q = 0; // Count of '?' in the first k positions after propagation

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else { // fixed_chars[i] == '?'
            count_q++;
        }
    }

    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means:
    // 1. All s[i] and s[i+k] constraints are consistent.
    // 2. The counts of '0's and '1's in the first k positions (after propagation)
    //    do not exceed k/2.
    //
    // Since count0 + count1 + count_q = k, and we need k/2 zeros and k/2 ones,
    // we must have:
    // count0 + (number of '?' replaced by '0') = k/2
    // count1 + (number of '?' replaced by '1') = k/2
    //
    // This implies:
    // (number of '?' replaced by '0') = k/2 - count0
    // (number of '?' replaced by '1') = k/2 - count1
    //
    // The total number of '?'s that need to be replaced is (k/2 - count0) + (k/2 - count1).
    // This sum must be equal to count_q.
    // (k/2 - count0) + (k/2 - count1) = k - count0 - count1.
    // Since count_q = k - count0 - count1, this condition is automatically met
    // if count0 <= k/2 and count1 <= k/2.
    //
    // Therefore, if count0 <= k/2 and count1 <= k/2, we can always fill the remaining '?'s
    // to satisfy the k-balanced condition for the first block.
    // Because of the s[i] == s[i+k] property, if the first block is k-balanced,
    // all subsequent blocks will also be k-balanced.

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

