#include <iostream>
#include <algorithm> // For std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for simpler logic, as the problem is symmetric
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: Not enough moves to reach the target even with all diagonal moves
        // The minimum number of moves to reach (n, m) is m (if n <= m),
        // by making n diagonal moves and m-n straight moves.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the maximum possible diagonal moves if we only consider reaching (n,m)
        // We make n diagonal moves to reach (n,n). This uses n moves.
        // Then we make m-n straight moves to reach (n,m). This uses m-n moves.
        // Total moves so far: n + (m-n) = m.
        // Number of diagonal moves so far: n.
        long long current_diagonal_moves = n;
        long long remaining_moves = k - m;

        // Now we have 'remaining_moves' to spend. Each pair of moves (e.g., (1,0) then (-1,0))
        // can be used to increase diagonal moves or just waste moves.
        // We want to maximize diagonal moves.
        // A pair of moves like (1,1) then (-1,-1) uses 2 moves and results in (0,0) displacement,
        // adding 2 diagonal moves.
        // A pair of moves like (1,0) then (-1,0) uses 2 moves and results in (0,0) displacement,
        // adding 0 diagonal moves.
        // A pair of moves like (1,1) then (1,0) is not useful for maximizing diagonal moves.

        // The parity of (n+m) must be the same as the parity of k.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // (x_new + y_new) - (x_old + y_old) = (dx + dy).
        // If dx, dy are both non-zero (diagonal), dx+dy can be -2, 0, 2.
        // If one of dx, dy is zero (straight), dx+dy can be -1, 0, 1.
        // This means (x+y) changes by an even amount if it's a diagonal move,
        // and by an odd amount if it's a straight move.
        // So, (x_final + y_final) - (x_initial + y_initial) has the same parity as (number of straight moves).
        // (n+m) - 0 has the same parity as (k - current_diagonal_moves).
        // (n+m) % 2 == (k - current_diagonal_moves) % 2
        // (n+m) % 2 == (k - n) % 2
        // This is equivalent to (n+m+k-n) % 2 == 0, or (m+k) % 2 == 0.
        // Or, more simply, (n+m) and k must have the same parity.
        // If (n+m) % 2 != k % 2, it's impossible.
        // However, this is not entirely true. Consider (0,0) to (1,0) in 2 moves.
        // (1,0) -> (1,0) (0,0) -> (1,0) -> (0,0) -> (1,0)
        // (1,0) in 2 moves: (0,0) -> (1,0) -> (1,0) (1 straight, 1 no-op)
        // (0,0) -> (0,1) -> (1,0) (1 straight, 1 diagonal)
        // The parity condition is (n+m) % 2 == k % 2.
        // Let's check this:
        // Each move changes x by dx, y by dy.
        // (x_final - x_initial) = sum(dx_i)
        // (y_final - y_initial) = sum(dy_i)
        // (x_final - x_initial) + (y_final - y_initial) = sum(dx_i + dy_i)
        // (n+m) = sum(dx_i + dy_i)
        // Each (dx_i + dy_i) can be -2, -1, 0, 1, 2.
        // The parity of (dx_i + dy_i) is the same as the parity of (dx_i + dy_i)^2.
        // (dx_i + dy_i) % 2 == (dx_i % 2 + dy_i % 2) % 2.
        // A diagonal move has dx_i != 0 and dy_i != 0. So dx_i, dy_i are both odd.
        // (odd + odd) % 2 == 0.
        // A straight move has one of dx_i, dy_i as 0, the other as non-zero. So one is even, one is odd.
        // (even + odd) % 2 == 1.
        // So, (n+m) % 2 == (number of straight moves) % 2.
        // We know k = (number of diagonal moves) + (number of straight moves).
        // So (number of straight moves) = k - (number of diagonal moves).
        // (n+m) % 2 == (k - current_diagonal_moves) % 2.
        // This is equivalent to (n+m) % 2 == (k - n) % 2, since n is the initial diagonal moves.
        // (n+m) % 2 == (k - n) % 2
        // (n+m) % 2 == (k + n) % 2 (since -n and +n have same parity)
        // (m+k) % 2 == 0.
        // If (m+k) is odd, it's impossible.
        if ((m + k) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If (m+k) is even, it means (k-m) is also even.
        // We have 'remaining_moves' = k - m. This must be an even number.
        // Each pair of these remaining moves can be used to increase diagonal moves by 2.
        // For example, if we are at (x,y), we can move to (x+1, y+1) (diagonal) and then to (x,y) (diagonal).
        // This uses 2 moves and adds 2 to the diagonal count, while returning to the same point.
        // So, we can add 2 diagonal moves for each 2 remaining moves.
        current_diagonal_moves += remaining_moves; // remaining_moves is even, so this is valid.

        std::cout << current_diagonal_moves << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, then b-1=0, sum_r_term should be 0.

    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * 500000004) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term_part1 = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * 500000004) % MOD; // (a * (a+1) / 2)
    sum_k_term_part1 = (sum_k_term_part1 * (b % MOD)) % MOD; // b * (a * (a+1) / 2)

    long long sum_k_term_part2 = a % MOD; // + a

    long long sum_k_b_plus_1 = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    // Total sum = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r_term * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_L = dq.empty() ? 0 : L[dq.back()];
        long long prev_h = dq.empty() ? 0 : h[dq.back()];

        L[i] = std::max(h[i], prev_max_L + (h[i] - prev_h));
        dq.push_back(i);
    }

    std::vector<long long> R(n);
    dq.clear();

    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_R = dq.empty() ? 0 : R[dq.back()];
        long long prev_h = dq.empty() ? 0 : h[dq.back()];

        R[i] = std::max(h[i], prev_max_R + (h[i] - prev_h));
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

