#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else {
                    // Check if N is a power of 2
                    // A number is a power of 2 if (n & (n - 1)) == 0
                    // For N > 2, if N is a power of 2, taking N/2 leaves N/2, which is also a power of 2.
                    // The opponent will then take N/4, and so on.
                    // This leads to a sequence of N/2, N/4, N/8, ..., 2, 1.
                    // The opponent will always take N/2, leaving Chanek with 1 coin at the end.
                    // If Chanek takes 1, N-1 is odd. Opponent takes 1. N-2 is even.
                    // This strategy is complex. Let's simplify.

                    // If N is even, Chanek has two choices: take 1 or take N/2.
                    // If Chanek takes 1: N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    // If Chanek takes N/2: N becomes N/2 (even or odd).

                    // Consider the case where N is even.
                    // If N is a power of 2 (e.g., 4, 8, 16, ...):
                    // Chanek takes N/2. N becomes N/2. Chanek gets N/2.
                    // Opponent takes N/4. N becomes N/4. Opponent gets N/4.
                    // Chanek takes N/8. N becomes N/8. Chanek gets N/8.
                    // ...
                    // This continues until N=2.
                    // Chanek gets N/2 + N/8 + N/32 + ...
                    // Opponent gets N/4 + N/16 + N/64 + ...
                    // The last coin (1) goes to whoever is turn it is when N=1.
                    // If N is a power of 2, say 2^k.
                    // Chanek takes 2^(k-1). N=2^(k-1).
                    // Opponent takes 2^(k-2). N=2^(k-2).
                    // ...
                    // This continues until N=2.
                    // If k is odd, Chanek takes 2^(k-1), 2^(k-3), ..., 2^0.
                    // If k is even, Chanek takes 2^(k-1), 2^(k-3), ..., 2^1.
                    // The sum of Chanek's coins would be N/2 + N/8 + ...
                    // The sum of opponent's coins would be N/4 + N/16 + ...
                    // Total coins taken by Chanek: N/2 + N/8 + ... + 1 (if k is odd) or N/2 + N/8 + ... + 2 (if k is even)
                    // Total coins taken by Opponent: N/4 + N/16 + ... + 1 (if k is even) or N/4 + N/16 + ... + 2 (if k is odd)
                    // This is (N-1)/3 if N is 2^k and k is odd.
                    // This is (N-2)/3 + 1 if N is 2^k and k is even.
                    // This is (N/2) + (N/8) + ...
                    // Sum of geometric series: a(1-r^k)/(1-r)
                    // For N=2^k, Chanek gets N/2 + N/8 + ...
                    // This is N/2 * (1 + 1/4 + 1/16 + ...) = N/2 * (1 / (1 - 1/4)) = N/2 * (4/3) = 2N/3.
                    // But this is not quite right because the game ends when N=0.
                    // If N is a power of 2, say N = 2^k.
                    // Chanek takes N/2. N becomes N/2.
                    // Opponent takes N/4. N becomes N/4.
                    // Chanek takes N/8. N becomes N/8.
                    // ...
                    // This continues until N=1.
                    // The last coin (1) goes to the player whose turn it is when N=1.
