int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Do nothing
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Do nothing
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] multiples of n
        // Segment [1, n-1] (0-indexed: [0, n-2])
        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = a[i] % n;
            long long to_add = (remainder == 0) ? 0 : (n - remainder);
            std::cout << to_add << (i == n - 2 ? "" : " ");
            a[i] += to_add;
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] a multiple of n
        // Segment [n, n] (0-indexed: [n-1, n-1])
        std::cout << n << " " << n << "\n";
        long long remainder = a[n - 1] % n;
        long long to_add = (remainder == 0) ? 0 : (n - remainder);
        std::cout << to_add << "\n";
        a[n - 1] += to_add;

        // Operation 3: Make all elements zero
        // Segment [1, n] (0-indexed: [0, n-1])
        std::cout << 1 << " " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

