void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Calculate prefix differences for the left side (jars 1 to n)
    // diff_L[k] = (s_count - b_count) for jars a_1, ..., a_k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix differences for the right side (jars n+1 to 2n)
    // diff_R[k] = (s_count - b_count) for jars a_{2n-k+1}, ..., a_{2n}
    // Note: a_{2n-k} is the (2n-k+1)-th jar from the left, which is the k-th jar from the right end.
    // We want to map the difference of the suffix of length k to the number of jars eaten from the right.
    // So, diff_R[k] is the difference for the last k jars.
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum k_L for each diff_L value
    std::map<int, int> min_kL_for_diff;
    for (int kL = 0; kL <= n; ++kL) {
        int current_diff = diff_L[kL];
        if (min_kL_for_diff.find(current_diff) == min_kL_for_diff.end()) {
            min_kL_for_diff[current_diff] = kL;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible k_R (number of jars eaten from the right)
    for (int kR = 0; kR <= n; ++kR) {
        int current_diff_R = diff_R[kR];
        // The target difference for the remaining jars is 0.
        // initial_diff - diff_L[kL] - diff_R[kR] = 0
        // initial_diff - current_diff_R = diff_L[kL]
        int target_diff_L = initial_diff - current_diff_R;

        if (min_kL_for_diff.count(target_diff_L)) {
            int kL = min_kL_for_diff[target_diff_L];
            min_jars_eaten = std::min(min_jars_eaten, kL + kR);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

