    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track how an input bit 'b' (0 or 1)
    // is transformed.
    // state[bit_pos][0] = result if input bit is 0
    // state[bit_pos][1] = result if input bit is 1
    // Initially, for an input 'x', the j-th bit is x_j.
    // So, if input bit is 0, output is 0. If input bit is 1, output is 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0; // If input bit is 0, current bit is 0
        state[i][1] = 1; // If input bit is 1, current bit is 1
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant 'val'
            if (op_char == '&') {
                state[i][0] &= bit_val;
                state[i][1] &= bit_val;
            } else if (op_char == '|') {
                state[i][0] |= bit_val;
                state[i][1] |= bit_val;
            } else if (op_char == '^') {
                state[i][0] ^= bit_val;
                state[i][1] ^= bit_val;
            }
        }
    }

    // Now, 'state[i][0]' and 'state[i][1]' represent the final transformation
    // for the i-th bit.
    // We need to find a minimal sequence of operations to achieve this.
    // There are 4 possible transformations for each bit:
    // 1. (0,0) -> always 0
    // 2. (0,1) -> identity (input bit)
    // 3. (1,0) -> negation (1 - input bit)
    // 4. (1,1) -> always 1

    // We can represent these 4 transformations using 3 operations:
    // AND with A, OR with B, XOR with C.
    // Let's find A, B, C such that for any input bit 'b':
    // ((b & A_i) | B_i) ^ C_i == state[i][b]

    int final_and_val = 1023; // All bits 1
    int final_or_val = 0;     // All bits 0
    int final_xor_val = 0;    // All bits 0

    for (int i = 0; i < 10; ++i) {
        int s0 = state[i][0];
        int s1 = state[i][1];

        if (s0 == 0 && s1 == 0) { // Always 0
            // To make bit 'i' always 0:
            // (b & 0) | 0 ^ 0 = 0
            // (b & 0) | 1 ^ 1 = 0
            // (b & 1) | 0 ^ 1 = 0
            // (b & 1) | 1 ^ 0 = 0
            // Simplest: AND with 0, OR with 0, XOR with 0.
            // This means final_and_val's i-th bit must be 0.
            final_and_val &= ~(1 << i);
            // final_or_val's i-th bit can be 0 or 1.
            // final_xor_val's i-th bit can be 0 or 1.
            // Let's try to keep final_or_val and final_xor_val 0 if possible.
            // If final_and_val's i-th bit is 0, then (b & 0) is 0.
            // So we need (0 | B_i) ^ C_i = 0.
            // If B_i=0, C_i=0. If B_i=1, C_i=1.
            // We prefer B_i=0, C_i=0.
        } else if (s0 == 0 && s1 == 1) { // Identity (b)
            // To make bit 'i' identity:
            // (b & 1) | 0 ^ 0 = b
            // This means final_and_val's i-th bit must be 1.
            // final_or_val's i-th bit must be 0.
            // final_xor_val's i-th bit must be 0.
            final_and_val |= (1 << i);
            final_or_val &= ~(1 << i);
            final_xor_val &= ~(1 << i);
        } else if (s0 == 1 && s1 == 0) { // Negation (1-b)
            // To make bit 'i' negation:
            // (b & 1) | 0 ^ 1 = 1-b
            // This means final_and_val's i-th bit must be 1.
            // final_or_val's i-th bit must be 0.
            // final_xor_val's i-th bit must be 1.
            final_and_val |= (1 << i);
            final_or_val &= ~(1 << i);
            final_xor_val |= (1 << i);
        } else if (s0 == 1 && s1 == 1) { // Always 1
            // To make bit 'i' always 1:
            // (b & 0) | 1 ^ 0 = 1
            // (b & 1) | 1 ^ 0 = 1
            // Simplest: OR with 1, AND with 1, XOR with 0.
            // This means final_or_val's i-th bit must be 1.
            final_or_val |= (1 << i);
            // final_and_val's i-th bit can be 0 or 1.
            // final_xor_val's i-th bit can be 0 or 1.
            // If final_or_val's i-th bit is 1, then (X | 1) is 1.
            // So we need (1 ^ C_i) = 1. This means C_i=0.
            final_xor_val &= ~(1 << i);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If any bit of AND constant is 0
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If any bit of OR constant is 1
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If any bit of XOR constant is 1
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Adjust to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Tracks vertices currently in the graph

    // Iterate through the removal sequence in reverse
    // This means we are effectively adding vertices one by one
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" in this reverse step

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update: consider k as an intermediate vertex
        // For all pairs (i, j) of currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        // Update paths involving k as an intermediate node
                        if (dist[i][k] + dist[k][j] < dist[i][j]) {
                            dist[i][j] = dist[i][k] + dist[k][j];
                        }
                    }
                }
            }
        }

        // After updating paths using k as an intermediate,
        // also update paths where k is an endpoint.
        // This is crucial because k itself might have found shorter paths to other active vertices
        // through other active vertices, and vice-versa.
        // The previous loop only considered k as an intermediate.
        // We need to ensure all pairs (i,j) where i,j,k are active are updated.
        // The standard Floyd-Warshall structure handles this naturally.
        // The three nested loops for i, j, k (where k is the intermediate)
        // correctly propagate shortest paths.
        // Since we are adding k, we need to ensure that for any active i, j:
        // dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k]) (if j was added before k)
        // dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j]) (if i was added before k)
        // The first set of loops (i,j,k) handles the first case.
        // The following two loops ensure that k's own paths are updated.
        // This is effectively running Floyd-Warshall on the subgraph of active_vertices.
        // The standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // By iterating k from the "last added" to "first added", and only considering active i,j,
        // this structure correctly computes APSP for the subgraph.
        // The previous loop (i,j,k) already does this.
        // The following two loops are redundant if the first loop is structured correctly.
        // Let's re-verify the Floyd-Warshall logic for adding a vertex.
        // When vertex `k` is added, it can serve as an intermediate.
        // For any existing pair `(i, j)`: `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        // Also, `k` itself forms new pairs with existing vertices.
        // For any existing `i`: `dist[i][k]` and `dist[k][i]` might be updated.
        // `dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k])` for any existing `j`.
        // `dist[k][i] = min(dist[k][i], dist[k][j] + dist[j][i])` for any existing `j`.
        // The three nested loops (i, j, k) where k is the intermediate vertex correctly handle all these cases.
        // So, the single set of loops for (i, j, k) where k is the newly active vertex is sufficient.
        // The order of loops is important: k (intermediate) must be outermost.
        // The current structure:
        // for k (newly active):
        //   for i (active):
        //     for j (active):
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This correctly updates all paths between active i,j using k as an intermediate.
        // It also implicitly updates paths like dist[i][k] and dist[k][j] if i or j are k.
        // Example: if i=k, then dist[k][j] = min(dist[k][j], dist[k][k] + dist[k][j]) which is dist[k][j].
        // This is correct.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last step)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to finding k such that 2^k <= X + 1
        // k = floor(log2(X + 1))
        if (X == 1) { // Special case for X=1, 2^0-1 is not 1. We need 2^1-1=1.
            k = 1;
        } else {
            k = static_cast<long long>(std::floor(std::log2(static_cast<double>(X + 1))));
        }

        // If 2^k - 1 > X, we need to reduce k.
        // This can happen if X+1 is not a perfect power of 2,
        // and log2(X+1) gives a slightly larger k due to floating point precision,
        // or if X is exactly 2^k - 1, but we want to use a smaller k to leave room for other blocks.
        // The strategy is to pick the largest k such that 2^k - 1 <= X.
        // If X is 1, k=1 (2^1-1=1).
        // If X is 2, k=1 (2^1-1=1).
        // If X is 3, k=2 (2^2-1=3).
        // If X is 4, k=2 (2^2-1=3).
        // If X is 5, k=2 (2^2-1=3).
        // If X is 6, k=2 (2^2-1=3).
        // If X is 7, k=3 (2^3-1=7).

        // The largest k such that 2^k - 1 <= X is equivalent to 2^k <= X + 1.
        // So k = floor(log2(X+1)).
        // However, we need to be careful with X=1.
        // If X=1, floor(log2(2)) = 1. 2^1-1 = 1. This works.
        // So the initial k calculation is generally correct.

        // Let's refine k selection:
        // We want to find the largest k such that (1LL << k) - 1 <= X.
        // This is equivalent to (1LL << k) <= X + 1.
        // So k = floor(log2(X+1)).
        // If X=0, k=0. (1LL << 0) - 1 = 0.
        // If X=1, k=1. (1LL << 1) - 1 = 1.
        // If X=2, k=1. (1LL << 1) - 1 = 1.
        // If X=3, k=2. (1LL << 2) - 1 = 3.
        // This logic seems sound.

        // The problem statement implies we want to use as many elements as possible for a given block.
        // So we should pick the largest k such that 2^k - 1 <= X.
        // This is exactly what k = floor(log2(X+1)) does.
        // Example: X=10. X+1=11. log2(11) approx 3.45. floor(3.45) = 3.
        // k=3. (1LL << 3) - 1 = 7.
        // We add 3 copies of current_val. X becomes 10-7=3.
        // Next iteration: X=3. X+1=4. log2(4)=2. floor(2)=2.
        // k=2. (1LL << 2) - 1 = 3.
        // We add 2 copies of current_val. X becomes 3-3=0.
        // This greedy approach works.

        // Add k copies of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= ((1LL << k) - 1);

        // Move to the next block of numbers
        // The next block's numbers must be at least current_val + d
        // to ensure max - min >= d for subsequences spanning blocks.
        // We add 1 to current_val + d to ensure strict inequality.
        current_val += (d + 1);

        // Check for overflow for current_val
        if (current_val >= 1000000000000000000LL && X > 0) { // 10^18
            // This means we can't construct the array within limits.
            // However, given X <= 10^9, d <= 10^9, and n <= 10^4,
            // current_val will not exceed 10^18.
            // Max n is 10^4. Max d is 10^9.
            // current_val can be at most 1 + (10^4 * (10^9 + 1)) which is approx 10^13.
            // So overflow is not an issue.
        }
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0] for 'x', counts[1] for 'y', counts[2] for 'z'
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];

        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            // Substring length is less than 3, no 3-char subsequence can be found.
            // Algorithm terminates immediately.
            std::cout << "YES\n";
            continue;
        }

        // Calculate counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The algorithm terminates if and only if the counts of 'x', 'y', 'z'
        // in the substring are "balanced" enough such that any 3-character
        // substring can be rearranged to one of "zyx", "xzy", "yxz".
        // This means the difference between the maximum and minimum count
        // of any character ('x', 'y', 'z') in the substring must be at most 1.
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horizontal_moves = std::min(counts['L'], counts['R']);
        int vertical_moves = std::min(counts['U'], counts['D']);

        if (horizontal_moves == 0 && vertical_moves == 0) {
            std::cout << 0 << "\n\n";
        } else if (horizontal_moves == 0) { // Only vertical moves possible
            std::cout << 2 << "\n";
            std::cout << "UD\n";
        } else if (vertical_moves == 0) { // Only horizontal moves possible
            std::cout << 2 << "\n";
            std::cout << "LR\n";
        } else {
            int total_moves = 2 * horizontal_moves + 2 * vertical_moves;
            std::cout << total_moves << "\n";
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'L';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'U';
            }
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'R';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'D';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n < 3) return false; // Should not happen based on constraints (n >= 3)

    std::vector<int> b = a;
    bool changed = false;

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        int median_val;
        if (sum >= 2) { // Two or three 1s
            median_val = 1;
        } else { // Zero or one 1 (two or three 0s)
            median_val = 0;
        }

        if (b[i] != median_val) {
            b[i] = median_val;
            changed = true;
        }
    }

    a = b;
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Edge case, though problem states n >= 3
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find the first 1 and last 1
    int first_one = -1;
    int last_one = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            if (first_one == -1) {
                first_one = i;
            }
            last_one = i;
        }
    }

    if (first_one == -1) { // All zeros, already stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find all "010" patterns
    std::vector<int> zero_one_zero_indices;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i - 1] == 0 && a[i] == 1 && a[i + 1] == 0) {
            zero_one_zero_indices.push_back(i);
        }
    }

    if (zero_one_zero_indices.empty()) { // No "010" patterns, sequence is stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    int max_dist = 0;
    for (size_t i = 0; i < zero_one_zero_indices.size(); ++i) {
        int current_idx = zero_one_zero_indices[i];
        int prev_one_idx = (i == 0) ? first_one : zero_one_zero_indices[i - 1];

        // If current_idx is the first 010, prev_one_idx is the first 1 in the whole sequence.
        // If current_idx is not the first 010, prev_one_idx is the previous 010's index.
        // In both cases, the segment is from prev_one_idx to current_idx.
        // The distance is current_idx - prev_one_idx.
        // The number of steps for this segment is ceil((current_idx - prev_one_idx) / 2.0)
        // which is (current_idx - prev_one_idx + 1) / 2 for integer division.
        max_dist = std::max(max_dist, (current_idx - prev_one_idx + 1) / 2);
    }

    // Handle the segment from the last 010 to the last 1 in the whole sequence
    int last_zero_one_zero_idx = zero_one_zero_indices.back();
    max_dist = std::max(max_dist, (last_one - last_zero_one_zero_idx + 1) / 2);

    // Apply smoothing max_dist times
    for (int k = 0; k < max_dist; ++k) {
        apply_median_smoothing(a);
    }

    std::cout << max_dist << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use in the alternating sequence to generate k differences

    // The first k+1 elements will generate k distinct differences:
    // |1 - (k+1)| = k
    // |(k+1) - 2| = k-1
    // |2 - k| = k-2
    // ...
    // |(k/2 + 1) - (k/2 + 2)| = 1 (if k is odd)
    // or |(k/2) - (k/2 + 1)| = 1 (if k is even)
    // This sequence is 1, k+1, 2, k, 3, k-1, ...

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...) -> print from left (1, 2, 3, ...)
            std::cout << left++;
        } else { // Odd index (1, 3, 5, ...) -> print from right (k+1, k, k-1, ...)
            std::cout << right--;
        }
        std::cout << " ";
    }

    // The remaining n - (k+1) elements are simply the next available numbers in increasing order.
    // These will only generate a difference of 1 with the previous element,
    // which is already covered by the first k+1 elements (unless k=0, but k >= 1).
    // The last element printed from the alternating sequence was either `left-1` or `right+1`.
    // The next number to print is `left`.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the zeros as evenly as possible among the m+1 possible blocks
        // created by the m ones.
        // Let k be the number of zeros in each block.
        // There will be (m+1) blocks of zeros.
        // Some blocks will have floor(num_zeros / (m+1)) zeros, and some will have ceil(num_zeros / (m+1)) zeros.

        // Number of blocks with floor(num_zeros / (m+1)) zeros
        long long k_floor = num_zeros / (m + 1);
        long long count_k_floor_blocks = (m + 1) - (num_zeros % (m + 1));

        // Number of blocks with ceil(num_zeros / (m+1)) zeros
        long long k_ceil = k_floor + 1;
        long long count_k_ceil_blocks = num_zeros % (m + 1);

        // Calculate the number of substrings consisting only of zeros
        long long substrings_zeros_only = 0;
        if (k_floor > 0) {
            substrings_zeros_only += count_k_floor_blocks * (k_floor * (k_floor + 1) / 2);
        }
        if (k_ceil > 0) { // k_ceil will be > 0 if num_zeros > 0 and m+1 > 0
            substrings_zeros_only += count_k_ceil_blocks * (k_ceil * (k_ceil + 1) / 2);
        }

        // The maximum value of f(s) is total_substrings - minimum_substrings_zeros_only
        long long max_f_s = total_substrings - substrings_zeros_only;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <tuple>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i to a very large value (effectively infinity)
    // b_i represents the maximum possible initial value for a[i]
    std::vector<long long> b(n, 2000000000000000000LL); // A value larger than 10^9 + 5*10^7 * 5000

    // Iterate operations in reverse to determine constraints on initial values
    // For each type 2 operation (l, r, m), it means that for any j in [l, r],
    // the initial value a_0[j] must be <= m - (sum of d's applied to j AFTER this operation).
    // We want to find the tightest upper bound for each a_0[j].
    std::vector<long long> current_delta(n, 0); // current_delta[j] = sum of d's applied to j from ops[i+1] to ops[m-1]
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (l, r, d), it means that for any j in [l, r],
            // this operation will add d to a[j].
            // So, for any future type 2 operation, the effective 'm' for a_0[j] will be d less.
            // We need to subtract d from current_delta for elements in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (l, r, m), it means that for any j in [l, r],
            // a_0[j] + (sum of d's applied to j up to this operation) <= m.
            // The sum of d's applied to j up to this operation is (total_d_from_all_ops) - (current_delta[j]).
            // No, it's simpler: a_0[j] + (sum of d's from ops[0] to ops[i-1]) + (d from ops[i] if type 1) <= m.
            // The current_delta[j] already accounts for d's from ops[i+1] to ops[m-1].
            // So, a_0[j] + (sum of d's from ops[0] to ops[m-1]) - current_delta[j] <= m.
            // This means a_0[j] <= m - (sum of d's from ops[0] to ops[m-1]) + current_delta[j].
            // Let's rephrase: a_0[j] + (sum of d's applied to j *before* this operation) <= m.
            // The sum of d's applied to j *before* this operation is (total_d_from_ops[0] to ops[m-1]) - current_delta[j].
            // This is not correct.
            //
            // Let a_k[j] be the value of a[j] after k operations.
            // a_k[j] = a_0[j] + sum_{p=0}^{k-1} (d_p if op_p affects j).
            // For a type 2 op (l, r, m) at index i:
            // max_{j=l..r} (a_0[j] + sum_{p=0}^{i-1} (d_p if op_p affects j)) = m.
            // This implies for all j in [l, r]:
            // a_0[j] + sum_{p=0}^{i-1} (d_p if op_p affects j) <= m.
            //
            // Let's define `delta_prefix[j][k]` as the sum of `d` values applied to index `j` by operations `0` through `k-1`.
            // Then `a_k[j] = a_0[j] + delta_prefix[j][k]`.
            // For a type 2 op `(l, r, m)` at index `i`:
            // `max_{j=l..r} (a_0[j] + delta_prefix[j][i]) = m`.
            // This implies `a_0[j] + delta_prefix[j][i] <= m` for all `j` in `[l, r]`.
            // So, `a_0[j] <= m - delta_prefix[j][i]`.
            //
            // When iterating backwards, `current_delta[j]` stores `sum_{p=i+1}^{m-1} (d_p if op_p affects j)`.
            // We need `sum_{p=0}^{i-1} (d_p if op_p affects j)`.
            // Let `total_delta[j]` be `sum_{p=0}^{m-1} (d_p if op_p affects j)`.
            // Then `sum_{p=0}^{i-1} (d_p if op_p affects j) = total_delta[j] - current_delta[j] - (d_i if op_i is type 1)`.
            // Since we are processing `op_i`, `d_i` is not yet added to `current_delta`.
            // So, `sum_{p=0}^{i-1} (d_p if op_p affects j) = total_delta[j] - current_delta[j]`.
            // This is still confusing.

            // Let's use a simpler definition for `current_delta[j]`:
            // `current_delta[j]` is the sum of `d` values that will be applied to `a[j]` by operations `i+1` to `m-1`.
            // When we are at operation `i`, the value of `a[j]` *before* this operation is `a_0[j] + sum_{k=0}^{i-1} d_k_for_j`.
            // The value of `a[j]` *after* all operations is `a_0[j] + sum_{k=0}^{m-1} d_k_for_j`.
            // So, `sum_{k=0}^{i-1} d_k_for_j = (sum_{k=0}^{m-1} d_k_for_j) - (sum_{k=i}^{m-1} d_k_for_j)`.
            // `sum_{k=i}^{m-1} d_k_for_j` is `current_delta[j]` if `op_i` is type 1, plus `current_delta[j]` from previous iterations.
            //
            // Let `delta_suffix[j]` be the sum of `d` values applied to index `j` by operations `i` through `m-1`.
            // When processing `op_i`:
            // If `op_i` is type 1 `(l, r, d)`: `delta_suffix[j]` increases by `d` for `j` in `[l, r]`.
            // If `op_i` is type 2 `(l, r, m)`:
            //   For any `j` in `[l, r]`, the value of `a[j]` *at the time of this query* is `a_0[j] + (total_d_applied_before_op_i)`.
            //   `total_d_applied_before_op_i = (total_d_from_all_ops) - delta_suffix[j]`.
            //   So, `a_0[j] + (total_d_from_all_ops) - delta_suffix[j] <= m`.
            //   `a_0[j] <= m - (total_d_from_all_ops) + delta_suffix[j]`.
            //   This means `b[j] = min(b[j], m - (total_d_from_all_ops) + delta_suffix[j])`.
            //
            // This is the correct logic:
            // `b[j]` stores `max_initial_value_for_j`.
            // `current_delta[j]` stores `sum_{k=i+1}^{m-1} (d_k if op_k affects j)`.
            // For a type 2 op `(l, r, m)` at index `i`:
            // The value of `a[j]` *at the time of this query* is `a_0[j] + (sum of d's from ops[0] to ops[i-1])`.
            // Let `D_before_i[j] = sum_{k=0}^{i-1} (d_k if op_k affects j)`.
            // We have `a_0[j] + D_before_i[j] <= m`.
            // So `a_0[j] <= m - D_before_i[j]`.
            //
            // We need `D_before_i[j]`.
            // Let `D_total[j] = sum_{k=0}^{m-1} (d_k if op_k affects j)`.
            // Then `D_before_i[j] = D_total[j] - (sum_{k=i}^{m-1} (d_k if op_k affects j))`.
            // The `current_delta[j]` in our loop is `sum_{k=i+1}^{m-1} (d_k if op_k affects j)`.
            // So `sum_{k=i}^{m-1} (d_k if op_k affects j)` is just `current_delta[j]` (because `op_i` is type 2, so no `d_i`).
            // Thus, `D_before_i[j] = D_total[j] - current_delta[j]`.
            // So, `a_0[j] <= m - (D_total[j] - current_delta[j])`.
            // `b[j] = min(b[j], m - D_total[j] + current_delta[j])`.
            // This requires `D_total[j]`. Let's compute it first.

            // Re-evaluate:
            // `b[j]` is the upper bound for `a_0[j]`.
            // `current_delta[j]` is the sum of `d` values applied to `a[j]` by operations `i+1` to `m-1`.
            // When we process `op_i` (type 2, `l, r, m`):
            // For any `j` in `[l, r]`, the value of `a[j]` *at the time of this query* is `a_0[j] + (sum of d's from ops[0] to ops[i-1])`.
            // Let `S_i[j] = sum_{k=0}^{i-1} (d_k if op_k affects j)`.
            // We have `a_0[j] + S_i[j] <= m`.
            // So `a_0[j] <= m - S_i[j]`.
            //
            // We need to find `S_i[j]`.
            // Let `D_total[j]` be the sum of all `d` values applied to `a[j]` by *all* type 1 operations (0 to m-1).
            // `S_i[j] = D_total[j] - (sum of d's from ops[i] to ops[m-1])`.
            // The `current_delta[j]` in our loop is `sum_{k=i+1}^{m-1} (d_k if op_k affects j)`.
            // If `op_i` is type 1, then `sum_{k=i}^{m-1} (d_k if op_k affects j) = ops[i].val + current_delta[j]`.
            // If `op_i` is type 2, then `sum_{k=i}^{m-1} (d_k if op_k affects j) = current_delta[j]`.
            //
            // So, for type 2 op `(l, r, m)` at index `i`:
            // `S_i[j] = D_total[j] - current_delta[j]`.
            // Thus, `b[j] = min(b[j], m - (D_total[j] - current_delta[j]))`.
            // This means we need `D_total[j]` first.

            // Let's compute `D_total[j]` first.
            std::vector<long long> D_total(n, 0);
            for (const auto& op : ops) {
                if (op.type == 1) {
                    for (int j = op.l; j <= op.r; ++j) {
                        D_total[j] += op.val;
                    }
                }
            }

            // Now, iterate backwards to determine `b[j]`.
            // `current_delta[j]` will store `sum_{k=i+1}^{m-1} (d_k if op_k affects j)`.
            std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta
            for (int i = m - 1; i >= 0; --i) {
                if (ops[i].type == 1) {
                    // This operation adds ops[i].val to a[j] for j in [l, r].
                    // This value will be part of `D_total[j]`.
                    // For future operations (k < i), this `d` value is part of `S_k[j]`.
                    // For current operation `i`, this `d` value is not part of `S_i[j]`.
                    // When we go to `i-1`, this `d` value will be part of `current_delta[j]` for `i-1`.
                    for (int j = ops[i].l; j <= ops[i].r; ++j) {
                        current_delta[j] += ops[i].val;
                    }
                } else { // ops[i].type == 2
                    // For any j in [l, r], a_0[j] + S_i[j] <= m.
                    // S_i[j] = D_total[j] - current_delta[j].
                    // So, a_0[j] <= m - (D_total[j] - current_delta[j]).
                    for (int j = ops[i].l; j <= ops[i].r; ++j) {
                        b[j] = std::min(b[j], ops[i].val - (D_total[j] - current_delta[j]));
                    }
                }
            }

            // The initial array `a_0` is now `b`.
            // We need to verify if this `a_0` works.
            // The `b[j]` values are the maximum possible initial values.
            // To satisfy `max(a[j]) = m`, we need at least one `a[j]` to be exactly `m`.
            // So, for each type 2 operation `(l, r, m)`, we need to find one `j` in `[l, r]`
            // such that `a_0[j] + S_i[j] = m`.
            // If we set `a_0[j] = b[j]`, then `a_0[j] + S_i[j] <= m`.
            // We need to find a `j` such that `b[j] + S_i[j] = m`.
            // If no such `j` exists, we must increase some `b[j]` to make it `m`.
            // But we cannot increase `b[j]` beyond its current value, as it would violate other constraints.
            // So, if for a type 2 operation `(l, r, m)`, `max_{j=l..r} (b[j] + S_i[j]) < m`, then no solution exists.

            // Let's construct the candidate initial array `a_initial`.
            // We can choose `a_initial[j] = b[j]`.
            // Then simulate all operations and check if they match.
            std::vector<long long> a_initial = b;

            // Check absolute value constraint for initial array
            for (int j = 0; j < n; ++j) {
                if (std::abs(a_initial[j]) > 1000000000LL) {
                    std::cout << "NO\n";
                    return 0;
                }
            }

            // Simulate operations with a_initial
            std::vector<long long> current_a = a_initial;
            std::vector<long long> current_prefix_delta(n, 0); // sum of d's applied to j up to current op
            bool possible = true;
            for (int i = 0; i < m; ++i) {
                if (ops[i].type == 1) {
                    for (int j = ops[i].l; j <= ops[i].r; ++j) {
                        current_a[j] += ops[i].val;
                        current_prefix_delta[j] += ops[i].val;
                    }
                } else { // ops[i].type == 2
                    long long max_val = -3000000000000000000LL; // A very small value
                    for (int j = ops[i].l; j <= ops[i].r; ++j) {
                        max_val = std::max(max_val, current_a[j]);
                    }
                    if (max_val != ops[i].val) {
                        possible = false;
                        break;
                    }
                }
            }

            if (possible) {
                std::cout << "YES\n";
                for (int j = 0; j < n; ++j) {
                    std::cout << a_initial[j] << (j == n - 1 ? "" : " ");
                }
                std::cout << "\n";
            } else {
                std::cout << "NO\n";
            }

            return 0;
        }
    }

    // This part is reached if m=0 or if the loop completes without returning.
    // If m=0, any array with |a_i| <= 10^9 is valid.
    // The problem statement says |a_i| <= 10^9, so 0 is a valid choice.
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << 0 << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate large values. x can also become large.
// The problem statement implies x is an index, so it should not exceed n.
// However, the termination condition x > n means x can exceed n.
// The values a_i are positive, so x will always increase in step 2 and decrease in step 3.
// The maximum value for n is 2 * 10^5.
// The maximum value for a_i is 10^9.
// If x becomes 1 + 10^9, it will be > n and terminate.
// If x becomes 1 - 10^9, it will be <= 0 and terminate.
// So x itself doesn't need to be long long, but the intermediate calculations might.
// Let's use long long for x and y to be safe, as it's common practice for competitive programming
// when values can grow large, and it doesn't hurt performance significantly here.

// Memoization table for results.
// `memo[i]` stores the pair `{final_x, final_y}` if starting with `a[1] = i`.
// `final_x` is the x value when the program terminates.
// `final_y` is the y value when the program terminates.
// If `final_x` is 0, it means the program terminates with `x <= 0`.
// If `final_x` is `n + 1`, it means the program terminates with `x > n`.
// If `final_x` is -1, it means the program does not terminate (cycle detected).
std::vector<std::pair<long long, long long>> memo;
std::vector<bool> visited_in_current_path; // To detect cycles

long long N;
std::vector<long long> A; // A[0] is unused, A[1]...A[N] are used.

// Function to solve for a given starting a[1] value
// `start_a1_val` is the value of a[1] for the current run.
// `current_x` is the current value of x.
// `current_y` is the current value of y.
// This function returns {final_x, final_y}
std::pair<long long, long long> solve(long long start_a1_val, long long current_x, long long current_y) {
    // Check termination conditions
    if (current_x <= 0) {
        return {0, current_y}; // Terminated with x <= 0
    }
    if (current_x > N) {
        return {N + 1, current_y}; // Terminated with x > N
    }

    // Check memoization table
    // The state is uniquely identified by (start_a1_val, current_x).
    // However, the problem structure allows us to memoize based on the *initial* a[1] value.
    // The `solve` function is called recursively.
    // The `memo` table stores results for `a[1] = i`.
    // The `current_x` and `current_y` are internal states during the simulation for a specific `a[1]`.
    // We need a way to memoize the *entire run* for a given `a[1]`.
    // The `memo` table is indexed by the initial `a[1]` value (which is `i` from 1 to N-1).
    // So, `memo[start_a1_val]` stores the result for the run where `a[1]` was `start_a1_val`.
    // If `memo[start_a1_val].first` is non-zero, it means we've already computed this run.
    // If `memo[start_a1_val].first` is -1, it means it's part of a cycle.
    // If `memo[start_a1_val].first` is 0 or N+1, it means it terminated.

    // This recursive function `solve` is not directly memoizing the intermediate states (current_x, current_y).
    // Instead, it's designed to compute the result for a *specific initial a[1]*.
    // The `memo` table is for the *initial* `a[1]` values.
    // The `visited_in_current_path` is for detecting cycles *within a single run*.
    // The `visited_in_current_path` array is indexed by `x` values.
    // If `visited_in_current_path[current_x]` is true, it means we've encountered this `x` before in the *current path*
    // for the *current initial a[1]*. This indicates a cycle.

    // The problem is that `a[x]` depends on `x`.
    // The state is `(x, y)`.
    // The `memo` table should store results for `(x, y)` pairs.
    // However, the problem asks for results for `a[1] = i`.
    // The `a` array is fixed except for `a[1]`.
    // Let's re-evaluate the state.
    // The state is `(x, y)`.
    // The values `a[x]` are fixed for `x > 1`.
    // For `x = 1`, `a[1]` is `start_a1_val`.
    // This means the `a` array is effectively `[start_a1_val, A[2], A[3], ..., A[N]]`.
    // The `memo` table should store results for `(x, y)` pairs.
    // But `y` can be very large.
    // The key insight for this type of problem is often that the `y` value is just an accumulation,
    // and the `x` value determines the path.
    // If we reach a state `(x, y)` that we've seen before *with the same `a[1]`*, it's a cycle.
    // If we reach a state `(x, y)` where `x` is an index `j` for which `memo[j]` is already computed,
    // we can use that result.

    // Let's define `dp[x]` as the result of starting the process from `x` with `y=0`.
    // This is not quite right because `y` accumulates.
    // The problem is that `a[1]` changes for each run.
    // The `a` array is `a_1, a_2, ..., a_n`.
    // For each `i` (1 <= i <= n-1), we run the program with `a_1 = i`.
    // The `A` vector stores `a_2, ..., a_n`.
    // So, `A[idx]` in the code corresponds to `a_{idx+1}` in the problem statement.
    // Let's adjust `A` to be 1-indexed for convenience.
    // `A[1]` will be `i` for each run. `A[2]` to `A[N]` are fixed.

    // Let's define `dp[x]` as the pair `{final_x_offset, final_y_offset}`
    // if we start at `x` with `y=0`.
    // `final_x_offset` is `final_x - x`.
    // `final_y_offset` is `final_y - y`.
    // This is a common technique for problems where `y` accumulates.
    // However, `a[x]` depends on `x`.
    // The `a` values are `a_1, a_2, ..., a_n`.
    // `a_1` is `i`. `a_2, ..., a_n` are given.
    // So, `A[1]` is `i`. `A[k]` for `k > 1` is `A_input[k-1]`.

    // Let's use `memo[x]` to store the result if we start at `x` with `y=0` and `a[1]` is fixed to `i`.
    // This means `memo` needs to be cleared for each `i`. This is too slow.
    // The key is that `a[x]` is fixed for `x > 1`.
    // So, if we are at `x > 1`, the next steps are independent of the initial `a[1]`.
