    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    int h_idx = 0; // Current index for heads

    while (p_idx < m) {
        if (h_idx >= n) {
            // No more heads available, but there are still target tracks to cover
            return false;
        }

        // Find the first head h_idx that can reach p[p_idx]
        // A head h_idx can reach p[p_idx] if h[h_idx] is within [p[p_idx] - T, p[p_idx] + T]
        // Or, more simply, if p[p_idx] is within [h[h_idx] - T, h[h_idx] + T]
        // This means abs(h[h_idx] - p[p_idx]) <= T
        // Since p and h are sorted, we can advance h_idx until h[h_idx] is not too far to the left of p[p_idx]
        // Specifically, h[h_idx] must be <= p[p_idx] + T
        // And to be useful for p[p_idx], h[h_idx] must be >= p[p_idx] - T
        // If h[h_idx] is too far to the left (h[h_idx] + T < p[p_idx]), this head cannot cover p[p_idx]
        // and also cannot cover any p_k > p[p_idx]. So we must advance h_idx.
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx >= n) {
            // No head can reach p[p_idx]
            return false;
        }

        // Now, h[h_idx] is the first head that *might* be able to cover p[p_idx]
        // (i.e., h[h_idx] + T >= p[p_idx])
        // We need to check if it actually covers p[p_idx] (i.e., h[h_idx] - T <= p[p_idx])
        if (h[h_idx] - T > p[p_idx]) {
            // This head is too far to the right to cover p[p_idx].
            // Since h is sorted, all subsequent heads will also be too far to the right.
            // So p[p_idx] cannot be covered.
            return false;
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // We use this head h[h_idx] to cover as many subsequent tracks as possible.
        // The range covered by h[h_idx] is [h[h_idx] - T, h[h_idx] + T].
        long long current_head_reach_right = h[h_idx] + T;

        // Advance p_idx past all tracks covered by h[h_idx]
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks
        h_idx++;
    }

    // All target tracks have been covered
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2 * 10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a'_1 + a'_2
    // max_f = a'_{n-1} + a'_n
    // goodness = (a'_{n-1} + a'_n) - (a'_1 + a'_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible value for f is min(a'_1 + a'_2, a'_1 + a'_2 + h).
    // This is always a'_1 + a'_2.
    // The maximum possible value for f is max(a'_{n-1} + a'_n, a'_{n-1} + a'_n + h).
    // This is always a'_{n-1} + a'_n + h.
    // So, goodness = (a'_{n-1} + a'_n + h) - (a'_1 + a'_2).
    // This is always worse than Case 1 if h > 0.
    // However, we need to consider the specific partition.

    // Let's consider a partition where a'_1 is in one group and a'_2, ..., a'_n are in another.
    // Or a'_1, ..., a'_{n-1} in one group and a'_n in another.
    // The critical values for min_f and max_f are:
    // min_f: a'_1 + a'_2 (if same group) or a'_1 + a'_2 + h (if different groups)
    // max_f: a'_{n-1} + a'_n (if same group) or a'_{n-1} + a'_n + h (if different groups)

    // The smallest possible sum is a'_1 + a'_2.
    // The largest possible sum is a'_{n-1} + a'_n.

    // Consider the partition where a'_1 is in group 1, and a'_2, ..., a'_n are in group 2.
    // min_f:
    //   - a'_1 + a'_k + h for k > 1. Smallest is a'_1 + a'_2 + h.
    //   - a'_i + a'_j for i,j > 1. Smallest is a'_2 + a'_3.
    //   So, min_f = std::min(a'_1 + a'_2 + h, a'_2 + a'_3).
    // max_f:
    //   - a'_1 + a'_k + h for k > 1. Largest is a'_1 + a'_n + h.
    //   - a'_i + a'_j for i,j > 1. Largest is a'_{n-1} + a'_n.
    //   So, max_f = std::max(a'_1 + a'_n + h, a'_{n-1} + a'_n).

    // This specific partition strategy is:
    // Put elements[0] (a'_1) into group 1.
    // Put elements[1] to elements[n-1] (a'_2 to a'_n) into group 2.
    //
    // min_f_val:
    //   - a'_1 + a'_2 + h (from different groups)
    //   - a'_2 + a'_3 (from same group 2)
    //   So, min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    //
    // max_f_val:
    //   - a'_1 + a'_n + h (from different groups)
    //   - a'_{n-1} + a'_n (from same group 2)
    //   So, max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //
    // goodness2 = max_f_val - min_f_val;

    // This is the key insight:
    // The minimum possible value for f is always `elements[0].value + elements[1].value`.
    // This can be achieved if `elements[0]` and `elements[1]` are in the same group.
    //
    // The maximum possible value for f is always `elements[n-1].value + elements[n-2].value + h`.
    // This can be achieved if `elements[n-1]` and `elements[n-2]` are in different groups.
    //
    // The minimum goodness is `max_f - min_f`.
    //
    // Consider two main strategies:
    // 1. All elements in one group.
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //    Partition: all 1s.
    //
    // 2. Partition such that elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    //    min_f:
    //      - elements[0].value + elements[1].value + h (different groups)
    //      - elements[1].value + elements[2].value (same group 2)
    //      So, min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    //    max_f:
    //      - elements[0].value + elements[n-1].value + h (different groups)
    //      - elements[n-2].value + elements[n-1].value (same group 2)
    //      So, max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //    goodness = max_f - min_f.
    //    Partition: elements[0] gets 1, others get 2.

    // Let's re-evaluate the minimum possible goodness.
    // The smallest possible sum of two elements is `elements[0].value + elements[1].value`.
    // The largest possible sum of two elements is `elements[n-1].value + elements[n-2].value`.

    // Option A: All elements in one group (e.g., all 1s).
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness_A = max_f - min_f

    // Option B: Partition elements[0] into group 1, and all others into group 2.
    // This ensures elements[0] and elements[1] are in different groups.
    // This ensures elements[n-1] and elements[n-2] are in the same group (if n > 2).
    //
    // min_f:
    //   - elements[0].value + elements[1].value + h (from different groups)
    //   - elements[1].value + elements[2].value (from group 2, if n >= 3)
    //   If n=2, only elements[0].value + elements[1].value + h is possible.
    //   So, min_f_B = (n == 2) ? (elements[0].value + elements[1].value + h) : std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    //
    // max_f:
    //   - elements[0].value + elements[n-1].value + h (from different groups)
    //   - elements[n-2].value + elements[n-1].value (from group 2, if n >= 3)
    //   If n=2, only elements[0].value + elements[n-1].value + h is possible.
    //   So, max_f_B = (n == 2) ? (elements[0].value + elements[n-1].value + h) : std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //
    // goodness_B = max_f_B - min_f_B;

    // The optimal strategy is to minimize the range of f values.
    // The smallest possible f value is `elements[0].value + elements[1].value`.
    // The largest possible f value is `elements[n-1].value + elements[n-2].value + h`.
    //
    // If we can achieve `elements[0].value + elements[1].value` as min_f,
    // and `elements[n-1].value + elements[n-2].value` as max_f,
    // then the goodness is `(elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)`.
    // This happens if all elements are in the same group.
    //
    // If we can achieve `elements[0].value + elements[1].value + h` as min_f,
    // and `elements[n-1].value + elements[n-2].value + h` as max_f,
    // then the goodness is `(elements[n-1].value + elements[n-2].value + h) - (elements[0].value + elements[1].value + h) = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)`.
    // This happens if all elements are in different groups (not possible for n > 2).
    // Or, more generally, if all pairs are in different groups. This is also not possible.
    //
    // The key is that `min_f` can be `elements[0].value + elements[1].value` (if they are in the same group)
    // or `elements[0].value + elements[1].value + h` (if they are in different groups).
    //
    // The `max_f` can be `elements[n-1].value + elements[n-2].value` (if they are in the same group)
    // or `elements[n-1].value + elements[n-2].value + h` (if they are in different groups).

    // Let's consider the two candidate partitions:
    // 1. All elements in group 1.
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    goodness_all_same = max_f - min_f

    // 2. elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    //    min_f:
    //      - elements[0].value + elements[1].value + h (diff groups)
    //      - elements[1].value + elements[2].value (same group 2, if n >= 3)
    //    max_f:
    //      - elements[0].value + elements[n-1].value + h (diff groups)
    //      - elements[n-2].value + elements[n-1].value (same group 2, if n >= 3)
    //
    //    Let's calculate these values carefully.
    long long min_f_val_all_same = elements[0].value + elements[1].value;
    long long max_f_val_all_same = elements[n - 1].value + elements[n - 2].value;
    long long goodness_all_same = max_f_val_all_same - min_f_val_all_same;

    long long min_f_val_split;
    long long max_f_val_split;

    if (n == 2) {
        // Only one pair (a'_1, a'_2). They must be in different groups.
        // f(a'_1, a'_2) = a'_1 + a'_2 + h.
        // min_f = max_f = a'_1 + a'_2 + h.
        // goodness = 0.
        // This is a special case.
        // If n=2, goodness_all_same = 0.
        // If n=2, elements[0] in group 1, elements[1] in group 2.
        // min_f_val_split = elements[0].value + elements[1].value + h;
        // max_f_val_split = elements[0].value + elements[1].value + h;
        // goodness_split = 0.
        // So for n=2, both partitions give goodness 0.
        // The problem states 2 <= n <= 10^5.
        // The example 1 (n=3, h=2, a={1,2,3}) output 1, 1 2 2.
        // Sorted: 1, 2, 3.
        // goodness_all_same = (3+2) - (1+2) = 5 - 3 = 2.
        // Partition 1 2 2: a'_1=1 in group 1, a'_2=2, a'_3=3 in group 2.
        // min_f_val_split = min(1+2+2, 2+3) = min(5, 5) = 5.
        // max_f_val_split = max(1+3+2, 2+3) = max(6, 5) = 6.
        // goodness_split = 6 - 5 = 1.
        // So goodness_split is better.

        // The logic for n=2:
        // If all in same group: f(a_0, a_1) = a_0 + a_1. min=max=a_0+a_1. goodness=0.
        // If split: f(a_0, a_1) = a_0 + a_1 + h. min=max=a_0+a_1+h. goodness=0.
        // So for n=2, goodness is always 0.
        // The code below handles n=2 correctly.
        // elements[1].value + elements[2].value would be out of bounds if n=2.
        // So we need to handle n=2 specifically for min_f_val_split and max_f_val_split.
        min_f_val_split = elements[0].value + elements[1].value + h;
        max_f_val_split = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        min_f_val_split = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        max_f_val_split = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    }
    long long goodness_split = max_f_val_split - min_f_val_split;

    if (goodness_all_same <= goodness_split) {
        std::cout << goodness_all_same << "\n";
        std::vector<int> result(n);
        for (int i = 0; i < n; ++i) {
            result[elements[i].original_index] = 1;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_split << "\n";
        std::vector<int> result(n);
        result[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result[elements[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line; // To mark if child is still in line without actually removing from vector
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child is now cured

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply confidence reduction from the current child being treated
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply confidence reduction from children who ran away earlier
            children[j].p -= total_d_cry_from_leaving;

            // Check if child j now runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}
